window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-001.json"] = [{"name":"马岛潜鸭","english_name":"Madagascar Pochard","scientific_name":"Aythya innotata","overview":"马岛潜鸭（英文名：Madagascar Pochard，学名：Aythya innotata），是雁形目鸭科潜鸭属的鸟类。极为罕见的潜水鸭。原以为已在20世纪90年代末灭绝，但在2006年于马达加斯加西北部Bemanevika附近的Matsaborimena湖被重新发现。该鸭种主要分布于马达加斯加内陆的淡水湖泊和湿地，以深色为主，雄鸟具白眼，雌鸟则为暗眼，腹部有白色扩散至两侧。","appearance":"马岛潜鸭体型中等，体长42至56厘米。幼鸭虹膜呈棕色，体羽淡棕色或栗色，腹部颜色较深。成年后，体色加深，雄鸟在第一个冬天后眼睛变为白色。繁殖期雄鸭头部、下巴、喉部、胸部和颈部呈深栗色，背部黑色偏褐，翅膀呈深棕色，带有白色翼纹，腹部至尾下覆羽渐变为白色，翅膀下方亦为白色。喙和腿为深灰色，趾甲黑色。","call":"鸣声特征包括雄鸟的类似猫叫的“wee-oow”和滚动的“rrr”声，以及雌鸟的尖锐‘squak’叫声。","habits":"栖息于马达加斯加的淡水湖泊和湿地，偏好有大量植被的浅水湖泊和沼泽。不迁徙，通常成对或单独活动，很少群聚。以水生昆虫为主要食物来源，不同于其同属其他物种。","breeding":"繁殖期从7月持续至2月，巢筑于岸边植物丛中，离水面20至40厘米高，每次产卵6至10枚，孵化期约26至28天。雏鸭上体黑褐色，下体黄色。","identification":"与同类物种相比，马岛潜鸭体型较大，颜色更深，尾巴下方白色明显。与白脸树鸭不同，它缺乏苍白的面部特征。","protection":"IUCN：CR（极危）","distribution":"仅限于马达加斯加西北部Banemavka区域的一个湖泊，历史记录显示曾在Central高原的Alaotra湖周边出现。","other":"2006年重新发现后，通过圈养繁殖计划，到2017年已产生大约90只个体，部分个体于2018年12月在Sofia湖重新引入野外。"},{"name":"青头潜鸭","english_name":"Baer's Pochard","scientific_name":"Aythya baeri","overview":"青头潜鸭（英文名：Baer's Pochard，学名：Aythya baeri），是雁形目鸭科潜鸭属的鸟类。极其罕见的潜鸭，曾广泛分布于东亚，现已成为极度濒危物种。繁殖季节，雄鸟头部呈深绿色光泽，雌鸟和幼鸟头部为深棕色。独特的栗白相间的两胁使其在鸭类中脱颖而出。","appearance":"成年雄鸟在繁殖季头部及颈部覆有绿色光泽，背部黑色带棕，胸部深栗色，两胁浅栗白相间，腹部白色，尾短低。雌鸟及幼鸟头部深棕色，眼睛深褐色，两胁棕褐色，腹部红褐色。两性均有宽阔的白色翼斑，喙深灰色，脚蹼深灰色，虹膜颜色随性别和季节变化。","call":"通常沉默，特别是在冬季。但在求偶期间，两性会发出尖锐的'graaaak'声，平时雄鸟会发出'koro koro'声，雌鸟则发出'kura kura kura'声。","habits":"偏好开阔、水流缓慢的湖泊、池塘和河流，繁殖于水生植被丰富的湖泊，冬季偏爱大型开阔水域。迁徙性物种，秋季离开繁殖地，春季返回。冬季与其他鸭类混群，如赤嘴潜鸭、红头潜鸭等。","breeding":"繁殖期为春末夏初，筑巢于水边草丛或芦苇丛中，巢由植被构成，每窝产卵6-14枚，平均9.7枚，孵化期约27天。雄鸟负责警戒，雌鸟孵化。","identification":"与白眼潜鸭相比，青头潜鸭的棕色更多，赤褐色较少，腹部白色延伸至两胁。与赤膀鸭区别在于头部无冠羽，体型较小，尾下羽白色。","protection":"IUCN：CR（极危）","distribution":"繁殖于西伯利亚东南部和中国北部，越冬于中国南部、东南亚，偶尔出现在南韩、日本、菲律宾和巴基斯坦。","other":"近年来数量急剧下降，可能与过度狩猎和栖息地丧失有关。"},{"name":"白眼潜鸭","english_name":"Ferruginous Duck","scientific_name":"Aythya nyroca","overview":"白眼潜鸭（英文名：Ferruginous Duck，学名：Aythya nyroca），是雁形目鸭科潜鸭属的鸟类。俗名: 白眼凫，中型潜水鸭，主要分布在欧亚大陆的西部至亚洲中部，以及非洲北部。雄鸟头部、胸部和两胁为深栗色，尾下覆羽纯白，雌鸟较暗淡，眼睛颜色不同。繁殖于浅水湖泊、沼泽地带，冬季迁徙至较大湖泊、河流和海湾。胆小机警，主要以植物性食物为主，兼食水生动物。","appearance":"白眼潜鸭体型中等，长度约38-42厘米，体重470-730克（雄）/464-727克（雌），翼展63-67厘米。整体呈现深栗色，头部、胸部和两胁颜色统一，尾下覆羽为醒目的白色。雄鸟具白色眼斑，喙蓝灰色，有小型黑钉和淡蓝色次端环。雌鸟色彩较暗淡，喙色较浅，尖端更暗，眼睛棕色。幼鸟无白色尾下覆羽，羽毛略带红褐色调，腹部斑驳，下覆羽灰白色；喙全灰。飞行时，两性均可见明显的白色翼带。","call":"通常被认为不很爱鸣叫，但在求偶时，雄鸟会发出柔和的‘weck’声，响亮的嘶哑‘wuck’或‘wuckwuck’声，大声的‘witt, wuck’或‘wheeooooo’声，以及尖锐的‘WEE-whew’声。雌鸟则发出‘gek’、‘du’或‘gak-gak-gak’声，似乎在催促雄鸟交配，还有‘err’和‘gaaak’声。飞行中，两性都会发出急促的、沙哑的‘aark’声。","habits":"偏好有丰富水生植被的浅淡水环境，如湖泊、池塘和沼泽。在繁殖季节，也会光顾盐湖、咸水或碱性湖泊。非繁殖季节，它们可能出现在大型湖泊、内陆海、水库、泻湖和沿海湿地。主要在低地繁殖，夏季最高可达海拔2000米，如西南阿拉伯和中国青海的记录。它们是迁徙鸟类，通常在9月至10月离开繁殖地，3月中旬至4月中旬返回。","breeding":"繁殖期通常从4月至5月开始，雌鸟独自孵化，雄鸟在雌鸟孵化初期即离开。巢位于地面靠近水源处，或隐藏在密集的植被中，有时建于被水淹没的柳树附近的洞穴。一窝产卵数通常为8-10枚，孵化期25-28天，幼鸟55-60天后离巢独立。","identification":"与凤头潜鸭雌鸟的区别在于白眼潜鸭具有明显的白色尾下覆羽（凤头潜鸭雌鸟有时也有类似特征），头形差异，缺少凤头冠羽，喙上无黑色次端环。与青头潜鸭相比，白眼潜鸭两胁的白色较少。","protection":"IUCN：NT（近危）","distribution":"繁殖区遍布从欧洲西部和北非向东至西蒙古，南部至阿拉伯半岛。冬季分布于地中海盆地、黑海沿岸，小部分进入撒哈拉以南非洲，东部种群在南亚和东南亚过冬。","other":"白眼潜鸭的数量在欧洲经历了严重下降，特别是在乌克兰、摩尔多瓦、西班牙和法国。然而，在阿尔及利亚、摩洛哥、瑞士、沙特阿拉伯、叙利亚、英格兰西南部、阿尔及利亚撒哈拉沙漠、埃及南部、科威特等地，观察到了局部增加或首次繁殖记录。"},{"name":"新西兰潜鸭","english_name":"New Zealand Scaup","scientific_name":"Aythya novaeseelandiae","overview":"新西兰潜鸭（英文名：New Zealand Scaup，学名：Aythya novaeseelandiae），是雁形目鸭科潜鸭属的鸟类。小型潜水鸭，体长40-46厘米，体重约650克。雄鸭具有独特的黑紫色外观，头部和身体带有绿色光泽，而雌鸭呈较暗淡的棕色。广泛分布于新西兰北岛和南岛的淡水湖泊和沿海泻湖，但在斯图尔特岛和查塔姆群岛已不再存在。新西兰潜鸭是优秀的潜水者，能够在水下活动长达20秒。","appearance":"新西兰潜鸭体长40至46厘米，雄鸭重630至760克，雌鸭重530至700克。雄鸟全身深色，带黄眼，上体黑色，头部和翅膀具蓝绿色虹彩，下体呈棕色斑点，翼上有宽阔的白色条纹，下翼呈棕色白。雌鸟上体暗棕色，臀部几乎全黑，下体棕色斑点，翼纹似雄鸟，但具棕色虹膜、棕黑色喙和暗棕色腿足。幼鸟类似雌鸟，但无面部白色，腹部呈灰白色，年轻雄鸟在约6个月大时可识别。","call":"新西兰潜鸭被认为是相对安静的物种，大多数叫声与展示行为相关联：雄鸟发出柔和的哨声‘whe’，可单次、双次或多次发出；雌鸟在社交互动中发出高音的‘errrr’，并在警告雏鸭时发出颤音‘whirr whirr’。","habits":"新西兰潜鸭主要栖息于较深的大型淡水湖泊和浅的沿海泻湖，海拔从海平面到约1000米，包括火山湖、高山冰川湖、低地泥炭湖和水电站形成的湖泊。它们大部分时间在水下度过，能够行进相当远的距离。主要以水生无脊椎动物（如蜗牛、蜻蜓、豆娘、水黾和仰泳蝽）和植物物质为食，尤其是水生大型植物。通常通过潜水觅食，偶尔从水面追逐昆虫。主要在黄昏时分觅食，形成群体。","breeding":"繁殖期主要在10月至11月，偶尔更早，季节可延续至2月；雏鸭主要观察到12月至1月。通常在单对或松散的群体中繁殖，特别是在岛屿上。巢为杯状结构，由芦苇茎、草和邻近植被构成，内衬绒羽，位于地面，藏于植被中，靠近水面，尤其是在可用的岛屿上。一窝蛋数为4至8枚乳白色到摩卡棕色的蛋，孵化期27至31天，仅由雌鸟孵化。雏鸭出生时覆盖着淡棕色绒毛，下体棕色或浅黄白色，喙棕色，腿足灰棕色，孵化后约24小时离开巢穴，约75天（圈养条件下）后离巢，由雌鸟照料，雏群有时会合并。","identification":"新西兰潜鸭是唯一的全身深色Aythya物种，具有黄色眼睛，无换羽期的羽毛，上体黑色，头部具强烈绿或紫色虹彩，下体棕色斑点，翼上有宽阔的白色条纹，下翼呈棕色白。雌鸟上体暗棕色，下体棕色斑点，与雄鸟相似的翼纹，但虹膜、喙和腿足颜色较暗。漂浮时，其独特的浴玩具鸭子轮廓与任何其他本地鸭类物种不同。","protection":"IUCN：LC（无危）。尽管广泛分布，但自本世纪初以来由于狩猎，数量大幅减少，狩猎仍因无法正确识别合法猎物而构成威胁。自欧洲定居以来，它已经从低地消失；化石记录显示，它曾经存在于查塔姆群岛。自1934年获得法律保护以来，恢复进程缓慢，由于大规模湿地排水。自1950年代以来，由于适应了人工水体（如怀卡托河上的水电大坝），在许多地区数量增加。总人口估计只有5000至10,000只，主要限于南岛东侧和北岛北部和中部部分，仅在陶波和罗托鲁瓦附近常见。在奇查格岛上，圈养繁殖和重新引入计划非常成功，可能需要这种方法才能使物种重新占领国家的低地地区。","distribution":"新西兰潜鸭的分布局限于新西兰的北岛和南岛，主要在东部南阿尔卑斯山脉一侧，以及北岛的北部和中部地区，尤其在陶波和罗托鲁瓦附近较为常见。","other":"新西兰潜鸭是一种高度适应性的物种，能够利用人造水体，如水电站形成的湖泊。"},{"name":"环颈潜鸭","english_name":"Ring-necked Duck","scientific_name":"Aythya collaris","overview":"环颈潜鸭（英文名：Ring-necked Duck，学名：Aythya collaris），是雁形目鸭科潜鸭属的鸟类。小型至中型的潜水鸭，原生于北美，广泛分布于北美地区的淡水湖泊和池塘。其最显著的外部特征是尖顶状的头部和独特的白色嘴部标记。这种鸭子的繁殖范围覆盖了从美国北部到加拿大北部的寒带森林，冬季则迁徙至美国南部的湖泊、河流和海湾。","appearance":"雄性环颈潜鸭具有光泽的黑色头部和背部，灰色的两侧，以及肩部前方明显的白色楔形斑。喙呈灰色，基部和鼻孔周围有白色，尖端为黑色并被白色带环绕。雌鸟则为灰褐色，头顶较暗，脸部较淡，有白色的环眼和从眼延伸至喙基部的白色条纹。喙同样呈灰色，但仅有微弱的白色远端带。两性的翅膀在飞行时显现出灰色而非白色的翼带。幼鸟外观类似于成年个体，但颜色较暗淡。","call":"未提供具体描述。","habits":"环颈潜鸭是迁徙性鸟类，夏季栖息于富含水生植物的淡水湖泊、池塘和沼泽地带，冬季则转移至较大的湖泊、缓慢流动的河流、河口、海湾和河口三角洲。它们主要在清晨和黄昏觅食，以植物性食物为主，包括块茎、种子、叶片和水生植物（如黑莎草、草、野生稻等）。也会食用水生昆虫、蜗牛和蛤蜊。它们通常成群迁徙，小群数量通常在十至数十只之间，偶尔会形成百只以上的大群。","breeding":"环颈潜鸭在春季迁徙期间结成配偶，配偶关系仅持续至繁殖期结束。巢穴呈碗状，位于近水的陆地上，由水生植被衬垫。雌鸟每次产卵8至10枚，孵化期为25至29天，雌鸟会在雏鸟能够飞行前持续照顾它们。","identification":"雄性环颈潜鸭与凤头潜鸭相似，但可通过尖顶状头部、黑色背部与灰色侧面的对比、肩部前方的白色楔形斑以及喙上的独特白色标记来区分。雌性环颈潜鸭与雌性美洲潜鸭类似，但体型较小，头部轮廓更尖锐，脸部前方有苍白区域。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于北美，包括美国北部和加拿大北部的寒带森林。非繁殖期则广泛分布于中美洲，包括美国南部的湖泊、河流和海湾。","other":"环颈潜鸭在迁徙和冬季时会形成混合群，与其它潜水鸭种共存。"},{"name":"凤头潜鸭","english_name":"Tufted Duck","scientific_name":"Aythya fuligula","overview":"凤头潜鸭（英文名：Tufted Duck，学名：Aythya fuligula），是雁形目鸭科潜鸭属的鸟类。又名: 泽凫、凤头鸭子、黑头四鸭，小型潜水鸭，广泛分布在欧亚大陆北部，数量接近一百万只。雄鸟具有独特的黑色外观，白侧翼和蓝灰色喙，以及头部后方的细长羽冠。雌鸟呈深褐色，侧面颜色较淡，头部羽冠较短。该物种适应性强，可在人类创造的人工环境中繁殖。","appearance":"成年雄性凤头潜鸭通体黑色，两侧翼白，喙蓝灰色，双眼金黄，头部后方有明显的羽冠。雌鸟整体深褐色，两胁颜色更浅，喙基处有模糊的白斑，眼睛金黄色，头部羽冠较短。飞行时，两性均展现出鲜明的白色翼带。幼鸟类似雌鸟，但头部和前颈颜色更深，背部有稍微的虫纹图案。","call":"雌鸟发出尖锐的‘karr’声，多在飞行中发出。雄鸟大多沉默，但在求偶期间会发出简单的‘wit-oo’哨声。","habits":"栖息于湖泊、河流、水库、池塘和沼泽等开阔水域，偏好有岸边植被的淡水环境。冬季迁徙至南欧、非洲、中东、印度、东南亚等地。主要通过潜水觅食，食物包括软体动物、甲壳类、水生昆虫和一些植物。夜间也会觅食。","breeding":"繁殖期为5月至7月，通常在第一年末达到性成熟，但多数雌鸟在第二年才参与繁殖。在湖边或岛屿上的草丛或灌木丛中筑巢，巢内铺满绒羽。每窝产卵6-13枚，孵化期23-25天，由雌鸟单独孵化。雏鸟孵化后即可跟随亲鸟活动，约40-50天后学会飞翔。","identification":"凤头潜鸭体型略小于红头潜鸭，但仅凭体型差异难以区分，除非两种鸭同时出现进行对比。雌性凤头潜鸭的羽冠较短，侧面颜色较淡，与红头潜鸭的特征明显不同。","protection":"IUCN：LC（无危）","distribution":"繁殖区域遍布温带和北欧亚大陆。冬季迁徙至南欧、南亚、东亚、东南亚和日本等地。在中国大陆，常见于湖泊和深池塘。","other":"凤头潜鸭的种群在某些地区显著增长，归因于其适应新环境的能力，尤其是在人类创造的公园和水库等地方。"},{"name":"斑背潜鸭","english_name":"Greater Scaup","scientific_name":"Aythya marila","overview":"斑背潜鸭（英文名：Greater Scaup，学名：Aythya marila），是雁形目鸭科潜鸭属的鸟类。俗名: 铃凫、东方蚬鸭，中型潜水鸭，体型大于近缘种小潜鸭。夏季繁殖于北极圈内的北美和欧亚大陆，包括阿拉斯加、北加拿大、西伯利亚及欧洲最北端。冬季迁徙至北美东西海岸、欧洲西北部沿海、日本和中国东部沿海地区。其特征为雄鸟头部、胸部和后部黑色，腹部白色，翅膀有白色条纹，雌鸟整体呈褐色，喙基有白斑，眼黄色。","appearance":"雄性斑背潜鸭具有黑色并带有绿或紫色光泽的头部，黑色胸部，灰背部，腹部白色，翅膀上可见白色条纹延伸至初级飞羽。雌鸟整体呈暗褐色，喙基有白色斑块，眼黄色，翅膀上的白色斑纹略淡。喙基的白色斑块在雌鸟中大小变化较大。幼鸟类似雌鸟，但颜色更暗，面部白色较少，颈前和侧面颜色较浅，尤其是雌鸟幼鸟。","call":"雄性斑背潜鸭发出柔和快速的哨声用于吸引雌鸟，雌鸟发出单一音调的粗糙叫声。","habits":"斑背潜鸭繁殖季节主要栖息于北极苔原带和西伯利亚北部开阔的泰加林带，非繁殖季节则迁徙至近海岸浅水处、河口、海湾、内陆湖泊、水库和沼泽地带。它们以群体形式活动，善于游泳和潜水，通常白天觅食。食物包括甲壳类、软体动物、水生昆虫、小型鱼类、水藻、水生植物叶、茎、种子等。","breeding":"斑背潜鸭在北极冻原带繁殖，繁殖期为5月至7月。成对出现，通常在冬季末形成伴侣。巢筑于靠近水源的干燥地面，多位于枯草或新鲜草丛中，或小柳树和灌木下。雌鸟孵化，雄鸟在孵化开始后离巢换羽。每窝产卵7至10枚，卵呈灰橄榄色或褐色，平均孵化期为27至28天。雏鸟出生后不久即可跟随亲鸟活动，约经40至50天后学会飞翔。","identification":"与小潜鸭相比，斑背潜鸭头形更圆，脸颊更丰满，翅膀上的白色条纹更宽，喙尖的黑色部分更大更宽。雌性斑背潜鸭随着羽毛磨损，到5月底会显示出明显的亮色耳侧斑点，而小潜鸭没有这一特征。","protection":"IUCN：LC（无危）；列入中国国家林业局2000年发布的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","distribution":"繁殖于北极圈内，包括北美、欧亚大陆的冰岛亚北极地区至堪察加半岛和科曼多尔群岛（俄罗斯东南部）、美国阿拉斯加至加拿大魁北克北部。冬季迁徙至欧洲西北部沿海、中东部（大西洋东部北部）、黑海和里海、日本、朝鲜半岛至中国东部和台湾（太平洋西部北部）、美国加利福尼亚州中部（太平洋东部北部）、五大湖、卡罗来纳州北部（大西洋西部北部）。在中国主要分布在东北、河北、山东、长江以南东部各省、广东、广西等地。","other":"斑背潜鸭自1980年代以来数量持续下降，面临的主要威胁包括栖息地退化、污染物摄入、繁殖地变化和雌鸟生存率降低。"},{"name":"小潜鸭","english_name":"Lesser Scaup","scientific_name":"Aythya affinis","overview":"小潜鸭（英文名：Lesser Scaup，学名：Aythya affinis），是雁形目鸭科潜鸭属的鸟类。小型北美洲潜水鸭，广泛分布且数量众多。其特征包括黑色带紫色或绿色光泽的头部、灰色背部、白色侧面，以及蓝色的喙和黄色的眼睛。雌雄两性的成鸟在繁殖季节有着明显的外观差异，雄鸟有黑头、灰背和白色侧面，雌鸟则全身呈棕色，头部较暗，喙基有白色斑块。主要栖息于内陆湖泊和沼泽，冬季南迁至中美洲。","appearance":"雄性小潜鸭在繁殖季节呈现黑色头部，带有紫色或绿色光泽，黑色颈部、胸部和上背部，灰斑点下背部，白色侧面，灰色斑纹下背部，黑色臀部和尾下覆羽。雌鸟全身呈深灰棕色至巧克力棕色，头部较暗，喙基有变大小的白色斑块；上体颜色更深，翼羽斑点灰色；喙呈暗灰色。所有性别的成鸟都有部分白色的次级飞羽，形成翼上的部分条纹，雄鸟的虹膜呈鲜黄色，雌鸟的虹色从橄榄棕色至橄榄色或棕色黄色变化。","call":"小潜鸭并不十分鸣叫，尤其与弄鸭相比。雌鸟会发出类似物种名的尖锐叫声，雄鸟在求偶时会发出微弱的哨声。","habits":"小潜鸭主要栖息于内陆湖泊和沼泽，冬季迁徙至中美洲和加勒比地区。它们通过筛选底部泥沙觅食，主要以软体动物、种子和其他水生植物为食，冬季时也会食用甲壳类动物、昆虫幼虫和小鱼。","breeding":"小潜鸭在5月开始繁殖，通常在6月筑巢，巢位于靠近水源的地面，通常藏匿于茂密植被中，如芦苇和香蒲。雌鸟独自孵化约9至11枚卵，孵化期约为3周。幼鸭在孵化后45至50天离巢。","identification":"小潜鸭与斑背潜鸭相似，但可以通过头部形状、喙宽度和翼条纹的差异来区分。小潜鸭的头部后部有小突起，喙更窄，翼条纹仅延伸到次级飞羽，而斑背潜鸭的翼条纹会延伸到初级飞羽。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美洲，包括美国阿拉斯加州西南部大陆至加利福尼亚州，加拿大魁北克省中西部和明尼苏达州西部。冬季南迁至中美洲和加勒比地区，包括哥伦比亚北部，以及偶尔到达厄瓜多尔、委内瑞拉和特立尼达。","other":"自1980年代中期以来，小潜鸭的数量持续下降，原因不明。"},{"name":"小绒鸭","english_name":"Steller's Eider","scientific_name":"Polysticta stelleri","overview":"小绒鸭（英文名：Steller's Eider，学名：Polysticta stelleri），是雁形目鸭科小绒鸭属的鸟类。俗名: 绒鸭，最小的海鸭之一，具有独特的北极生态习性。最初由Pallas在1769年以Anas stelleri命名，其发现者为Georg Wilhelm Steller。小绒鸭主要分布在北极圈，繁殖于俄罗斯及阿拉斯加的北极苔原地带，冬季迁徙至北欧和太平洋沿岸，包括日本至阿拉斯加。在北美的主要繁殖区为阿拉斯加巴罗附近的北极平原，是当地最常见的繁殖鸭种。","appearance":"小绒鸭体型紧凑，长43-48厘米，重约690-1010克。雄鸟具鲜明的黑白配色，头部白色，绿色眼周和前额，黑色斑点环绕眼睛，胸部呈肉桂色，翼下有蓝紫色与白色相间的羽片。雌鸟和幼鸟主要为红棕色，雌鸟头部略显淡红棕色，有较淡的眼环，翼下与雄鸟相似。幼鸟颜色较浅，更为红棕色，有斑驳的下腹部。雄鸟的替代羽衣在春季和夏季展示，雌鸟则保持较为一致的外观。","call":"雄鸟发出低沉的混杂咆哮声，雌鸟则发出类似'qua-haaa'的叫声。在飞行时，其羽毛会产生机械哨音。","habits":"小绒鸭栖息于北极苔原的淡水区，冬季则转向沿海水域，主要在白令海南部和北太平洋活动，但不会南迁至阿留申群岛以南。它们以群居方式生活，尾巴常上翘。饮食以无脊椎动物为主，如藤壶、蛤蜊、贻贝等，也会食用水生昆虫、蠕虫和小型鱼类。","breeding":"小绒鸭在淡水池塘筑巢繁殖，偏好岩石或草木隐蔽处。雌鸟产卵1-10枚，平均5枚，蛋壳颜色多样，由雌鸟孵化25-30天。幼鸟出生后即随母鸟前往海边，学会自行觅食。孵化后约56天，幼鸟开始学习飞行。","identification":"雄性小绒鸭的黑白羽色和橄榄绿眼周非常独特，易于识别。雌鸟与雌性普通秋沙鸭和雌鸟潜鸭（Melanitta spp.）相似，但可通过头部锈色和全身紫黑色、深色羽轴的特征加以区分。","protection":"IUCN：VU（易危）","distribution":"繁殖于北美和欧亚的西伯利亚西北部、东北部（从Yamal半岛至楚科奇半岛）和北极平原沿海，以及阿拉斯加北部。非繁殖期分布至堪察加半岛、千岛群岛和阿留申群岛（俄罗斯东南部），以及科拉半岛、巴伦支海和白海（俄罗斯西北部），以及波罗的海。","other":"由于繁殖范围的收缩，小绒鸭的阿拉斯加种群在1997年被IUCN列为易危物种。在俄罗斯和美国受到保护，欧盟和美国鱼类和野生动物管理局正在实施恢复计划。"},{"name":"白眶绒鸭","english_name":"Spectacled Eider","scientific_name":"Somateria fischeri","appearance":"白眶绒鸭雄鸭体长52.8厘米，雌鸭49.8厘米。雄鸟具橄榄绿头部，白色眼圈，暗色胸部，橙色喙，颈部及下颏烟灰色。雌鸟全身呈棕褐色，眼周有淡色眼圈，喙色较暗。幼鸟和雌鸟相似，但眼圈颜色和纹理有别，成鸟后差异更为明显。所有个体都有黄色脚蹼。","call":"雄鸭发出类似鸽子的咕咕声或'kor－er－kor'声，偶尔发出呻吟声。雌鸟则发出类似鹅鸭的声音。冬季较为沉默。","habits":"白眶绒鸭栖息于北极海沿岸，全年以无脊椎动物为食，如软体动物、蠕虫和甲壳类。夏季在大陆架边缘的浅水区觅食，冬季则在白令海的无冰海域集群。飞行能力强，能长时间潜水。","breeding":"繁殖期于夏末开始，雌鸭在岛屿上筑巢，通常利用树枝、叶片、草类和海藻作为巢底，内衬绒羽。一窝产卵5-9枚，平均5枚，卵色多样。孵化期为21-28天，由雌鸭单独承担。幼鸭出生后不久即随母鸭下水觅食。","identification":"与其他绒鸭物种相比，白眶绒鸭的独特之处在于其面部羽毛呈现鲜明的几何图案，尤其是围绕眼睛的大块白色斑纹。雄鸟的蓝灰色喙和雌鸟的亮橙色喙也是辨识要点。","protection":"IUCN：NT（近危）","distribution":"繁殖于阿拉斯加和俄罗斯东北部，包括莱纳三角洲至楚科奇半岛；阿拉斯加州尤肯三角洲和北极沿海平原。非繁殖期分布于白令海北部的无冰海域，介于圣劳伦斯岛和圣马修岛之间。","other":"由于气候变迁和潜在的油气开发威胁，白眶绒鸭的未来生存面临挑战。"},{"name":"王绒鸭","english_name":"King Eider","scientific_name":"Somateria spectabilis","overview":"王绒鸭（英文名：King Eider，学名：Somateria spectabilis），是雁形目鸭科绒鸭属的鸟类。大型海鸭，适应极端北极环境，体形圆润，羽毛丰盈。雄鸟在繁殖季节展现出醒目的黑白羽衣，头部装饰着蓝、绿、橙色的独特图案，雌鸟则呈现柔和的棕褐色。分布于北美、欧亚北极沿岸，从格陵兰至俄罗斯东北部，至阿拉斯加、加拿大北极地带。","appearance":"王绒鸭身长53-60厘米，翼展可达94厘米。雄鸟拥有独特的婚礼帽状头部装饰，由浅灰色、蓝色、绿色和红色构成，面部覆盖着绚丽的面具，橙红色的喙带有长方形的覆头面板。身体后部三分之二为黑色，与白色的翕、喉咙及胸部形成鲜明对比，背部羽毛显著。雌鸟为一致的棕褐色，带有较深的斑纹，下体羽毛为棕色和白色混合。","call":"雄鸟的叫声为颤抖的鸽子般的咕咕声，常被转录为croo-croo-croo或hoo-hoo-hooo。雌鸟发出一系列低沉的咯咯声、哼哼声和咆哮声。","habits":"王绒鸭是最大的海鸭之一，具有迁徙习性。它们主要在极北地区繁殖，越冬南至法国、新英格兰和阿留申群岛。以海底的贻贝、贝类、小鱼、甲壳类、鱿鱼和海胆为食，善于潜水至深达数十米的水域。冬季饮食转向藻类和海洋植物。","breeding":"繁殖期在晚夏，于北极岛屿上筑巢，巢穴常隐藏于岩石或草木之中。雌鸟每次产蛋3至6枚，孵化期21至24天，由雌鸟独自承担。孵化后，幼鸭跟随雌鸟到海边觅食，约56天后幼鸭学会飞行，随后迁往白令海和阿拉斯加海湾过冬。","identification":"王绒鸭雄鸟与雌鸟在外观上有明显区别，雄鸟头部的多彩装饰和雌鸟的棕褐色斑纹帮助辨识。与同类相比，王绒鸭的体型较大，头部更为圆润。","protection":"IUCN：LC（无危）","distribution":"繁殖于格陵兰、斯瓦尔巴、俄罗斯东北部、阿拉斯加、加拿大北极地带；越冬分布至堪察加半岛、阿留申群岛、纽芬兰、格陵兰南部、冰岛、挪威北部。","other":"王绒鸭在北极地区是重要的食物来源之一，特别是在春季，成为当地社区新鲜肉食的重要组成部分。"},{"name":"欧绒鸭","english_name":"Common Eider","scientific_name":"Somateria mollissima","overview":"欧绒鸭（英文名：Common Eider，学名：Somateria mollissima），是雁形目鸭科绒鸭属的鸟类。大型海鸭，体长50-71厘米，广泛分布于欧洲北部、北美北部和东亚的海岸线。在北极和温带北部地区繁殖，冬季向南迁徙至温带海域形成大群。该物种能够以高达113公里/小时的速度飞行。","appearance":"欧绒鸭体型庞大，体长50-71.1厘米，翼展95-98厘米，体重可达2.2千克。雄鸟羽毛黑白分明，头部黑色，颈部带有淡绿色斑块，雌鸟则为温暖的棕色，带有密集的黑色条纹。幼年个体的雌雄差异不大，雌鸟与麻鸭相似，但体形更大。","call":"雄性欧绒鸭发出类似鸽子的咕咕声或kor－er－kor声音，有时会发出呻吟声；雌鸟则发出类似鹅鸭的声音，冬季通常较为沉默。","habits":"欧绒鸭主要栖息于沿海岛屿，繁殖季节结束后，它们会聚集在近海区域，以无脊椎动物为食，如软体动物、蠕虫和甲壳类动物。它们会潜入10-18米深的水下捕食，利用翅膀游泳，然后直线飞出水面。","breeding":"雌性欧绒鸭用枝叶、青草和海藻筑巢，并用绒毛铺垫，巢位于岩石或植被遮蔽处。繁殖期一般在夏季，雌鸟产卵1-10枚，平均5枚，孵化期为21-28天。孵化后，幼雏由雌鸟带领，56天后便能飞行。","identification":"雄性欧绒鸭与雌鸟和幼年个体有明显区别，主要通过羽毛颜色和头部形状辨识。与其他海鸭相比，欧绒鸭体型最大，可通过其独特的轮廓和色彩模式进行区分。","protection":"IUCN：NT（近危）","distribution":"繁殖区主要分布在格陵兰岛、冰岛、法罗群岛、西北欧洲至俄罗斯楚科奇半岛、阿拉斯加至加拿大北极地区和美国马萨诸塞州（北大西洋）。非繁殖区扩展至法国、俄罗斯东南部的堪察加半岛、阿留申群岛和纽约的长岛。","other":"欧绒鸭在英国法恩群岛有一著名群体，受到圣库特伯特的保护，该群体约有1000对繁殖。"},{"name":"丑鸭","english_name":"Harlequin Duck","scientific_name":"Histrionicus histrionicus","overview":"丑鸭（英文名：Harlequin Duck，学名：Histrionicus histrionicus），是雁形目鸭科丑鸭属的鸟类。别称包括山地鸭、白眼潜水鸭等。小而色彩斑斓的潜水鸭，以近湍急水流和尖锐岩石的危险生活方式著称。雄鸟拥有醒目的繁殖羽色，雌鸟则呈暗棕色，脸部带有小白斑。分布于北美西部、东部亚洲和冰岛，夏季常在岩石溪流中成对出现，冬季聚集在海岸边。","appearance":"雄性丑鸭拥有引人注目的繁殖羽色，头部和颈部呈深蓝灰色，脸部有白色新月形图案，冠部有黑色条纹，两侧有栗色斑点，胸部有白色条纹。身体大部分为较浅的蓝灰色，侧翼为栗色。雌鸟则为棕色，头部有三个白色斑块，下腹有褐色斑点。成年雄鸟的总长度为34-46厘米，雌鸟为33-42厘米，雄鸟的平均体重约为650克，雌鸟约为575克。","call":"鸣叫特征为可爱的高音尖叫，与多数鸭类的叫声截然不同。","habits":"丑鸭偏好清澈、湍急的河流和溪流，能在激流中迅速移动，夏季繁殖期间栖息于此，冬季则迁移到北美的海岸线上，占据岩石海岸的潮间带，主要以昆虫、鱼类和水生无脊椎动物为食。","breeding":"繁殖期在夏季，雌鸟单独筑巢孵化，巢多位于隐蔽的悬崖平台、空心树或树桩上。每窝产卵5-7枚，孵化期为27至30天。幼鸟出生后不久就能自行觅食，约5-6周后即可飞行。","identification":"雄性丑鸭的繁殖羽色极为独特，与雌鸟形成鲜明对比。雌鸟与海番鸭的雌鸟相似，但B,210体型较小，喙部较小。幼鸟和未成熟的个体与雌鸟相似，但脚部偏黄，而非灰色。","protection":"IUCN：LC（无危）。在加拿大东部被列为濒危物种，受到石油泄漏、栖息地破坏和过度猎杀的影响。在中国，被列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","distribution":"繁殖于北美、东北亚的西伯利亚东北部、楚科奇、堪察加半岛等地，以及日本、阿留申群岛、阿拉斯加、加拿大、格陵兰南部和冰岛。冬季迁徙至太平洋中西部、中东部北部和大西洋中西部北部海岸线。","other":"丑鸭能够适应恶劣环境，逆水行进，攀登陡峭山坡上的滑石。冬季在多岩石的港湾越冬。飞行快速而低，求偶期雄鸟会发出高哨音，雌鸟则发出粗短叫声。"},{"name":"拉布拉多鸭","english_name":"Labrador Duck","scientific_name":"Camptorhynchus labradorius","overview":"拉布拉多鸭（英文名：Labrador Duck，学名：Camptorhynchus labradorius），是雁形目鸭科拉布拉多鸭属的鸟类。具有独特的黑白斑驳外观。北美首个已知因哥伦布大交换而灭绝的特有种，最后一次确切的目击记录是在1878年的纽约州埃尔米拉。这种鸭子在欧洲人到来之前就极为罕见，现存关于它的信息有限，但对其栖息地、特征、饮食习惯及灭绝原因有一定的了解。全球博物馆中保存了55个标本。","appearance":"雌性拉布拉多鸭呈灰色调，虽图案不明显，但类似海鸭。雄鸟的羽毛为鲜明的黑白相间，翅膀几乎全白，仅主翼羽为黑色。头部椭圆，眼睛小而圆，喙长且扁平，尖端宽大，内部有多数齿状突起。身体短而扁平，脚短而强壮，位置靠后。羽毛细小，尾巴短且圆。雄鸟的喉管类似于海鸭，但在前端有扩张，管中段有两个膨大部分，而非海鸭的一个。其骨质气囊不对称，突出于左侧，这与海鸭不同，更接近斑头海番鸭和山鸭。喙软而特殊，可能用于在泥沙中探食。","habits":"拉布拉多鸭为迁徙性鸟类，冬季栖息在美国东北部的新泽西州和新英格兰沿海，偏好沙质海岸、避风港湾、港口和入海口。夏季繁殖于拉布拉多和魁北克北部。它曾被目击在圣劳伦斯湾的岛屿上筑巢。这种鸭子以小型软体动物为食，渔民报告称曾在以贻贝为饵的渔线上捕获过它们。喙部高度特化，适应了在浅水区觅食。","breeding":"繁殖生物学知之甚少，有报道称在拉布拉多地区观察到巢穴。雄鸭的求偶行为未知，但其喉管结构暗示可能有复杂的鸣叫。","identification":"与海鸭和斑头海番鸭相比，拉布拉多鸭最显著的特征是其黑白斑驳的羽毛和特殊的喙部构造。雄鸟与雌鸟的色彩差异明显，雄鸟为黑白相间，雌鸟为灰褐色。与其他海鸭相比，它的喙更为柔软，有更多齿状突起。","protection":"IUCN：EX（灭绝）","distribution":"繁殖于加拿大拉布拉多和魁北克北部，冬季迁徙至美国东北部，从加拿大拉布拉多至切萨皮克湾一带。","other":"拉布拉多鸭的灭绝时间约为19世纪晚期，具体原因尚不明朗，可能与人类活动导致的生态环境改变有关，包括过度猎杀、蛋的采集、羽毛贸易的影响，以及其主要食物来源——软体动物的减少。"},{"name":"斑头海番鸭","english_name":"Surf Scoter","scientific_name":"Melanitta perspicillata","appearance":"斑头海番鸭体型中等，雄鸭全长约48厘米，重约1050克，雌鸭略小，约44厘米，重约900克。雄鸭全身羽毛丝绒般黑，具白色前额和颈背大斑块；雌鸭呈深褐色，头顶较暗，脸颊有棕黑色羽毛，两侧有白色斑纹。雄鸭具大型橙白相间嘴，嘴基有黑色斑痕，雌鸭嘴为蓝黑色。幼鸟似雌鸭，但更淡更棕色。","call":"斑头海番鸭通常沉默，其鸣叫声较为罕见，包括雄鸟求偶时的咕噜声和爆炸性的\"puk-puk\"叫声，以及雌鸟守护幼鸟时类似乌鸦的叫声。受惊时，会发出介于\"cluck\"和\"tok\"之间的\"guk\"声。","habits":"斑头海番鸭繁殖于北美北部森林湖泊，冬季迁徙至太平洋和大西洋沿岸。栖息于近岸海域，偏好浅水区域，常在湖泊和池塘附近筑巢。潜水捕鱼方式独特，常跳跃前进，翅膀半开，颈部伸直。以无脊椎动物和甲壳类为主食，冬季转向海洋水域，捕食贻贝、蛤蜊、鲱鱼和蟹类。","breeding":"繁殖期在5月至6月初开始，雌鸭在北方森林或苔原的浅水湖泊附近筑巢，巢隐蔽，用草和羽毛内衬。每窝产5至7枚白色卵，孵化期27至29天。雏鸭出生即可下水觅食，55天后才能飞行。雌鸟在雏鸭尚不能飞行时便离开，前往近海换羽。","identification":"斑头海番鸭通过白色头斑和独特的多彩嘴型与黑海番鸭和白翅黑海番鸭区分。雌鸟和幼鸟可通过扁平的头部轮廓和较厚的嘴型与其它海番鸭种类区别开来。在飞行中，它是唯一翅膀全黑的海番鸭。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国阿拉斯加州至加拿大亚北极东部至拉布拉多；冬季迁徙至阿留申群岛东至墨西哥下加利福尼亚州（太平洋北部）和爱德华王子群岛至北卡罗来纳州（大西洋中西部北部）。","other":"斑头海番鸭在冬季和春季会调整其饮食，根据食物的相对盈利性选择进食地点，显示了一定程度的适应性。"},{"name":"丝绒海番鸭","english_name":"Velvet Scoter","scientific_name":"Melanitta fusca","overview":"丝绒海番鸭（英文名：Velvet Scoter，学名：Melanitta fusca），是雁形目鸭科海番鸭属的鸟类。俗名: 海番鸭、奇嘴鸭，直译: 绒海番鸭，以及土耳其和格鲁吉亚有小而孤立的繁殖群体。","appearance":"体型庞大，长度在51至58厘米之间，翼展86至99厘米，雄鸟体重1173至2104克，雌鸟1140至1895克。雄鸟呈亮黑色，非繁殖季节较暗淡，两颊有白色标记，翼下有显著的白色斑块。喙色从黄色到黄橙色，基部颜色延伸至根部，尖端粉色或橙色，顶部和切割边缘黑色，常有两侧黑色线条。雌鸟和幼鸟为中至深棕色，脸侧有灰色斑点，喙色为暗橄榄色或黑色，虹膜为棕色。","call":"通常被认为相当沉默，但在求偶时，雄鸟会发出‘vak-vak’的声音，雌鸟在早晨飞行展示时会发出‘braaa-braaa-braaa’或‘kraa-ah kraa-ah kraa’的叫声。","habits":"繁殖于北方森林和北极苔原的小型淡水体周围，有时深入内陆，偶尔沿波罗的海林木岸线。冬季主要在海岸水域度过，通常在浅水区，也会在迁徙期间出现在内陆大湖。以潜水为主要觅食方式，食物主要是软体动物和甲壳类动物。","breeding":"繁殖季节始于五月或六月，季节性一夫一妻制，可能在巢址周围保卫小领地。在单对或松散群落中繁殖，有时与海鸥和燕鸥的群体相关联。巢建于地面植被中，靠近开放水域，通常为淡水湖泊，有时在海洋环境中，距离可达2至3公里。每窝通常产7至9枚蛋，由雌鸟单独孵化，孵化期为26至29天。雏鸟在大约50至55天后离巢。","identification":"与其他海番鸭相比，雄性丝绒海番鸭具有独特的白色眼下方标记和翼下的白色斑块。白翅黑海番鸭和斑脸海番鸭（以前被归类为此物种的亚种）主要通过喙的形状和颜色进行区分。","protection":"IUCN：VU（易危）","distribution":"繁殖于欧亚大陆北部，从挪威到西伯利亚中部的叶尼塞河，以及哈萨克斯坦东北部，土耳其和格鲁吉亚。越冬于南至英国的温带区，黑海和里海。少量个体达到法国和西班牙北部。","other":"在高加索地区的格鲁吉亚Tabatskuri湖上，发现了丝绒海番鸭的最后一个繁殖种群，2017-2018年研究发现有25-35对鸟，但实际繁殖数量较少。"},{"name":"白翅黑海番鸭","english_name":"White-winged Scoter","scientific_name":"Melanitta deglandi","overview":"白翅黑海番鸭（英文名：White-winged Scoter，学名：Melanitta deglandi），是雁形目鸭科海番鸭属的鸟类。以独特的翼上白色斑块而著称，全身暗巧克力棕色，雄鸟比雌鸟更暗，具有眼下的小白标记、黑色喙上的暗色肿块和粉红色喙尖。雌鸟头部有两块圆形白色斑点。广泛分布于北美北部森林地区的淡水湖泊和湿地，冬季主要在太平洋和大西洋沿岸过冬。","appearance":"雄鸟全长53-58厘米，体重约1,360-1,780克；雌鸟稍小，全长48.3-54.9厘米，重950-1,500克。雄鸟全黑，眼周有白色标记，翼上有明显的白色斑块，喙橙红，基部有黑色肿块。雌鸟和幼鸟呈深棕色，腹部较淡，头侧有白色斑块，喙黑色无肿块。第二年雄鸟相似，但眼周白色标记不明显，腹部棕色，喙正发育成成年形态。","call":"关于鸣叫特征的详细描述缺失。","habits":"它们栖息于北美的淡水湖泊和湿地，冬季移居至沿海水域和大型淡水湖。飞行迅速，常低空飞行成行，以软体动物和甲壳类为食。偏好开阔的海岸环境，如海湾和入口处，食物丰富。","breeding":"白翅黑海番鸭通常在淡水湖泊或河流附近的巢穴中繁殖，雌鸟负责筑巢，雄鸟在雌鸟开始产卵后不久离开。巢隐藏在密集的灌木丛下。幼鸟存活率低，多数死亡发生在生命的前几周。","identification":"与丝绒海番鸭和斑脸海番鸭相比，白翅黑海番鸭的侧面和喙的颜色和形状不同，翼上的白色斑块更为显著。雄鸟的侧面羽毛颜色和喙的形状与雌鸟及幼鸟明显不同。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国阿拉斯加州亚北极地区西部至詹姆斯湾(加拿大中东部)。非繁殖季节分布于阿留申群岛至加利福尼亚州(北美太平洋海岸东部)，圣劳伦斯湾至新泽西州(北美大西洋西部)。","other":"白翅黑海番鸭对石油泄漏和冬季的深水捕鱼网捕获非常脆弱，可能受到大规模海洋环境变化的影响。尽管不是猎人特别追求的目标，每年仍有不少数量被射杀，尤其是在大西洋沿岸。"},{"name":"普通海番鸭","english_name":"Common Scoter","scientific_name":"Melanitta nigra","overview":"普通海番鸭（英文名：Common Scoter，学名：Melanitta nigra），是雁形目鸭科海番鸭属的鸟类。大型海鸭，身长43-54厘米，广泛分布于远北欧及帕莱阿尔特地区东至奥列尼奥克河。雄鸟全身深黑色，雌鸟呈灰褐色，以其笨重的体态和硕大的喙为显著特征。","appearance":"雄鸟个体通体黑色，喙部带有黄色斑块，喙基部有明显的突起；雌鸟个体为暗褐色，脸颊处有淡色斑纹，喙部颜色较暗，有时带黄绿色条纹。幼鸟类似雌鸟，但下体颜色更浅，头部下半部也偏浅色。雄鸟幼鸟保持棕色的翼覆羽、飞羽和下翼覆羽直至首次换羽，而雌鸟幼鸟则保留幼鸟时期的翼羽直到次年七月。","call":"通常较为沉默，但在适宜天气条件下，雄鸟能发出尖细的哨声，雌鸟则有粗糙的嘶哑叫声。","habits":"繁殖于淡水池塘、小湖或缓慢流动的河流，冬季和换羽期主要栖息于近海海域，偏好水深小于20米的浅水区。迁徙时会访问淡水湿地。以软体动物为主食，偶尔摄取其他水生无脊椎动物和小型鱼类。","breeding":"繁殖季节始于五月到六月，一窝产6-8枚蛋，孵化期约27-31天，由雌鸟独自孵化。雏鸟由雌鸟单独抚育，45-50天后离巢。性成熟年龄为2-3岁。","identification":"与黑海番鸭区别在于喙部形状和图案，以及飞行羽下翼的银灰色内网与黑色下翼覆羽的对比。","protection":"IUCN：LC（无危）","distribution":"繁殖于格陵兰东南部、冰岛、苏格兰北部至斯堪的纳维亚，西至俄罗斯西伯利亚的奥列尼奥克河。非繁殖期分布于波罗的海和北大西洋沿岸，南至非洲西北部。","other":"数量可能正在减少，尤其是在某些地区。受到商业捕鱼对贝类资源的影响，以及海洋风力发电场开发的潜在威胁。"},{"name":"黑海番鸭","english_name":"Black Scoter","scientific_name":"Melanitta americana","overview":"黑海番鸭（英文名：Black Scoter，学名：Melanitta americana），是雁形目鸭科海番鸭属的鸟类。俗名: 美洲黑凫，矮胖型深色海鸭，雄鸟全身乌黑，嘴基处有醒目的黄色肉瘤；雌鸟烟灰褐色，头顶及枕部黑色，脸部和前颈皮灰黄色。属于潜水鸭类，善于游泳和潜水，陆地上行走笨拙。繁殖于北极苔原和亚北极开阔地带的淡水湖泊、水塘与河流中，非繁殖季栖息于沿海海面、海湾与河口等咸水水域。","appearance":"雄性黑海番鸭通体黑色，嘴基有显眼的黄色肿块；雌鸟和幼鸟呈烟灰褐色，头部顶部和枕部黑色，脸颊和前颈皮灰黄色，与头顶形成鲜明对比。飞行时，两翼接近黑色，翼下羽深色。成年雄鸟体型较大，平均长度49厘米，体重约1100克；成年雌鸟平均长度45厘米，体重约980克。","call":"黑海番鸭的叫声柔和，雄鸟的求偶叫声为低沉的哨声，雌鸟的叫声为低沉的吼声。","habits":"黑海番鸭栖息于北极苔原和亚北极开阔地带的淡水湖泊、水塘与河流中，非繁殖季节主要栖息于沿海海面、海湾与河口等咸水水域。性喜集群，几乎全年成群活动。潜水能力优秀，每次能在水下潜行30秒以上。春季迁徙至繁殖地，秋季迁回越冬地。","breeding":"黑海番鸭通常2岁时性成熟，营巢于北极和亚北极苔原及苔原森林带，巢置于离湖泊、水塘、河流等淡水水域不远的地上草丛或灌木丛中。每窝产卵6至10枚，孵化期27至28天。","identification":"雄性黑海番鸭与其它海鸭种类的区别在于其全身黑色且嘴基有黄色肉瘤，雌鸟则通过其烟灰褐色的羽毛、黑色的头顶和鲜明的脸颊对比来辨识。","protection":"IUCN：NT（近危）","distribution":"繁殖于欧亚大陆的Yana River至堪察加半岛（西伯利亚东部），美国阿拉斯加州东部至加拿大育空地区西北部，Northwest Territories Nunavut东部和西南部至加拿大纽芬兰（中部至加拿大东部）。非繁殖季节分布至日本中部（太平洋西部北部海岸线），阿留申群岛，太平洋东部北部海岸线至美国加利福尼亚州中部，加拿大纽芬兰至美国佛罗里达北部（大西洋西部北部海岸线）。","other":"黑海番鸭的食物主要为水生昆虫、甲壳类、软体动物等动物性食物，也吃眼子菜和其他水生植物的根、叶等植物性食物。"},{"name":"斑脸海番鸭","english_name":"Stejneger's Scoter","scientific_name":"Melanitta stejnegeri","overview":"斑脸海番鸭（英文名：Stejneger's Scoter，学名：Melanitta stejnegeri），是雁形目鸭科海番鸭属的大型海鸭。其体型硕大，雄鸟具独特的白色翼斑，眼下方有小白斑，嘴上有深色肉瘤，嘴端橙红；雌鸟为深巧克力棕色，脸部有两处椭圆形的白色斑纹。分布于亚洲东北部，自叶尼塞河盆地东至堪察加半岛，南至中国北部，冬季向南迁徙至温带区域。","appearance":"雄性斑脸海番鸭长51-58厘米，体重1020-1437克；雌鸟略轻，约957克。翼展86-99厘米。雄鸟全身黑色光泽，非繁殖季节略显暗淡，腹部有斑驳的浅色斑点。雌鸟介于中至深棕色之间，眼周和嘴边有灰棕色斑块，嘴呈暗橄榄黑或暗灰色，脚部暗红色，虹膜棕色。幼鸟外观似雌鸟，胸部较浅色，头部标记更白更大；嘴在早春可能开始着色，但缺乏成年鸟的基部肿胀，直至第二年秋季才换上成羽。","call":"通常沉默，但在求偶展示时雄鸟会发出吹哨般的‘fee-er’声，雌鸟则发出低沉的鼻音‘aah-er’，而雌鸟的叫声为粗哑的‘kraa-ah kraa-ah kraa’。","habits":"斑脸海番鸭在繁殖季节栖息于北极苔原和北方森林的小淡水体附近，有时深入内陆，而在哈萨克斯坦可达海拔1,760-2,300米。冬季主要栖息于海上，偏好浅水区，偶尔在迁徙季于内陆水域被记录。","breeding":"繁殖季节通常在5月至6月，季节性一夫一妻制，雄雌成对或松散群居于岛屿或与鸥和燕鸥群落相邻的木本地带。巢建于地面植被中的浅凹处，由周围植物物质和绒羽构成。每次繁殖产卵6-9枚，蛋壳呈奶油色或黄白色，大小为55.4-72.5毫米×35.7-49毫米。孵化期未知，仅由雌鸟承担；雏鸟上身深棕色，下身至脸颊、颈侧和下喉均为白色，约在50-55天后离巢。","identification":"与白翅黑海番鸭相比，斑脸海番鸭雄鸟的头部结构更加棱角分明，嘴部肿胀更为明显，嘴基部的肿块更大，颜色更深，上部更偏橙黄色，下缘红色或紫红色。雌鸟和幼鸟的辨识较为困难，但其嘴基部肿胀更为突出。","protection":"IUCN：LC（无危）","distribution":"繁殖于亚洲远东北部，包括俄罗斯的叶尼塞河盆地以东至堪察加半岛，哈萨克斯坦东北部和蒙古北部，冬季迁徙至日本、朝鲜半岛东部和中国东部沿海。在欧洲为稀有迷鸟，记录于法国、芬兰、波兰、冰岛、爱尔兰、挪威和苏格兰。","other":"斑脸海番鸭的全球种群估计在40万至70万之间，可能正在减少。在哈萨克斯坦的繁殖地数量下降，而阿拉斯加埃克森瓦尔迪兹油轮灾难长期影响了该物种的生存。"},{"name":"长尾鸭","english_name":"Long-tailed Duck","scientific_name":"Clangula hyemalis","overview":"长尾鸭（英文名：Long-tailed Duck，学名：Clangula hyemalis），是雁形目鸭科长尾鸭属的鸟类。中等体型的海鸭，繁殖于北极的苔原和泰加林地区，冬季迁徙至北大西洋和北太平洋的海岸线。本属唯一物种。这种独特的鸭类，以其长而尖的尾羽和随季节变化的羽毛色彩闻名。","appearance":"长尾鸭的成年个体具有白色的腹部，雄鸟的羽毛复杂多变。在冬季，雄鸟拥有黑白相间的头部，颈部有明显的暗色斑块，胸部为深色，身体大部分为白色，尾羽长达10至15厘米，喙为暗灰色并带有粉红色环带。夏季时，雄鸟的头部、颈部和背部变为深色，脸颊处有一白色斑块。雌鸟背部呈棕色，尾羽相对短小，冬季头部和颈部为白色，带有深色冠羽；夏季头部转为深色。幼鸟外观类似雌鸟，但在秋季时脸颊斑块较轻且不那么明显。","call":"雄性长尾鸭叫声独特，发出悦耳的yodeling声，类似“ow, ow, owal-ow”。","habits":"长尾鸭栖息于夏季的苔原池塘和湿地，冬季则出现在沿海水域和大湖，偶尔在淡水区域发现。它们是群居性鸟类，冬季和迁徙期间会形成大型群体。通过潜水捕食，主要以软体动物、甲壳类和小型鱼类为食，能够潜入深达60米的水域。飞行速度快，平均时速可达80公里。","breeding":"繁殖期在5月至7月间，巢通常建在靠近水体的岸边植被中，使用植物材料和雌鸟的绒羽衬垫。一窝产卵数为5至9枚，孵化期约为23至25天。幼鸟在35至40天后能飞行。","identification":"雄性长尾鸭与针尾鸭的区别在于后者灰暗的两侧和白色的胸部，而长尾鸭雄鸟则有银灰色的两侧和棕色的胸部。雌鸟和幼鸟可能与小绒鸭或丑鸭混淆，但长尾鸭具有亮色的腹部和两侧，丑鸭的腹部有棕色条纹和两侧。此外，长尾鸭的尾羽特征显著，是识别的关键。","protection":"IUCN：VU（易危）","distribution":"繁殖于格陵兰沿海、冰岛、芬兰、挪威、俄罗斯北部和西伯利亚至楚科奇半岛，以及北美阿拉斯加和加拿大北部。冬季分布至日本北部、阿留申群岛至加拿大西南部的北太平洋，以及大西洋中西部和中东部北部。","other":"长尾鸭在北美的某些地区仍被猎杀。在波罗的海冬季聚集的数量显著下降，部分原因是容易被困在渔网中。"},{"name":"白枕鹊鸭","english_name":"Bufflehead","scientific_name":"Bucephala albeola","overview":"白枕鹊鸭（英文名：Bufflehead，学名：Bucephala albeola），是雁形目鸭科鹊鸭属的鸟类。北美洲体型最小的潜鸭，因雄鸟枕部具醒目的白色三角斑而俗称“白枕”。繁殖期局限于北美洲的针叶林与山杨林湿地，冬季迁至沿海及内陆浅水区。其体型极小，可充分利用北扑翅䴕钻凿的小树洞营巢，形成独特的生态位。自20世纪50年代以来，种群数量显著增长。","appearance":"体小而紧凑，雄鸟繁殖羽头黑色带绿紫虹彩，枕部具大白斑；背黑，下体白；翼上具显著白块。雌鸟与亚成雄鸟灰褐色，具白色面斑；雄鸟蚀羽似雌鸟但翼上白斑更大。喙短，灰色；跗跖雄性粉或淡肉色，雌性暗粉。雌雄大小差异明显：雄鸟体长35–40厘米，体重约450克；雌鸟32–35厘米，约325克。","call":"为属内最少鸣叫的种类。雄鸟求偶时有沙哑的咯咯或刺耳颤音；雌鸟招雏时发出低哑“cuc-cuc-cuc”声，警戒时则更高亢。雌鸟夏季寻巢飞行时发出连续的“cuk-cuk-cuk”。","habits":"繁殖期栖息于永久性的淡水小湖或池塘，周围需有山杨、白杨等供啄木鸟筑洞的树丛；冬季多见于沿海港湾、河口及内陆湖泊、水库的浅水区。完全迁徙；夜间迁飞，秋季10月下旬开始，春季2–4月返回。潜水觅食，主食水生昆虫、甲壳类、软体动物及少量植物种子，咸水区以虾、蟹、贝为主。","breeding":"一夫一妻制，常连续多年维持配偶。雌鸟2岁首次繁殖，4月底至5月初产卵，每窝6–11枚；卵乳白或淡橄榄色，重约37克。孵化期30–33天，仅雌鸟负责。雏鸟早成性，24–36小时后离巢，50–55日龄可飞。雌鸟单独育雏并保卫约0.5公顷的幼雏领域。无补巢习性。","identification":"体型明显小于同属的鹊鸭与巴氏鹊鸭；雄鸟枕部白斑大而靠后，雌鸟具白色面斑，而鹊鸭雌鸟无面斑。翼拍快，飞行中翅不啸鸣。","protection":"IUCN: LC（无危）。未列入CITES附录及中国国家重点保护名录。","distribution":"繁殖于北美洲西部和中部的针叶林及山杨林湿地，从阿拉斯加、育空至加拿大中部及不列颠哥伦比亚省，南至美国西北部内陆山区；冬季分布于太平洋与大西洋沿岸，从阿拉斯加东南部至加利福尼亚，以及新泽西至北卡罗来纳，亦见于内陆湖泊。偶见于日本、西欧等地。","other":"已知与鹊鸭、巴氏鹊鸭及棕胁秋沙鸭有极罕见的杂交记录；化石记录可追溯至更新世。"},{"name":"鹊鸭","english_name":"Common Goldeneye","scientific_name":"Bucephala clangula","overview":"鹊鸭（英文名：Common Goldeneye，学名：Bucephala clangula），是雁形目鸭科鹊鸭属的鸟类。俗名: 金眼鸭、喜鹊鸭、白脸鸭，因其金色的眼睛而得名，具有独特的黑白相间的外观。广泛分布于北美洲、欧洲和亚洲的湿地环境，包括湖泊、河流、海岸和近海区域。在中国，繁殖于东北及西北地区，越冬于华北、东南沿海及长江中下游。","appearance":"雄性鹊鸭繁殖期头部黑色，带有绿色光泽，嘴基部有圆形白色斑点，背部黑色，下体白色。雌鸟和一岁雄鸟头部巧克力棕色，体羽灰色。两性均具亮黄色眼睛。冬季雌雄羽色相似，头部和颈部暗褐色，背部灰色，腹部白色。","call":"飞行时翅膀发出特有的哨声，因此有\"哨子\"的俗称。","habits":"鹊鸭栖息于森林地带的溪流、湖泊、河流附近。它们是潜水型鸭类，主要以水生无脊椎动物为食，包括昆虫、蠕虫、甲壳类、软体动物、小鱼等。春季迁徙至繁殖地，秋季返回越冬地，迁徙时沿河流或海岸线飞行，一般贴近水面。","breeding":"繁殖期为5月至7月，通常在湖泊、河流附近的天然树洞中筑巢，偏好杨树、桦树、橡树等树洞。每窝产卵8-12枚，孵化期约为30天，由雌鸟单独承担孵化任务。雏鸟出生后第二天即可自行下水，跟随雌鸟学习游泳和潜水，约50-70天后学会飞翔。","identification":"与巴氏鹊鸭相似，但可通过头部形状、翼斑、嘴型等特征区分。雄性鹊鸭头部更为圆润，嘴较长且斜向延伸，翼斑更圆。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美洲北部、苏格兰、斯堪的纳维亚至俄罗斯远东、中国东北和西北；越冬于北美的太平洋和大西洋沿岸、中国华北、东南沿海及长江中下游。","other":"鹊鸭对环境变化较为敏感，可用于监测北极野生动物对环境扰动的影响。"},{"name":"巴氏鹊鸭","english_name":"Barrow's Goldeneye","scientific_name":"Bucephala islandica","overview":"巴氏鹊鸭（英文名：Barrow's Goldeneye，学名：Bucephala islandica），是雁形目鸭科鹊鸭属的鸟类。别名: 巴罗鹊鸭、冰洲鹊鸭、巴罗氏金眼鸭，中型海鸭，主要分布于北美西北部和冰岛的森林湖泊中，冬季会迁徙至非冰冻水域。该物种以独特的黑紫头部、白色新月状面斑和黄色或黑色的喙著称。","appearance":"巴氏鹊鸭成年雄鸟平均长49厘米，重约970克；雌鸟平均长43厘米，重约590克。雄鸟拥有深色头部，带紫光，前脸有白色新月斑；背部、翅膀和尾巴黑色，翼下有明显的白色斑点。雌鸟头部巧克力棕色，背部、翅膀和尾巴呈石板灰色，腹部和两胁白色，喙大多呈黄色。虹膜金黄色，喙色随季节和性别而异。","call":"巴氏鹊鸭相对安静，仅在繁殖季和求偶时发出低音量的尖叫、咕噜声和嘶哑声。飞行时，快速的翼拍会产生低沉的哨音。","habits":"巴氏鹊鸭栖息于北美西北部的森林湖泊和池塘，冬季迁徙至沿海受保护的水域或开放的内陆水域。它们偏好潜水觅食，主要食物包括水生昆虫、甲壳类动物和水生植物。雌鸟有回归同一繁殖地和巢位的倾向。","breeding":"繁殖期通常在春季，雌雄配对维持整个冬季，雄鸟在繁殖季节保卫领地，夏季换羽期间离开到特定的换羽地。巢建在成熟树木的空洞中，或地面上的隐蔽处。雌鸟独自孵卵，孵化期约为一个月。","identification":"与鹊鸭相比，巴氏鹊鸭雄鸟的背部更黑，面部新月斑更明显，雌鸟的喙颜色更为独特。此外，巴氏鹊鸭的头部形状较陡，颈短而圆，喙部较短且基部较圆。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于北美西北部，包括美国阿拉斯加至加拿大西部，南至美国西北部的俄勒冈州和科罗拉多州，加拿大魁北克东北部和拉布拉多西南部，以及冰岛。非繁殖期分布至美国中部加利福尼亚州和加拿大东南部。","other":"巴氏鹊鸭受1989年埃克森瓦尔迪兹石油泄漏事件严重影响，其冬候鸟栖息地受到污染，数量有所下降。"},{"name":"斑头秋沙鸭","english_name":"Smew","scientific_name":"Mergellus albellus","overview":"斑头秋沙鸭（英文名：Smew，学名：Mergellus albellus），是雁形目鸭科斑头秋沙鸭属的鸟类。俗名: 花头锯嘴鸭、鱼鸭、狗头钻、小秋沙鸭、斑头秋沙鸭、熊猫鸟、白秋沙鸭，简称: 白秋沙，以其独特的黑白羽毛和浓密的冠羽而著称。分布于欧亚大陆的亚北极区域，从斯堪的纳维亚北部延伸至俄罗斯东南部的堪察加半岛。","appearance":"雄性斑头秋沙鸭身长35-44厘米，体重540-935克，拥有引人注目的‘熊猫’外观，头部、颈部、背部及腹部主要为白色，脸部有一黑色面具，两侧胸部和胁部有细黑条纹。雌鸟和未成年个体为灰色，头部呈深锈褐色，喉部和脸颊白色，体型较小，重量约510-650克。飞行时，它们展现出鲜明的黑白对比，翼展可达55-69厘米。","call":"鸣叫相对较少，除求偶期间或警戒时发出的特殊声音外，通常保持安静。雄鸟在展示时会发出低沉而多变的机械式咔哒声，而雌鸟在激发雄鸟交配时会发出刺耳的连续咔哒声。","habits":"斑头秋沙鸭栖息于富含鱼类的湖泊、河流和池塘，偏好森林地带的淡水环境，尤其是低地的牛轭湖。迁徙时，它们会前往欧洲西部、中部、东南部，亚洲中部，日本，朝鲜半岛和中国东南部的大型湖泊、无冰河流、咸水泻湖和河口地带。","breeding":"繁殖季节始于每年的4月至5月，雌鸟独自孵化7-11枚淡黄色至奶油色的卵，孵化期为26-28天。幼雏出生后不久即可离开巢穴，大约10周后学会飞行。","identification":"雄性斑头秋沙鸭的黑白相间羽毛和独特的冠羽使其极易识别，而雌鸟和未成年个体则需通过头部的深锈褐色和白色的面部特征来区分，特别是在远处与斑背潜鸭混淆时。","protection":"IUCN：LC（无危），在中国国家重点保护野生动物名录中列为Ⅱ级（2021年2月5日更新）。","distribution":"繁殖于欧亚大陆的亚北极地区，冬季迁徙至欧洲西部、中部、东南部，亚洲中部，日本，朝鲜半岛和中国东南部。","other":"斑头秋沙鸭在迁徙途中和冬季面临一定的狩猎压力和油污污染的风险，尤其是在沿海水域聚集时。"},{"name":"棕胁秋沙鸭","english_name":"Hooded Merganser","scientific_name":"Lophodytes cucullatus","overview":"棕胁秋沙鸭（英文名：Hooded Merganser，学名：Lophodytes cucullatus），是雁形目鸭科棕胁秋沙鸭属的鸟类。仅分布于该大陆。其最显著的外部特征是雄鸟的黑白扇形头冠和红棕色侧腹，而雌鸟则呈棕色，具蓬松的头冠和部分黄色的喙。繁殖于北美东部及西北部森林地带，冬季则迁往美国南部沿海地区。该物种偏好林间湿地和小型湖泊，尤其喜爱树木茂盛的沼泽。","appearance":"棕胁秋沙鸭体长40-49厘米，翼展60-66厘米。雄鸟有黑色和白色的扇形头冠，侧面为红棕色，雌鸟则为棕色，具蓬松的头冠。两性在非繁殖季节外观相似，但雄鸟的虹膜为黄色，雌鸟为棕色。幼鸟与成年雌鸟相似，但颈和上部为灰棕色，翅膀上的白色边缘较窄。","call":"在求偶期间，雄鸟会发出类似蛙鸣的低沉叫声。","habits":"栖息于小型湖泊、池塘和河流，偏好森林环境中的淡水水域。冬季迁徙至美国南部沿海地带，避免海洋。以鱼类、水生昆虫和甲壳类动物为食，利用适应水下视觉的眼睛捕食。飞行迅速，翼拍频率高，常与同类混群。","breeding":"繁殖期为2月至6月，雌雄配对形成单偶制，雌鸟独自筑巢孵化，雄鸟在雌鸟开始孵化后离开。巢建于树洞中，离地面3至6英尺，每窝产卵7至15枚，孵化期为32至33天。幼鸟孵化后一天内即可离开巢穴，自行觅食。","identification":"与红胸秋沙鸭相比体型较小，雄鸟具独特的黑白头冠和红棕色侧腹，雌鸟则为棕色。在飞行中可通过细长的身体和快速的翼拍来辨认。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美东部，从美国西北部至加拿大南部，向南至美国德克萨斯州东部和佛罗里达北部；冬季迁徙至美国加州南部、得克萨斯州南部和佛罗里达南部。","other":"历史上曾因森林砍伐、狩猎和污染而遭受影响，目前种群稳定，部分地区可能有所增加。"},{"name":"奥克兰秋沙鸭","english_name":"New Zealand Merganser","scientific_name":"Mergus australis","overview":"奥克兰秋沙鸭（英文名：New Zealand Merganser，学名：Mergus australis），是雁形目鸭科秋沙鸭属的鸟类。又名: 奥克兰岛秋沙鸭，已灭绝的鸟类。也被称为奥克兰岛秋沙鸭，体型与红胸秋沙鸭相似。其生存范围仅限于新西兰的奥克兰群岛。","appearance":"成年雄性奥克兰秋沙鸭的头部、胸部和颈部展示出深红褐色的华丽色泽，而背部和尾巴则呈现出蓝黑色。双翼覆盖着灰色羽毛。相比之下，雌鸟个体更为小巧，胸部的长度也较短。","protection":"IUCN：EX（已灭绝）","distribution":"奥克兰秋沙鸭的分布区域严格限制在新西兰的奥克兰群岛（Auckland Is.），位于南岛（South I.）以南。"},{"name":"褐秋沙鸭","english_name":"Brazilian Merganser","scientific_name":"Mergus octosetaceus","overview":"褐秋沙鸭（英文名：Brazilian Merganser，学名：Mergus octosetaceus），是雁形目鸭科秋沙鸭属的鸟类。全球最濒危的水禽之一，也是美洲最受威胁的鸟类之一。分布局限于巴西中南部、巴拉圭东部和阿根廷东北部。栖息于清澈河流与溪流，偏好有激流和静水、被森林环绕且鱼类丰富的环境。尽管自然分布稀疏，人类活动对其栖息地的直接或间接干扰加剧了其濒危状态。","appearance":"褐秋沙鸭体长49-56厘米，拥有细长的深绿色具光泽的头部冠羽，雌鸟冠羽较短。上体呈暗灰色，胸部为浅灰色，腹部白色，飞行时可见翅膀上的白色翼镜。喙细长锯齿状，黑色，脚和腿红色。雌雄颜色相似，但雌鸟的喙和冠羽较短。幼鸭以黑白相间的喉部和胸部与成鸭相区别。","call":"通常沉默，但在特定情境下会发出吠叫般的叫声。已记录四种叫声，包括报警声、雄鸟类似狗吠的叫声、雌鸟的粗糙叫声以及联系时的柔和叫声。幼鸭则发出尖锐的叫声。","habits":"栖息于热带森林覆盖的浅水溪流、湍急河流及清澈水域。主要以鱼类为食，辅以软体动物、昆虫及其幼虫。褐秋沙鸭占据8至14公里的河流地带作为永久领土，根据适宜的筑巢和觅食条件。","breeding":"繁殖季节通常在南半球冬季，此时雨量少，水位低。筑巢于树洞、石缝或废弃的洞穴中。每年6月至7月产卵，每窝3至6枚，雏鸟在7月至8月孵化。幼鸭在9月或10月具备飞行能力。母鸭独自孵化，双亲共同参与幼鸟的照顾，直接提供食物，这种行为在鸭类中极为罕见。","identification":"是南半球唯一的秋沙鸭，与美洲鸬鹚在外观上有显著区别，后者体型更大、更暗，无头部冠羽，潜水时露出的身体部分更多。","protection":"IUCN：CR（极危）","distribution":"主要分布于南美洲巴西中南部、巴拉圭东部和阿根廷东北部，具体包括巴西的Serra da Canastra区域、Jalapão区域、Paraná河、Goiás的Paranã河以及Tocantins的Novo河。","other":"面临的主要威胁包括栖息地退化、农业扩张、采矿、森林砍伐、水坝建设以及旅游活动的干扰。"},{"name":"普通秋沙鸭","english_name":"Common Merganser","scientific_name":"Mergus merganser","overview":"普通秋沙鸭（英文名：Common Merganser，学名：Mergus merganser），是雁形目鸭科秋沙鸭属的鸟类。又称: 川秋沙鸭，体型最大之一。繁殖期雄鸟拥有深绿色头部与白色身体，雌鸟和亚成雄鸟则为锈褐色头部和灰色身体，特征性的白喉清晰可见。广泛分布于北美洲、欧洲、亚洲的森林湖泊与河流附近，耐寒性强，越冬时可见于有开阔水域的北方地区。","appearance":"大型鸭类，总长度为54-71厘米，体重可达2公斤左右。雄鸟繁殖期头部为绿色光泽的黑色，身体大部分白色，带有桃红色泽，背部和尾巴灰色，喙为红色。雌鸟和亚成雄鸟头部锈褐色，身体灰色，白色喉部界限分明，喙同样为红色。幼鸟类似雌鸟，但头部颜色较淡，头部羽毛更短，缺乏明显的图案。","call":"普通秋沙鸭的叫声通常为低沉、粗哑的嘎嘎声，但在繁殖季节，雄鸟和幼鸟会发出柔和的哨声。","habits":"栖息于河流、湖泊和大型池塘，通过潜水捕食鱼类。它们广泛分布在北美洲、欧亚大陆的森林湖泊和河流附近，冬季向南迁徙，最远可达美国南部和中国中部。耐寒，冬季可在北方有开放水域的地区越冬。在迁徙和冬季，它们形成大群，常与其它潜水鸭混群。","breeding":"繁殖期为5月至7月。雌鸟在树洞或岩隙中筑巢，每窝产卵8-13枚，孵化期为32-35天。雄鸟在雌鸟开始孵卵后不久便离开，与其他雄鸟一同换羽。雏鸟早熟，出壳后第二天即可游泳和潜水。","identification":"与红胸秋沙鸭相比，普通秋沙鸭体型更大，颈部更粗壮，喙更厚实，头部棕色，与胸部的白色界限分明，背部蓝色灰色。红胸秋沙鸭颈部较细，喙更细长，头部棕色较暗淡，与胸部灰色混合，背部棕色灰色，喉部白色斑块不明显。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括北美、欧亚大陆的森林湖泊和河流附近。非繁殖区域覆盖美国南部、中国中部等地。在中国，常见于东部和长江流域的湖泊、山区溪流和低地。","other":"普通秋沙鸭因其主要食鱼，被认为对渔业造成一定影响。"},{"name":"红胸秋沙鸭","english_name":"Red-breasted Merganser","scientific_name":"Mergus serrator","overview":"红胸秋沙鸭（英文名：Red-breasted Merganser，学名：Mergus serrator），是雁形目鸭科秋沙鸭属的鸟类。亦被称为黑头尖嘴鸭（雄鸟）和棕头尖嘴鸭（雌鸟）。拥有长而细的喙和蓬松的羽冠，繁殖期雄鸟头部深绿色，胸部褐色，两侧灰色，雌鸟和亚成雄鸟头部褐色，身体灰色。相比普通秋沙鸭，喙部更细，羽冠更蓬松，体态更为纤细。分布于北半球，从北美的格陵兰至亚洲的库页岛和堪察加半岛。偏好在咸水环境中繁殖。","appearance":"红胸秋沙鸭体型中等，长51-64厘米，翼展66-74厘米，体重800-1350克。雄鸟在繁殖期具有暗绿色头部，白色颈圈，红褐色胸部，黑色背部，白色腹部，雌鸟头部锈色，身体灰褐色。喙长而窄，边缘锯齿状，红色，末端黑色。脚红橙色。雌雄幼鸟外观相似，但缺乏白色颈圈，翼下白色斑块较小。","call":"红胸秋沙鸭在求偶时，雌鸟发出嘶哑的‘prrak prrak’声，雄鸟发出猫似的‘meow’声。飞行中，雌鸟发出尖锐的‘gruk’声，其余时间基本保持沉默。","habits":"红胸秋沙鸭栖息于森林中的河流、湖泊、河口及无林苔原地带的水域。非繁殖期偏好沿海海岸、河口和浅水海湾。以小型鱼类为主食，也摄食水生昆虫、甲壳类、软体动物等。潜水捕食，飞行快速而直接，迁徙期间会进入内陆淡水湖泊。","breeding":"繁殖期为5-7月，营巢于湖泊、河流岸边的灌丛、草丛中或岩石下，每窝产卵8-12枚，孵化期31-35天，由雌鸟负责孵卵。雏鸟早成性，约一个月后即可飞翔。性成熟年龄为2岁。","identification":"与中华秋沙鸭区别在于胸部棕色，条纹深色。与普通秋沙鸭区别在于胸色深，冠羽更长。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美、欧亚，南至哈萨克斯坦北部和中国东北部。非繁殖期分布至欧洲南部、黑海和里海、日本、朝鲜半岛和中国东部，以及墨西哥中西部、美国墨西哥湾沿岸和佛罗里达州。","other":"红胸秋沙鸭是《非洲-欧亚迁徙水鸟保护协定》（AEWA）适用物种之一，也被视为北美与加拿大之间迁徙鸟类条约下的猎鸟，但因对猎人吸引力不大，收获量较少。"},{"name":"中华秋沙鸭","english_name":"Scaly-sided Merganser","scientific_name":"Mergus squamatus","appearance":"中华秋沙鸭体长52-62厘米，雄鸟体重1125-1400克，雌鸟870-1100克。雄鸟繁殖羽有光泽的绿色头部、颈部和肩部，黑色边缘的白色鳞状纹在两侧，长长的双层垂状羽冠。雌鸟头部锈褐色，背部灰色，同样有黑白相间的鳞状纹。幼鸟与雌鸟相似，但头部颜色更深，侧面鳞纹不那么明显，眼下方有淡色新月形斑纹。","call":"通常沉默，但在互动和求偶时，会发出类似普通秋沙鸭的叫声，雌鸟发出深沉的‘kreck’警报声，比普通秋沙鸭更柔和和安静。","habits":"中华秋沙鸭栖息于山林中的清澈、湍急的河流，偏好有砾石滩和岛屿的环境。它们主要以小型鱼类和水生昆虫为食，通过潜水捕食，每次潜水持续15-30秒。在繁殖季节，它们会在树洞中筑巢，树洞距离地面1.5-18米高，多位于河岸附近的树木中。","breeding":"中华秋沙鸭在树洞中筑巢，通常在4月上旬至5月产卵，每窝产卵10-11枚，孵化期约为32天。雏鸟出生后两天内会跟随雌鸟离开巢穴，进入水中。繁殖成功后，雏鸟会在8周左右离巢。","identification":"中华秋沙鸭雄鸟与红胸秋沙鸭的区别在于胸白和体侧的鳞状纹；雌鸟与红胸秋沙鸭的区别在于体侧的带状图案，灰色宽而黑色窄。","protection":"IUCN：EN（濒危）","distribution":"中华秋沙鸭繁殖于西伯利亚极端东南部、中国东北部和朝鲜北部，越冬于中国中部和南部，包括长江流域。小数量个体在冬季也会出现在日本、韩国、台湾、越南北部、缅甸和泰国。","other":"中华秋沙鸭的数量在1960年代和1970年代曾因栖息地丧失而大幅下降，当前面临的主要威胁包括非法狩猎、捕鱼网缠绕和河流污染。"},{"name":"黑头鸭","english_name":"Black-headed Duck","scientific_name":"Heteronetta atricapilla","overview":"黑头鸭（英文名：Black-headed Duck，学名：Heteronetta atricapilla），是雁形目鸭科黑头鸭属的鸟类。小型鸭类，长约35厘米，分布于南美洲温带区域，包括阿根廷、玻利维亚、巴西、智利、巴拉圭和乌拉圭。独特的硬尾鸭亚科成员，具有长而坚硬的尾羽，但外观上更像普通潜水鸭，而非其硬尾鸭亲属。雄鸭头部和上颈呈黑色光泽，雌鸭整体羽毛浅棕色，体型略大于雄鸭。","appearance":"雄性黑头鸭拥有光泽黑色的头部和上颈部，白色下巴，深褐色背部带有肉桂色或淡赤褐色斑点，翅膀折叠时显示两条白色条纹，下体主要为白色带有棕色斑点，呈现银色外观。雌鸟头部和颈部主要为变色棕色，喉咙呈灰白色，其余特征与雄鸟相似。幼鸟类似于雌鸟，但上体更红褐色，下体更黄，具有一条明显的淡色眼纹。","call":"黑头鸭通常沉默，但在求偶展示中会发出低沉的“quah quah”声，也会发出两音节的鼻音后跟一声哨音：“gr-rump-freet”。雌鸟会发出‘咯咯’声。","habits":"栖息于淡水沼泽、湖泊、水库等地，偏好被香蒲（Scirpus californicus）主导的水域，也见于水塘、溪流及偶尔的洪水田。部分迁徙，全年居住在其大部分范围内，但在非繁殖季节会扩展到巴拉圭和玻利维亚。通过潜水觅食，以香蒲种子为主食，辅以少量蜗牛。","breeding":"黑头鸭是强制性巢寄生者，不筑巢也不孵卵，而是将蛋产在其他鸟类的巢中，已知宿主包括粉嘴潜鸭、红额骨顶和黄腿骨顶等。幼鸭在孵化后几小时内就能完全独立，离开巢穴。","identification":"与南美硬尾鸭、安第斯硬尾鸭相比，黑头鸭的雌鸟可通过较浅的眉纹和脸部侧面的淡色来区分。其独特的身体形状（长身短翅）和在水中的低姿态也有助于识别。","protection":"IUCN：LC（无危）","distribution":"分布于南美两大区域：一是智利中部，二是从玻利维亚南部延伸至阿根廷中部，东至乌拉圭南部和巴西最南端。非繁殖季节可能遍及大部分巴拉圭和小范围的玻利维亚。","other":"黑头鸭是硬尾鸭亚科中唯一成员，也是水禽中唯一的强制性巢寄生者，这一独特的繁殖策略使其在鸟类中独树一帜。"},{"name":"花脸硬尾鸭","english_name":"Masked Duck","scientific_name":"Nomonyx dominicus","overview":"花脸硬尾鸭（英文名：Masked Duck，学名：Nomonyx dominicus），是雁形目鸭科花脸硬尾鸭属的鸟类。本属唯一物种。体型小巧，长约33厘米，翼展约43厘米，平均重363克。繁殖季节的雄鸭面部呈黑色，翅膀与体羽斑驳铁锈色。雌鸭及非繁殖季雄鸭、幼鸭体羽灰褐色，面颊有两条棕黄色横纹，嘴薄黑色，具白眼环。广泛分布于中美洲、南美洲及加勒比海地区，偏好密集植被的淡水沼泽、红树林及稻田环境。","appearance":"成年雄鸭在繁殖期脸部为黑色，翅膀与体羽呈现斑驳的铁锈色。雌鸭及幼鸭在冬季体羽灰褐色，面颊有两条棕黄色横纹，嘴薄黑色，具白眼环。上体红褐色，有黑色、褐色与红褐色斑点。背部与两侧有黑褐色条纹，飞行时可见白色翼镜。雌鸭整体颜色较浅，有深色帽，眼棕色至红棕色，脸颊具条纹，鸭喙蓝灰色，尾黑色，腿灰黑色。","habits":"栖息于植被茂密的淡水沼泽、树木覆盖的池塘、红树林沼泽，也常见于稻田。善于游泳与潜水，潜入水下停留时间短暂，通常3至5分钟。从水面起飞时的飞行模式为快速振翅，紧凑直接飞行。主要以水生植物的种子、根茎和叶子为食，也捕食昆虫、鱼、蛙、甲壳动物、软体动物和蠕虫。","breeding":"花脸硬尾鸭实行一夫一妻制。雌鸭在近水植被的灌丛或草丛中建巢，巢呈屋顶式或深杯状，内衬羽毛。每巢产卵4至10枚，白色或浅黄色，孵化期为23至24天。繁殖期主要在5月至7月。","identification":"与同类相比，花脸硬尾鸭在繁殖季节的雄鸭面部为黑色，翅膀与体羽斑驳铁锈色，雌鸭体羽灰褐色，有两道横穿脸颊的棕黄色条纹。与棕硬尾鸭相似，但可通过面颊上的双条纹以及翼上的白色斑块加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，包括墨西哥南部、南美洲东部、加勒比海岛屿以及美国最南部地区。在繁殖季节以外的时间，它们在南美的分布更为广泛。"},{"name":"棕硬尾鸭","english_name":"Ruddy Duck","scientific_name":"Oxyura jamaicensis","overview":"棕硬尾鸭（英文名：Ruddy Duck，学名：Oxyura jamaicensis），是雁形目鸭科硬尾鸭属的鸟类。小型、体壮、尾硬而呈扇形的硬尾鸭。雄鸟繁殖羽极具辨识度：北美及加勒比种群（指名亚型）具亮栗色体羽、黑色头罩与白色脸颊，喙呈天蓝色；南美安第斯种群（ferruginea）则全体更暗，雄鸟头颈全黑无白颊，体型亦略大。该复合种繁殖范围自阿拉斯加、加拿大草原洼地区向南经美国、墨西哥、中美洲直至南美安第斯山至火地岛，越冬于太平洋、大西洋沿岸及内陆大型湿地，主食摇蚊幼虫等水生无脊椎动物。北美种群稳定或增长；西欧引入种群因与濒危白头硬尾鸭杂交，已被大规模控群。","appearance":"体长35–48厘米，体重约0.6–0.85千克。尾羽硬挺，常直立。北美及加勒比雄鸟繁殖期：头黑、脸白、喙天蓝；体羽亮栗红，腹银白。非繁殖羽及雌鸟：通体褐，头罩黑，喙暗灰，面颊具暗贯眼纹。安第斯亚型（ferruginea）：雌雄均较暗，雄鸟头颈全黑无白颊，下体栗红至黑栗色，尾下覆羽栗红；雌鸟上体深褐，面颊条纹不明显。幼鸟羽色似雌鸟但偏淡。","call":"雄鸟求偶时发出低沉“raa-anh”并伴鼓泡声；雌鸟以鼻音“raanh”或高音“E”示警。受惊时两性均可发出嘶嘶声。","habits":"繁殖期栖于半永久性淡水或微咸水沼泽、湖泊、水库，需开阔水面与浓密挺水植被；安第斯亚型可上至海拔4500米高原湖泊。迁徙性：北美及温带南美种群中至短距离迁徙，夜间迁飞；热带安第斯及加勒比种群多为留鸟。潜水觅食，平均潜水18–21秒，主食摇蚊幼虫、端足类、水生昆虫及甲壳类，极少摄植物。","breeding":"繁殖期北半球5–7月、南半球10–2月。配对在抵达繁殖地后迅速形成，雄鸟以鼓泡展示及飞行展示求偶，配对期4–8周。雌鸟独立在挺水植被中筑浮巢，距水面30–60厘米，每窝6–10（偶达17）枚乳白大型卵，卵重约74克，孵化期23–26天仅雌鸟担任。雏鸟早成，24小时内即可潜水，雌鸟单独育雏20天左右，雏鸟7–9周可飞。","identification":"与白头硬尾鸭雄鸟区别：后者头白、喙蓝黑；雌鸟头侧具淡颊斑。与迷鸟花脸硬尾鸭区分：后者体型更小，喙短而深，飞行垂直起飞，翼具三角形白斑。安第斯亚型（ferruginea）与指名型（jamaicensis）雄鸟差异：前者头全黑无白颊，体羽更暗；雌鸟更暗且颊纹不明显。","protection":"IUCN: LC（无危）。北美种群稳定；南美安第斯种群估计2.5–10万只，局部因湿地退化下降；欧洲引入种群因与白头硬尾鸭杂交已被大规模捕杀，数量锐减。","distribution":"繁殖区：北美自阿拉斯加、加拿大草原至美国大部、墨西哥高原、中美洲局部、加勒比岛屿；南美安第斯山脉自哥伦比亚至火地岛。越冬区：美国大部、墨西哥、中美洲沿海、加勒比及南美低地；西欧引入种群原在英国扩散至20余国，现因控群已不足7%。","other":"系统发育上，棕硬尾鸭复合种与旧世界白头硬尾鸭、澳洲硬尾鸭、非洲硬尾鸭构成单系，而与麝鸭互为姊妹群。形态与分子证据支持北美与南美种群互为最近缘，现在被视为同种。"},{"name":"安第斯硬尾鸭","english_name":"Andean Duck","scientific_name":"Oxyura ferruginea","overview":"安第斯硬尾鸭（英文名：Andean Duck，学名：Oxyura ferruginea），是雁形目鸭科硬尾鸭属的鸟类。又称: 火地岛棕硬尾鸭，原被视为棕硬尾鸭的一个亚种，现已独立为一物种。以独特的黑色面部和较大的体型与棕硬尾鸭相区分。该物种主要栖息于南美洲哥伦比亚南部至南锥体地区的安第斯山脉。","appearance":"安第斯硬尾鸭是一种小型、紧凑的鸭类，拥有长而扇形的尾巴，通常会翘起。繁殖季节的雄鸟具有深栗色的身体、黑色头部和婴儿蓝的喙。雌鸟和非繁殖季节的雄鸟整体呈棕色，脸部模糊暗淡，脸颊上有一条深色线条。与棕硬尾鸭相比，它的体型更大，颜色更深，尤其是繁殖期雄鸟的黑脸和白下巴尤为明显。","call":"安第斯硬尾鸭的叫声与棕硬尾鸭相似，包括机械式的鼓声或冒泡声在求偶展示中发出，以及雄鸟发出的鼻音‘aarp’声，同样在求偶展示中出现。","habits":"它们生活在安第斯山脉的淡水沼泽、湖泊、池塘和湿地，偏好有浮水植物和开阔水面的环境，但避免湍急水流。它们主要以水生无脊椎动物为食，可能偏好Chara植物。","breeding":"繁殖季节似乎全年都有，具体时间在不同地区有所差异。它们倾向于季节性的一夫一妻制，雌鸟独自筑巢，巢由死亡或活着的植被构成，位于密集的浮水植物中。每窝通常产6-10枚白色蛋，孵化期约为24-26天，仅由雌鸟承担。雏鸟的绒羽呈深灰色或橄榄灰色。","identification":"安第斯硬尾鸭与棕硬尾鸭最明显的区别在于其全黑的脸部和较大的体型。雌鸟和幼鸟与冬季的雄鸟相似，但脸颊上的条纹更为模糊。","protection":"IUCN: LC（无危）。总数量估计在25,000到100,000之间，但在部分地区数量显著，如秘鲁和玻利维亚的某些湿地。然而，由于湿地的丧失和退化，该物种在一些地区可能正在减少。","distribution":"安第斯硬尾鸭分布在南美洲的安第斯山脉，从哥伦比亚南部一直延伸到南锥体地区。在玻利维亚的某些湖泊中数量较多，而在哥伦比亚的拟议种族andina则相对稀少且局部。","other":"安第斯硬尾鸭曾被认为是棕硬尾鸭的亚种，但现在被大多数分类系统视为独立物种。"},{"name":"南美硬尾鸭","english_name":"Lake Duck","scientific_name":"Oxyura vittata","overview":"南美硬尾鸭（英文名：Lake Duck，学名：Oxyura vittata），是雁形目鸭科硬尾鸭属的鸟类。又称阿根廷蓝嘴鸭、阿根廷蓝嘴鸭、阿根廷湖鸭或阿根廷锈鸭，小型的南美洲硬尾鸭。雄鸟具有黑色头部，红褐色身体和蓝色鸭喙，而雌鸟则呈褐色，喉部白色，带有明显的白色眼纹和脑后宽纹。分布于南美洲南部锥体，包括大部分智利和阿根廷，以及巴西东南部、巴拉圭和乌拉圭部分地区。","appearance":"雄性南美硬尾鸭身长36-46厘米，体重600-850克，拥有黑色头部、红褐色身体，以及深蓝色的喙。雌鸟较雄鸟小，重510-700克，体色较为暗淡，褐色为主，喉部白色，眼上方有白色眼纹，脑后有白色宽纹。雌鸟喙色为铁灰色。两性皆有翘起的尾羽。","call":"雄鸟在展示时会发出机械般的沙沙声和柔和的‘pup-pup-pup-prup’叫声，而雌鸟则在受到威胁或抵抗雄鸟的追逐时发出尖锐的叫声。","habits":"栖息于淡水湖泊、小池塘和湿地，周围有丰富的植被。它们善于游泳和潜水，通常在水底过滤残渣觅食，食物包括种子、植物残留物和小型水生无脊椎动物。南美硬尾鸭在非繁殖季节也会出现在较大的湖泊和泻湖。","breeding":"繁殖季节在阿根廷为10月至1月，筑巢于水边的灌木丛或草丛中，形成浮巢。每窝产卵3至5枚，有时可达12枚，但后者通常是寄生行为的迹象。孵化由雌鸟单独完成，持续23至24天。雏鸟孵化时体重43至58克，孵化后56至63天离巢。","identification":"与安第斯硬尾鸭相似，但南美硬尾鸭体型更小，头部更扁平，尾巴略长，喙部更短，缺乏下巴上的白色标记。雌性南美硬尾鸭的侧翼花纹比安第斯硬尾鸭更明显，背部有网状的红棕色纹理。","protection":"IUCN：LC（无危）","distribution":"分布于智利和阿根廷大部分地区，向南至火地岛，冬季时会北迁至巴西东南部和巴拉圭。在南美洲南部锥体广泛分布，但在某些地区数量较少。","other":"南美硬尾鸭持有吉尼斯世界纪录，拥有最长的鸟类生殖器官，长度可达42.5厘米，是所有脊椎动物中相对于体长最长的。"},{"name":"澳洲硬尾鸭","english_name":"Blue-billed Duck","scientific_name":"Oxyura australis","overview":"澳洲硬尾鸭（英文名：Blue-billed Duck，学名：Oxyura australis），是雁形目鸭科硬尾鸭属的鸟类。小型硬尾鸭，体型小巧，约35-44厘米长，翼展60厘米。雄鸟重610-965克，雌鸟重476-1300克。分布于澳大利亚的温带地区，包括西澳大利亚西南部、昆士兰州西南部至维多利亚州南部和南澳大利亚东南部以及塔斯马尼亚州。偏好深淡水湖泊、水坝、内陆河流、池塘和沼泽地带，几乎完全水生，陆地罕见。","appearance":"雄鸟具有亮黑色的头部，深栗色的羽毛，腹部带褐色，中心有白色区域，搭配着一张紧凑而明亮的淡蓝色鸭喙。雌鸟则为较深的灰色，带有细小的条纹，喙为暗角质色。两者均具有竖起的坚硬尾羽，通常与水面保持水平。幼鸟外观类似雌鸟，但色调较淡，喙呈灰绿色。","call":"蓝嘴鸭的叫声较为低沉，但在野外极少听到。雄鸟在求偶期间会发出一系列非声音的展示，如拍打水面产生的响声，以及通过脚拍水产生的有节奏的涟漪声，这些声音在理想条件下可达1公里远。雄鸟的主要声音展示为低频的‘咚咚咚’和柔和的、喘息般的‘chee-chee-che-chee-’或‘chit-chit-chit-’。雌鸟几乎无声，偶尔会发出轻柔的鼻音叫声。","habits":"澳洲硬尾鸭栖息于开放的深淡水湖泊、水坝、内陆河流、池塘和沼泽，几乎完全水生。非繁殖季节，它们会聚集形成数百只的大群，尤其在秋天和冬天远离岸边的开阔湖泊或水库中。它们的食物主要是水生植物的种子、幼芽、果实，以及小型水生无脊椎动物，如螺类、昆虫幼虫、甲壳动物和蠕虫。它们通过在水下筛选底泥进食。","breeding":"繁殖季节在澳大利亚的春季和夏季，但机会主义繁殖可能全年发生。雄鸟在求偶时会展现出复杂的仪式。巢穴建在靠近水源的密集植被中，通常是用死叶子建成的深碗状巢，有时用少量绒羽衬垫。每次产卵5-6枚，孵化期大约24-27天，仅由雌鸟单独承担。雏鸟出生后一天左右就会离开巢穴，由雌鸟独自照顾，直至约60天后完全独立。","identification":"雄鸟在繁殖季节的亮蓝色喙和深栗色羽毛与雌鸟的暗灰色形成鲜明对比。雄鸟的喙在非繁殖季节变为暗绿色。与南美硬尾鸭相比，澳洲硬尾鸭体型较小，喙较长且较细。雌鸟与其他Oxyura物种的区别在于缺乏明显的面部图案。","protection":"IUCN：LC（无危）。然而，它在维多利亚州和新南威尔士州被列为近危物种。目前估计有大约12,000只成熟个体，总数量约为18,000只。面临的主要威胁包括湿地的排水、退化、引入的鱼类、周边牛群放牧、盐碱化和地下水位下降。","distribution":"主要分布在澳大利亚的温带地区，包括西澳大利亚西南部、昆士兰州西南部至维多利亚州南部、南澳大利亚东南部以及塔斯马尼亚州。在非繁殖季节，它们可能会向北扩散到新南威尔士州北部、中部和东部澳大利亚。","other":"蓝嘴鸭能够适应人工湿地环境，如污水处理厂，这有助于其种群的稳定。然而，过度的干旱、湿地的减少和水质的恶化仍对其构成威胁。"},{"name":"非洲硬尾鸭","english_name":"Maccoa Duck","scientific_name":"Oxyura maccoa","overview":"非洲硬尾鸭（英文名：Maccoa Duck，学名：Oxyura maccoa），是雁形目鸭科硬尾鸭属的鸟类。雄鸭在繁殖期展现鲜艳的淡红色羽毛和鲜蓝色的喙，雌鸭羽色较为单一，体型较小，具1或2条贯脸纹。该物种分布于东非至南非，偏好淡水湿地，如湖泊、池塘和泻湖，偶尔可见于盐湖。","appearance":"非洲硬尾鸭体长46-51厘米，体重介于450至820克。雄鸭头部呈黑色，拥有独特的蓝色鸭喙，背部为板栗色，腿部灰色；雌鸭体色灰褐，嘴部深灰色，冠部深棕色，后颈和颊部饰有条纹。无论雌雄，尾部均保持翘起姿态。","call":"该物种通常被认为是沉默的，但在展示时，雄鸭会发出振动的、类似牛蛙的“prrr...”声，持续2-3秒，同时也会发出柔和的口哨声。威胁状态下，两性都会发出低沉的咕噜声。","habits":"非洲硬尾鸭栖息于湿地、沿江地带、湖泊、池塘和沼泽等环境，与其他鸭类混群活动，擅长游泳和潜水。它们倾向于在水中度过大部分时间，仅在必要时上岸或飞行。食物来源包括水生植物、昆虫、鱼、蛙、甲壳类、软体动物和蠕虫。","breeding":"繁殖期在5月至7月之间，雄鸟表现出多配偶倾向。筑巢于水边的灌木丛或草丛中，每次产卵4至8枚蓝色卵，孵化期约为25天。","identification":"非洲硬尾鸭的特殊形态使其在分布范围内独一无二。雄鸭的鲜艳色彩和独特鸭喙使其容易识别，而雌鸭与灰嘴潜鸭的雌鸟相似，但灰嘴潜鸭体形更修长，面部具有垂直的白色标记。","protection":"IUCN：EN（濒危）","distribution":"非洲硬尾鸭分布在东非至南非，从厄立特里亚向南至坦桑尼亚北部，以及从纳米比亚和津巴布韦向南至南非西开普省。","other":"适应性强，能栖息于人工水库、污水池和水库，尤其是在南非和纳米比亚。"},{"name":"白头硬尾鸭","english_name":"White-headed Duck","scientific_name":"Oxyura leucocephala","overview":"白头硬尾鸭（英文名：White-headed Duck，学名：Oxyura leucocephala），是雁形目鸭科硬尾鸭属的鸟类。小型潜水鸭，长约46厘米。雄鸟特征鲜明，头部白色，黑色王冠，蓝嘴，雌鸟颜色较暗淡。在中国极为罕见，主要栖息于开阔平原地区的淡水湖泊，分布于欧洲南部、非洲北部至亚洲中部和中国西北部。IUCN评级为\"EN\"（濒临灭绝），被列入中国国家重点保护野生动物名录，保护级别为I级。","appearance":"白头硬尾鸭体型中等，长度43–48厘米，体重553–900克，翼展62–70厘米。雄鸟拥有醒目的白色头部，黑色王冠，蓝色喙，身体呈红褐色，尾部黑色。雌鸟和幼鸟喙色较暗，头部棕色，有明显的淡颊纹。雄鸟在非繁殖季节变得较为暗淡，雌鸟则呈现灰褐色，缺乏红褐色调。","call":"一般沉默，仅在争斗或求偶时发出声音，雄鸟会发出类似玩具钟表的快速咔哒声，以及高音节、加速的笛状音符。","habits":"栖息于湖泊、池塘和泻湖，偏好淡水环境，深度在0.5至3米之间，周围有密集植被。繁殖期主要在开阔平原地区的淡水湖泊，冬季则迁移到地中海、中东至印度西北部的较大湖泊。夜间活动，主要通过潜水觅食，食物以水生植物为主，也包括水生昆虫和其他小型无脊椎动物。","breeding":"繁殖期为5月至7月，通常在春季迁徙途中和抵达繁殖地后形成配偶。营巢于水边地上灌丛或草丛中，或在芦苇丛中建浮巢。每窝产卵6-10枚，孵化期约为25天。","identification":"与棕硬尾鸭相似，但可通过头部形状、更健壮的铅灰色喙和不同的体型大小加以区分。雌性白头硬尾鸭与红头鸭相比，体型更小，更灰暗，尾部更短，体态更为浮肿。","protection":"IUCN：EN（濒临灭绝）","distribution":"繁殖于西班牙、北非、西亚和中亚，越冬于地中海、中东至印度西北部。在中国西北部也有记录。","other":"面临的主要威胁包括栖息地丧失和污染，以及与引入的红头鸭杂交。"},{"name":"麝鸭","english_name":"Musk Duck","scientific_name":"Biziura lobata","overview":"麝鸭（英文名：Musk Duck，学名：Biziura lobata），是雁形目鸭科麝鸭属的鸟类。体形健硕，羽色暗淡，雄鸟具有独特的皮质突起在喙下，散发类似麝香的气息，源自其尾脂腺的分泌物。广泛分布于澳大利亚南部，尤其在墨累-达令盆地、库珀溪流域、西南部西澳大利亚、维多利亚和塔斯马尼亚的湿润地带最为常见。","appearance":"成年雄性麝鸭长度约60至70厘米，雌鸟约47至55厘米。雄鸟拥有显眼的大型、皮革状的喙下突起；雌鸟则较小，无此装饰。羽毛呈单调的灰褐色，带有细纹，两性颜色相近。雄鸟平均重约2,398克，雌鸟约1,551克，体重范围自993克至3,170克。雏鸭覆以深棕色绒毛。成鸭在水中浮行姿态极低，脚掌宽大，位于身体后方，鸭雏覆以深棕色绒毛。","call":"在非繁殖季节，麝鸭较为安静，仅雄鸟在繁殖期发出独特的声音序列：先是在水面用脚拍打产生‘ker-plonk’声，随后是柔和尖锐的‘cuc cuc’叫声，接着是响亮的哨音和低沉的哼声。雌鸟极少发声，但在受困时可能发出沙哑的哼鸣。","habits":"偏爱深邃、静止的湖泊和湿地，同时拥有开阔水面和芦苇床。它们很少离开水面，即使在陆地上也行动笨拙。飞行虽少，但一旦起飞，能快速且持久地飞翔。在水中展现出惊人的敏捷，利用脚蹼和尾巴灵活移动。白天大部分时间都在水面休息或觅食，偶尔上岸小憩。夜晚则在水中睡眠，头埋入身体或翅膀下。潜水能力出色，可潜至至少6米深处，主要以水生昆虫、甲壳类、软体动物和少量鱼类为食。","breeding":"繁殖季因降雨和水位而异，通常在7月至1月间，高峰期在9月或10月。雄鸟在繁殖期散发麝香味。雄鸟不参与筑巢或育雏，雌鸟选择隐蔽地点筑巢，多在远离陆地的高大芦苇中，巢由植物材料构成，内铺柔软物质和产卵后添加的绒羽。每窝产卵数未知，最多记录到10枚，但可能因寄生繁殖导致。一般仅一至两只雏鸭存活。雏鸭出生几天后即能游泳和潜水，随母亲至少几个月，有时骑在其背上。母鸭持续喂养雏鸭直至它们接近成年。","identification":"与其他水鸭相比，麝鸭的扇形尾部和雄鸟显著的喙下突起是辨识关键。与澳洲斑鸭和澳洲硬尾鸭有相似的体型和颜色，但尾部形状和雄鸟繁殖期的特殊特征使其易于区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚西南部、昆士兰南部至维多利亚南部、南澳大利亚东南部和塔斯马尼亚，以及西澳大利亚西南部。在墨累-达令盆地和库珀溪流域相对丰富。","other":"已知的最长寿命为超过23年的圈养个体。面临的主要威胁包括湿地的改变和退化，如农业实践、排水、过度放牧、盐碱化和水位波动。"},{"name":"大塚雉","english_name":"Australian Brushturkey","scientific_name":"Alectura lathami","overview":"大塚雉（英文名：Australian Brushturkey，学名：Alectura lathami），是鸡形目冢雉科丛塚雉属的鸟类。大型黑色鸟，拥有垂直扇形尾巴、庞大的强壮腿脚和明显的红色头部。雄鸟发育有大的黄色颈部垂肉（在卡佩约克半岛亚种中为淡紫色）。大塚雉是澳大利亚东海岸热带雨林的特有种，常见于城市公园和花园，如凯恩斯和布里斯班。","appearance":"体型60–70厘米，雄鸟体重2120–2950克，雌鸟1980–2510克。无可混淆，其大尺寸、鲜艳的裸露皮肤和大部分黑色羽毛带有白色斑点下部特征明显。最大的冢雉，体型差异显著，可能与气候或个体有关，南方个体最大。头部和颈部颜色在求偶期间更为明亮，繁殖季节外通常较暗淡，此时颈囊缩小。虹膜浅棕色至黄色或乳白色。雌鸟略小，颈囊非常小，头颈裸露皮肤较少。幼鸟几乎无法与雌鸟区分，但头部和颈部羽毛较不粗糙，裸露皮肤更少。purpureicollis亚种颈囊粉红至紫色，虹膜偏暗。","call":"只有成年雄鸟发出深沉、回荡的‘oom’声，有时长达5-6音节，总是低沉而共鸣。叫声用于多种情境：不在雌鸟面前的土堆上、与对手雄鸟的争斗中，以及在栖息地。其他叫声包括两性都会发出的低沉咕噜声，通常在潜在捕食者面前，以及高音尖叫，仅在被捕食者捉住时发出。","habits":"大塚雉常出现在热带和暖温带雨林的封闭区域，但也适应了多种其他生境，包括干燥硬叶林、画廊森林、桉树森林和包括红树林的沼泽林地。偏好密集的下层植被，常见于引入的龙舌兰（Lantana camera）广泛生长的区域。沿干涸的小溪活动，倾向于在树冠封闭、有足够的落叶层的区域筑巢。越来越多地占据受干扰的环境，甚至城市郊区，在公共和私人花园中筑巢。以植物性食物为主，包括种子、谷物、嫩芽、根、果实和浆果，也食用青蛙、蜗牛、蠕虫、昆虫及其幼虫，以及腐肉。在飞行中取食仙人掌（Opuntia）的果实，挖掘并以阿劳卡里亚·库宁汉姆（Araucaria cunninghamii）的根为食，对种植园造成损害。","breeding":"筑巢始于昆士兰州东南部的5-6月（冬季），巢弃于1-2月；purpureicollis亚种（卡佩约克）于2月产卵，3月孵化。雄鸟同时多配偶制，雌鸟顺序多雄制；雌鸟可能对单一雄鸟忠诚数周。雄鸟用大约37天时间筑巢（14-77天），有时会侵占其他冢雉的巢穴。巢由湿润的落叶和泥土构成，平均85厘米高×300-410厘米宽（偶尔可达700厘米），包含2-4吨材料。单个巢可容纳来自多个雌鸟的多达58枚白色蛋（平均12枚）。每只雌鸟在一个季节内可产15-27枚蛋，间隔几天。孵化期47-52天。雏鸟出生时体重约为80-120克，覆盖柔软的棕色绒毛，翅膀羽毛已发育。","identification":"大塚雉在其分布范围内无可混淆。purpureicollis亚种具有独特的紫粉色颈囊和较光滑的胸部皮肤。雄鸟和雌鸟在大小、颈囊和裸露皮肤上有明显差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从远北昆士兰到新南威尔士州南部海岸的欧罗博达拉。20世纪初，随着仙人掌向内陆扩散，大塚雉的分布范围相应扩大，因为它们利用仙人掌的多汁部分作为干旱地区筑巢材料；随着植物控制和最终移除，鸟类退回传统分布区。最近，它们在悉尼北部（新南威尔士州）和昆士兰东南部布里斯班的城市区域扩展，经常与人类社区发生冲突。","other":"1936年，一对大塚雉被引入南澳大利亚的袋鼠岛，至今仍在岛上繁盛。"},{"name":"肉垂塚雉","english_name":"Wattled Brushturkey","scientific_name":"Aepypodius arfakianus","overview":"肉垂塚雉（英文名：Wattled Brushturkey，学名：Aepypodius arfakianus），是鸡形目冢雉科冠冢雉属的鸟类。分布于新几内亚的山地雨林中。具有明显的雌雄异型，雄鸟拥有淡蓝色裸露面部皮肤，而雌鸟为暗灰色，头部和胸部的红色肉垂在雄鸟中更为显著。","appearance":"肉垂塚雉体长38至46厘米，雄鸟体重约1450至1600克，雌鸟1200至1530克。其臀部和上尾覆羽呈深红褐色，腿脚颜色为蓝灰至橄榄棕色。雄鸟的鲜红色冠和颈肉垂在繁殖季节外颜色变暗；裸露的面部皮肤通常为蓝白色，但在某些情况下可能呈现蓝灰色。雌鸟体型较小，头部颜色较暗，肉垂较小，面部皮肤更偏向绿色。幼鸟外观类似雌鸟，但头部裸露皮肤被黑色毛发状细刺覆盖，没有肉垂，冠显著减小。","call":"肉垂塚雉通常很安静，但在特定情况下会发出一系列尖锐的‘ki！kekekekekeke’叫声，其中第一个音节音调较高。","habits":"它们生活在海拔750至2800米的山地森林，主要在1000米以上高度活动。以落叶果实、种子和无脊椎动物为食，会摄入大量小石子帮助消化。肉垂塚雉在受到惊扰时倾向于飞入树上。","breeding":"繁殖活动全年均可发生，除7月和8月（此时发现幼鸟）以及11月。它们是筑巢者，通常建造由叶子和树枝堆成的陡峭巢丘，宽度约300至350厘米，高度150至200厘米。在圈养条件下，雄鸟负责筑巢，单个雌鸟可在约4个月内产下20枚蛋，平均间隔约6天。蛋在温度29.4至34.3℃的巢丘中孵化。雏鸟孵化时重115至125克，上面有黑褐色条纹，下面主要是灰棕色，下巴和脸颊呈赭黄色。","identification":"肉垂塚雉与其它冢雉相比，具有垂直扁平的尾巴，臀部为栗色，腿部颜色较深。雄鸟的红色肉垂和面部皮肤颜色在繁殖季节外会变暗，而雌鸟的肉垂比雄鸟小。","protection":"IUCN：LC（无危）","distribution":"肉垂塚雉主要分布在新几内亚的山地雨林中，海拔从750至2800米，特别是在1000米以上的区域。","other":"该物种有两个亚种被认可。"},{"name":"冠塚雉","english_name":"Waigeo Brushturkey","scientific_name":"Aepypodius bruijnii","overview":"冠塚雉（英文名：Waigeo Brushturkey，学名：Aepypodius bruijnii），是鸡形目冢雉科冠冢雉属的鸟类。大型黑色鸟类。其特征为胸部带有栗色，裸露的头部和喉咙呈粉色。雄鸟的头部有不讨喜的红色皮肤褶皱，喉部基部垂挂一串肉垂。雄鸟会频繁地抖动头部。这种鸟仅分布于瓦伊盖奥岛的山林之中，与暗色塚雉同域，但体型更大，头部呈粉红色。","appearance":"体长41至46厘米，上体呈暗褐色但略显灰色，胸腹部为更浓的栗棕色，两翼下方和尾羽覆羽为橄榄灰。脸部裸露部分呈粉红至鲑鱼色。雄鸟具有红色的冠状肉垂和颈部三根悬垂的肉垂（最长的一根位于前颈），下巴处有一小肉垂。雌鸟和幼鸟缺乏或仅有较小的颈部肉垂，雌鸟的冠状肉垂也较小。虹膜为榛色至橙色，环绕着灰色的眼环，喙为深棕色至黑色，腿和脚主要为绿色。","call":"通常保持沉默，但有两种已知的叫声类型：一种是短暂、微弱到爆发性的咯咯声，焦虑时会偶尔或持续重复，类似于红颈秧鸡和格氏雕的夜间叫声；另一种是一系列嘈杂的咯咯笑声，持续约2秒，可能与极度痛苦相关，有时伴随快速起飞时的呼啸声。","habits":"栖息于瓦伊盖奥岛崎岖喀斯特地貌中的常绿矮小云雾林，树冠高度主要在7至12米之间，林中多有附生植物和蕨类植物，下层植被密集，包括许多棕榈树。巢穴位置仅在海拔620至930米的高度被发现。大多数孵化土堆位于主山脊和支撑的山顶附近，较少出现在干燥溪流附近的永久水坑附近。偶尔有报道显示，它们在更低的海拔，甚至海平面附近出现。","breeding":"直到最近，其繁殖习性完全未知，但现在确认为土堆筑巢者。土堆的尺寸和形状与肉垂塚雉相似，最高可达120厘米，底部宽度为210厘米，主要由树叶构成，伴有少量树枝和细枝。单个雄鸟可能同时照料两个土堆，但未得到证实。疑似实行多雄制。孵化和处于繁殖状态的雌鸟在五月被记录。","identification":"与同域的暗色塚雉相比，冠塚雉体型更大，头部颜色更鲜艳。雄鸟具有独特的红色头部皮肤褶皱和颈部肉垂，而雌鸟则缺少或仅有较小的颈部肉垂。","protection":"IUCN：EN（濒危）","distribution":"冠塚雉仅分布在印尼的瓦伊盖奥岛（四王群岛西北部，新几内亚以西）。","other":"尽管过去仅有不到25个标本记录，但在2002年再次被发现。由于森林砍伐、火灾、狩猎和狗的捕食，其总成熟个体数量估计仅为约980只，且被认为正在减少。"},{"name":"红嘴塚雉","english_name":"Red-billed Brushturkey","scientific_name":"Talegalla cuvieri","overview":"红嘴塚雉（英文名：Red-billed Brushturkey，学名：Talegalla cuvieri），是鸡形目冢雉科营冢雉属的鸟类。身长可达57厘米，主要分布在新几内亚西北部的Misool和Salawati岛以及Vogelkop半岛西部雪山西部。其特征为红橙色的喙、黄色的眼圈和橙色的腿脚，面部裸露皮肤呈淡黄绿色或黄色。该物种以法国动物学家Frédéric Cuvier命名。","appearance":"红嘴塚雉体长约45至57厘米，体重约1785克，雌雄相似，全身深黑光泽，上体至尾羽最深。头部覆盖着类似鬃毛的黑色羽毛，喙为橙红色，腿和脚为橙色或偶尔黄色，面部裸露皮肤为淡绿黄色或黄色，虹膜呈黄色调。幼鸟颜色较暗淡，头部和颈部羽毛较多，有时翼覆羽和次级飞羽保留有红黑相间的条纹，喙可能为灰褐色。","call":"红嘴塚雉叫声响亮刺耳，常听到三音节的“wok-wak！wak！”叫声，首音较低，第二与第三音之间有停顿。","habits":"栖息于低地和山丘森林，最高可达海拔1600米。当受惊扰时，它们会奔跑逃离，而不是像那样飞向树梢。红嘴塚雉被假定为杂食性。","breeding":"红嘴塚雉的繁殖期不详，但在Misool岛11月曾收集到处于繁殖状态的雌鸟，而在北Vogelkop半岛7月收集到处于繁殖状态的雄鸟。它们筑巢于大树底部，巢由树叶和树枝构成，高度从45至135厘米，宽度可达360厘米。蛋壳呈粉棕色，形状与Megapodius属的蛋相似。","identification":"与肉垂塚雉相比，红嘴塚雉通常出现在更低的海拔，且具有橙色腿脚。与Yellow-legged Brushturkey的区别在于，后者腿脚更明亮的黄色。","protection":"IUCN：LC（无危）","distribution":"分布于Misool和Salawati（位于新几内亚西北的Raja Ampat群岛）、Bird's Head和Neck（北部区域）以及西新几内亚。","other":"尽管在适宜的栖息地中曾经常见，但由于人类密集采集鸟蛋和偶尔猎杀成鸟，加上栖息地退化，红嘴塚雉的种群数量正在减少。"},{"name":"黑嘴塚雉","english_name":"Black-billed Brushturkey","scientific_name":"Talegalla fuscirostris","overview":"黑嘴塚雉（英文名：Black-billed Brushturkey，学名：Talegalla fuscirostris），是鸡形目冢雉科营冢雉属的鸟类。大型地面栖息鸟类。主要分布在印尼阿鲁群岛（新几内亚西南）和新几内亚南部的低地雨林中。","appearance":"体型较大，全长约51至58厘米，雄鸟体重1325至1400克，雌鸟体重1000至1560克。面部裸露皮肤呈灰色，喙黑色，腿和脚亮黄色至粉红色。头侧裸皮颜色从灰黑色到钴蓝色，虹膜棕色至红棕色。喙色从深棕色至黑色，腿部淡绿黄。幼鸟较小，颜色较暗淡，颈部有褐色斑块，头部被毛发覆盖。存在显著的地理变异，分为多个亚种，如occidentis、aruensis和meyeri，它们在大小和裸皮颜色上有所不同。","call":"发出一系列3至5个非常响亮、上升的号叫声，随后是一个平音或1至3个更慢的下降音符，如'wha-wha-wha-wa hah hah hah'，持续2.5至5秒。有时会发出连续的嘈杂笑声，重复的咕噜声，微弱的咔哒声，和低沉的'鹦嘴管舌雀音。","habits":"栖息于低地雨林、季风林和偶尔的画廊林，海拔高度可达800米。在受干扰的森林区域也能发现其踪迹。通常单独或成对出现，以昆虫、幼虫和落果为食，偶尔捕食小蜥蜴。在干燥季节会从森林池塘饮水。","breeding":"繁殖活动全年可见，但在低地的湿季（10月至5月）和高海拔（700至800米）的干季（9月至1月）可能有高峰。建造土堆以孵化卵，土堆主要由枯叶和树枝构成，一般位于大树基部，尺寸可达700厘米×540厘米，高度60至100厘米。卵呈浅粉色至暗褐色，雏鸟全身暗棕色，下腹部带锈色，喉部和腹部中央黄色。","identification":"与其他类似大小的黑色鸟类共存，但明亮的黄色腿使其易于识别。与红嘴塚雉相比，黑嘴塚雉具有更深的喙和更多裸露的小腿部分。亚种aruensis比指名亚种略大，头部裸皮有时呈绿色。meyeri亚种在大小上接近红嘴塚雉，喙色从角棕色至黑色，尾巴较短。","protection":"IUCN：LC（无危）。总数量估计在670至67,000只之间，因栖息地转换和退化而减少。在人类稀少的地区被认为安全，但在人口密集区因猎杀而迅速消失。","distribution":"主要分布于印尼阿鲁群岛（西南部，新几内亚）和新几内亚南部。在伊里安查亚（西新几内亚）广泛且常见，在巴布亚新几内亚亦广泛分布，但在适宜生境中较为常见。","other":"在印度尼西亚受到法律保护，没有已知的个体被圈养。"},{"name":"褐领塚雉","english_name":"Collared Brushturkey","scientific_name":"Talegalla jobiensis","overview":"褐领塚雉（英文名：Collared Brushturkey，学名：Talegalla jobiensis），是鸡形目冢雉科营冢雉属的鸟类。主要分布于新几内亚的北部和东南部，以及印尼亚彭岛（鸟头湾，新几内亚西北部）。以全身黑色羽毛、突出的红橙色腿和独特的头部羽毛构成的冠羽而闻名。","appearance":"成年褐领塚雉体长介于53至61厘米之间，雄鸟体重可达1531至1705克（长脚亚种），雌鸟约为1360克（jobiensis亚种）。其全身羽毛黑色，腿和脚橙色到鲜红色，脸部和颈部裸露皮肤呈暗红色调，具有红棕色的颈环，虹膜颜色从棕色到红色。喙色为黄褐色至暗红色。未成年个体与成年相似，但头部和颈部羽毛更密，体羽偏棕色且较暗淡。","call":"褐领塚雉的鸣声非常响亮，通常发出2至4个升调的嘶哑音符，类似红嘴塚雉的叫声，但音调上升更高，速度更慢，持续时间更长，如“owagh-aagh”（约2秒）或“agggh-owagh-aggh-ah”（6.5秒）。它们日夜皆可听到叫声。","habits":"褐领塚雉栖息于低地至中高山的雨林地带，海拔高度可能从海平面至1980米，偏好干燥地面，避免沼泽森林区域。它们在较高海拔地区常出现在沟壑中，且似乎倾向于定居，而非迁徙。关于饮食习惯的信息有限，但推测它们可能是杂食性动物。","breeding":"繁殖季节不固定，但有记录显示雌鸟在九月处于繁殖状态，雏鸟在七月被发现。它们建造平而宽的土堆，位于大树之间，有时高达150厘米，宽90至450厘米，温度保持在32至36°C。一对鸟可能会连续3至5年使用同一个土堆。一次最多可产17枚蛋。雏鸟孵化时重约110至125克，六周大时体重增至292克。蛋壳颜色为酒红色至棕色，孵化期间外层会剥落。","identification":"褐领塚雉与黑嘴塚雉在海拔分布上可能有重叠，也可能彼此替代。其头部外观类似鹃鵙，与黑嘴塚雉或红嘴塚雉明显不同。红橙色腿是区分它与体型相近鸟类的重要特征。","protection":"IUCN：LC（无危）。虽然总数量估计在10,000至1,000,000只之间，但近年来估计已降至670至67,000只，且数量正在下降。主要威胁是栖息地的转换和退化，以及人类对蛋的密集采集和对成鸟的猎杀。在人类人口稀少的地区，物种被认为是安全的，但在人类人口较多的地区，猎人迅速将其消灭。","distribution":"主要分布于新几内亚北部和东南部，以及印尼亚彭岛（鸟头湾，新几内亚西北部）。在伊里安查亚（西新几内亚）广泛且常见，例如在霍姆博尔特湾周围。","other":"褐领塚雉在法律上受到印度尼西亚的保护。"},{"name":"斑塚雉","english_name":"Malleefowl","scientific_name":"Leipoa ocellata","overview":"斑塚雉（英文名：Malleefowl，学名：Leipoa ocellata），是鸡形目冢雉科斑眼塚雉属的鸟类。大小类似家鸡。以雄鸟构建的大规模巢丘和雏鸟孵化后的缺乏亲鸟照料而闻名。斑塚雉是Leipoa属下的唯一现存物种。","appearance":"斑塚雉体长约60厘米，雄鸟体重2000至2800克，雌鸟体重1520至2050克。其特征为灰褐色的羽毛，上有黑色、白色和栗色条纹，头部扁平，颈部灰色，胸部灰色，背部和尾部有强烈的斑点图案，用于伪装。雌鸟比雄鸟略小且轻。虹膜呈榛色至棕色，眼周皮肤蓝色到暗灰色，喙蓝角至黑色，腿和脚蓝灰色至黑褐色。幼鸟外观与成年相似但体型较小，幼雏为灰褐色，背部有奶油色条纹。","call":"斑塚雉最常听到的是领地叫声，通常在靠近巢丘附近发出，由雄鸟发出响亮的轰鸣声，被描述为“uh-uh-uh-oome-oome-oome”，最多重复五次，可远达800米。有时雄雌会合唱，雌鸟以高音的‘waugh waugh’回应雄鸟的轰鸣。","habits":"斑塚雉栖息于半干旱地区的温带林地和灌木丛，尤其是多茎的Mallee桉树植被区，年降雨量在300至430毫米之间。它们在食物丰富的巢丘周围活动，雄鸟几乎全年都在维护巢丘，有时每小时都会返回巢丘。斑塚雉主要以种子为食，但也吃昆虫和其他无脊椎动物。","breeding":"斑塚雉在三月至五月开始建造巢丘，但更常见的是六月至八月。它们通常是单配的，拥有强大的配偶关系，持续至少六年。雄鸟主要使用树叶、树枝、树皮、碎片和沙子建造巢丘，巢丘高度可达60至75厘米，直径270至450厘米。雌鸟在一个季节内通常产卵15至24枚，间隔平均为6.4天，孵化期平均为62至64天。","identification":"斑塚雉是Megapodidae家族中最独特的物种之一，以其淡色、图案化的羽毛和扁平的冠饰而著称。与其他冢雉科成员相比，其巢丘建造和维护的复杂性以及特定的叫声是识别的关键。","protection":"IUCN：VU（易危）","distribution":"斑塚雉分布在澳大利亚西南部至新南威尔士州中东部，主要集中在三个独立的群体：默里-默伦比吉河盆地、斯宾塞湾以西沿辛普森沙漠边缘以及西澳大利亚州肥沃西南角的半干旱边缘。","other":"斑塚雉面临的主要威胁包括栖息地破坏、放牧影响、火灾和外来掠食者的引入。"},{"name":"塚雉","english_name":"Maleo","scientific_name":"Macrocephalon maleo","overview":"塚雉（英文名：Maleo，学名：Macrocephalon maleo），是鸡形目冢雉科苏拉塚雉属的鸟类。又名: 冢雉、苏拉冢雉、苏拉威西冢雉、西里伯斯大头鸡或营冢鸟，印度尼西亚特有的一种大型地栖鸟类。体型庞大，体长可达55厘米，拥有黑色的羽毛、突出的黑色盔状冠和明显的玫瑰粉色下腹部。分布在苏拉威西岛和Butung岛，偏好低地和山地森林，尤其在接近沙滩或火山砂地的地区繁殖。塚雉以独特的地下孵化方式著名，利用地热或太阳热能孵化其巨大的卵。","appearance":"塚雉是一种大型的黑色地栖鸟类，体长约55厘米，体重雄鸟1365至1622克，雌鸟1430至1758克。头部黑色，带有白色的喉咙，具有一顶黑色的绒毛状冠。面部皮肤裸露，颜色为黄色至蓝黄色。喙粗壮，颜色从橙红到灰蓝。下腹部呈现变化强度不一的鲑鱼粉色彩，大腿黑色，有时被腹部羽毛遮盖。雌鸟体型略小，下体颜色更浅。幼鸟头部大部分为棕色，有短黑褐色的冠，上体颜色更偏棕色，缺乏黄色面部皮肤。","call":"塚雉一般沉默，但偶尔会发出响亮的、类似气泡沸腾的“waow”声。","habits":"塚雉栖息在低地和山地森林，靠近沙滩或火山砂地繁殖。它们成对活动，白天在地面觅食，夜间在树上栖息。食物包括落果、种子、昆虫和其他无脊椎动物。塚雉偏好在沙质或火山土壤中孵化卵。","breeding":"塚雉全年均可繁殖，但在北苏拉威西，高峰期为10月至次年4月。它们通常在沙滩或火山加热的地区挖掘深达100厘米的洞穴，以地热或太阳能孵化卵，孵化期为62至85天。雌鸟每年可能产10枚卵，最多可达30枚。幼鸟自孵化后即独立。","identification":"塚雉的显著特征包括其大型的体型、黑色的羽毛、突出的黑色冠和玫瑰粉色的下腹部。与其他冢雉科鸟类相比，其独特的孵化方式和生活习性也是重要的辨识点。","protection":"IUCN：CR（极危）。总数量估计为8000至14000只，且正在减少。","distribution":"主要分布在印度尼西亚的苏拉威西岛和Butung岛（位于苏拉威西东南部）。","other":"塚雉的巢穴可能受到人类、猪、蜥蜴和过去鳄鱼的捕食威胁。在野外已知寿命至少可达23岁。"},{"name":"摩鹿加塚雉","english_name":"Moluccan Megapode","scientific_name":"Eulipoa wallacei","overview":"摩鹿加塚雉（英文名：Moluccan Megapode，学名：Eulipoa wallacei），是鸡形目冢雉科摩鹿加塚雉属的鸟类。小型冢雉，约31厘米长。其体色橄榄棕色，腹部蓝灰色，尾羽基部白色，虹膜棕色，面部裸皮粉色，喙蓝黄色，腿深橄榄色。背部有红褐色羽毛上带有灰色条纹。幼鸟具棕色羽毛，黑色喙，腿部和榛色虹膜。该物种为印度尼西亚特有种，分布于摩鹿加群岛的山林地带。","appearance":"摩鹿加塚雉体长约31厘米，雄雌相似，体色橄榄至棕色，腹部呈现灰蓝色调，尾下覆羽纯白。虹膜颜色由浅至深棕，喙色绿至黄，面部裸露皮肤呈淡粉至暗肉色，腿和脚为深橄榄色。翅膀上的中覆羽和大覆羽尖端呈灰色，与背部红褐色形成对比。幼鸟外观类似成鸟，但头部羽毛更密集。","call":"夜间发出响亮的领域二重奏，包括‘ki-ouw kouw, kou - kouw - kouw - kouw’的叫声，其中第一个音节比后面三个更长，有时会被省略。","habits":"生活在摩鹿加群岛的低地到山区森林，高度范围700至1950米，偶尔下至海岸沙滩产卵。在石灰岩环境中可能更为常见。夜间前往特定海滩产卵，通常在明亮的夜晚活动频繁。","breeding":"繁殖期从9月至12月在Buru岛，而在北Halmahera岛的高峰时间为3月至5月。采用群居筑巢方式，利用太阳加热的沙滩或火山土壤作为巢穴，深度可达50至100厘米。每只雌鸟能每月产下一枚蛋，有时间隔10至16天。孵化期受温度影响，野外数据未知，但圈养条件下大约97至101天。雏鸟出生时下体棕色，上体带斑纹，类似成鸟。","identification":"与暗色塚雉和橙脚塚雉相比，摩鹿加塚雉体型较小，颜色较浅，没有明显的冠羽，面部皮肤颜色偏淡。","protection":"IUCN：VU（易危）","distribution":"分布于摩鹿加群岛北部和中部，包括Halmahera、Buru、Seram、Ambon、Ternate、Haruku和Bacan，以及西巴布亚省的Misool岛。","other":"摩鹿加塚雉的巢穴常受到人类过度采集的威胁，特别是在产卵高峰期。此外，蛇、巨蜥、猫、猪、野狗和鼠类会捕食鸟蛋，而白腹海雕等猛禽捕食幼鸟。"},{"name":"汤加塚雉","english_name":"Tongan Megapode","scientific_name":"Megapodius pritchardii","overview":"汤加塚雉（英文名：Tongan Megapode，学名：Megapodius pritchardii），是鸡形目冢雉科塚雉属的鸟类。又称波利尼西亚塚雉或Niuafo'ou塚雉，以暗灰色为主色调，带有一抹红棕色翅膀和背部，拥有亮黄色的腿脚和橙色喙，头顶白色羽冠，眼周及喉部裸露皮肤血红色。主要分布在太平洋中的Niuafo'ou岛，是汤加群岛唯一的塚雉。该物种因独特的地热孵卵习性和脆弱的生存状态而受到关注。","appearance":"体型丰满，主要地面活动，身长28至35厘米，体重在315至500克之间，雄雌相似。全身暗灰，翅膀和背部泛红棕色。头部深灰，有白色羽冠，眼睛周围和喉咙处有血红色裸露皮肤。嘴黄色，虹膜棕色，腿脚鲜黄。雌鸟的腿略淡，但差异有时不明显。雏鸟颜色较暗，具褐色和黑色条纹，无白色翼斑，腿脚呈棕色或绿色。","call":"叫声独特，最常听到的是响亮的哨音和尖锐的啼鸣，通常由群体合唱，包括三音节的‘kway-kwee-krrrr’哨声，以及‘kreek’的警报声。在领地争夺时发出低沉的颤音，雌鸟在筑巢地或接近巢穴时会发出低沉的‘coo’声。","habits":"栖息于成熟林地，偏好火山湖岛屿。在Niuafo'ou岛，常见于各种阶段的阔叶林，包括椰子树、tavahi和芒果树林，以及密闭成熟的森林。利用地热孵卵，偏好陡峭的林区，尤其是火山口内部斜坡，有大量松散的火山灰。以动物性食物为主，包括昆虫、陆生蜗牛、蜈蚣和蠕虫，偶尔食用Syzygium果实。","breeding":"全年繁殖，高峰期在4月至5月，最少在1月和2月。单配偶制，领域性强，每对鸟占据平均0.84公顷的领地。雌鸟每年可产12至16枚卵，间隔14至32天产一枚。卵在约90至150厘米长的土洞中孵化，温度控制在29℃至38℃，孵化期47至51天。新孵化的雏鸟长度12至13.5厘米，重40至51克。","identification":"与无斑田鸡相似，但后者上体暗棕色，下体灰黑色，体型较小。汤加塚雉是其分布范围内唯一的一种塚雉，因此容易识别。","protection":"IUCN：VU（易危），数量持续下降。主要威胁是过度采集卵和野猫捕食。曾经在Niue岛上存在，但人类定居后迅速灭绝。","distribution":"仅限于Niuafo'ou岛（汤加西北部，波利尼西亚中南部），曾引入至Tafahi岛（汤加东北部），但已消失。最近引入至Late和Fonualei岛（汤加北部），Fonualei岛上估计有300至500只成鸟。","other":"政府计划在Niuafo'ou建立石油储存设施，可能对物种造成毁灭性影响，但项目可能被放弃。正在进行行为、栖息地需求和种群规模的研究。建议措施包括建立额外种群（通过移植卵）以防止Niuafo'ou种群的灭绝或大幅减少。"},{"name":"马岛塚雉","english_name":"Micronesian Megapode","scientific_name":"Megapodius laperouse","overview":"马岛塚雉（英文名：Micronesian Megapode，学名：Megapodius laperouse），是鸡形目冢雉科塚雉属的鸟类。体型丰满、主要栖息于地面。其特征为长而黄褐色的腿、深黑色的身体、高耸的淡灰色冠羽、黄色的喙以及血红色的颈部。广泛分布于太平洋西部岛屿，适应性强，常见于森林、椰林、海岸灌木丛等地。鸣声响亮，常发出尖锐的‘KEEK... KEEK KEEK’叫声。","appearance":"体长约28至30厘米，雄鸟体重约275至291克，雌鸟400至455克。体型最小的冢雉之一，具有短而灰白的冠羽，全身主要呈黑褐色。虹膜橙棕色至深棕色，腿呈黄色到黄褐色。雄鸟的喉部皮肤可能比雌鸟更红；性别间其余特征相似。幼鸟体色较棕色，翼覆羽带锈色边缘，腿部红棕色。senex亚种体型较小，跗跖较长，体色更深，冠羽更浅，虹膜金黄色至棕黄色，喙基部颜色较暗。","call":"最常听到的是雄鸟领地叫声，响亮而刺耳的‘keek...keek keek’，后两个音节下降且较弱；全年早晚皆可听见，常被附近雄鸟回应。雌鸟的叫声由6至9个较短但上升的‘kek’音节组成，随后短暂停顿，然后是一个较长、更响亮的‘keek’。","habits":"栖息于石灰岩区的森林、椰林、海岸灌木丛和海滩附近的森林地带。频繁地在岛屿间移动，有时跨过几公里的海域。以蜘蛛、昆虫（包括鳞翅目和鞘翅目幼虫）、种子、植物碎片、小果实、蜗牛和蚂蚁为食，也会摄入一些砂砾。通常成对在森林地面上的土壤和落叶层中觅食。","breeding":"依赖地热或太阳能加热的巢穴或堆筑大土丘产卵。繁殖季节可能全年或几乎全年，高峰期在9月至次年2月。雌鸟单独挖掘巢穴，雄鸟有时陪伴。巢穴深度一般在48至94厘米之间。在senex亚种中，双方共同参与堆筑高达100至200厘米、直径200至600厘米的土丘。","identification":"与其他冢雉相比，体型最小，具有独特的灰白色冠羽和血红色颈部。不同亚种间存在差异，如senex亚种的叫声更低沉。","protection":"IUCN：NT（近危）","distribution":"分布于帕劳（西卡罗琳群岛）、北马里亚纳群岛和关岛（关岛已灭绝）。在帕劳的某些岛屿上较为常见，但在较大的火山岛上罕见。北马里亚纳群岛的Saipan岛北部岛屿、Farallon de Medinilla岛、Aguiguan岛等也有分布。","other":"面临的主要威胁包括栖息地破坏、非法采集鸟蛋、引入的捕食者（如野猪、蜥蜴）和人类活动的影响。"},{"name":"尼柯巴塚雉","english_name":"Nicobar Megapode","scientific_name":"Megapodius nicobariensis","appearance":"尼科巴塚雉是一种体型较大的鸟类，体长37至43厘米，雄鸟体重在595至907克之间，雌鸟体重在850至1021克之间。雄雌羽毛和大小相似，但物种存在灰色和橄榄色两种形态，以及介于两者之间的形态。橄榄色形态在雄鸟和幼鸟中较为常见。头部较灰，具有一顶赤褐色的冠羽，面部皮肤裸露呈红色。幼鸟头部和颈部为棕色，缺乏红色面部皮肤，下体大部分为红棕色。Abbotti亚种上部和下部颜色更深，尤其是在初级飞羽上，可能体型略小。","call":"尼科巴塚雉的叫声包括领地鸣叫，由雄鸟独自发出，声音响亮且传播远，持续约3.5秒，有时被形容为类似牛蛙的声音。两性在构建巢穴时会发出喉咙颤动的'woubwoubwoub'声和快速的一系列'uhk'音符。接触叫声为响亮的'kuk-a-kuk-kuk'声。它们经常在夜间鸣叫。","habits":"尼科巴塚雉栖息于沿海森林的密林下层，包括干燥落叶林和常绿森林，以及Areca、Casuarina和Pandanus的次生林。它们主要在海岸边的沙滩上繁殖，特别是在高于高潮线的地方；有时也会向内陆移动。它们以蜗牛、种子、其他植物物质、昆虫等为食，已记录的食物包括Scarabus plicatus甲虫和Helicina zelebori蜗牛。它们还会吞食沙子和鹅卵石帮助消化食物。在圈养条件下，幼鸟以白蚁为食。它们成对或家庭群落嘈杂地觅食，有时多达6至30个个体。","breeding":"尼科巴塚雉可以在一年中的任何时候繁殖，但主要限制在旱季（11月至次年4月）。它们是单配性的。它们建造土丘作为巢穴，由沙子、树叶、珊瑚碎片和植物物质构成，高度可达240厘米，但通常高达180厘米，宽度超过10米，周长可达18米。一些土丘较低（小于100厘米）且较平坦，建在大树的根部或腐烂树桩周围或下方。蛋可以在一天中的任何时候产下，一对鸟共同挖掘巢穴。一个土丘中最多可发现20枚蛋，可能由多个雌鸟所产；平均每个土丘有两对鸟。雏鸟出生时全身为烟灰色，体重约55克。","identification":"尼科巴塚雉与菲律宾塚雉较为相似，但下面更偏棕色，颜色更浅，腿和脚为绿色至红褐色。Abbotti亚种颜色更深。雄鸟和雌鸟在外表和大小上相似，但存在灰色和橄榄色形态，以及介于两者之间的形态。","protection":"IUCN：VU（易危）","distribution":"尼科巴塚雉仅分布在印度的尼科巴群岛，包括Tillangchong、Bompuka、Teressa、Camorta、Trinket、Nancowry、Katchal、Meroe、Trak、Treis、Menchal、Little Nicobar、Kondul、Great Nicobar和Megapode Island等岛屿。","other":"尼科巴塚雉受到狩猎和栖息地破坏的威胁，特别是在经济开发加剧的地区。2004年的海啸导致两个岛屿上的种群灭绝，对其他几个岛屿的种群数量造成减少。"},{"name":"菲律宾塚雉","english_name":"Philippine Megapode","scientific_name":"Megapodius cumingii","overview":"菲律宾塚雉（英文名：Philippine Megapode，学名：Megapodius cumingii），是鸡形目冢雉科塚雉属的鸟类。分布于菲律宾、东北部婆罗洲和苏拉威西岛，其自然生境涵盖亚热带或热带的干燥森林、湿润低地森林以及湿润山地森林。物种以采集者Hugh Cuming的名字命名。","appearance":"菲律宾塚雉拥有棕色背部，蓝灰色腹部，眼部周围有裸露的红色皮肤。体长介于31至44厘米之间，头部短小，翅膀呈棕色，下部为灰色，喙为黄色。幼鸟与成鸟相似，但在眼周有更密集的羽毛覆盖。","call":"菲律宾塚雉在早晨和下午频繁发出哀怨的啼鸣，夜间也非常活跃。其叫声被描述为“whaoooo .......whaoooo.....whaooooooo”的哭泣声，持续时间长达4至5秒，节奏类似快艇引擎的快速节拍。","habits":"栖息于丘陵和山区的森林地带，海拔高度从250至2100米。也会出现在海滩森林、沿海灌木丛甚至农田区域。主要以各种昆虫（包括甲虫和白蚁）、蠕虫、蜗牛、水果和种子为食。通常通过快速奔跑穿过茂密的植被逃避危险。","breeding":"可能全年在沙巴繁殖，菲律宾北部的繁殖记录显示在3月、5月、11月和12月有产卵活动。一夫一妻制，但雌鸟通常单独访问产卵地点。在北婆罗洲、塔劳群岛和菲律宾大部分地区为筑巢者，而在苏拉威西岛和菲律宾的部分地区（如巴拉望岛、内格罗斯岛、班乃岛）则在腐烂的树根或大树（尤其是Alstonia ranvolfia）的树桩下挖掘巢穴。","identification":"与尼科巴塚雉相似，但颜色更深，下方和头部一般呈灰色。虹膜通常是棕色，但在苏拉威西岛（cumingii）偶尔呈橙黄色，或在棉兰老岛（pusillus）为金棕色。面部皮肤通常为红色，在雄鸟中更亮，但在幼鸟中较淡。","protection":"IUCN：LC（无危）。总数量可能约为6700至67,000只，但数量似乎正在下降。菲律宾本地已变得较为罕见，受到蛋收集、狩猎压力的影响，以及人类活动导致的栖息地丧失。","distribution":"分布在远东和澳新界的菲律宾、婆罗洲和印尼苏拉威西岛。在菲律宾，主要在海岸附近繁殖，偶尔在内陆地区也有记录。","other":"历史上曾被归入暗色塚雉，与尼科巴塚雉关系密切。遗传研究支持其与塔宁巴塚雉的紧密关系。"},{"name":"苏拉塚雉","english_name":"Sula Megapode","scientific_name":"Megapodius bernsteinii","overview":"苏拉塚雉（英文名：Sula Megapode，学名：Megapodius bernsteinii），是鸡形目冢雉科塚雉属的鸟类。拥有明显羽冠，体色统一的红褐色，腿脚橙红。分布于印尼的邦盖群岛和苏拉群岛，栖息于低地森林和沿海灌木丛中。叫声独特，起始响亮后渐弱。","appearance":"苏拉塚雉体型略胖，似鹑鸡，羽毛均匀呈红褐色，具短而尖的羽冠，腿部和脚橙红色。雌雄外观相似，幼鸟色彩偏黄，腿黑。体长介于30至35厘米。","call":"叫声爆发式，开始强烈后减弱，有时夹杂气泡音，常见于清晨和黄昏。","habits":"栖息于低地森林、海岸灌木丛和竹林，海拔最高可达450米。常以对或小群体出现，适应多种生境，包括农业边缘的密灌丛。","breeding":"筑巢于沙土或粘土中，可能独占巢区，巢形多样，蛋需约两个月孵化。繁殖季节从十月开始，可能更早。","identification":"与菲律宾塚雉的区别在于下体颜色与上体相似，胸部棕色，腹部红褐色，虹膜棕色，眼周皮肤灰黑至棕黑色，腿脚橙红或红色。","protection":"IUCN：VU（易危）","distribution":"分布于印尼的邦盖群岛和苏拉群岛，包括苏拉威西东侧岛屿。","other":"历史系统学上曾被归入暗色塚雉，现今被认为是单型种。"},{"name":"塔岛塚雉","english_name":"Tanimbar Megapode","scientific_name":"Megapodius tenimberensis","appearance":"塔宁巴塚雉体长介于35至47厘米之间，具有非常短的尖端颈背冠羽。其羽毛主要是棕橄榄色，背部更偏栗色，腹部呈炭灰色；喙部颜色较浅，眼睛周围的裸露皮肤为红色；腿部为黑红色。与橙脚塚雉相比，它的冠羽更短，尾巴比例上更短，下体羽毛略显淡色，臀部和尾巴缺乏栗色；与暗色塚雉相比，其羽毛为灰棕色（而非黑色），腿部为黑红色（没有绿色或黄色的痕迹），翅膀较长。雌雄相似，幼鸟信息较少。","call":"发出一系列悲伤的‘kwak-kwak-kwak’或‘kuu-kull-kuu’音符，间隔短而规律。二重奏表演常见，声音响亮且传播远：第一只鸟（推测为雄鸟）以高音的‘kee-yu’开始，随后是一系列五个稍低音调的短促‘keyu’音符；在第一个音符之后，有时在整个叫声之后，第二只鸟会发出一系列七个上升的‘kwou’音符，持续约4秒，这一系列音符会在不同间隔（几秒到几分钟）重复。","habits":"塔宁巴塚雉栖息在低地森林地面，以种子、落果和陆生无脊椎动物为食。它们在沙子、落叶和其他碎屑构成的大土堆中筑巢，利用有机物质分解产生的热量孵卵。","breeding":"关于繁殖的数据很少，已知它们是土堆筑巢者。","identification":"塔宁巴塚雉与其他冢雉科成员的区别在于其独特的外形和叫声，特别是在与和的比较中，其冠羽、羽毛颜色和叫声都有明显差异。","protection":"IUCN：VU（易危）。全球估计数量在1000-10,000个个体之间，相当于大约670-6700个成熟个体。由于栖息地退化、转化以及过度猎捕和采集鸟蛋，该物种的数量被认为正在减少。","distribution":"分布于澳新界的塔宁巴尔群岛（印尼摩鹿加群岛南部），主要在Yamdena岛上广泛但稀疏地分布于低地。","other":"塔宁巴塚雉有时被认为是橙脚塚雉的亚种。"},{"name":"暗色塚雉","english_name":"Dusky Megapode","scientific_name":"Megapodius freycinet","appearance":"暗色塚雉具有中等大小的体型，体长约为41厘米（16英寸），全身覆盖着均匀的黑褐色羽毛。头部有明显的冠羽，腿脚呈黑色至暗绿色橄榄色。雌雄两性在外表上几乎无法区分，幼鸟比成鸟略显暗淡，面部羽毛更加完整。成年鸟的羽毛边缘呈现出暗铅灰色，赋予头部和身体一抹蓝灰色调。额头和眼窝周围裸露，仅覆盖有短而黑的刚毛状羽毛，耳羽稀疏。头顶后部（枕部）的羽毛有时会略微延长，形成短而宽的冠羽，冠羽尖端稍有指向性，但其形态从明显到几乎不存在都有变化。","call":"暗色塚雉经常发出的歌声是一声响亮上升的哨音“keey-keey”，有时后跟着较为柔和、下降、波动的“kwolooooor”。成对的鸟通常会合唱。","habits":"暗色塚雉栖息于低地森林，最常在地面单独或成对觅食。它在石灰岩丘陵森林中出现的高度范围从大约100米到450米，记录显示它在巴干岛可高达600米。在米苏尔岛上，该物种既在海滩附近繁殖，也在内陆深处繁殖。与福尔斯特塚雉相比，暗色塚雉更频繁地出现在较湿润的生境中。","breeding":"暗色塚雉在土壤、树叶、沙子、砾石和树枝混合而成的大土堆中筑巢产卵，土堆直径可达11米，高度近5米。关于繁殖的其他详细信息目前尚未提供。","identification":"暗色塚雉与福尔斯特塚雉的区别在于后者头部皮肤颜色更鲜艳，拥有明显的肉垂和头冠。在瓦伊盖奥岛上，它与瓦伊盖奥刷鸡的区别在于后者头部颜色更鲜亮、脸部有肉垂和头冠。与橙脚塚雉相比，暗色塚雉的颜色更深，头部皮肤颜色不是黄色或橙色，尾巴相对较短，但跗跖、趾和爪较长。","protection":"IUCN：LC（无危）","distribution":"暗色塚雉分布在印尼摩鹿加群岛北部、中部以及四王群岛（位于新几内亚西北部）。在这些岛屿群中，它们在红树林、沼泽林地和萨果沼泽的边缘以及湿地常绿森林的低地生活，通常海拔低于300米，但在瓦伊盖奥岛可达400米。在哈马黑拉岛，暗色塚雉在石灰岩丘陵森林中被发现的高度范围从约100米到450米，巴干岛的记录显示它可高达600米。","other":"暗色塚雉曾被一些权威机构归入其他几种塚雉，如尼科巴塚雉、菲律宾塚雉、苏拉塚雉、瓦努阿图塚雉、新几内亚塚雉、比亚克塚雉、红斑塚雉和橙脚塚雉。然而，现在它被普遍认为是一个独立的物种。"},{"name":"比岛塚雉","english_name":"Biak Scrubfowl","scientific_name":"Megapodius geelvinkianus","overview":"比岛塚雉（英文名：Biak Scrubfowl，学名：Megapodius geelvinkianus），是鸡形目冢雉科塚雉属的鸟类。分布于印尼西巴布亚地区的Biak、Mios Korwar、Numfor、Manim和Mios Num等岛屿上，拥有暗灰色的羽毛，面部呈红或蓝色，腿部颜色为红色或深灰色。在森林和受扰动的生境中活动。","appearance":"比岛塚雉体长约36厘米，体重可达525克，属于中等体型的塚雉。全身羽毛主要是深灰棕色，背部带有橄榄色的色调。脸部颜色为红或蓝，腿色为红或深灰。头部后方有轻微的冠羽，有时末端呈尖状，但并不常见。与相似物种暗色塚雉相比，比岛塚雉的后身略显淡一些，上方更偏向暗褐色橄榄色，喉咙和颈部的羽毛较少，且冠羽形状有所不同。","call":"比岛塚雉的叫声多样，以鹦鹉般的尖叫为主，最常听到的叫声是由两声不成调的吠叫组成，类似于斑喉塚雉的叫声，第一声高于第二声。","habits":"生活在初级森林、次生林、干燥灌木丛和被伐过的森林中，也会在靠近河流的灌木丛中活动。它用大脚在森林地面刮擦，以寻找无脊椎动物为食。通常听到其声音比看到它的机会更多。","identification":"与暗色塚雉相比，比岛塚雉在后身颜色、喉咙和颈部羽毛覆盖程度以及冠羽形状上有细微差异。","protection":"IUCN：NT（近危）。估计成熟个体数量在2500至9999之间，总个体数约3500至15000。由于栖息地丧失和退化，加上狩猎压力，数量可能正在中等速率下降。","distribution":"分布于印尼西巴布亚的Biak、Mios Korwar、Numfor、Manim和Mios Num等岛屿，位于新几内亚西北部的鸟头湾附近。","other":"曾被认为是暗色塚雉或橙脚塚雉的亚种，但现在普遍认为是独立的物种。"},{"name":"瓦努阿图塚雉","english_name":"Vanuatu Megapode","scientific_name":"Megapodius layardi","overview":"瓦努阿图塚雉（英文名：Vanuatu Megapode，学名：Megapodius layardi），是鸡形目冢雉科塚雉属的鸟类。大型地栖鸟类，体大头小，腿长。其显著特征为鲜亮的黄色腿脚、红色面部皮肤、全黑色圆润身躯和橙色喙。该物种仅见于瓦努阿图，栖息于低地森林或灌木丛，偶尔在火山加热区域或海岸边繁殖。","appearance":"瓦努阿图塚雉体长约42至45厘米，全身深棕色或铅黑，头部和颈部裸露皮肤较多，额头和面部有广泛的粉红至红色裸露皮肤，虹膜呈棕色，喙为淡黄色，腿脚鲜黄。两性相似，但幼鸟颜色较暗淡，腿脚和喙呈褐色，随着成长逐渐变为黑色，同时面部皮肤转为鲜红色，腿脚变黄。","call":"瓦努阿图塚雉在黎明和黄昏时特别活跃，发出响亮且远传的咕噜声和类似鸡的咯咯声，双音节的‘took-tooorrr’叫声，持续约4至5秒，第二部分音量渐增，常以雄雌二重奏形式出现。喂食时也会发出柔和的叫声。","habits":"瓦努阿图塚雉主要生活在低地森林或灌木丛的地面，也能在海拔高达800米的地带发现。它们似乎比其他同类更耐受环境退化，能在花园和退化的森林中生存，尽管密度较低。它们偏好在危险面前奔跑而非飞行。以昆虫、虫蛹、蠕虫、蜗牛和其他无脊椎动物为食，也吃果实、种子等植物物质。","breeding":"瓦努阿图塚雉全年均可繁殖，尤其是在6月至8月期间更为常见，可能为一夫一妻制。在腐朽树根间、火山加热土壤中的大型公共繁殖地或阳光曝晒的海滩上挖掘巢穴，巢穴深度30至200厘米，长度可达200厘米。每窝产卵20至100枚，孵化期超过45天，雏鸟孵化时体重约60克，呈淡黄褐色，上有深色条纹。","identification":"瓦努阿图塚雉与其它同类相比，头部和颈部裸露皮肤更多，腿脚颜色鲜明，无相似物种共存于瓦努阿图。与引进的红原鸡雏鸟和雌鸟个体在羽色模式和腿脚颜色上有所不同。","protection":"IUCN：LC（无危）。总数量估计最多约10,000只，被认为正在减少。在某些岛屿的繁殖地和一般栖息地受到农业扩张和发展威胁，如埃法特岛。森林砍伐和家畜放牧亦构成潜在威胁。长期收集鸟蛋和当地人的机会性狩猎对物种造成影响，需要有效保护措施以确保其长期生存。","distribution":"瓦努阿图塚雉分布在托雷斯群岛至埃法特岛（北至瓦努阿图中南部）。","other":"瓦努阿图塚雉的蛋和雏鸟被当地人捕捉食用，但历史上只限于最易接近的繁殖点，主要是为了本地消费而非商业利益。"},{"name":"斑喉塚雉","english_name":"New Guinea Scrubfowl","scientific_name":"Megapodius decollatus","overview":"斑喉塚雉（英文名：New Guinea Scrubfowl，学名：Megapodius decollatus），是鸡形目冢雉科塚雉属的鸟类。分布于新几内亚北部至东南部，包括亚彭岛（鸟头湾，新几内亚西北部）、Tarawai和Manam（新几内亚东北部北部）。其显著特征包括暗灰色下体和颈部，深棕色背部与翅膀，黑色腿脚，红色面部或喉咙，黄色喙，以及头部后方显眼的尖顶冠羽。","appearance":"斑喉塚雉长约33-35厘米，雄鸟体重约715克，雌鸟体重介于550-692克。两性基本相似，拥有相对较长的顶冠；下体颜色从灰褐色到橄榄褐色不等；腿脚颜色为深橄榄绿或黄褐色至黑色；虹膜颜色从浅到深棕。幼鸟似成鸟，但次级飞羽部分带有黑和淡色条纹。半岛东部（Wau）的个体上体颜色更深。","call":"雄鸟开始二重奏鸣叫，先发出上升的“kok, nyacal, nailleue”声，逐渐变为高音尖叫，随后另一鸟加入，发出断续的“nu-nu-nu-nu-nu”声。这种叫声白天和夜晚都有，尤其在月夜更为常见。","habits":"斑喉塚雉生活在雨林中，从海平面至海拔2100米，有时甚至高达2950米（Huon半岛，新几内亚东北部）。它们在Sepik河沿岸的沼泽森林中筑巢繁殖，与肉垂塚雉和Talegalla (?) jobiensis共存，有时在同一区域内繁殖。","breeding":"斑喉塚雉全年均可产卵，已知记录包括2月、3/4月和10月。在高地地区，繁殖季节可能在1月至5月的旱季。它们是筑巢者，严格的一夫一妻制，成对保持在巢堆附近，甚至夜间也不离开。巢堆高度约90厘米，直径360-600厘米，可能被四对鸟共用，持续使用时间可达13年。一年内，单个巢堆最多可产28枚蛋或孵化28只幼鸟。","identification":"斑喉塚雉比红腿灌丛雉小，且腿脚颜色较暗。与橙脚塚雉相比，后者具有橙红色腿脚，红棕色上体，缺乏喉部羽毛，且尾巴更长。","protection":"IUCN：LC（无危）。总数量估计为6700至670,000只，被认为稳定。在印尼西新几内亚广泛且常见。威胁包括栖息地退化和转化。在印尼受到法律保护。没有圈养记录。","distribution":"分布于新几内亚北部至东南部，包括亚彭岛（鸟头湾，新几内亚西北部）、Tarawai和Manam（新几内亚东北部北部）。在繁殖季节，它们广泛分布在这些区域内的雨林和沼泽森林中。","other":"斑喉塚雉被认为会寄生在肉垂塚雉和褐领塚雉的巢堆中，尽管在东新几内亚的一个特定地点，没有证据显示前者与斑喉塚雉共享巢堆。"},{"name":"橙脚塚雉","english_name":"Orange-footed Scrubfowl","scientific_name":"Megapodius reinwardt","overview":"橙脚塚雉（英文名：Orange-footed Scrubfowl，学名：Megapodius reinwardt），是鸡形目冢雉科塚雉属的鸟类。原生于小巽他群岛、新几内亚南部和北部澳大利亚。类似家鸡大小的陆栖鸟类，深色羽毛，拥有醒目的橙色腿和头部后方的尖顶冠羽。在达尔文郊区花园中常见，当地人称之为丛林鸡或丛林火鸡。","appearance":"成年橙脚塚雉体型介于30至47厘米，体重雄鸟851至1200克，雌鸟550至1200克。其外观特征为长而尖锐的冠羽，大部分羽毛呈橄榄灰褐色，背部带赤褐色调；腿和脚呈现橙色到粉红色；裸露的面部皮肤也是红色。雌鸟平均稍小，但羽毛与雄鸟相同。幼鸟与成鸟相似，但体型更小，有时头部颜色较浅，裸露部位色泽较暗淡，尾巴更短，上身更多肉桂色，下体通常更浅色。","call":"橙脚塚雉的叫声响亮，具有地域性变体，尤其是指名亚种种reinwardt的叫声更为复杂和悦耳。雌雄二重唱，雄鸟发出‘kli-kiau-(kiau)-kiau-kiau-kiaukiou-kle-ou’的叫声，雌鸟以高音、滚动但结巴的‘krrrrr-ukuk-uk-uk-krrrrr’回应。","habits":"栖息于热带雨林地面，亦见于城市公园和花园。主要分布在低地，但在新几内亚东南部可达1500米高度。在澳大利亚北部，它能在茂密森林、溪流旁以及离森林边缘不远处筑巢。以植物为主食，包括种子、浆果和根茎；偶尔食用幼蛇、蜗牛、蝎子、蠕虫、千足虫、蜈蚣、甲虫和其他昆虫及其幼虫。在森林地面上行走，频繁停下来在落叶中翻找食物。","breeding":"繁殖期主要在7月至3月，新几内亚东南部的繁殖高峰在雨季和雨后，即11月至次年5月；在科莫多岛，筑巢活动高峰出现在3月（湿季末期）。筑大型巢堆，由树叶、树枝、泥土或沙子构成，有时使用人类垃圾。巢堆尺寸巨大，最高可达3.5米，周长20米，温度维持在29℃至38℃之间。单个雌鸟可在一个约20周的时间内产下12至13枚蛋，间隔9至20天，孵化期约为70天。雏鸟出生时呈深红棕色，腹部中心呈黄褐色，喙呈暗褐色，腿和脚橙色。","identification":"与同类物种相比，橙脚塚雉的橙色腿和脚、尖顶冠羽和特定的叫声是辨识关键。不同的亚种在大小和颜色上有局部差异。","protection":"IUCN：LC（无危）。总数量可能在10万至100万只之间，总体稳定。在印尼广泛分布且常见，但在帝汶岛上的状况较为不明朗。在科莫多岛上，尽管受到科莫多龙和野猪的频繁捕食，但种群数量似乎稳定。","distribution":"分布于澳新界的小巽他群岛、印尼卡伊群岛（印尼摩鹿加群岛南部）、新几内亚西北部、南部、东南部以及澳大利亚北部和卫星岛屿。","other":"在一些地区，由于人类活动的压力，橙脚塚雉曾被消灭，但后来成功地重新定居。在澳大利亚，特别是在达尔文市郊，橙脚塚雉的数量有所增加，甚至在城市郊区筑巢。"},{"name":"纯色小冠雉","english_name":"Plain Chachalaca","scientific_name":"Ortalis vetula","overview":"纯色小冠雉（英文名：Plain Chachalaca，学名：Ortalis vetula），是鸡形目凤冠雉科小冠雉属的鸟类。常见于从美国德克萨斯州南部至哥斯达黎加西北部的热带和亚热带环境。在林地和灌木丛中活动，特别是在有水边的干燥和湿润森林地带。这种鸟因其独特的‘cha-cha-lac-a’叫声而得名。","appearance":"纯色小冠雉是一种中等大小的鸡形目鸟类，体长约48-58厘米，体重介于468-794克（雄鸟）和439-707克（雌鸟）之间。雄鸟和雌鸟的外观相似，拥有灰色头部和颈部，橄榄褐色的身体和翅膀。腹部颜色较淡，从浅色到赭色不等。尾巴呈黑色，带有绿色光泽和白色尖端。繁殖季节时，它们的喉咙处会显现出鲜艳的红色皮肤。虹膜为棕色，喙为黑色，眼周皮肤和脚趾为暗灰色。","call":"纯色小冠雉发出响亮、粗哑的‘RAW-pa-haw’或‘cha-cha-LAW-ka’叫声，常由几只鸟以节奏性的合唱形式在清晨和傍晚时分鸣叫，通常在树梢高处发声。它们也会发出哨声和咯咯声。","habits":"纯色小冠雉栖息于多种生境，包括原始森林、次生林、林缘、河岸森林、灌木丛和草地。它们能够适应热带雨林被清除后形成的灌木丛生地。白天大部分时间活动，尤其在清晨和傍晚较为活跃。它们通常以小群体的形式活动，最多可达15只，善于在树上或地面觅食果实、种子、叶子和花朵，有时会成为番茄和黄瓜等作物的害虫。","breeding":"纯色小冠雉的繁殖期通常在早春的雨季开始时。它们会在浓密的植被中建造浅盘状的巢，由树枝和植物纤维构成，内部铺垫着树叶。每窝产2-4枚粗糙壳质的白色至奶油色的蛋。","identification":"纯色小冠雉与墨西哥小冠雉和白腹小冠雉容易混淆，但前者体型较小，下体白色更多，尾羽白色尖端更宽。山冠雉也可能与之混淆，但其颜色更深，呈棕色，外表有条纹。","protection":"IUCN：LC（无危）","distribution":"分布于北美和中美，从美国德克萨斯州南部至哥斯达黎加西北部，包括墨西哥东部海岸、尤卡坦半岛、伯利兹、危地马拉北部、洪都拉斯北部和尼加拉瓜北中部，以及哥斯达黎加尼科亚半岛北部的小区域。","other":"纯色小冠雉在一些引入的地区被视为入侵物种，例如在美国德克萨斯州的圣帕特里西奥县和乔治亚州沿海的三个岛屿。"},{"name":"灰头小冠雉","english_name":"Grey-headed Chachalaca","scientific_name":"Ortalis cinereiceps","overview":"灰头小冠雉（英文名：Grey-headed Chachalaca，学名：Ortalis cinereiceps），是鸡形目凤冠雉科小冠雉属的鸟类。外观类似火鸡，分布于洪都拉斯东部至哥伦比亚北部，包括中美洲和南美洲的部分地区。","appearance":"灰头小冠雉身长48至58厘米，体重约490至540克。它们具有较为暗淡的羽毛，上半身为灰褐色，下半部颜色较浅。头部呈深灰色，带有红色喉囊，黑色尾羽末端点缀着淡黄色。亮栗色的一级飞羽在飞行中尤为显眼。幼鸟整体颜色偏棕色，尤其是头部。","call":"灰头小冠雉的叫声相对柔和，其歌谣式的鸣叫被描述为快速重复的“cha-cha-lac-ah”。群鸟发出嘈杂的叫声，音似“kloik, kleeuk kraahk”，缺乏规律性和同步性，有时会加速，夹杂着类似母鸡的声音。此外，它们也会发出高声尖叫、尖锐的警报声和安静的咕噜声。","habits":"灰头小冠雉偏好湿润环境中的茂密灌木丛、次生林、废弃的灌木田地、清澈开阔的森林边缘以及稀疏的森林，海拔高度从海平面到1700米。它们通常以6至12只或更多（最多报道过20只）为一群进行活动，主要在树冠层觅食，偶尔也会落地寻找食物。饮食以果实为主，约占75%，其次是叶片（16.7%）和无脊椎动物（8.3%）。在旱季，它们会在早晨和傍晚前往河流饮水。","breeding":"繁殖季节在1月至5月间，覆盖部分雨季。巢穴由树枝、树叶、草茎、藤蔓碎片和花序组成，形状为宽阔浅平的平台，建于离地面0.9至2.4米高的藤蔓缠绕的灌木、攀缘植物丛或小树上。每窝产3枚淡白色蛋，尺寸约为55.6至61.9毫米×38.1至42.5毫米。孵化期超过22天。雏鸟上部呈暗巧克力色和烟灰色，带有一些肉桂色斑点，下部为肉桂色和白色。","identification":"灰头小冠雉与其他同属物种的区别在于其灰褐色的头部和明亮的栗色一级飞羽。幼鸟的颜色比成鸟更偏向棕色，特别是在头部，这有助于区分不同发育阶段的个体。","protection":"IUCN：LC（无危）。灰头小冠雉在中美洲的种群估计有10万只，哥伦比亚额外有2万只。尽管在某些地区如洪都拉斯由于过度猎杀数量显著减少，但在尼加拉瓜仍然广泛分布且局部地区数量丰富。在哥斯达黎加，若非遭受严重猎杀则常见。在巴拿马许多地区相当普遍，尽管局部地区已减少，如伊莎德尔雷岛（珍珠群岛）和达里恩省的部分地区，因印第安人大量猎杀而数量下降。在哥伦比亚1986年仍常见。全范围内因食用而被捕猎。能够适应适度的栖息地改变，但在森林砍伐和狩猎压力双重作用下，部分地区已被彻底清除。","distribution":"分布于中美洲和南美洲，从洪都拉斯东部的Mosquitia地区，贯穿东部尼加拉瓜、哥斯达黎加大部分地区、巴拿马，直至哥伦比亚的Chocó省。在巴拿马本土及伊莎德尔雷岛（珍珠群岛）均有分布，后者可能由当地印第安人引入。在海拔从海平面到1700米的各种潮湿环境中均可见其踪迹。","other":"灰头小冠雉曾被认为与胸翼小冠雉同种，现已确认为独立物种。"},{"name":"棕臀小冠雉","english_name":"Rufous-vented Chachalaca","scientific_name":"Ortalis ruficauda","overview":"棕臀小冠雉（英文名：Rufous-vented Chachalaca，学名：Ortalis ruficauda），是鸡形目凤冠雉科小冠雉属的鸟类。古老鸟类家族Cracidae的成员，与澳洲的土堆筑巢鸟有亲缘关系。主要分布在哥伦比亚东北部、委内瑞拉北部（当地称为guacharaca）以及特立尼达和多巴哥的托巴哥岛（在当地被称作cocrico，也是该国的两种国鸟之一，出现在国家的国徽上）。此外，在格林纳丁斯的贝基亚岛和联合岛也有发现，可能系人为引入。","appearance":"棕臀小冠雉是中等体型的鸟类，外观类似火鸡，头部较小，腿长而强壮，尾部长且宽。它们通常长度在53至61厘米之间，重量从430到800克不等。整体呈深褐色，腹部灰白色，逐渐变为下体的棕色。尾羽端部在不同亚种间有差异，emruficauda/em亚种为丰富的栗色，而emruficrissa/em亚种为灰白色。雏鸟与成鸟相似，性别上并无显著差别。成年雄鸟和雌鸟的体型存在差异，雄鸟较大。","call":"发出响亮嘈杂的叫声，如同其他种类的chachalaca，通常在黎明时分最为活跃。叫声包括低沉的'OTRA MAS'和更高音调的'WATCH-a-lak'，两者的叫声会精确同步地重复多次，相邻群体也会回应。","habits":"生活在荆棘落叶灌木丛和森林较为开阔的地带，如委内瑞拉和哥伦比亚的草原。偏好靠近水源的地方，如河岸森林、河流旁或湖泊附近。常见于废弃农田、混合次生林和棕榈树丛，也能在郊区和耕地上找到，只要周围有自然植被即可。主要栖息在低地，但在委内瑞拉部分地区可高达1600米，哥伦比亚则约为900米。以水果、嫩芽和树叶为主食，已知食用29种植物，包括多种树种的果实和叶子。在旱季，水果消耗量减少。硬壳种子通常完整排出，软质食物则会被消化。","breeding":"在哥伦比亚的7月和托巴哥岛全年繁殖，高峰季节为3月至7月。维持全年伴侣关系，一夫一妻制，但领地意识不强。巢穴为篮状结构，由枝条和叶子构成，位于树上或藤蔓中，有时会利用其他鸟类遗弃的巢穴，如鸽子的巢。巢高通常在1至5米，偶尔高达25米。每窝产3至4枚蛋，新鲜时呈淡象牙色，孵化期间转为棕色，孵化期约28天。雏鸟主要呈棕色，头顶和颈背有深色条纹，下体大部分为白色，翅膀为棕色和深色条纹交错。一只仅重300克的幼鸟已经能够像成鸟一样飞行。","identification":"与栗翅小冠雉相比，棕臀小冠雉的下体颜色较浅，尾部没有栗色。不同亚种在体型、一般色调和尾尖颜色上有差异：emruficrissa/em体型略小，腹区颜色较深，尾尖为灰白色；emruficauda/em尾尖为丰富的栗色。","protection":"IUCN：LC（无危）。在哥伦比亚和委内瑞拉广泛分布且数量充足，尤其在托巴哥岛，自1962年起被宣布为国鸟，几乎占据岛上所有栖息地。飓风后农场废弃导致数量有所增加。在格林纳丁斯的贝基亚岛，最近估计有大约150对，但在联合岛的数量可能更少。虽然适应性强，能在农业和郊区生存，但也需要附近的茂密植被或森林。","distribution":"南美洲的哥伦比亚和委内瑞拉，以及加勒比海的托巴哥岛、贝基亚岛和联合岛。","other":"尽管在收藏中不常见，但曾有人工繁殖成功。"},{"name":"棕头小冠雉","english_name":"Rufous-headed Chachalaca","scientific_name":"Ortalis erythroptera","overview":"棕头小冠雉（英文名：Rufous-headed Chachalaca，学名：Ortalis erythroptera），是鸡形目凤冠雉科小冠雉属的鸟类。以其独特的红褐色头部著称。主要分布在南美洲的哥伦比亚极西南部、厄瓜多尔西部和秘鲁西北部。该物种拥有醒目的外观特征，包括红褐色的头部和颈部，灰棕色的背部，以及奶油色的下胸和腹部。","appearance":"棕头小冠雉体长介于56至66厘米之间，体重约620至645克。其最显著的特征是红褐色的头部和颈部，背部呈灰色至棕色。中央尾羽为深灰色，而外侧尾羽近体部为灰色，外半部分为栗色。下胸和腹部为奶油白色。主要飞羽明亮的栗色。眼睛为棕色，周围环绕着暗蓝灰色的裸露皮肤。腿脚颜色为淡蓝色。幼鸟特征未详细描述，但可能与成鸟相似。","call":"棕头小冠雉的鸣声非常粗糙，常在清晨前开始，重复发出“kwak-ar-ar-ar”、“cha-cha-kaw”或更尖锐的“kra-kra-kra”叫声，通常由雄鸟发起。此外，成对的鸟还会发出柔和的咕咕声或咯咯声，以及刺耳的“cow”音和快速重复的“kawuck”声。","habits":"该物种栖息于热带沿海地带的干燥落叶林和湿润云雾林，偶尔出现在农业用地。它们在森林中层活动，最高可达1800米左右。在旱季，永久水源可能对它们很重要。主要以果实为食，已知会啄食树叶和摄食咖啡浆果、无花果、黄檀果和木棉的猫须花。群体通常由2到7只组成。","breeding":"繁殖季节疑似与雨季同步，大致在1月至5月间。圈养条件下，一窝产3枚卵，孵化期约为26至28天。雏鸟上部毛色不均匀，从锈棕色到深棕色再到黑色，下部较浅。大约6个月大时达到成年体型。","identification":"与栗翅小冠雉相比，棕头小冠雉的尾端为栗色，下胸和腹部更呈奶油色。叫声独特，明显比同类物种的叫声更慢、更简单、音调更低。","protection":"IUCN：VU（易危）","distribution":"棕头小冠雉主要分布在南美洲的厄瓜多尔西部和秘鲁西北部，少量分布于哥伦比亚极西南部。在厄瓜多尔的Sozoranga山区、Loja和El Oro有记录，以及秘鲁西北部的Tumbes国家森林等地。","other":"尽管在一些受保护区域如Machalilla国家公园和Tumbes国家森林中被发现，但栖息地破坏和狩猎仍然是主要威胁。"},{"name":"棕腹小冠雉","english_name":"Rufous-bellied Chachalaca","scientific_name":"Ortalis wagleri","overview":"棕腹小冠雉（英文名：Rufous-bellied Chachalaca，学名：Ortalis wagleri），是鸡形目凤冠雉科小冠雉属的鸟类。体型较大的热带森林鸟类，主要分布在墨西哥西部。其最显著的特征是胸腹部的红褐色羽毛和尾端的相同颜色，使其成为同属中色彩最为丰富的物种。生活在低海拔的热带落叶林、半落叶林以及沿海的红树林中。","appearance":"棕腹小冠雉体长62至67厘米，体重约834克。全身羽毛以灰褐到橄榄褐色为主，但其独特的红褐色腹部和尾羽尖端是识别的关键。眼周裸露的皮肤呈粉蓝相间色。幼鸟色泽较为暗淡，缺乏鲜明的红褐色尾羽尖端。","call":"发出响亮而有节奏的四到五个音节的合唱声，如“kirr-i-i-kr”，“chrr-i-k-rr”或“chrr-uh-uh-rr”。有时伴随更长的、同样响亮的咯咯声、哨声或低吼声。","habits":"通常以十只左右的小群体活动，觅食树上的果实。生活在低地的热带森林，包括落叶林、半落叶林和灌木林，以及沿海的红树林。海拔高度一般在1,300米以下，但也有记录显示可达2,000米。在人类严重改变的环境中也能生存。","breeding":"繁殖季节集中在6月，可能从5月持续至7月。巢筑于离地面1米高，位于大约3.5米高的带刺小树上。每窝通常产三枚白色蛋，雏鸟身上有丰富的棕色和淡黄色条纹，下部较浅，喉咙和腹部为白色。","identification":"与墨西哥小冠雉相比，红褐色的腹部和尾羽尖端是区分的关键特征。在内陆地区，可能与墨西哥小冠雉杂交。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥西北部和西部，具体而言是从南部索诺拉州南至西北部哈利斯科州。","other":"虽然在一些被人类严重改变的环境中也能找到，但其数量普遍被认为是常见或相当常见的。"},{"name":"墨西哥小冠雉","english_name":"West Mexican Chachalaca","scientific_name":"Ortalis poliocephala","overview":"墨西哥小冠雉（英文名：West Mexican Chachalaca，学名：Ortalis poliocephala），是鸡形目凤冠雉科小冠雉属的鸟类。通常以小组形式活动。其历史分类复杂，曾被认为是纯色小冠雉的亚种，或包含棕腹小冠雉为其亚种。墨西哥小冠雉具有灰褐色的上体和头部，下体白色，尾羽尖端呈奶油色。","appearance":"这种相对较大的小冠雉，上体和上胸部通常为灰褐色，头部和上颈部颜色更灰。下胸部和腹部为白色，尾下覆羽为肉桂色，尾羽尖端宽而呈奶油色。两性相似，幼鸟与成鸟相比，尾羽更为尖锐。雄鸟平均翼展248.4毫米，尾长283.2毫米；雌鸟平均翼展244毫米，尾长276毫米。","call":"其最常被通过响亮刺耳的歌声发现，这种歌声传播得很远。","habits":"墨西哥小冠雉栖息于落叶林中，活动范围广泛，既能在地面觅食，也能在高树上沿枝奔跑。它主要以果实和植物为食，警惕性高，尤其是在猎捕区域，容易从视线中消失。","breeding":"其生物学特性与其他小冠雉种类相似，具体繁殖细节未详述。","identification":"与棕腹小冠雉的区别在于后者腹部和尾羽尖端为红褐色。白腹小冠雉比墨西哥小冠雉体型更小，尾羽尖端更宽且呈白色，尾下覆羽为白色，通常出现在较低海拔。","protection":"IUCN状态未提供。","distribution":"分布于墨西哥西部和西南部，从哈利斯科州南部至恰帕斯州。","other":"与其他小冠雉种类的地理分布几乎没有重叠，不同物种在地理上互相替代。"},{"name":"查科小冠雉","english_name":"Chaco Chachalaca","scientific_name":"Ortalis canicollis","overview":"查科小冠雉（英文名：Chaco Chachalaca，学名：Ortalis canicollis），是鸡形目凤冠雉科小冠雉属的鸟类。大型鸟类，常发出响亮的叫声。全身羽毛呈单一褐色，头部和身体颜色相近，几乎无明显的冠羽。主要分布在南美洲的阿根廷、玻利维亚、巴西、巴拉圭及可能的乌拉圭地区。常见于沼泽森林、草原和次生林，群居，数量可达30只以上。","appearance":"体长50至56厘米，体重479至678克。头、颈与背部色彩差异不大，与身体其余部分融合。成鸟羽毛呈均匀的棕色，腹部颜色偏棕至灰。面部皮肤裸露，粉色或紫色。幼鸟与成鸟外观相似。亚种pantanalensis较棕色，面部皮肤更偏向紫色。","call":"清晨会发出典型的响亮‘chata-ra-ta’或‘bink, ka chee chaw raw taw, chaw raw taw, chaw raw taw’的叫声，由雄鸟发起，通常有另一只鸟以不同的音调响应。此外还有类似家鸡的‘cha-cha-cha’声和其他几种叫声。","habits":"栖息于低地沼泽森林、灌木丛、干燥的亚热带森林、半落叶林、画廊森林和棕榈树林。在成熟和次生森林中均可发现。主要以果实、种子、叶子为食，偶尔食用昆虫，尤其是毛虫。在农业区远离开阔地带觅食，有时群体可达150只。","breeding":"繁殖季节在阿根廷为10月至2月，可能在玻利维亚早至8月开始。筑巢于树上，高约2.5至4米，巢由树枝、茎叶构成，有时衬以树叶。每窝产2至4枚深奶油色蛋，孵化仅由雌鸟承担。","identification":"与纯色小冠雉相比，pantanalensis亚种更棕色，面部皮肤紫而非粉红。可通过声音、行为和分布区域加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美的阿根廷、玻利维亚、巴西、巴拉圭，可能也在乌拉圭。在巴西的潘塔纳尔地区普遍分布，在阿根廷的查科地区常见。","other":"在一些地区遭受狩猎压力，尤其是在阿根廷和玻利维亚，被当地人用于食物和运动狩猎。"},{"name":"白腹小冠雉","english_name":"White-bellied Chachalaca","scientific_name":"Ortalis leucogastra","overview":"白腹小冠雉（英文名：White-bellied Chachalaca，学名：Ortalis leucogastra），是鸡形目凤冠雉科小冠雉属的鸟类。长尾热带森林鸟类，常见于小型群体。其特征为清洁的白色腹部和白色的尾尖。与体型较大的墨西哥小冠雉相似，但其合唱般的鸣声更为柔和细腻。在奇瓦瓦州西南部，两者分布重叠区，墨西哥小冠雉栖息于山脚，而白腹小冠雉则居住于沿海低地。","appearance":"白腹小冠雉体长43-50厘米，体重439-560克。胸部棕色，与暗淡的白色腹部形成鲜明对比；面部皮肤呈深灰色。幼鸟外观与成鸟相似，但羽毛较为松散且蓬松。","call":"发出典型的粗哑、沙哑的四音节鸣叫，如“k-ku’uh-uh”或“ch-k-uh-urr”。","habits":"栖息于沼泽森林、密布椰子棕榈灌木丛的沼泽、干燥森林、牧场边缘和红树林（尤其在墨西哥和尼加拉瓜）。通常在距离地面6-10米的高度觅食，主要以浆果和水果为食，包括绿色或成熟的果实，尤其是椰子棕榈的果实，也会食用树叶、花蕾、花朵和一些无脊椎动物。","breeding":"繁殖季节较长，从三月持续到七月。在危地马拉，筑巢于树上，高度在5-20米之间，巢为简单的平台状，内部铺垫扁平的叶子。每窝产2-3枚乳白色的蛋，孵化期由雌鸟单独承担，大约22-26天。","identification":"与墨西哥小冠雉相比，白腹小冠雉的腹部更干净、更白，尾尖也更白。在分布重叠区，两者的生境选择不同，白腹小冠雉倾向于沿海低地。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥南部至尼加拉瓜，主要集中在太平洋沿海平原，但在危地马拉海拔可达约1500米。","other":"尽管部分地区因转变为牧场、甘蔗和棉花田而失去栖息地，但白腹小冠雉似乎从密集森林的开放中受益，特别是在危地马拉，其海拔分布范围有所上升，因为树荫咖啡种植园的更开阔的树冠似乎比原始阔叶林更适合这种鸟类。"},{"name":"鳞斑小冠雉","english_name":"Speckled Chachalaca","scientific_name":"Ortalis guttata","overview":"鳞斑小冠雉（英文名：Speckled Chachalaca，学名：Ortalis guttata），是鸡形目凤冠雉科小冠雉属的鸟类。比冠雉和盔雉略小。其主要特征为褐色外观，颈部和头部带有鳞状斑纹，喉部有红色裸露皮肤。常见于森林边缘地带，包括河流沿岸及农田附近。黎明和黄昏时，响亮而粗犷的叫声常常引发周围鳞斑小冠雉群体的合唱。","appearance":"成年鳞斑小冠雉体长49至55厘米。头顶和颈项较暗，呈灰褐色，背部有栗色斑点；尾羽带有青铜光泽，外侧尾羽为红棕色；下颌和胸部的羽毛为深棕色，边缘和尖端有白色或乳白色；喉部中央有一块红色裸露皮肤；下腹部为浅灰褐色，臀部为鲜艳的红棕色。两性相似，雄鸟的下颌至胸部羽毛边缘可能比雌鸟更偏黄褐色。幼鸟与成鸟相似。","call":"具有节奏感的五音节鸣唱，表现为ha-ga-GAA-gogok的重复快速发声，通常在清晨和黄昏时分最为活跃。","habits":"栖息于低地热带雨林边缘，包括灌木丛、草地斜坡、棕榈树丛、森林与次生林的交界处，偶尔出现在高大森林的树冠层或边缘。常在受人类活动影响的地区，如农田和小村庄周边被发现。以果实和其他植物物质为主食，群居生活，小群体最多可达7只。","breeding":"繁殖生态学研究有限，但在秘鲁观察到的繁殖季节至少涵盖11月至3月。筑巢高度约1.6米，由干蕨叶构成，巢呈浅杯状，直径约11厘米。一窝产3至4枚白色蛋，孵化期约为21天。","identification":"与哥伦比亚小冠雉、巴西小冠雉和点斑小冠雉的区别在于体型较小，胸部的鳞状斑纹更宽泛且不清晰，头冠颜色更深，上体色调更丰富；与点斑小冠雉相比，下尾覆羽更偏向栗红，腹部羽毛基部少有灰色黑色，臀部色调更红。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马逊雨林，具体包括哥伦比亚东部、厄瓜多尔北部、秘鲁东部、玻利维亚北部以及巴西西部。在玻利维亚，其分布可达海拔近2400米，但在秘鲁和厄瓜多尔的分布高度通常低于1700米和1100米。在巴西东南部的马托格罗索州和圣保罗州，有一个孤立的种群。","other":"subspecies remota 被认为非常罕见，若提升为独立物种，则国际保护状况将十分严峻。"},{"name":"巴西小冠雉","english_name":"East Brazilian Chachalaca","scientific_name":"Ortalis araucuan","overview":"巴西小冠雉（英文名：East Brazilian Chachalaca，学名：Ortalis araucuan），是鸡形目凤冠雉科小冠雉属的鸟类。与白色的腹部形成鲜明对比。主要分布在巴西东部的多种森林环境中，包括次生林、Caatinga灌木丛和沿海森林。","appearance":"巴西小冠雉长约50厘米，头顶至颈背呈暗红褐色，背部棕色带有红褐色的臀部；喉部有红色裸皮，下喉及胸部为深棕色，饰有显眼的白色斑点（羽毛尖端），其余腹部白色，腹侧橙黄色；眼睛深棕色，周围有一片蓝灰色裸露皮肤；喙暗蓝色；腿深粉红色至灰色。两性相似，雄鸟的喉咙和胸部标记更偏黄褐色（而非白色）。幼鸟整体更偏棕色。","call":"其叫声非常响亮，重复发出类似‘哈嘎-GAA-戈克’的嬉戏式二重唱，持续不断。","habits":"它们通常在小群体中活动，数量少于八只，主要在树上觅食，偶尔会下降到地面。栖息于多种森林环境，包括次生林、Caatinga灌木丛和沿海森林，以及大西洋森林。以水果和其他物品为食，饮食可能与其他凤冠雉相似。","breeding":"繁殖资料有限，活跃的巢穴在2月初被发现，三只大约一个月大的雏鸟在五月被捕获。在圈养条件下，一对巴西小冠雉尝试了四次繁殖，共产下十枚蛋，其中有七只幼鸟成功离巢。巢穴建在Myrcia树顶的枝叉中，高度约3.2米，巢浅且未加衬垫，可能是由干枝和树叶构成。一窝三枚淡白色蛋，大小分别为53.4×37毫米、55.4×38.4毫米和56.3×39.7毫米，重量39.75克、43.25克和46.75克。孵化期约为29-30天，显著长于先前对该属物种估计的21-24天。雏鸟在孵化几小时后即可离开巢穴。","identification":"与鳞斑小冠雉相比，巴西小冠雉具有更少的栗色尾巴底面，羽毛基部更多灰黑色（3级差异）；臀部更红褐色（2级差异）；以及棕色而非黑色的冠羽（2级差异）。叫声也有差异。与哥伦比亚小冠雉的区别在于体型更小，胸部鳞状图案更宽泛模糊，头部顶部和颈背呈暗红褐色而非蓝灰色，背部呈棕色而非橄榄色。与点斑小冠雉的区别在于头部顶部和后方呈暗红褐色而非暗棕色，后头部的箭头形、淡色尖端的羽毛，腹部白色至灰白色而非黄褐色，以及腹侧橙黄色而非栗色。","protection":"IUCN：LC（无危）。全球种群规模尚未量化，但可能相当大；没有快速下降的迹象。在其分布范围内相当常见，即使在人口密集地区也很普遍。尽管能较好地适应次生栖息地和人类活动，但仍报告了局部减少，这主要是由于栖息地破坏和狩猎。它出现在一些保护区，例如Espírito Santo的Sooretama生物保护区。","distribution":"分布于巴西东部，从东北部Rio Grande do Norte州的Pernambuco和Paraíba南部到Minas Gerais和Espírito Santo东部。","other":"过去曾被认为是鳞斑小冠雉的一个亚种，也被认为与小冠雉和黄眉小冠雉同种。"},{"name":"点斑小冠雉","english_name":"Scaled Chachalaca","scientific_name":"Ortalis squamata","overview":"点斑小冠雉（英文名：Scaled Chachalaca，学名：Ortalis squamata），是鸡形目凤冠雉科小冠雉属的鸟类。体型中等，以褐色羽毛为主，胸部鳞片状花纹明显，分布于巴西东南部，从圣保罗南部至里奥格兰德杜苏尔州，可能也曾出现在巴拉圭东南部。","appearance":"点斑小冠雉约50厘米长，体重介于498克到620克之间。其羽毛大多呈棕色调，上身颜色较深，下喉及胸部为暗棕色，羽毛边缘白色，形成鳞片状外观。腹部为淡黄色，臀部呈栗色，有小块粉红色喉裸区。雌雄相似，幼鸟特征未详述。","call":"鸣叫声嘈杂且极具变化，以‘re-a-tok’音节反复高声鸣叫。此外，还有嘈杂的‘racket’声，由多只个体合唱，音调不一，包含cacataPOOP、cacataPOP、cacataWHUMP、cacataWEEcata等音节，以及不规则的咯咯声或喉咙中的咕噜声。","habits":"栖息于热带低地常绿森林边缘、restinga森林和Laguncularia racemosa主导的红树林中，海拔从海平面至800米。通常以小型家庭群体出现，主要食物为水果和树叶，偶尔访问香蕉喂食站或城市花园。","breeding":"繁殖季节从10月至翌年3月，成鸟在此期间处于繁殖状态，巢穴为浅篮状，由叶子和树枝构成，隐藏于树叉中，离地面约1至3米。每窝产卵三枚，蛋色污白，大小约为60.8 x 39.8毫米，孵化期约21天。","identification":"与巴西小冠雉相比，点斑小冠雉外观更暗，冠部少有赤褐色，前颈为鳞片状而非斑点状，腹面区域更偏黄而非白色，面部裸露皮肤面积较小。与鳞斑小冠雉的区别在于尾下覆羽的色彩、臀部色调和头部颜色的差异。","protection":"IUCN：LC（无危）。尽管全球数量未量化，但在部分范围内至少局部常见，面临狩猎压力和因森林砍伐导致的栖息地丧失。","distribution":"分布于巴西东南部，从圣保罗南部至里奥格兰德杜苏尔州。可能曾在东南巴拉圭出现，但近80年来无确切报告。","other":"曾被视为鳞斑小冠雉、纯色小冠雉或小冠雉的亚种，目前认为是独立物种。"},{"name":"哥伦比亚小冠雉","english_name":"Colombian Chachalaca","scientific_name":"Ortalis columbiana","overview":"哥伦比亚小冠雉（英文名：Colombian Chachalaca，学名：Ortalis columbiana），是鸡形目凤冠雉科小冠雉属的鸟类。特有种，仅分布于哥伦比亚中北部的森林和林地，尤其在卡乌卡河和马格达莱纳河谷。该鸟体型较大，外表呈灰棕色，颈部和胸部带有白色鳞状斑纹，喉咙处有一红色肉垂，尾羽外侧为赤褐色。","appearance":"成年哥伦比亚小冠雉长度约50至60厘米，体重在500至600克之间。背部和翅膀为棕色，尾羽也是棕色但边缘赤褐色。头部、颈部和胸部为灰色或灰棕色，覆有明显的白色鳞片状斑纹。腹部为浅棕色，下腹和尾下覆羽更显赤褐色。两性相似，腿和脚为粉红色，喙基部暗灰色渐变为白色，虹膜深棕色，眼周有灰色裸皮。","call":"发出嘈杂的‘chac-a-lac’叫声，声音响亮。","habits":"哥伦比亚小冠雉栖息于海拔高达2000米的潮湿和落叶森林，包括开放的树林和灌木丛边缘。它们过着树栖生活，主要在森林中层到树冠层活动，偏好果实丰富的树种，如无花果和Cecropia。以小型家庭群体或成对出现，偶尔会聚集多达20只的群体。它们能忍受次生环境和人类居住区附近的生存，但研究显示其在成熟森林中的生存状况更佳。","breeding":"关于繁殖习性的信息有限，推测它们可能是一夫一妻制，并在繁殖季节持有领地。在马格达莱纳河谷记录了二月间雌鸟的育雏斑块肿胀、雄鸟的延长睾丸以及半大的幼鸟，这表明该地区的繁殖季节。","identification":"与鳞斑小冠雉相比，哥伦比亚小冠雉具有更多且更明显的胸部和腹部的淡色斑点。两物种的分布完全不重叠，哥伦比亚小冠雉局限于卡乌卡河和马格达莱纳河流域，而鳞斑小冠雉出现在亚马逊和东安第斯山脉的山麓。","protection":"IUCN：LC（无危）","distribution":"南美洲：哥伦比亚中北部，包括卡乌卡河和马格达莱纳河谷。分布区域高度碎片化，仅存于上河谷的局部地区，如马格达莱纳河从胡伊拉省至桑坦德省，以及卡乌卡河谷从卡乌卡省至安蒂奥基亚省。","other":"哥伦比亚小冠雉的种子传播作用对于维持热带森林多样性至关重要。"},{"name":"小冠雉","english_name":"Little Chachalaca","scientific_name":"Ortalis motmot","overview":"小冠雉（英文名：Little Chachalaca，学名：Ortalis motmot），是鸡形目凤冠雉科小冠雉属的鸟类。拥有灰褐色的羽毛，头部呈温暖的栗色，最显著的特点是裸露的红色喉部和粉红色的腿。小冠雉常见于南美洲北部亚马逊雨林以北的低地地区，主要栖息于次生林、河流边缘以及受干扰的环境，包括农场和村庄。","appearance":"小冠雉体长43至54厘米，体重介于345到620克之间。头部呈红栗色，上身颜色从红棕色过渡到灰棕色，下身则是灰色。初级飞羽为深棕色，面部皮肤为深灰色石板色。与栗翅小冠雉和棕头小冠雉相比，小冠雉的上身颜色更暗，呈深棕色而非栗色。","call":"小冠雉的叫声独特，清晨时会听到群组间响亮的互答声，其重复的“WATCH-a-lak”叫声能远传超过一公里，是其显著的鸣叫特征。","habits":"小冠雉通常在树上或地面觅食，常以成对或小型群体的形式出现，主要食物为浆果和水果，偶尔也会食用花朵和叶子。它们生活在次生林、河岸密林、被遗弃的牧场以及密集的次生植被中，偏好低地环境，海拔可达1700米。","breeding":"繁殖记录显示小冠雉在圭亚那地区于5月、9月和12月产卵，而在巴西，繁殖期则在11月至12月初的雨季开始时。巢穴为较小的杯状，由细根、扁平叶片和枝条构成，内衬叶子，通常位于灌木或树木较低处。每窝产三枚白色蛋，大小约为52.2至56.9毫米×36.2至38.9毫米。雏鸟的上半身大部分为暗色，头部和翼覆羽尖端呈栗色，下半身为淡黄色。","identification":"小冠雉与Spix’s和Marail Guans相似，但体型明显更小，且不会出现在高大森林的树冠层。与栗头小冠雉相比，小冠雉的体型更小，颜色更深。","protection":"IUCN：LC（无危）。小冠雉在苏里南、圭亚那和法属圭亚那相当常见，在巴西、委内瑞拉等地也有稳定的分布。它存在于多个保护区，如苏里南的Raleigh Falls自然保护区、巴西的塔帕若斯国家森林公园等。","distribution":"小冠雉的分布范围涵盖了南美洲北部，从委内瑞拉南部和东部向东穿过圭亚那地区，进入巴西北部，南至亚马逊河以东的黑河北部。","other":"小冠雉在圈养环境中较为常见，经常被繁殖。"},{"name":"栗头小冠雉","english_name":"Chestnut-headed Chachalaca","scientific_name":"Ortalis ruficeps","overview":"栗头小冠雉（英文名：Chestnut-headed Chachalaca，学名：Ortalis ruficeps），是鸡形目凤冠雉科小冠雉属的鸟类。偏好沿河的密集灌木丛和茂密的次生林。","appearance":"该鸟长43至54厘米，体重介于345至620克之间。头部呈红褐色，上体灰褐，下体灰色，翼部的初级飞羽深褐色。与Variable Chachalaca相比，体型较小，叫声有明显差异。","call":"发出响亮的嬉闹二重唱，重复的“WATCH-a-lak”声，主要在黎明和黄昏时分鸣叫，与Variable Chachalaca的叫声相似但节奏更慢。","habits":"栖息于沿河地带的密集次生林和开阔林地中的灌木层，通常以小群活动，觅食果实、浆果，偶尔食用花朵和叶子。","breeding":"关于繁殖生态的信息尚未发表。","identification":"与Variable Chachalaca最相似，但体型较小，叫声有显著差异。地理上不重叠，由亚马逊河隔开。","protection":"IUCN：LC（无危）；在某些保护区较为常见。","distribution":"仅分布于南美巴西中北部，位于亚马逊河以南，从帕拉州的塔帕若斯河到托坎廷斯州的阿拉瓜亚河。","other":"近期系统学研究支持其独立物种的地位，基于形态和叫声的差异。"},{"name":"黄眉小冠雉","english_name":"Buff-browed Chachalaca","scientific_name":"Ortalis superciliaris","overview":"黄眉小冠雉（英文名：Buff-browed Chachalaca，学名：Ortalis superciliaris），是鸡形目凤冠雉科小冠雉属的鸟类。体型较小的凤冠雉科小冠雉鸟类，以独特的黄褐色眉毛条纹著称。广泛分布于巴西东北部亚马逊河以南的地区，包括帕拉州、马拉尼昂州、塞阿拉州、托坎廷斯州和皮奥伊州的部分地带。","appearance":"体长约42至46厘米，为小冠雉中最小的种类。头部、颈部和上胸部呈灰色，体背为棕色，腹部和下胸部为淡褐色。尾羽中央为深绿褐色，末端和两侧为栗色，具有明显的超眉纹，颜色从淡黄白色到浅肉桂色不等。面部皮肤为深石板灰色。幼鸟的描述尚未公开，但在其他小冠雉物种中，年龄相关的变化并不显著。","call":"其叫声通常为小冠雉特有的高音、刺耳的“TJURRE-wruh”，连续重复。","habits":"栖息于低地的灌木丛和森林边缘，包括严重退化的区域。已观察到它在棕榈果和某些花朵上觅食。","breeding":"繁殖季节主要在12月至2月间，但也有记录显示其他月份有筑巢行为。巢穴由干树枝构成，有时使用棕榈叶，内部铺垫干叶、草和细枝。巢穴高度平均为90厘米，尺寸约为18至22厘米×14厘米。每窝产卵2至3枚，蛋壳呈污白色，平均尺寸为53毫米×36.1毫米。","identification":"与同属的其他物种相比，黄眉小冠雉是最小的，且是唯一具有超眉纹的种类，该纹路的颜色从淡黄白到浅肉桂色不等。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲巴西东北部，亚马逊河以南的区域，包括帕拉州、马拉尼昂州、塞阿拉州、托坎廷斯州和皮奥伊州的部分地带。","other":"曾被视为近危物种，初步估计其数量约1万只，覆盖面积389,000平方公里。"},{"name":"斑尾冠雉","english_name":"Band-tailed Guan","scientific_name":"Penelope argyrotis","overview":"斑尾冠雉（英文名：Band-tailed Guan，学名：Penelope argyrotis），是鸡形目凤冠雉科冠雉属的鸟类。分布于南美的鸟类，常见于哥伦比亚和委内瑞拉的云雾森林中。其最显著的特征是红喉、暗褐色体羽带精细的白色条纹以及苍白的脸部标记。","appearance":"斑尾冠雉体长50至61厘米，体重介于625到981克之间，雄雌相似。上体呈黑褐至深赤褐色，有明显的白色条纹；胸部橄榄褐色，腹部淡至中褐色。脸部灰白至苍白，有突出的红色喉囊。尾羽末端有一宽广的栗色带，为其命名之由。P. a. albicauda亚种尾羽尖端呈浅黄色，P. a. colombiana亚种头部有更多白色，而脸部白色少于指名亚种。","call":"通常较为安静，但在建立领地时会进行翼鸣展示，声音类似\"画布前拉再反拉\"，可达百米外。警戒时发出柔和的笛声哨音，极度警觉时会反复尖叫\"GUEEA!\"，其间夹杂粗糙音符。","habits":"栖息于亚热带和上层热带的茂密森林，偏好湿润原始林，偶尔出现在高大的次生林、阴凉咖啡种植园和较干燥森林的上缘。常见于崎岖山地，海拔高度从550至2000米不等，偶尔在更高或更低处被发现。以果实为主食，尤其是果肉丰富的树果，如月桂和瓜鲁莫树的果实。偶尔落地觅食掉落的果实，通常在树的中层觅食。喝水来源于积水的凤梨科植物叶鞘或鹤望兰的花朵中。","breeding":"一月至五月间开始划分领地，二月至四月筑巢，甚至五月，雨季结束时平均繁殖时间在较干燥的南部山脉比北坡早。巢由松散的植物材料构成，通常位于地面以上1至8米的树上。雏鸟全身暗褐色，腹部呈浅黄褐色和暗白色。","identification":"与须冠雉相比，斑尾冠雉的翼上覆羽有明显的白色标记，脸上的白色更多，尤其是在耳羽上。幼鸟的羽毛几乎与成鸟无法区分。","protection":"IUCN：LC（无危）；在委内瑞拉，指名亚种在多个国家公园中得到保护，如瓜托波、亨利皮蒂尔、特雷帕伊马和亚坎布国家公园，但也是偷猎者的目标。","distribution":"主要分布在哥伦比亚东部安第斯山脉和委内瑞拉西部，以及委内瑞拉沿海山脉。在圣玛塔山脉，分布海拔从550至2000米；在委内瑞拉，主要分布于800至2400米，局部可达3050米或低至300米。","other":"斑尾冠雉与须冠雉关系密切，有时被视作同一物种。它有三个亚种，指名亚种P. a. argyrotis、P. a. albicauda和P. a. colombiana。"},{"name":"须冠雉","english_name":"Bearded Guan","scientific_name":"Penelope barbata","overview":"须冠雉（英文名：Bearded Guan，学名：Penelope barbata），是鸡形目凤冠雉科冠雉属的鸟类。大型类似鸡的鸟类，拥有长尾，巧克力棕色的整体外观，头部和颈部带有银色斑点。其分布限于厄瓜多尔南部和秘鲁西北部的亚热带和温带森林中，海拔大约在2000至3000米之间。在繁殖季节（2月至7月）期间，雌雄鸟通常成对或小群体出现在森林中层。在Cuenca以南和Jaén以西取代了安第斯冠雉，与之相比，须冠雉在眉部有更广泛的银色斑点，胸部条纹而非鳞片状图案。","appearance":"须冠雉长约55厘米，全身呈巧克力棕色，尾部末端有不明显的红褐色带。上半身和后腹部为暗灰褐色，头部和颈部覆有银色羽毛。颈缘和胸羽边缘为白色，腿脚粉红色。雄鸟与雌鸟在羽毛颜色和大小上相似，幼鸟特征不详。","call":"须冠雉展示时发出典型的翼鸣声，这是Penelope属鸟类的共同特征。其报警叫声频率较低，包括一系列急促的咕咕声，音调随情绪升高而加速，有时会变成兴奋的、更有节奏的吠叫声。当受干扰时，会发出几乎听不见的上升哨音。","habits":"须冠雉栖息于亚热带和温带的山地云雾林，海拔高度从1500米到3100米，尤其在2700米以上。它们主要在清晨和傍晚活动，通常以2至4个个体的小群体形式在树冠层觅食，偶尔也会在地面寻找食物。食物主要包括果实，其次是叶子和花朵，偶尔吃昆虫。","breeding":"繁殖季节主要在2月至7月，窝卵数估计为2枚，推测可能有多窝繁殖现象。幼鸟记录显示，雏鸟在12月至3月间出现，而较大的幼鸟在5月至8月间被观察到。","identification":"须冠雉与斑尾冠雉的区别在于缺乏上翼盖上的明显白色标记，下巴和喉咙上部完全被羽毛覆盖，胫骨部分被羽毛覆盖，以及主要飞羽的修饰程度较小。","protection":"IUCN：NT（近危）","distribution":"须冠雉分布在厄瓜多尔南部（El Oro, Loja 和 Zamora-Chinchipe地区，可能还包括Azuay）和秘鲁西北部（Piura, Cajamarca 和 Lambayeque地区）。在Podocarpus国家公园有大量种群存在。","other":"须冠雉在19世纪末在秘鲁北部和厄瓜多尔的森林中曾普遍分布，但在森林破坏广泛发生后数量减少。在厄瓜多尔，它是最濒危的山地凤冠雉科鸟类之一。"},{"name":"古铜冠雉","english_name":"Baudo Guan","scientific_name":"Penelope ortoni","overview":"古铜冠雉（英文名：Baudo Guan，学名：Penelope ortoni），是鸡形目凤冠雉科冠雉属的鸟类。体型中等，类似火鸡，主要分布在南美洲哥伦比亚西部和厄瓜多尔西北部的湿润森林地带。其对环境变化极为敏感，因狩猎和栖息地破坏而面临严重威胁，已被列为濒危物种。","appearance":"古铜冠雉高约65厘米，通体呈深褐色，胸部和颈部点缀有规律的小白斑点。头部和颈部的褐色略显灰褐，使斑点更为明显。头型简洁，与同地区其他紫冠雉显著不同，后者头部有淡色标记。腿和肉垂均为红色，肉垂颜色更鲜艳，容易识别。幼鸟外观预计与成鸟相似。","call":"清晨，古铜冠雉会发出远距离传播的低沉、重复的‘waou’声，作为领地呼唤。当察觉人类接近时，它们会用低沉、柔和且持续上升的哨声警告同伴。遇险报警时，会发出连续急促的‘konh-konh-konh-konh’声，这一报警声也见于其他Penelope属物种。","habits":"古铜冠雉栖息于热带湿润森林的上层，通常活动于海拔1500米以下的区域，偏好地形崎岖的山脚地带，但也出现在低地森林。它们以小群或家族群形式活动，主要在树冠和亚树冠层觅食较小的果实，很少降至地面。其生存高度依赖于高大原始森林的存在。","breeding":"关于繁殖信息知之甚少，但已知在8月中旬曾收集到准备产卵的雌鸟，推测繁殖季为7月至9月。每次产卵2枚，其他繁殖细节尚不清楚。","identification":"古铜冠雉比同域分布的其他冠雉属物种更小、更暗淡，缺乏胸腹和尾巴的栗色，且头部没有明显的羽冠。与体型相似的褐镰翅冠雉相比，后者具有红色肉垂。幼鸟与成鸟外观相似。","protection":"IUCN：EN（濒危）","distribution":"分布于哥伦比亚西部（从奇奥科省向南至纳里尼奥省）和厄瓜多尔西部（南至皮钦查省，历史上曾到达瓜亚斯省）。在哥伦比亚，记录于100米至1500米之间，偶尔高达3100米。厄瓜多尔的分布范围急剧收缩，目前主要局限于埃斯梅拉达斯省的极北端，以及皮钦查省的部分地区。","other":"古铜冠雉对栖息地改变和狩猎极其敏感，容易成为猎杀目标，因为它们不会逃避人类的接近。随着道路网络的快速扩张，其栖息地正遭受农业、非法可可种植园、选择性伐木、狩猎和金矿开采的威胁。"},{"name":"安第斯冠雉","english_name":"Andean Guan","scientific_name":"Penelope montagnii","overview":"安第斯冠雉（英文名：Andean Guan，学名：Penelope montagnii），是鸡形目凤冠雉科冠雉属的鸟类。体型较大的雉类，广泛分布在南美洲安第斯山脉，从委内瑞拉至玻利维亚。其特征为全身呈暗褐色，头部、胸部覆盖着霜白条纹，下腹略带红褐色，腿部呈红色，雌雄外观相似。","appearance":"安第斯冠雉体长51-61厘米，体重818-840克。体型健壮，不如多数同属物种修长。喉部和跗跖部分覆羽，尾羽颜色统一，与须冠雉相似但尾羽色彩一致。幼鸟类似成鸟，但更显棕色，下体斑纹不明显，面部和喉咙颜色较淡。亚种间在羽毛色彩和头颈标记上存在细微差异。","call":"黎明时分的翼颤鸣声前有一声柔和的哨音，最常听到的是连续的沙哑和啼鸣音，间杂高音符。当受惊时发出急促的音调，早晚则发出低沉的‘dock’音，有时持续数分钟，速度逐渐加快，还有类似Ortalis的叫声。","habits":"栖息于海拔较高的山区湿润森林，包括矮林区，最高可达3700米，偶尔进入次生林或有果实的开阔地带。以1-30毫米范围内的种子为主食，包括成熟和未成熟的果实，偶尔食用叶部。通常成群活动，由3-12只组成，偶尔单独行动。","breeding":"繁殖季节可能在2月至3月在委内瑞拉/哥伦比亚，但在玻利维亚疑似在11月至2月。巢穴由树枝搭建，内铺树叶，每次产卵两枚。雏鸟深棕色，混有淡黄色，头顶有不规则白色带。","identification":"与同属其他物种相比，安第斯冠雉在较高海拔生活，其喉部和跗跖的覆羽特征明显，尾羽颜色均匀。亚种P. m. atrogularis叫声较为哀怨，而P. m. sclateri的声音更像红脸冠雉。","protection":"IUCN：LC（无危）。在玻利维亚、哥伦比亚和委内瑞拉分布普遍，秘鲁常见，厄瓜多尔局部罕见。在多个保护区中得到保护，如秘鲁的Yanachaga-Chemillén国家公园，玻利维亚的Cotapata、Madidi、Carrasco和Amboró国家公园。","distribution":"安第斯冠雉分布于南美洲的安第斯山脉，从哥伦比亚南部至玻利维亚北部，可能延伸至阿根廷西北部。在秘鲁东部安第斯山脉的广阔不可接近区域，种群数量可能健康。","other":"尽管受到森林破坏和有限的狩猎威胁，但安第斯冠雉能在部分受干扰的区域生存，甚至在人类聚居地附近频繁出现。"},{"name":"绿背冠雉","english_name":"Marail Guan","scientific_name":"Penelope marail","overview":"绿背冠雉（英文名：Marail Guan，学名：Penelope marail），是鸡形目凤冠雉科冠雉属的鸟类。广泛分布在南美洲北部，包括巴西、法属圭亚那、圭亚那、苏里南和委内瑞拉。成鸟体长约63至68厘米，雄鸟体重介于772至1,310克之间，雌鸟体重则在770至1,450克之间。其背部、翅膀和中央尾羽呈现暗绿色光泽，外侧尾羽为蓝黑色。","appearance":"绿背冠雉体型中等，雄鸟看似比雌鸟大，背部、翅膀和中央尾羽带有绿橄榄色光泽，外侧尾羽为蓝黑色。喉部和胸部颜色较暗，饰有白色斑点，腹部呈红棕色，拥有红色的肉垂。亚种jacupeba体型略小，色调更淡，偏灰褐色。幼鸟描述不详，但可能与成鸟相似。","call":"绿背冠雉会发出翼振声展示，持续约5秒，通常在黎明前进行，随后发出类似小狗吠叫的\"whaf, whaf, whaf\"叫声，有时伴有更高音的叫声（可能是雌鸟的声音）。黄昏时也会发出犬吠般的叫声。","habits":"绿背冠雉主要栖息于热带雨林，尤其靠近水源，低地或沿海地带，偶尔出现在次生林中。它们通常独居或成对活动，有时会在果实丰富的树木附近聚集。它们几乎完全以水果为食，偶尔摄入昆虫，比例极低。在旱季，依然依赖少量种类的果实。它们在树上觅食，有时也会在地面觅食，尤其是在有雏鸟陪伴时。","breeding":"繁殖季节在法属圭亚那为10月至11月，雏鸟记录始于11月；在苏里南，产卵记录在12月至2月，成熟雏鸟观察到5月；在巴西，雏鸟记录在8月。巢呈杯状，位于高树叉上，产卵数为2至3枚，孵化期为29天（在圈养条件下）。","identification":"与棕胸冠雉非常相似，但绿背冠雉体型较小，腿较短，这在判断上可能相当困难。亚种jacupeba相较于指名亚种更小、更灰褐色，且可能具有稍微较短的头冠。","protection":"IUCN：LC（无危）。绿背冠雉的总数量估计约为15万只。尽管在许多地区常见，但在狩猎压力大的区域，如法属圭亚那的首都卡宴周围，其数量明显下降。","distribution":"绿背冠雉分布于南美洲北部，包括东部委内瑞拉、圭亚那、法属圭亚那、苏里南和巴西北部亚马逊河以北地区。在巴西，它在阿马帕州、罗赖马州北部和亚马逊州马瑙斯周边较为常见。","other":"绿背冠雉在某些受保护区域相对常见，如委内瑞拉的几个保护区，尽管受到狩猎压力的影响，但影响程度适中。"},{"name":"眉纹冠雉","english_name":"Rusty-margined Guan","scientific_name":"Penelope superciliaris","overview":"眉纹冠雉（英文名：Rusty-margined Guan，学名：Penelope superciliaris），是鸡形目凤冠雉科冠雉属的鸟类。中型长尾鸟，分布于南美洲中部和东部地区，包括亚马逊雨林、干燥森林和红树林等多种生境。","appearance":"该鸟长度介于55至73厘米之间，体重950至1150克（superciliaris亚种），或750至880克（jacupemba亚种）。其上体颜色为深橄榄色至褐色，翼羽和肩羽边缘呈锈红色，腹部亦为锈色。面部较淡，具有一条从白色到黄褐色或赭色的眉纹，不同亚种间颜色有所差异。","call":"发出粗哑的吠叫声，有时更显喉音，可能在警报时发出，也可能在其他情境中出现。","habits":"眉纹冠雉通常栖息于各种森林环境，包括热带雨林、半落叶林地、红树林以及桉树种植园。它们主要生活在低地，偶尔可在高达1300米的地方发现。鸟群通常为留鸟，虽然在一些地方会有垂直迁移，每天上下移动可达400米。飞行距离一般不超过约20米，常在地面附近活动。它们主要以果实为食，偶尔吃花、叶和昆虫。","breeding":"繁殖季节在阿根廷为10月至翌年2月，在巴西东南部为8月至翌年2月。巢由树枝构成，直径约45厘米，高19厘米，内部铺有干湿叶片，一般建于树上。每次产三枚脏奶油白色的蛋，大小约为55.5至64.3毫米×38至42.1毫米，孵化期大约28天。","identification":"与同类物种相比，眉纹冠雉具有不明显的眉毛纹路和无斑点的背部。在jacupemba亚种中，眉纹更为明显，常呈黄褐色或丰富淡黄色。","protection":"IUCN：NT（近危）","distribution":"分布在亚马逊河以南的巴西、玻利维亚东部、巴西中部和南部、巴西南部至阿根廷东北部和巴拉圭东部。","other":"尽管受到法律保护，但在某些地区仍面临偷猎威胁。在一些保护区较为常见，但即便在保护区内，狩猎仍然是一个令人担忧的问题。"},{"name":"红脸冠雉","english_name":"Red-faced Guan","scientific_name":"Penelope dabbenei","overview":"红脸冠雉（英文名：Red-faced Guan，学名：Penelope dabbenei），是鸡形目凤冠雉科冠雉属的鸟类。体型较大的鸟类，主要分布在南美洲玻利维亚东南部和阿根廷西北部的云雾森林地带。其最显著的特征是面部裸露的红色皮肤和红色肉垂。","appearance":"红脸冠雉体长63至69厘米，雌鸟平均体重约为1230克。全身主要呈深棕色，头部、胸部和上背部点缀有白色或银白色斑点。具有明显的白色眉纹，腿色淡粉色，脸部裸露皮肤为亮粉红色，红色肉垂是其所属凤冠雉科的典型特征。","call":"红脸冠雉黎明时会发出翅膀振动的声音作为展示，其叫声包含粗糙而随机的音符，以平缓的系列发出，警报时则发出响亮、喉音重复的'kroa, kroa...'，其间穿插着吹哨般的'luuuii'声。","habits":"红脸冠雉主要栖息于安第斯山脉东侧的云雾森林，偏好大型树木覆盖的广阔区域，偶尔也会出现在较小的林区或年轻的次生林。海拔主要在1800至2500米之间，有时低至1300米。它们通常成对或小群活动，以水果为主食，也会食用树叶和节肢动物。","breeding":"繁殖季节尚未完全确定，但观察到的求偶和鸣叫行为发生在9月至12月之间。它们会在树上用树枝和茎搭建平台状巢穴，内衬叶子，每窝产3枚白色蛋，尺寸约为69-70毫米×49-51毫米。","identification":"红脸冠雉与同属的乌腿冠雉区别在于面部裸露皮肤的颜色，前者为亮粉红色，后者为灰色或蓝灰色。此外，红脸冠雉的报警叫声中的两个音调类型不是同步发出的。","protection":"IUCN：LC（无危）","distribution":"红脸冠雉的分布局限于南美洲玻利维亚南部圣克鲁斯省、楚基萨卡省和塔里哈省，以及阿根廷西北部的胡胡伊省和萨尔塔省。","other":"尽管红脸冠雉的分布范围有限，但因其栖息地偏远且难以进入，受到的猎杀压力相对较低，特别是在阿根廷的Calilegua国家公园和玻利维亚的蒙特斯查佩多斯地区，种群数量较为稳定。"},{"name":"紫冠雉","english_name":"Crested Guan","scientific_name":"Penelope purpurascens","overview":"紫冠雉（英文名：Crested Guan，学名：Penelope purpurascens），是鸡形目凤冠雉科冠雉属的鸟类。体型较大的凤冠雉。其分布广泛，自墨西哥南部及尤卡坦半岛延伸至厄瓜多尔西部及委内瑞拉北部，常见于海拔1850米以下的热带及亚热带森林。紫冠雉通常成对或小群体活动，因人类活动和猎杀压力，其分布地逐渐偏远。","appearance":"紫冠雉体长约76至91.5厘米，体重约1.6至2.4公斤。全身主要为暗橄榄褐色，带有微弱的绿色或紫色光泽。腹部和肛周区域为栗色，胸部和腹部的羽毛边缘为白色。喉部覆盖着一些刚毛，松软的皮肤形成一个小红肉垂。幼鸟与成鸟相似，但整体带有黑色斑点，翼和尾羽带有赤褐色。两性皆有红色虹膜、黑色喙、石板黑色裸露面部皮肤和红色腿脚。","call":"紫冠雉的清晨鸣唱如同强有力的蒸汽哨声，尾音低沉如吼叫：ku LEEErrr！此外，它还会发出响亮的‘honking quonk’声，警报时则是一连串异常响亮的‘honking squawks’声，以及一系列其他声音，包括远距离传播的‘WOK！-WOK！’声，吹笛般的‘POK！-POK！’声，和低沉鼻音的‘aahhnk-aahhnk’声。","habits":"紫冠雉全年在分布区域内居住，主要栖息于热带和亚热带常绿、落叶森林，云雾林，河岸林和常绿山地森林，海拔高度从海平面到2500米不等。它们以果实为主食，偶尔也会食用嫩叶和昆虫，通常在树冠高处取食，有时也会在地面觅食。紫冠雉成对或小群体活动，迅速敏捷地在树枝间跳跃和短距离飞行。","breeding":"紫冠雉为一夫一妻制。在哥斯达黎加，繁殖季节大约从三月持续到六月，但在其他地区时间尚未明确。它们的巢由粗枝和树叶搭建，位于高树上。一般认为每窝产两枚蛋。在圈养条件下，孵化期约为26天。野外的孵化期、离巢时间和亲鸟照料细节尚不清楚。","identification":"紫冠雉是Penelope属中分布最北的物种。与之相似的古铜冠雉体型较小，羽毛颜色较暗淡，可能缺乏紫冠雉那种响亮的‘honking’叫声。安第斯冠雉和斑尾冠雉体型更小，常出现在更高海拔地区。棕胸冠雉在哥伦比亚东部安第斯山脉基部与紫冠雉可能有地理重叠，但其特征有所不同。","protection":"IUCN：NT（近危）。紫冠雉因森林丧失和破碎化，主要是为了农业用地和牧场的转换，以及在其分布范围内被大量猎杀，尤其是中美洲，导致其数量减少。墨西哥官方将其列为受威胁物种。","distribution":"紫冠雉分布于中美洲和南美洲，从墨西哥南部至南美西北部，包括墨西哥、伯利兹、危地马拉、萨尔瓦多、洪都拉斯、尼加拉瓜、哥斯达黎加、巴拿马、哥伦比亚、厄瓜多尔、秘鲁北部和委内瑞拉北部。","other":"紫冠雉在受到保护的地区，由于禁止狩猎，可能会显得较为亲近人类甚至驯化。"},{"name":"考卡冠雉","english_name":"Cauca Guan","scientific_name":"Penelope perspicax","overview":"考卡冠雉（英文名：Cauca Guan，学名：Penelope perspicax），是鸡形目凤冠雉科冠雉属的鸟类。仅见于哥伦比亚西部和西南部的特定区域，尤其是考卡河谷一带。这种鸟拥有鲜明的肉桂色翅膀和尾巴，以及显著的喉部皮肤斑块，与安第斯冠雉明显不同。主要栖息于云雾森林中，偶尔会在地面觅食。尽管在其分布范围内较为罕见，但在某些保护区，如Otún Quimbaya保护区，却容易见到。","appearance":"成年考卡冠雉体长约76厘米，平均体重约为1197克。背部、臀部、翅膀、腹部和尾巴主要呈丰富的栗色；腹部和大腿上有不显眼的深色标记。头部至胸脯的羽毛边缘有明显的白色鳞状斑点。幼鸟的描述不详，但可能与成鸟相似。体型比紫冠雉大，后者有明显的条纹外观和橄榄棕色的后身；而比安第斯冠雉小，后者有极小的喉囊，背部和翅膀的栗色较暗淡。","call":"考卡冠雉的叫声通常响亮而粗糙，特别是在繁殖季节和受到惊吓时。已知的鸣唱是一连串响亮的‘chiriwichi, chiriwichi, chiriwichi…’，主要在清晨发出，尤其是在2月至6月间。当群鸟重新聚集时，会发出柔和的下滑哨声。在警戒时，会发出一系列快速的‘quan…quan’音节，有时会明显加速。","habits":"考卡冠雉主要栖息于热带和亚热带湿润森林中，海拔高度从1200米到2100米之间，但记录显示其活动范围可低至816米，高至2690米。它们在原始森林和次生林中活动，甚至在靠近道路和异国树种如中国白蜡树和帕图拉松树种植园的树丛中也能发现。它们大部分时间在中层和上层林冠活动，但在边缘地带会下降至较低的位置。以多种水果为主食，同时也吃树叶和花，尤其在水果稀缺时会大量食用中国白蜡树的嫩叶。","breeding":"繁殖期似乎与雨季和水果丰盛期相吻合，一般在9月至10月和2月至3月。巢筑于地面1.8米高的松树桩上，由干叶构成，被蕨类植物遮掩。另一个巢位于9月，由细枝组成，周围有蕨类植物和藤蔓，位于倒下的Myrcia树上。巢的尺寸大约为直径34厘米，深度25厘米，由Gleichenia sp.的叶子和茎构建。每窝产两枚白色的蛋，大小约为73.9-78.9毫米×49-53.4毫米，重94-96克。孵化由雌鸟单独完成，需时约29天。雏鸟出生时类似于安第斯冠雉的雏鸟，5个月左右变得与成鸟相似，但会与成鸟一起生活约一年。","identification":"与安第斯冠雉的区别在于更亮的肉桂色翅膀和尾巴，更大的喉部皮肤斑块，以及在较低海拔处发现。与安第斯冠雉相比，体型较小，喉囊更小，背部和翅膀的栗色较暗淡。与紫冠雉相比，外表有明显的条纹而非鳞片状。","protection":"IUCN：VU（易危）","distribution":"分布于哥伦比亚西部，主要集中在考卡河谷的中部和上游，包括里斯阿拉尔达、昆迪奥、考卡山谷和考卡省。在西部安第斯山脉西侧相对较少见，主要出现在低山口。","other":"考卡冠雉的历史分布区从24,900平方公里缩减至仅750平方公里，且高度碎片化。曾被认为可能灭绝，但后来发现在几个区域仍有小而稳定的种群存在。栖息地破坏和狩猎是导致其数量减少的主要原因。"},{"name":"白翅冠雉","english_name":"White-winged Guan","scientific_name":"Penelope albipennis","overview":"白翅冠雉（英文名：White-winged Guan，学名：Penelope albipennis），是鸡形目凤冠雉科冠雉属的鸟类。分布于秘鲁西北部的特定干林地区。曾一度被认为灭绝，直至1977年被重新发现。其特征性的暗褐色羽毛上带有红色肉垂、粉色面斑和白色胸鳞，最为显著的是其白色翼斑，飞翔时尤为醒目。栖息于坡地和峡谷的干燥落叶森林，以果实为主食。","appearance":"成年白翅冠雉体型庞大，羽毛呈深褐色，带有绿色光泽，头部、颈部、上背部及胸部有白色细边条纹。翅膀上最外侧的九至十支主飞羽为白色，与身体其余部分形成鲜明对比。尾部和腿较长，面部裸露皮肤紫色，喉部肉垂橙色，喙暗灰色，尖端黑色，跗跖和趾橙色或粉红色。","call":"白翅冠雉在黎明和黄昏时分的叫声尤为响亮，其领地叫声类似‘jar-jar-jar’结尾快速转换为‘ha-ha-ha-ha’，通常由雄鸟发出。","habits":"主要栖息于秘鲁西北部的干林地带，偏好坡地和峡谷环境，海拔高度一般在500至1100米之间。白天大部分时间保持静止，仅在清晨和傍晚活动，以果实、花朵、叶子和种子为食。","breeding":"白翅冠雉通常以配偶或家庭群体形式出现，繁殖季节从11月持续到次年5月，雨季资源丰富时期。它们在藤蔓覆盖的树木中用枝条和树叶搭建巢穴，离地面约2.5米高，每窝产卵数量通常为两枚。","identification":"与同域分布的须冠雉相比，白翅冠雉体型更大，颜色更深，翅膀上有白色斑块，而须冠雉的腿部为红色，面部裸露部分更不显眼。紫冠雉则更为棕褐色，且无白色翼斑。","protection":"IUCN：EN（濒危）","distribution":"南美：秘鲁西北部，具体在兰巴耶克大区、卡哈马卡大区及皮乌拉地区。","other":"尽管面临栖息地破坏和猎杀的威胁，但通过建立保护区和成功的再引入项目，白翅冠雉的数量已有所恢复。"},{"name":"棕胸冠雉","english_name":"Spix's Guan","scientific_name":"Penelope jacquacu","overview":"棕胸冠雉（英文名：Spix's Guan，学名：Penelope jacquacu），是鸡形目凤冠雉科冠雉属的鸟类。分布于南美洲亚马逊低地。其名称源于德国自然学家约翰·巴普蒂斯特·冯·斯皮克斯（Johann Baptist von Spix）。本物种包含四个亚种，曾一度被认为与暗腿冠雉或羽冠冠雉同种。","appearance":"棕胸冠雉体长66至76厘米，体重因亚种而异，雄鸟重约1.24至1.78千克，雌鸟约1.14至1.72千克。指名亚种（nominate）上体呈橄榄绿带青铜色光泽，下体鲜红色。格兰特亚种（granti）较深色，上体蓝绿色光泽，下体暗红。speciosa亚种与指名亚种相似，但额部、眉纹和耳羽有更多白色。orienticola亚种介于granti和指名亚种之间。","call":"黎明或黄昏时会发出翅膀振动的展示声，同时雄鸟发出响亮的‘QUOOEEEL！’叫声，若播放此叫声能引发强烈攻击行为。常见叫声为响亮粗糙的‘honking’声，有时以轻微哀怨的前奏开始，若受惊则连续发出。还会发出响亮的三音节吠叫。","habits":"生活在湿润的雨林和云雾林，包括常年湿润和季节性泛滥的森林。在亚马逊地区，通常独居或成对，偶尔形成小家庭群。以小型果实为主食，如棕榈果，偏好成熟的软果，也会跟随蚁群捕食昆虫，偶尔食用蚯蚓。主要在树冠层觅食，但在某些地区也常下地。","breeding":"繁殖期在南委内瑞拉为1月至5月，秘鲁东北部可能始于8月至9月，巴西亚马逊州的繁殖记录在11月至12月。巢由树叶构成，位于树上约5米高处。每窝产2至3枚白色蛋，但孵化和离巢时间未知。","identification":"体型较大，颜色深于chachalacas，喉部有更明显的红色皮肤。granti亚种比其他亚种更大，上体蓝绿色光泽明显，易于与obscura区分。speciosa亚种额部、眉纹和耳羽有更多白色。orienticola亚种介于granti和指名亚种之间。","protection":"IUCN：LC（无危）。全球范围内分布广泛，尽管总体数量未知且可能在减少。在亚马逊低地仍较常见，但面临狩猎压力，部分地区已罕见。","distribution":"分布于南美洲的玻利维亚、巴西、哥伦比亚、厄瓜多尔、圭亚那、秘鲁、苏里南和委内瑞拉的奥里诺科河上游和亚马逊河流域。从北向南依次为granti、orienticola、jacquacu和speciosa亚种。","other":"在某些保护区，如秘鲁的Tambopata-Candamo保留区，由于有效保护，种群显著恢复。"},{"name":"乌腿冠雉","english_name":"Dusky-legged Guan","scientific_name":"Penelope obscura","appearance":"乌腿冠雉成鸟体长68至75厘米，体重介于960至2100克之间。整体羽毛呈暗褐色，上体带有橄榄色光泽，腹部颜色更暖。头部裸露皮肤和腿部颜色暗淡。性别间差异不大，雄鸟虹膜红色，雌鸟虹膜浅棕色。幼鸟比成鸟小，约40天时有白色喉部，无上体白色斑点；到90天时，羽毛和体型基本与成鸟相似。种族间存在大小、色彩和标记的变化。","call":"乌腿冠雉会发出响亮、刺耳的叫声和嘶吼，通常成系列出现。","habits":"乌腿冠雉栖息于热带和上热带区的高大森林、河岸森林、次生林以及成熟的种植园周边草地，海拔可达2300米。它们有时也会进入灌木丛和农业地带。主要以果实为食，包括特定种类的水果和花蕾，同时也扮演着种子传播者的角色。在冬季，它们可能依赖两种引入的冬青树物种。","breeding":"繁殖季节主要在10月至12月，巢穴杯状或碗状，由枝条和茎构成，内部铺垫叶子，位于树木中，高度约3至10米。每次产2至3枚奶油色的蛋，孵化期大约28天。","identification":"与眉纹冠雉最为相似，但后者体型较小，主要局限于较干燥的森林、灌木丛和restinga。乌腿冠雉的前颈和胸部有白色条纹，而眉纹冠雉前颈和胸部有灰色斑纹，背部无斑点。","protection":"IUCN：LC（无危）。然而，bronzina亚种在巴西圣保罗州大幅减少，被认为是受到威胁。","distribution":"分布于南美洲中南部和东南部，包括乌拉圭、阿根廷东北部、巴西南部和巴拉圭最南部地区。","other":"2021年初，前subspecies P. o. bridgesi被提升至物种级别，称为云加斯冠雉。"},{"name":"白顶冠雉","english_name":"White-crested Guan","scientific_name":"Penelope pileata","overview":"白顶冠雉（英文名：White-crested Guan，学名：Penelope pileata），是鸡形目凤冠雉科冠雉属的鸟类。体型较大的鸟类，以独特的白色羽冠和鲜明的对比色羽毛著称。分布于巴西东部亚马逊盆地，主要栖息于热带湿润森林，面临栖息地破坏的威胁。","appearance":"白顶冠雉体长约80厘米，具有显著的白色羽冠，蓝灰色脸颊，黑色上部羽毛带有绿色光泽，下部羽毛呈深红棕色，尾羽长且黑。成年鸟眼虹膜颜色因性别而异，雄鸟呈深红色，雌鸟则较淡。幼鸟与成鸟相似，但色彩较为暗淡，眼睛颜色更浅，即使在七个月大时羽毛已接近成鸟，眼色依然较浅。","call":"白顶冠雉发出典型的嘈杂或嘶哑的叫声，尤其在清晨长时间鸣叫，叫声被描述为‘sharkoo’，与飞行时发出的吠叫和沙哑声类似。","habits":"主要栖息于低地的坚固地面森林，偶尔进入季节性洪水泛滥的林区。生活习性仍需更多研究，但在南帕拉州与眉纹冠雉和棕胸冠雉共存，在托坎廷斯西部与共存。据观察，它们会食用放置给家鸡的玉米。","breeding":"在北巴西的三月曾观察到成年的幼鸟。在圈养条件下，每窝产四枚蛋，但通常产三枚较为常见。雏鸟出生时重约64至70克，30天后体重约240克，90天后约550克。","identification":"白顶冠雉通过其宽阔的白色羽冠、上体深绿橄榄色与下体丰富红褐色的强烈对比，以及红色眼虹膜（雄鸟）来识别。与栗腹冠雉相比，它在面部有更多黑色，特别是在耳羽处。","protection":"IUCN：VU（易危）","distribution":"分布于巴西中北部，具体在亚马逊河以南，从马德拉河下游向东至马拉尼昂州，向南至帕拉州南部和托坎廷斯州西部。"},{"name":"栗腹冠雉","english_name":"Chestnut-bellied Guan","scientific_name":"Penelope ochrogaster","overview":"栗腹冠雉（英文名：Chestnut-bellied Guan，学名：Penelope ochrogaster），是鸡形目凤冠雉科冠雉属的鸟类。分布于巴西中部，主要栖息于热带干林与沼泽地带。其最显著的外部特征是头部浅棕色，逐渐加深至翅膀与尾部，胸腹部有醒目的白色斑点与鲜艳的红褐色羽毛。","appearance":"栗腹冠雉是一种中等体型的鸟，体长67.5至75厘米，雄雌外观相似，但雄鸟的虹膜颜色更偏红色，雌鸟则呈灰色，雌鸟的腿色也更为红润。全身颜色从头部的淡棕色渐变为翅膀和尾部的深棕色，胸部至腹部覆盖着白色的斑点，翅膀覆羽也有白色条纹，胸部羽毛呈现亮丽的红褐色。","call":"栗腹冠雉发出的叫声被描述为粗糙而类似乌鸦的叫声，当受到惊吓时会发出响亮的吠叫，类似于小型狗的叫声，但比同类物种眉纹冠雉的叫声更刺耳。","habits":"栗腹冠雉偏好生活在河流边或沼泽地带的茂密森林中，这些地方富含木质藤蔓。它们通常在树冠层觅食，偶尔也会到地面觅食。在旱季，它们会食用花朵，尤其是Tabebuia impetiginosa和Vismia树的花，也会吃年轻藤蔓的叶子甚至新鲜的草。在树冠和中层树木上觅食，以昆虫为主食。","breeding":"繁殖季节疑似在10月至11月间，至少在马托格罗索州的潘塔纳尔地区如此。已知一窝通常有两个蛋，关于繁殖的其他信息尚未可知。","identification":"与眉纹冠雉相比，栗腹冠雉有更明显的淡色眉毛和白色条纹背部。与白顶冠雉相比，栗腹冠雉的羽毛颜色对比不那么强烈，上体颜色较淡；与眉纹冠雉相比，后者内翼羽毛边缘呈锈色，且有时会有锈色的眉纹。","protection":"IUCN：VU（易危）","distribution":"分布于巴西中部，从托坎廷斯州西部和戈亚斯州西部到米纳斯吉拉斯州东北部、马托格罗索州南部和马托格罗索州南部。在托坎廷斯州、马托格罗索州的Poconé地区和托坎廷斯州西部相对常见，但在其他地区记录稀少。","other":"栗腹冠雉在半落叶林中的数量极为稀少，特别是在潘塔纳尔地区。虽然被认为非常罕见，但一些权威人士认为它并不特别受威胁。在野外的标本和观察记录很少，表明其种群数量可能很小，或者物种高度局域化或非常隐秘。"},{"name":"白眉冠雉","english_name":"White-browed Guan","scientific_name":"Penelope jacucaca","overview":"白眉冠雉（英文名：White-browed Guan，学名：Penelope jacucaca），是鸡形目凤冠雉科冠雉属的鸟类。生活在南美东北部，以宽阔而醒目的白色眉纹命名，栖息于多种干燥森林环境，如开放的angical、caatinga和restinga，偶尔也会出现在campo rupestre草甸。白眉冠雉常在地面觅食，有时会组成大群。","appearance":"白眉冠雉身长65至70厘米，通体呈深褐色，拥有突出的白色眉纹，下方有一条细黑线，与裸露的灰色眼周皮肤相隔。雄鸟的虹膜颜色偏红，雌鸟则更偏向棕色。上翼有明显的白色条纹，比眉纹冠雉更为显著。幼鸟的前颈为黄色，无红色肉垂，眼周皮肤黄，翅膀、胸和侧翼的白色条纹较淡。","call":"发出一系列的‘ga-ga’和‘ga-o’叫声，形成嘈杂的叫声组合，如‘ga-ga-ga-...’或‘ga-o-o-o-...’，也有哨声和特别响亮的‘sh-sh-..-ga-ga-..’叫声，某些声音在几百米外仍可听到。","habits":"主要栖息于干燥的矮树丛生半落叶林，适应于各种环境，包括被选择性砍伐和退化的区域，靠近临时河流时数量较多。在低地活动，海拔低于1000米。通常在地面觅食，偏好Ziziphus joazeiro树的果实，以及Copaifera langsdorfii和Eugenia cearensis的种子，也吃昆虫。","breeding":"繁殖季节未知，但可能包含雨季部分时段。在树上或棕榈树中筑巢，巢由树枝构成，内部铺满干叶，产2-3枚白色蛋，平均尺寸为68毫米×50毫米，重约92克。","identification":"与眉纹冠雉相比，白眉冠雉具有更鲜明的眉纹和苍白的腿。幼鸟与成鸟的区别在于黄色的前颈，无红色肉垂，眼周皮肤黄，白色条纹不明显。","protection":"IUCN：VU（易危）","distribution":"分布于巴西东北部，从南部马拉尼昂向东跨过皮奥伊、塞阿拉、帕拉伊巴和伯南布哥，向南延伸至阿拉戈斯、巴伊亚和东北部米纳斯吉拉斯。在低地活动，海拔低于1000米。","other":"在一些人口密集区仍然可见，曾因栖息地丧失和狩猎压力而数量大幅减少，已被列为易危物种。"},{"name":"央葛斯冠雉","english_name":"Yungas Guan","scientific_name":"Penelope bridgesi","appearance":"云加斯冠雉全身主要为深栗色，翼羽、肩羽、胸羽和背部有明显的白色条纹。头部黑色，冠羽边缘泛白，尤其在前额处最为明显。尾巴棕色带有光泽，喉部肉垂红色。两性相似，但雄鸟的虹膜为红色，雌鸟为浅棕色。体型较大，长度介于77.0至89.0厘米之间。","call":"发出混合低音哨声和沙哑音符的叫声，例如“SWig SWI-u，SWig-u KREG，swig-u，u，KREG KREG KREG”。在高度警戒状态下，后一类叫声更为频繁。","habits":"云加斯冠雉生活在安第斯山脉东侧的南美亚热带常绿森林中，海拔范围从1000米以下到约1900米。它们通常以家庭群或小群体出现，经常在果实丰富的树上觅食，也会在地面行走。主要以树叶和果实为食，冬季会以可得的果实补充食物。","breeding":"繁殖季节主要在10月至12月，巢中有卵的记录出现在10月底，而雏鸟则在1月初至3月被观察到。","identification":"与红脸冠雉相比，红脸冠雉具有独特的亮粉色面部裸露皮肤、虹膜和冠羽颜色。与乌腿冠雉相比，云加斯冠雉体型更大，腹部有棕色到橙色的水平标记，且颈部、背部和胸部的羽毛边缘更宽。","protection":"IUCN：LC（无危）。在阿根廷北部的El Rey国家公园内数量丰富，但在公园外依赖于山区森林，这些森林受到的破坏程度低于区域内的查科和前山森林。在玻利维亚和阿根廷西北部的总体估计数量超过10万只。在阿根廷被列为Vulnerable，由于狩猎活动，数量正在减少，尽管在一些国家公园内数量稳定。","distribution":"分布于玻利维亚中部至阿根廷西北部的南美亚热带常绿森林中，包括中央玻利维亚的Cochabamba、Santa Cruz、Chuquisaca和Tarija，向南延伸至阿根廷的Jujuy、Salta、Tucumán和Catamarca。","other":"曾被认为是乌腿冠雉的亚种，直到2018年基于体型和羽毛差异被提升为独立物种。"},{"name":"鸣冠雉","english_name":"Trinidad Piping Guan","scientific_name":"Pipile pipile","overview":"鸣冠雉（英文名：Trinidad Piping Guan，学名：Pipile pipile），是鸡形目凤冠雉科鸣冠雉属的鸟类。大型的鸟类，外观类似火鸡，仅见于特立尼达岛的森林中。其全身黑色，翼部和头部有白色斑点，面部呈淡蓝色，喉部有一片天蓝色的皮肤褶。当地人称之为‘pawi’，因狩猎而极度濒危，目前仅在少数地方，如Grand Riviere镇附近，能定期观察到。","appearance":"鸣冠雉体型大，约65至69厘米长，体重2500至3300克。雄鸟比雌鸟略大，上翼覆羽上的白色斑块更明显且较大。与蓝喉鸣冠雉相比，鸣冠雉颜色更偏向棕色，光泽较暗淡，头顶主要是深色。成年鸟近黑色，幼鸟体羽更偏棕色，头部和翼覆羽上的白色标记较少。","call":"鸣冠雉发出一系列拉长的上升哨音，有时在飞行中会大声拍打翅膀。其叫声包括单一响亮的‘啪嗒’声，随后是4至6个引子‘啪嗒’声，接着是一连串鼓点般的颤音，通常在黎明时分发出。此外，还有薄薄的‘pee-oo’或‘pyoo’声，由独处或群体中的个体发出，可能用于联系；鸭子般的低哑叫声；单个上升的哨音；以及与展翅飞行展示结合的歌曲，由3至5个上升的哨音组成，持续约5秒，每个音符的起始音调都略低于前一个。","habits":"鸣冠雉主要栖息于特立尼达岛东北部的偏远高大原始森林中，树冠高度可达40至50米，偏好地面覆盖稀疏、树冠闭合、丰富的藤本植物和寄生植物的环境。它们倾向于在陡峭的丘陵地带，有深谷和丰富的水道，海拔400至900米的地方活动，偶尔在接近海平面的地方也有记录。鸣冠雉主要以树木的果实和种子为食，包括至少14种不同的物种，如Virola surinamensis、Ocotea glomerata等。它们也吃嫩叶和偶尔的昆虫。鸣冠雉主要在小群中觅食，通常聚焦于特定区域长时间觅食，甚至在天黑后1至2小时仍在活动。它们几乎完全生活在树上，仅偶尔下地。","breeding":"鸣冠雉的繁殖季节似乎很长，记录显示在大多数月份都有繁殖活动，包括3月至4月的交配，1月的雌鸟带卵，3月和4月的小鸡，以及11月、1月、2月和5月的幼鸟。巢通常是位于离地面不远的植被缠绕中的树枝平台。一窝产两个蛋。关于繁殖的更多信息尚不可得。","identification":"鸣冠雉与蓝喉鸣冠雉相比，颜色更偏向棕色，光泽较暗淡，头顶主要是深色。幼鸟的体羽更偏棕色，头部和翼覆羽上的白色标记较少。在特立尼达岛上，它是唯一的本地鸟类，与其他鸟类通过其独特的外观和声音易于区分。","protection":"IUCN：CR（极危）CITES: I（濒危物种国际贸易公约附录一）。鸣冠雉曾经在全岛广泛分布，数量众多，直到1940年代或1950年代。现在，它可能仅限于特立尼达岛东北部的东部山脉上方400米以上，偶尔在阿瑞玛山谷和其他地方的山麓有目击记录。估计剩余的适宜栖息地仅有150至350平方公里。总数量大约在1980年约为100只，最近估计在70至200只之间。栖息地丧失和过度狩猎是其显著下降的原因。","distribution":"鸣冠雉分布于南美的特立尼达岛，主要集中在东北部山脉，特别是阿瑞玛—布兰奇苏斯路以东的地区。在阿瑞玛山谷和其他地方的山麓偶尔有目击记录。","other":"鸣冠雉是特立尼达岛唯一的本土鸟类，曾经广泛分布于全岛，包括北方山脉和南部的Trinity Hills，以及低地地区如Nariva沼泽和Aripo草原。"},{"name":"蓝喉鸣冠雉","english_name":"Blue-throated Piping Guan","scientific_name":"Pipile cumanensis","overview":"蓝喉鸣冠雉（英文名：Blue-throated Piping Guan，学名：Pipile cumanensis），是鸡形目凤冠雉科鸣冠雉属的鸟类。大型鸟类，最显著的特征是拥有裸露的白色面部和翅膀上的白色斑块，头部和颈背部分主要为白色，但带有淡褐色条纹。喉咙处有一片通常呈蓝色的肉质斑块，但颜色可能在某些个体上变为灰色或黑色。广泛分布于南美洲的低地雨林中。","appearance":"蓝喉鸣冠雉是一种中等体型的黑白色凤冠雉科鸟类，全身大部分为黑色，带有绿色光泽，尤其在肩部、翅膀和尾巴上最为明显。头部的额头、头顶和颈背为白色，带有宽阔的淡褐色条纹。翅膀的外侧大覆羽上有大面积的白色斑块，内侧覆羽有白色斑点。其最明显的特征是下垂的长而细的喉部肉垂，颜色从白色到钴蓝色不等，偶尔会呈现暗紫色或黑色。眼睛周围有白色至钴蓝色的裸露皮肤。","call":"在黎明或黄昏时分，蓝喉鸣冠雉会发出一系列上升的清晰哨音，通常由缓慢的哨声组成，每一声都逐渐变长。","habits":"主要栖息在亚马逊盆地的热带湿润森林中，包括高地森林、河滩森林、画廊森林和半落叶森林。在圭亚那地区，也能在较开阔的沿海地带找到它们。通常在河流附近约100米范围内活动。以果实和树叶为主食，偏爱无花果，但在繁殖季节以外，可能会形成多达30只的小群，尤其是在盐土地区。在地面或树冠层觅食。","breeding":"蓝喉鸣冠雉的繁殖季节一般从8月持续到次年4月，可能与当地雨季相吻合。巢由树枝构建，通常位于密林高处。一窝产1到3枚蛋，孵化期在圈养条件下为24至28天，雏鸟离巢时间未知。","identification":"与鸣冠雉相比，蓝喉鸣冠雉更黑、更有光泽，冠羽更窄且尖锐，翼部的白色斑块略大，胸羽的白色边缘更宽。与红喉鸣冠雉的区别在于后者喉部肉垂主要为红色，翼部白色斑块较小，且覆羽上有更多的黑色斑点。白喉鸣冠雉与蓝喉鸣冠雉存在混合区，白喉鸣冠雉的头部为白色，带有黑色或棕色条纹，颈后白色斑块更发达，延伸至颈部更下方，喉部肉垂更细长，呈下垂状，上体颜色更偏向橄榄绿，翼部白色斑块更大且更均匀。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马逊盆地，包括哥伦比亚东部至圭亚那，巴西西部和秘鲁。在玻利维亚可达海拔300米，在厄瓜多尔可达400米，在哥伦比亚可达500米，在委内瑞拉可达1000米，在秘鲁局部可达1100米。","other":"曾被认为与白喉鸣冠雉为同一物种，但现在被视为独立的物种。"},{"name":"红喉鸣冠雉","english_name":"Red-throated Piping Guan","scientific_name":"Pipile cujubi","overview":"红喉鸣冠雉（英文名：Red-throated Piping Guan，学名：Pipile cujubi），是鸡形目凤冠雉科鸣冠雉属的大型黑白色鸟类。具有红色喉囊。分布于南美洲的巴西中北部和玻利维亚东部，主要栖息于热带和半落叶森林，尤其偏好河流沿岸森林。","appearance":"全长69至76厘米，体重1100至1300克。全身黑色，翼部和头部有黑白相间的斑纹，头部有蓬松的白色羽冠，胸部点缀白色斑点，面部裸露皮肤呈淡蓝色，喉部有醒目的红色肉垂。与蓝喉鸣冠雉相比，红喉鸣冠雉的羽色更闪亮，带有蓝色光泽，翼部白斑较小。","call":"发出一系列上升的清晰哨声，通常在早晨鸣唱，有时在白天其他时间也能听到。黎明时的翅膀振动展示发出粗重的撕裂声。","habits":"主要栖息于至少15至20米高的热带和半落叶森林，包括河岸森林，海拔可达700米。以群居为主，有时可见到多达30只的群体。以果实和花为食，偶尔会到地面觅食。与蓝喉鸣冠雉混群觅食。","breeding":"关于繁殖生态学的信息极少，仅知在9月中旬的玻利维亚观察到两只幼鸟跟随成鸟。","identification":"与蓝喉鸣冠雉相比，红喉鸣冠雉的喉囊颜色和面部图案不同，且羽色更为光泽。亚种nattereri与指名亚种为例，有更长的喉囊，白羽面积较大。","protection":"IUCN：VU（易危）","distribution":"分布于南美巴西中北部的亚马逊雨林地区，以及玻利维亚的圣克鲁斯省东部。在亚马逊国家公园、Rondônia部分地区以及诺埃尔·肯普夫·梅尔卡多国家公园均有记录。","other":"受狩猎和栖息地丧失威胁，尤其是在马托格罗索州和Rondônia地区的森林砍伐尤为严重。"},{"name":"黑额鸣冠雉","english_name":"Black-fronted Piping Guan","scientific_name":"Pipile jacutinga","overview":"黑额鸣冠雉（英文名：Black-fronted Piping Guan，学名：Pipile jacutinga），是鸡形目凤冠雉科鸣冠雉属的鸟类。又名: 黑胸鸣官鸟，珍稀、受威胁的大型鸟类，其显著特征为黑白相间的羽毛，拥有独特的黑色额头和白色眼环，分布于南美的巴西东南部、阿根廷东北部及巴拉圭东南部的亚热带雨林。曾广泛分布，现仅存于少数保护区。","appearance":"黑额鸣冠雉体型大，长度介于63.5至74厘米之间，体重约1100至1400克。其外观类似瘦长的火鸡，具有一条长长的黑色尾巴。头部特征鲜明，拥有粗犷的白色羽冠和大胆的白色眼环，与红色和蓝色的喉垂形成对比，同时配以蓝色带黑色尖端的喙和黑色脸部。翅膀上有显著的白色斑块，带有黑色斑点的上翼覆羽形成特有的图案。幼鸟与成鸟相似。","call":"其鸣声为一系列高音上升的哨音，与同属物种类似。此外，它还会发出特有的翼振声，由两拍无声振翅、一长串干燥的颤音、两拍快速振翅和最后更长的颤音组成。","habits":"黑额鸣冠雉栖息于大西洋森林的各种类型，包括常绿、河岸和沿海森林，海拔高度通常低于1000米。它们偏好成熟的一级森林，偶尔也会在较老的次生林中出现。以果实为主食，已记录到至少41种不同的水果种类。有时也会食用种子、花蕾、昆虫甚至软体动物。它们单独、成对或小群活动，主要在树上觅食，偶尔会到地面捡拾掉落的果实。","breeding":"繁殖季节从8月持续到12月，巢穴为树枝和茎构成的平台，位于树叉中，离地高度可达1.7米。每窝产2至4枚白色蛋，孵化期约为28天，主要由雌鸟负责。双亲共同喂养幼鸟，幼鸟约3个月大时获得成鸟羽毛。","identification":"黑额鸣冠雉最明显的识别特征是其黑色的前额和白色的眼环，这是同属其他物种所不具备的。与蓝喉鸣冠雉在地理分布上曾有少量重叠。","protection":"IUCN：EN（濒危）","distribution":"黑额鸣冠雉分布于巴西东南部（从巴伊亚州南部至南里奥格兰德州）、阿根廷东北部（米西奥内斯省）和巴拉圭东南部。在巴西，零星的种群分布在圣保罗州的Intervales和Carlos Botelho州立公园等保护区；在阿根廷，主要见于米西奥内斯省的乌尔瓜伊省级公园；在巴拉圭，少量种群存在于阿图帕拉伊和卡尼德尤。","other":"自20世纪中叶以来，由于栖息地丧失和过度狩猎，黑额鸣冠雉数量急剧下降，目前仅在少数保护区内尚存。"},{"name":"白喉鸣冠雉","english_name":"White-throated Piping Guan","scientific_name":"Pipile grayi","overview":"白喉鸣冠雉（英文名：White-throated Piping Guan，学名：Pipile grayi），是鸡形目凤冠雉科鸣冠雉属的鸟类，主要分布在南美洲的巴西西南部、秘鲁东南部、玻利维亚东部以及巴拉圭东北部。这种近威胁物种具有独特的黑白色羽毛，以及白色的额头、冠羽和颈背。","appearance":"白喉鸣冠雉体长约60至69厘米，雌雄外观相似。其羽毛大多呈黑色，带有一种淡橄榄绿到橄榄绿色光泽，尤其在肩部、翅膀和尾巴处最为明显。额头、冠羽和颈背为白色，胸羽边缘亦为白色。冠羽由细长的毛发状羽毛构成，带有黑色或棕黑色的羽轴条纹。翼上的外覆羽形成一块显著的白色斑块，而内覆羽则有白色斑点。环绕深红棕色眼睛的是白色至钴蓝色的裸露皮肤，喉咙下方有类似垂肉的裸露部分，颜色同样为白色至钴蓝色。喙可能是淡蓝色带黑尖，或是黑色基部粉红和蓝色。腿为棕红色。","call":"白喉鸣冠雉的叫声主要在繁殖季节发出，可能仅限于这一时期。它会做出一次或两次拍翅的飞行展示，随后是它的鸣唱，大约8到10个缓慢、清晰且略升调的哨音，每个音符逐渐变长，通常在黎明和黄昏时分进行。","habits":"白喉鸣冠雉主要栖息在亚马逊盆地的热带湿润森林中，包括高地森林、河滩林和画廊林，也会出现在塞拉多灌木丛。它们几乎总是靠近河流，一般不会离开河流超过约100米。在海拔上，它们可以达到玻利维亚的1,500米高度。饮食以水果和树叶为主，会在树冠层或其下方觅食，偶尔在地面进食。在非繁殖季节，它们可能会聚集多达20只的群体，尤其是在盐泉附近。它们经常与同科其他鸟类一起觅食。","breeding":"关于白喉鸣冠雉的繁殖生态知之甚少，只知道它们会在密林的树冠中筑巢。","identification":"白喉鸣冠雉与鸣冠雉的区别在于更为漆黑和光泽感更强（光泽为橄榄绿而非紫褐色），冠羽更窄且尖锐，翼上的白色羽毛略多，胸羽的白色边缘更宽。与蓝喉鸣冠雉的区别在于冠羽为白色且有黑色或棕黑色的羽轴条纹，颈背的白色斑块更发达，延伸至颈部更下方，喉咙下的垂肉细长且悬挂，上体颜色更偏向橄榄绿，翼上的白色斑块更大且更均匀。","protection":"IUCN：NT（近威胁）","distribution":"白喉鸣冠雉的分布范围涵盖了南美的巴西西南部、秘鲁东南部、玻利维亚东部以及巴拉圭东北部。","other":"白喉鸣冠雉被认为是大部分时间定居的，但在寻找果实时可能进行局部或海拔移动。"},{"name":"肉垂冠雉","english_name":"Wattled Guan","scientific_name":"Aburria aburri","overview":"肉垂冠雉（英文名：Wattled Guan，学名：Aburria aburri），是鸡形目凤冠雉科肉垂冠雉属的鸟类。全身羽毛黑色，喙蓝基黑尖，脚呈淡黄色。分布于南美洲的委内瑞拉至秘鲁的安第斯山脉，常见于海拔500至2500米的湿润山林。","appearance":"肉垂冠雉体型较大，长度约72.5至81.5厘米，体重介于1195至1550克之间。其特征性的红色和黄色肉垂从喉咙垂下，羽毛整体呈黑色，胸背部光泽感强，色泽从北向南由橄榄绿转为深蓝色。喙大部分呈蓝色，尖端暗色，腿和脚颜色非常浅。雌鸟拥有黄色有时带红底的下垂肉垂，而雄鸟则没有。幼鸟外观与成鸟相似，但肉垂发育不全。","call":"肉垂冠雉主要在黎明和黄昏时分发出响亮的叫声，声音为持续几秒的上升嗡嗡声，带有类似芦苇的音质，类似小燕尾夜鹰的叫声，具有独特的‘baaaarrreeeeeeeeer’音节，结尾处有噼啪声。","habits":"肉垂冠雉栖息于湿润的山地森林，靠近森林边缘和次生林，主要分布在安第斯山脉的亚热带地带，偶尔在季节性迁移中到达温带地带的下限。它们通常在树冠中到上层觅食，以果实和叶子为主食，偏好高密度Fraxinus chinensis树林和Geissanthus树种，可能作为种子传播者。","breeding":"繁殖期在南美不同地区有所差异，一般从九月到三月。在哥伦比亚，筑巢期集中在十二月至二月，巢为杯状或篮状，由雄鸟主导建造，位于树枝分叉处，直径约25至40厘米，深度约10厘米。蛋为污白色，尺寸约为74至81.3毫米×53至55毫米，重量在104至124.5克之间。","identification":"肉垂冠雉与褐镰翅冠雉的区别在于体型更大，下体羽毛颜色更深，以及独特的喉部肉垂。在繁殖区域内，可通过肉垂和叫声进行辨识。","protection":"IUCN：LC（无危）","distribution":"肉垂冠雉分布在委内瑞拉东部至秘鲁南部的安第斯山脉区域，包括哥伦比亚、厄瓜多尔。在委内瑞拉，分布高度可达1800米，偶尔至2200米。在哥伦比亚，分布范围从400米至2500米。在秘鲁，主要分布在1000米至1900米之间，有记录显示最低至500米，最高至2300米。在厄瓜多尔，主要分布在更湿润的东坡，但也出现在西坡的Pichincha和Cotopaxi地区。","other":"肉垂冠雉受到栖息地破坏的威胁，尤其是在哥伦比亚和秘鲁的部分地区，由于森林砍伐和狩猎压力，其数量正在下降。在墨西哥的一个收藏中，该物种已被成功繁殖，但在圈养条件下仍然非常罕见。"},{"name":"黑镰翅冠雉","english_name":"Black Guan","scientific_name":"Chamaepetes unicolor","overview":"黑镰翅冠雉（英文名：Black Guan，学名：Chamaepetes unicolor），是鸡形目凤冠雉科镰翅冠雉属的鸟类。全身黑色羽毛，蓝色面部皮肤环绕红眼，腿脚呈粉红色。分布于哥斯达黎加至巴拿马西部的山区云雾森林。","appearance":"成年黑镰翅冠雉体长62至69厘米，平均体重约1135克。全身羽毛统一为黑色，面部皮肤呈现鲜艳的蓝色，眼睛红色，腿脚粉红。幼鸟与成鸟相似，但光泽较弱，腹部颜色偏褐色，面部皮肤初期为黑色或深棕色，数月后变为蓝色。","call":"繁殖季节发出管状叫声，受惊扰时会发出低沉的“ro-rooo”或咳嗽般的“kowr”声，以及尖锐的重复“tsik tsik…”报警声。黎明或黄昏时会展开翅膀，发出响亮、尖锐、沙沙的翼振声。","habits":"主要栖息于中美洲山区的云雾林，偏好陡峭地形，海拔通常在1000至2250米之间，偶尔下降至800米。以水果为主食，摄食多种植物果实。活动模式主要是独居、成对或小群，既在树上觅食也在地面捡食落果。","breeding":"繁殖季节为2月至6月。筑巢于树上4.5米高的寄生植物丛中，巢由树叶和树枝构成的小平台。每窝产2-3枚白色蛋。雏鸟孵化后不久便离开巢穴。","identification":"与同类物种相比，黑镰翅冠雉体型较大，全身羽毛全黑，面部皮肤蓝色，区别于其它种类的头部羽毛卷曲或分布区域差异。","protection":"IUCN：LC（无危）。在哥斯达黎加保护区较为常见，但在巴拿马仅局部地区数量较多。即便受到保护，仍因食用而被大量猎杀。","distribution":"繁殖区域位于哥斯达黎加北部的Cordillera de Guanacaste山脉至巴拿马西部的Coclé省。在中美洲的Talamancan山区云雾林生态区广泛分布。","other":"尽管在全球范围内并不面临威胁，但在局部地区由于非法狩猎，其生存状况令人担忧。"},{"name":"褐镰翅冠雉","english_name":"Sickle-winged Guan","scientific_name":"Chamaepetes goudotii","overview":"褐镰翅冠雉（英文名：Sickle-winged Guan，学名：Chamaepetes goudotii），是鸡形目凤冠雉科镰翅冠雉属的鸟类。大型鸟类，分布于南美洲的哥伦比亚至玻利维亚。这种鸟体型似鸡，但在冠雉中属于小型。最显著的特点是深棕色的外表、鲜明的栗色腹部和亮蓝色面部皮肤环绕着红色的眼睛。","appearance":"褐镰翅冠雉长度介于50至65厘米之间，体重在550至800克之间。成鸟具有独特的外观，包括明亮的栗色腹部、浅蓝色的面部皮肤和红色的眼睛，以及鲜红的腿。幼鸟与成鸟相似，但颜色较暗淡，喉咙部分羽毛尚未完全发育。不同的亚种在体型和羽毛颜色上有所差异，比如C. g. sanctaemarthae的上胸部、喉咙和脸颊带有部分栗色，腹区和大腿的颜色更深；C. g. fagani的头部和上部比其他亚种更暗，下部呈栗色；C. g. tschudii与fagani类似，但上部更偏橄榄褐色，下部的栗色较浅；C. g. rufiventris的颈羽边缘呈灰色，形成鳞状外观，上部更接近橄榄色，下部的栗色不如tschudii深。","call":"这种鸟在黎明和黄昏时最为活跃，发出持续约2秒的翅膀拍打声，伴随3到6次的向下飞行，每次飞行距离约为20米。C. g. fagani亚种会发出极高音的口哨声，随后是更粗重的叫声或与翅膀拍打展示结合。当受到惊扰时，如在巢边，会发出高音的警报声。","habits":"褐镰翅冠雉主要栖息于安第斯山脉两侧的亚热带湿润和潮湿森林地带，从哥伦比亚到玻利维亚均有分布。它倾向于在陡峭的山丘上活动，主要在高降水区域，偏好高大的森林，但也偶尔出现在次生林和较轻的开阔林地中，如咖啡种植园。它们主要以水果为食，偶尔也吃种子、花、叶子和昆虫。它们通常在果树上觅食，高度可达13米，成对或小群体活动，通常在黎明和黄昏时分。在一些地区，它们会造访香蕉喂食站。","breeding":"繁殖季节在哥伦比亚中部安第斯山区为1月至6月，可能在其他地区更长。巢是一个由苔藓、死植被、绿叶和细枝构成的平台，通常放置在树杈或凤梨科植物上，离地面2.1至6米。一窝产2到3枚白色蛋，有时带有棕色或红棕色斑点。孵化期间可能是雌鸟单独孵化，或是双亲共同参与，但已知的离巢时间间隔从78.5到107.6分钟不等，最长记录为310分钟。雏鸟刚出生时为巧克力棕色，背部有奶油色条纹，头部和下部为赤褐色或肉桂色，腹部逐渐变白，有黑色眉纹，红色腿和暗白色的眶周皮肤。","identification":"与其他冠雉相比，褐镰翅冠雉可以通过其独特的栗色腹部、浅蓝色面部皮肤和红色眼睛来识别。不同亚种之间在颜色和体型上存在细微差别。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，包括哥伦比亚至玻利维亚，主要栖息于安第斯山脉两侧的亚热带湿润和潮湿森林。","other":"尽管在一些地区数量减少，特别是在村庄周边，但总体上，这种鸟在某些区域仍然相当常见。"},{"name":"山冠雉","english_name":"Highland Guan","scientific_name":"Penelopina nigra","overview":"山冠雉（英文名：Highland Guan，学名：Penelopina nigra），是鸡形目凤冠雉科山冠雉属的鸟类。体型接近雉鸡的大型鸟类，其分布于中美洲的高山森林，从墨西哥南部至尼加拉瓜，常见于云雾林和松栎混交林。雄鸟拥有亮泽的黑色羽毛和醒目的红色喉部肉垂，雌鸟则为棕色条纹黑褐色。山冠雉在繁殖季节，雄鸟的响亮哨声和翅膀震动产生的噼啪声尤为突出。","appearance":"雄性山冠雉全身羽毛呈光泽的黑色，上身带有绿色或蓝色的反光，腹部颜色较暗淡；眼圈、喙、喉部肉垂、腿脚均为鲜艳的红橙色。雌鸟羽毛为黑色，密集地缀以红褐色和肉桂色的斑点与条纹，喙和眼周裸露皮肤为红色。幼鸟的羽毛比成年雌鸟更暗，但未达到成年雄鸟的全黑色，头部和颈后有一条黑色带纹，边缘为淡黄色条纹。","call":"雄鸟在春季会发出刺耳的上扬哨声，通常伴随着翅膀振动产生的奇特的噼啪声和破碎的颤音，这些声音在滑翔展示飞行中交替出现。","habits":"山冠雉栖息于海拔700至3300米的高湿度常绿森林中，偏好云雾林和松栎混交林。它们利用森林的所有层次觅食，从底层到树冠，以各种果实为主食，也会捡食地面的落果。山冠雉在繁殖季节较为活跃，此时雄鸟会发出远距离传播的哨声。","breeding":"繁殖期主要集中在2月至4月。雌鸟单独筑巢于森林的下层或中层，有时在地面上，孵化两个白色的蛋。雄鸟的求偶展示包括哨声和翅膀的振动。","identification":"山冠雉与同域分布的紫冠雉区别明显，后者体型更大，胸部有白色条纹。与纯色小冠雉和白腹小冠雉也有区别，尤其是在颜色和体型上。山冠雉的黑色雄鸟和条纹雌鸟在外貌上具有独特性。","protection":"IUCN：VU（易危）","distribution":"山冠雉的分布范围覆盖了中美洲的墨西哥南部至尼加拉瓜，包括奥哈卡州、恰帕斯州、危地马拉、萨尔瓦多、洪都拉斯和尼加拉瓜的高山地区。","other":"山冠雉因栖息地丧失和被猎杀用于食用，其数量近年来显著下降。"},{"name":"角冠雉","english_name":"Horned Guan","scientific_name":"Oreophasis derbianus","overview":"角冠雉（英文名：Horned Guan，学名：Oreophasis derbianus），是鸡形目凤冠雉科角冠雉属的鸟类。为古代鸟类家族的一员，与澳洲的巨鸟科（Megapodiidae）有亲缘关系。这种珍稀鸟类仅分布于墨西哥东南部（恰帕斯州和奥阿哈卡州）、危地马拉南部，可能也存在于洪都拉斯部分地区。其最显著的特征是头部顶部的红色角状突起，全身呈现黑色并带有蓝色光泽，喉咙、胸部及上腹部点缀着白色的斑点。","appearance":"角冠雉体型长约75至85厘米，头部较小，腿长且强壮，尾部长而宽。成年个体头部、颈部和上体为黑色，带有蓝绿色光泽。尾巴为黑色，靠近基部有一条宽阔的白色带。喉咙、胸腹和上腹部为白色，带有黑色斑点，下腹部和两侧为棕色。拥有红色的小肉垂、白色的眼珠、黄色的喙以及红色的腿和脚。雄鸟和雌鸟在外表上相似，但雄鸟的角、翅膀、尾巴和跗跖比雌鸟更长。幼鸟与成鸟类似，但色泽较暗淡，角较小。","call":"角冠雉的鸣叫特征明显，雄鸟和雌鸟的叫声各有特色。雄鸟的主要叫声是一种非常低沉、缓慢而柔和的‘哞哞声’，由七个音符组成，开始是一声短暂的哼鸣，接着是六组成对的哼鸣声。雌鸟的叫声较为嘶哑且响亮，通常是对雄鸟叫声的回应，包括一系列重复的‘咕噜咕噜’声或‘哇呜哇呜’声。","habits":"角冠雉全年居住在其分布范围内，偏好湿润的常绿山地森林，云雾林和松栎混交林。海拔主要在2300米至3100米之间，偶尔可低至1200米或高达3350米。它们主要以各种果实为主食，绿叶也是饮食的重要组成部分，偶尔食用花朵和少量昆虫。它们在森林各层单独或小群体觅食，甚至在地面活动。它们可能是重要的种子传播者。","breeding":"繁殖季节通常在二月至三月的低降雨月份，此时幼鸟在五月雨季回归前已成长至半大。据信实行一雄多雌制，雄鸟在繁殖季节中会轮流与3到5个雌鸟相处，每只雌鸟停留3到9天。巢筑在高树上，由干燥的树叶和寄生植物的根构成，雌鸟单独孵化两枚白色的蛋，孵化期为34到36天。幼鸟在孵化后3到6天离开巢穴。","identification":"角冠雉的辨识特征在于其头部顶部的红色角状突起，全身黑色并带有蓝色光泽，以及白色的喉咙、胸腹和上腹部，下腹部和两侧为棕色。幼鸟与成鸟相似，但色泽较暗，角较小。","protection":"IUCN：EN（濒危）","distribution":"角冠雉主要分布在墨西哥东南部（恰帕斯州和奥阿哈卡州）和危地马拉南部，可能也存在于洪都拉斯部分地区。它们偏好海拔在2300米至3100米之间的湿润常绿山地森林，偶尔可低至1200米或高达3350米。","other":"角冠雉的数量受到栖息地丧失、非法狩猎和分布地的限制，导致其被世界自然保护联盟列为濒危物种。"},{"name":"夜冠雉","english_name":"Nocturnal Curassow","scientific_name":"Nothocrax urumutum","overview":"夜冠雉（英文名：Nocturnal Curassow，学名：Nothocrax urumutum），是鸡形目凤冠雉科夜冠雉属的鸟类。分布于南美洲的亚马逊雨林西部。其体型较小，全长约50至57.5厘米，以暗褐色羽毛为主，拥有醒目的橙色喙和眼上黄色皮肤。夜行性特征显著，主要在夜间活动，难以直接观察。","appearance":"夜冠雉体长50-57.5厘米，体重可达1250克。全身呈温暖的棕色，具有橙色的喙，眼上部为黄色皮肤，眼下部为灰色皮肤。头部有一长而扁平的黑色冠羽，腹部区域为淡黄色，尾羽尖端颜色较浅。两性相似，但雌鸟侧面有更重的虫蚀状斑纹。雏鸟与成鸟非常相似。","call":"夜冠雉仅在夜间鸣叫，通常在晴朗黑暗的夜晚发出低沉、共鸣强的七音符系列，声音可远达1公里，被描述为‘hmm-hmm-hmmmm, hmm hmm-hmmm, hmmph!’。有时会听到几只鸟在小范围内相互呼应。","habits":"夜冠雉生活在亚马逊流域的茂密湿润森林中，包括高地森林和永久或季节性洪水淹没的森林，通常靠近黑水河流。它们似乎偏爱低洼部分被淹的区域，白天也会活动，主要在黎明和黄昏时段。它们单独、成对或以小群体形式觅食，以植物性食物为主。","breeding":"夜冠雉的繁殖季未完全确定，但已知在10月至次年2月间有繁殖活动。它们会建造一个大而松散的巢，由树枝或活的棕榈叶构成，内衬小枝条和干叶，通常位于树上或倾斜的藤蔓上，离地面不远。每窝产2枚白色蛋，孵化期约为28-29天。","identification":"夜冠雉与其他凤冠雉科鸟类的区别在于其较小的体型和暗红或栗色的羽毛，以及独特的夜间鸣叫。在亚马逊地区，它的独特外形和行为模式使其容易识别。","protection":"IUCN：LC（无危）","distribution":"夜冠雉分布在南美洲亚马逊雨林的西部，范围包括委内瑞拉南部、哥伦比亚东南部、厄瓜多尔东部、秘鲁东北部以及巴西西部和中部。在一些地区，如哥伦比亚的Guainía地区和秘鲁Loreto，夜冠雉被认为是常见的。","other":"夜冠雉的隐蔽习性可能使它免受狩猎压力的影响。在某些地区，尽管其他凤冠雉科鸟类因狩猎而数量锐减，但夜冠雉的叫声仍然经常被听到。"},{"name":"无冠盔嘴雉","english_name":"Crestless Curassow","scientific_name":"Mitu tomentosum","overview":"无冠盔嘴雉（英文名：Crestless Curassow，学名：Mitu tomentosum），是鸡形目凤冠雉科盔嘴雉属的鸟类。圭亚那地盾特有的大型地栖鸟类。通体以深黑为主，腹羽呈栗色，鲜红短喙无冠无瘤，体长75–85厘米，雄鸟体重可达3千克。栖息于海拔600米以下河漫滩雨林、季节性水淹林及稀树草原廊道，分布于哥伦比亚东部、委内瑞拉南部、圭亚那及巴西北部黑河与布朗库河流域。","appearance":"成鸟通体黑羽，具暗蓝至紫绿金属光泽；腹羽、尾下覆羽及尾端呈鲜明的栗色，极易识别。头顶无冠，鲜红短喙平滑无瘤，喙端有时略浅。雌雄同色，雄鸟体型大，体重2300–3050克，雌鸟1300–2425克。幼鸟上体绒羽乌黑色，密布淡黄褐与灰白点斑，下体色浅。","call":"全年可鸣，繁殖季尤盛，多在清晨、傍晚或月夜吟唱。鸣声为低沉的“uuut…uu-UU-uu-uhoot”哼吟，每句间隔约3秒，句间停顿较长。受惊时发出尖锐的“queet”哨音，与其他盔嘴雉类似。","habits":"留鸟，仅随水位高低在河岛与大陆林之间做局部移动。喜栖于河流沿岸密林、季节性水淹林及棕榈灌丛，常单独或成对在地面上觅食，偶见5只以内小群。主食16种以上掉落果实，如巴西椰、哥比亚木等，未见取食叶、花或无脊椎动物记录。受惊时飞上树冠夜宿。","breeding":"繁殖期约始于雨季来临，委内瑞拉奥里诺科流域6月曾发现两巢，南亚马逊州成鸟2–4月已具繁殖态。巢置于低矮树杈，每窝2枚白色卵，卵长77–84毫米、宽55–59毫米；雏鸟绒羽黑色，上体具淡黄褐点斑。圈养个体寿命逾10年。","identification":"与同属其他种类相比，本种腹羽栗色而非白色，头顶无冠，红喙短且无瘤。黑凤冠雉体型更大且喙基具黄色瘤突；白腹盔嘴雉具明显冠羽及厚重瘤喙。在哥伦比亚中部与白腹盔嘴雉同域分布，但两者生境隔离，无杂交记录。","protection":"IUCN: LC（无危）；在委内瑞拉、哥伦比亚及巴西亚马逊国家公园与河岛保护区中仍属常见，但因狩猎压力在圭亚那南部局部缺失。","distribution":"繁殖区：哥伦比亚东部、委内瑞拉南部（奥里诺科河以南）、圭亚那南部及巴西北部（黑河与布朗库河以东）的低地雨林；非繁殖期仍留居原地，仅随水位在河岛与大陆林之间短距离移动。","other":"本种曾被归入Crax属；分子证据显示其与阿尔戈亚斯盔嘴雉亲缘最近。在分类上与白盔嘴雉属（Pauxi）并系群关系较远。"},{"name":"白腹盔嘴雉","english_name":"Salvin's Curassow","scientific_name":"Mitu salvini","overview":"白腹盔嘴雉（英文名：Salvin's Curassow，学名：Mitu salvini），是鸡形目凤冠雉科盔嘴雉属的鸟类。大型黑色盔嘴雉，具有鲜红的喙，白色下腹部和白色尾端。主要分布在南美洲西部亚马逊地区的哥伦比亚、厄瓜多尔和秘鲁北部，较为罕见。该鸟以独特的外观特征和低沉的夜鸣声而著称。","appearance":"成年白腹盔嘴雉体长75至89厘米，体重约3100克。全身大部分呈黑色，光泽较少。拥有白色的下腹部和尾羽尖端，以及可竖立的冠羽，通常保持扁平状态。与近似种无冠盔嘴雉相比，其喙更大但不如后者粗壮，羽毛光泽度较低。幼鸟与成鸟相似，但虹膜颜色为棕色，直至接近一岁时才变为酒红色。","call":"白腹盔嘴雉发出极低沉的吼叫声，常在夜间鸣叫。其鸣声与夜冠雉有所不同，后者通常发出三音节的歌曲。","habits":"栖息于亚马逊低地森林中的湿润高地森林，包括高原、山脊和河岸的次生植被，也会季节性地进入泛洪的várzea森林。它们通常单独或成对出现，主要在地面活动，有时在森林中层。饮食以落地果实和种子为主，但也包括花、叶、无脊椎动物、子叶和小型脊椎动物，幼鸟初期可能更多地摄取脊椎动物和无脊椎动物。白腹盔嘴雉基本上是定居的，但会根据食物供应在季节性迁移。","breeding":"繁殖期在哥伦比亚为1月至5月/6月，雌雄鸟全年保持配对关系，雄鸟会在1月初至2月底建造多个巢穴供雌鸟选择。巢位于离地面5至7米高的地方，但只有várzea森林的巢被雌鸟使用。每窝产两枚白色蛋，孵化期约为32天，由雌鸟独自承担。雏鸟孵化后不久便离开巢穴，由雌鸟照顾数月，之后雄鸟开始协助。","identification":"白腹盔嘴雉是唯一腹部白色的Mitu属成员，与无冠盔嘴雉相比，后者胸部为栗色。幼鸟与巨嘴盔嘴雉的幼鸟非常相似，但虹膜颜色变化明显。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲西部的亚马逊雨林地区，包括哥伦比亚南部、厄瓜多尔东部和秘鲁东北部。在哥伦比亚的Macarena山脉国家公园较为常见，而在亚马逊地区的厄瓜多尔，虽然广泛分布但数量稀少。在秘鲁，近人居住区数量减少，但在其他地区仍较为常见。","other":"白腹盔嘴雉在一些地区受到人类狩猎的影响，尤其是在靠近人类居住地的地方。尽管如此，它在全球范围内并不受威胁。"},{"name":"巨嘴盔嘴雉","english_name":"Razor-billed Curassow","scientific_name":"Mitu tuberosum","overview":"巨嘴盔嘴雉（英文名：Razor-billed Curassow，学名：Mitu tuberosum），是鸡形目凤冠雉科盔嘴雉属的鸟类。广泛分布于亚马逊雨林区域，南至玻利维亚，东跨巴西，主要生活在亚马逊河南部。其最显著的特征是红色、带羽冠的大喙，体羽呈现深色，在良好光照下显现出蓝紫色光泽，腿红，尾尖呈淡黄色。","appearance":"巨嘴盔嘴雉体长约83至89厘米，雄鸟体重约3860克。全身羽毛以黑色为主，带有强烈的蓝紫色光泽。下腹部和下尾覆羽为栗色，尾羽末端白色。头部有短而松散的羽冠，喙侧扁且鲜红，虹膜棕色或红棕色，跗跖和趾红色。","call":"巨嘴盔嘴雉的鸣叫包括一系列低沉的轰鸣声，前三个音节上升，后两个音节平稳，有时在停顿后发出尖锐的‘BMM!’声。此外，还会发出升调哨音和爆破音，以及柔和的‘pweet’叫声。","habits":"栖息于低地常绿森林，偏好高地森林，但也出现在画廊森林、várzea森林以及湖泊和溪流边缘。主要在地面或成对出现在树上觅食，食物包括落地果实、叶子、昆虫、真菌和小型脊椎动物。迁徙行为未知，通常在日出前后和繁殖季节歌唱。","breeding":"繁殖季节在北部秘鲁至少从11月持续到2月。巢是一个由树枝、藤蔓和树叶组成的完美圆形杯状结构，每窝产卵2到3枚。雄鸟偶尔多配偶制，可能在某些地区是常态。","identification":"在大部分分布范围内，巨嘴盔嘴雉是唯一的盔嘴雉种类。与白腹盔嘴雉相比，后者体型略小，喙较小，下腹部和下尾覆羽为白色而非栗色。在亚马逊河北部，无冠盔嘴雉具有栗色而非白色的尾羽末端，喙较小，无短羽冠。","protection":"IUCN：NT（近危）","distribution":"巨嘴盔嘴雉主要分布在南美洲亚马逊雨林南部，包括秘鲁东部、玻利维亚北部、巴西北部直至大西洋沿岸。在哥伦比亚东南部、秘鲁东北部和巴西的亚马逊河北部也有分布。","other":"人类活动增加是该物种面临的主要威胁，尤其是狩猎压力。"},{"name":"阿拉戈盔嘴雉","english_name":"Alagoas Curassow","scientific_name":"Mitu mitu","overview":"阿拉戈盔嘴雉（英文名：Alagoas Curassow，学名：Mitu mitu），是鸡形目凤冠雉科盔嘴雉属的鸟类。大型、光泽黑色，具有独特的盔状喙。主要分布于巴西东北部的低地森林，包括Alagoas和Pernambuco州。其特征为全身黑色带蓝紫色光泽的羽毛，尾羽末端呈栗色，耳部周围有灰白色裸皮，雄鸟喙和腿脚鲜红。目前，该物种已野外灭绝，仅存约130只个体被圈养。","appearance":"阿拉戈盔嘴雉体长约83至89厘米，雄鸟平均体重2960克，雌鸟平均体重2745克。拥有大而似盔的喙，全身羽毛黑色并带有紫蓝色光泽，除胸腹部的栗色和尾羽下方的覆羽外。尾羽尖端呈棕色，中央尾羽全黑。喙颜色在雄鸟中更亮，尾尖较淡，眼睛虹膜深红色（雌鸟为栗红色），腿脚鲜红（雌鸟为淡红）。雌雄基本相似，但雄鸟的喙更大更亮。","call":"鸣叫声未详细描述，但在圈养环境下，观察到该物种能够发出类似其他同属物种的轰鸣声，且这种能力似乎在两岁时才具备。","habits":"栖息于低地森林，包括restinga森林和capoeira，最高可达海拔400米。以果实为主食，如Phyllanthus树的castelo果实和Eugenia树的果实。推测为留鸟，未见迁徙记录。","breeding":"繁殖季节在2月至4月间，但有记录显示11月也有筑巢行为。雄鸟负责筑巢，使用茎、藤蔓和树叶。每次产2至3枚白色蛋，平均尺寸为77.1毫米×56.9毫米，孵化期约为30天，由雌鸟独自承担。雏鸟出生时体重约86.2克，上体橙褐色带黑斑，喉部和腹部白色，胸部橙褐色。雏鸟约90天后失去绒羽，60天左右开始长出冠羽，喙在12个月大时达到成鸟形状。","identification":"与其他盔嘴雉属物种的区别在于喙部较轻薄，基部粉色，远端白色，以及耳部周围独特的灰白色裸皮。最接近的近亲为巨嘴盔嘴雉，但喙部结构和颜色有所不同。","protection":"IUCN：EW（野外绝灭）","distribution":"原生于巴西东北部沿海地区，包括Alagoas和Pernambuco州，现仅存圈养个体。","other":"自1977年起，所有个体均处于圈养状态，总数约130只，其中约35%为与巨嘴盔嘴雉的杂交后代。计划于2015年开始的重新引入项目面临挑战，包括有限的适宜栖息地和非法狩猎的风险。"},{"name":"盔凤冠雉","english_name":"Helmeted Curassow","scientific_name":"Pauxi pauxi","overview":"盔凤冠雉（英文名：Helmeted Curassow，学名：Pauxi pauxi），是鸡形目凤冠雉科盔凤冠雉属的鸟类。红色的喙和腿，白色腹部和尾尖。分布于南美的委内瑞拉东部安第斯山脉和哥伦比亚北部山区的云雾森林。","appearance":"成年盔凤冠雉体长80至100厘米，体重可达3.6千克（雄鸟）和2.6千克（雌鸟）。雄鸟和大多数雌鸟外观相似，具蓝灰色额头盔，红喙红腿，白色腹面和尾羽末端带白。部分雌鸟呈棕褐色并有条纹。幼鸟与成鸟相似，但下体部有棕色虫蚀状斑纹，头盔较小。两个亚种在头盔形状上有所差异。","call":"在繁殖季节会发出低沉重复的‘umm...uUH a umm.. umm.. uUH.. um-uUH...um’声调，警报时则会发出急促、清脆的哨音‘fweet’或‘tzsuk’。","habits":"主要栖息于陡峭山坡上的湿润凉爽的云雾林，有时也会出现在邻近的热带和温带区域。偏好非常密集的云雾林，海拔主要在1000米至1500米之间，偶尔记录到低至500米，甚至350米的落叶林。以单独、成对或家庭群形式在地面寻找落果和种子为食，也会食用嫩叶、草类和灌木丛中的芽。通常在清晨和傍晚活动。","breeding":"领地性鸣唱始于雨季开始，通常在12月；筑巢发生在3月至4月；已知有记录的幼鸟出现在8月。巢由树枝、小枝和树叶构成，置于树叉或离地面4至6米高的水平枝上。产两枚蛋，孵化期约30至32天，但在野外观察到34至36天。雏鸟头部、胸部、肩部和翅膀呈褐色，翼羽带有黑色条纹，其余下体部位为淡黄褐色。","identification":"与其他凤冠雉科物种在分布范围内无相似物种。雌鸟中罕见的红褐色条纹形态有助于区分。","protection":"IUCN：VU（易危）","distribution":"分布于委内瑞拉东部安第斯山脉和哥伦比亚北部山区，主要栖息于云雾森林。","other":"在委内瑞拉和哥伦比亚的部分地区受到法律的全面保护。"},{"name":"单盔凤冠雉","english_name":"Horned Curassow","scientific_name":"Pauxi unicornis","overview":"单盔凤冠雉（英文名：Horned Curassow，学名：Pauxi unicornis），是鸡形目凤冠雉科盔凤冠雉属的鸟类。大型黑色鸟类，以其独特的蓝色垂直角状突起著称。分布于玻利维亚中部安第斯山脉的森林地带，数量极为稀少，仅在少数偏远地区被发现。","appearance":"体长85至95厘米，雄鸟体重约3850克，雌鸟约3600克。全身几乎全黑，腹部和尾羽尖端白色。喙鲜红色，头顶有淡蓝色角状突起，最长可达6.3厘米。腿通常呈淡红色，但在繁殖季节雄鸟的腿会变成黄色。两性相似，但在角状突起形状和裸露部分颜色上存在细微差异，雌鸟有时会出现赤褐色变型。","call":"低沉而深邃的叫声，尤其在清晨和黄昏最为频繁，持续时间约9秒，以最后一声高亢响亮为特点。","habits":"生活在密集的低山森林中，海拔介于400至1300米之间，通常在雨量充沛的崎岖丘陵地带。主要食物包括果实、种子、软质植物以及成虫和幼虫昆虫。日间活动，尤其在黎明至上午8点半和下午4点至黄昏时段最为活跃。","breeding":"繁殖活动始于雨季初期，可能实行一雄多雌制。已知巢穴位于孤立树木的分叉处，距离地面5米，由枯叶和枝条构成，巢宽约30厘米，巢内通常仅有一枚蛋，孵化由雌鸟单独承担。","identification":"与其他凤冠雉属物种的区别在于角状突起的形状、更深的喙色以及中央尾羽的白色尖端。叫声和行为也有显著差异。","protection":"IUCN：CR（极危）","distribution":"分布于玻利维亚中部，包括圣克鲁斯和科恰班巴省的安第斯山脉东坡。","other":"面临严重的栖息地丧失和猎杀威胁，其生存状况极其脆弱。"},{"name":"希拉盔嘴雉","english_name":"Sira Curassow","scientific_name":"Pauxi koepckeae","overview":"希拉盔嘴雉（英文名：Sira Curassow，学名：Pauxi koepckeae），是鸡形目凤冠雉科盔凤冠雉属的鸟类。主要分布在南美秘鲁中部的Sira山脉。其自然栖息地位于热带湿润的高山云雾林中，海拔高度约在1100至1500米之间，有时可达1690米左右。于1969年首次被发现，直到2000年和2003年再次由当地Asháninka人证实其存在，因稀少而被归类为极危物种。","appearance":"体型较大，全长85至95厘米，全身羽毛黑色带有变化不定的蓝色光泽，除了白色的腹部和尾部末端有狭窄的白色尖端。喙鲜红色，头部上方有一个扁平的灰色蓝调盔状突起，腿色通常为浅红色，但在繁殖季节雄鸟的腿色变为黄色。雌雄相似，但雌鸟可能有赤褐色相位。","call":"其鸣唱特征为深沉的轰鸣声，由3至4个音符组成，每4秒重复一次，第一个音符最为响亮，较之近缘种的鸣声更短，音节更少，缺乏特有的结尾强音。","habits":"栖息于云雾森林中，以水果、种子、软质植物、节肢动物及其幼虫为食。主要在地面觅食，通常是单独活动，特别是在下午。推测其社会性不如同域的。在干燥季节，偶尔会下降到950米的山脚森林边缘。","breeding":"展示歌曲的高峰期似乎在2月至3月，即雨季末期，此时可能处于繁殖期。已观察到幼鸟出现在6月。雄鸟可能在鸣叫高峰期参与'爆炸式求偶场'系统，但具体繁殖行为细节尚不清楚。","identification":"与单盔凤冠雉相比，其盔状突起较短、圆且蓝色纯度较低，羽毛光泽呈蓝色而非绿色，尾羽白色尖端极薄，常在野外难以察觉。","protection":"IUCN：CR（极危）。全球估计成熟个体数量不足250只，总个体数不超过400只，且持续下降。面临的最大威胁是当地社区的狩猎行为，以及道路建设和农村发展导致的栖息地破坏。虽然El Sira Communal Reserve理论上提供保护，但实际保护措施执行力度不足。","distribution":"分布于秘鲁中部的Sira山脉，具体在Cerros del Sira，位于Huánuco省。该物种的分布范围非常小，仅限于这一特定区域。","other":"为了保护希拉盔嘴雉，已开展教育项目以对抗狩猎行为，提高对其严重生存状况的认识。需要继续在Cerros del Sira的人类社区中开展工作，以更准确地确定该物种的分布情况，强调其保护状态。"},{"name":"大凤冠雉","english_name":"Great Curassow","scientific_name":"Crax rubra","overview":"大凤冠雉（英文名：Great Curassow，学名：Crax rubra），是鸡形目凤冠雉科凤冠雉属的鸟类。体型庞大的热带雨林鸟类，分布于墨西哥东部至哥伦比亚西部及厄瓜多尔西北部的雨林区域。雄鸟羽毛黑色，具独特的卷曲羽冠和黄色喙部；雌鸟存在三种形态：斑纹、赤色和黑色。该物种以果实、节肢动物及小型脊椎动物为食，常在地面觅食，但也在树上筑巢和休息。","appearance":"雄性大凤冠雉体长87-92厘米，重3600-4800克；雌鸟体长78-84厘米，重3100-4270克。雄鸟羽毛全黑，具发达的卷曲羽冠和黄色喙上的显著突起。雌鸟有三种形态：斑纹形态（颈部、展翼、翼及尾巴有斑纹）、赤色形态（整体赤褐色，尾巴有斑纹）、黑色形态（颈部、展翼、翼及尾巴黑色，翼上有些许斑纹）。雌鸟形态变异较大，有的较暗淡，有的几乎无斑纹。幼鸟初期与雌鸟暗形态相似，但颜色更深，成年前获得黑色成鸟羽毛。","call":"雄鸟的叫声是低沉而回荡的‘oomp’声，重复间隔大约10秒，通常在系列中呈现为‘whooó-hoo-hoo’或‘woo...woooó, hoo, woo... woo’。雌鸟则会发出柔和的重复‘humm’声和更响亮的‘hoot, hoot’声。此外，还会有短促的报警声和与威胁展示相关的嘶吼声。","habits":"大凤冠雉主要栖息于热带和亚热带的密集雨林地带，海拔高度可达1200米，有时高达1900米。它们日间活动，常在地面寻找果实和节肢动物，偶尔也会在低枝上觅食。成对或小群体活动，最多可达六只，但有时在果树林中聚集多达50只。它们在水源附近饮水。","breeding":"繁殖季节通常在2月至5月，正值雨季前。雄鸟会在繁殖季节前开始歌唱，持续至雌鸟孵卵期间。巢由雄鸟开始搭建，最终可能由一对共同完成，位于树上或大灌木中，离地4-9米。每窝产两枚白色卵，孵化期为33天。雏鸟孵化后20天内即可飞行，性成熟年龄在2-3岁之间，最长寿命记录为24年。","identification":"雄性大凤冠雉的特征是黑色羽毛、卷曲羽冠和喙上的黄色突起，这些特征使其易于识别。雌鸟形态多样，通过斑纹、颜色和大小区分。与其他Crax属物种相比，雄鸟具有更发达的羽冠和喙上的突起。","protection":"IUCN：VU（易危）","distribution":"分布于墨西哥东部至哥伦比亚西部及厄瓜多尔西北部的热带雨林地区。在墨西哥尤卡坦半岛、科苏梅尔岛和哥斯达黎加的干旱森林中也有记录。在科苏梅尔岛，其种群估计为300只左右。","other":"大凤冠雉受到栖息地丧失和过度狩猎的威胁，特别是在人类活动增加的地区。人工繁殖计划有助于种群恢复。"},{"name":"蓝嘴凤冠雉","english_name":"Blue-billed Curassow","scientific_name":"Crax alberti","overview":"蓝嘴凤冠雉（英文名：Blue-billed Curassow，学名：Crax alberti），是鸡形目凤冠雉科凤冠雉属的鸟类。大型鸟类，为哥伦比亚特有种。其最显著特征为蓝色的肉垂和肉冠，雄鸟拥有白色腹部和尾尖，雌鸟则有栗色下腹，翼和尾部有白色条纹。主要栖息于哥伦比亚北部低地雨林，现今生存于残存森林碎片中。","appearance":"体长82.5至92.5厘米，体重介于3.2到3.6公斤。雄鸟黑色为主，具白色腹区和尾端，有耸立的绒毛状顶冠，雌鸟则有更多白色横斑，尤其在胸部和腹部。年轻个体的喙部蓝色较浅。雌鸟罕见的带状形态拥有更多的白色顶冠，以及黑白相间的胸腹横斑。","call":"雄鸟的鸣唱为一系列深沉音符，重复的‘hmm...hmh...hmm...hmm...hmh’，其中第二和第五个音节最低且最短，第一个和第三个音节则更加强调，随后短暂停顿。受惊时，两性会发出柔和高音的哨声‘peh-weeeéoh’或‘pehoo’。","habits":"栖息于低地和山脚的未受干扰热带雨林，海拔高度通常低于600米，偶尔可达1200米。主要地面觅食，食物包括坚硬果壳的豆科果实、蠕虫和昆虫，消化辅助依赖吞食沙粒和小石子。","breeding":"繁殖季节自12月中旬至翌年3月初，巢筑于藤蔓密集处，由枯枝落叶构成，位于灌木层至次冠层之间，巢距地面1.9至4米。每次产2枚白色卵，据称实行一夫一妻制，但关于孵化和育雏的细节尚不清楚。","identification":"与其他凤冠雉区别在于蓝色的肉垂和肉冠，雄鸟具有独特的白色腹部和尾端，而雌鸟的带状形态则在凤冠雉中独树一帜。","protection":"IUCN：CR（极危）","distribution":"仅分布于南美洲哥伦比亚北部，目前仅限于La Guajira至Magdalena南至Antioquia和Boyacá的几片残存森林，包括圣玛尔塔山脉北坡的El Paujil鸟保护区和Tayrona国家公园。","other":"历史上曾广泛分布，但由于森林砍伐和狩猎压力，数量急剧下降，目前总估计数量仅为150至700只。"},{"name":"黄瘤凤冠雉","english_name":"Yellow-knobbed Curassow","scientific_name":"Crax daubentoni","overview":"黄瘤凤冠雉（英文名：Yellow-knobbed Curassow，学名：Crax daubentoni），是鸡形目凤冠雉科凤冠雉属的鸟类。体型较大的黑色与白色相间、具有显著卷曲羽冠的鸟类。雄鸟特征为喙基部的黄色瘤状突起，雌鸟则有淡灰色的喙，胸腹部有细白横纹。该物种主要分布于南美洲的哥伦比亚东北部和委内瑞拉北部的森林及林地。","appearance":"黄瘤凤冠雉体长介于84至92.5厘米之间，雄鸟体重通常在2925至3200克范围内，但也有记录显示有1625克重的个体；雌鸟的平均重量为2325克。雄鸟具有独特的黄色瘤状突起和肉垂，雌鸟则没有这一特征，其喙呈暗色，胸腹处有白色斑纹。雄鸟和雌鸟都呈现黑色与白色的对比，下腹部和尾羽尖端为白色。","call":"雄性黄瘤凤冠雉的叫声独特，被称为‘炸弹掉落式’的下降哨声，有时会与翅膀拍打展示或深沉的轰鸣声结合，哨声持续约4秒，通常在清晨至上午时段从地面或树顶发出。","habits":"黄瘤凤冠雉偏好栖息于画廊森林和高灌木丛，特别是在委内瑞拉和哥伦比亚的草原地区。它们也出现在山脚和崎岖地带，尤其在河流旁或有森林覆盖的山谷和沟壑。该物种在旱季会聚集在剩余水源附近，筑巢倾向于靠近森林边缘或密集灌木丛中。","breeding":"黄瘤凤冠雉的繁殖期在五月到六月，即雨季初期。它们的繁殖系统可能为一雄多雌制。巢穴由树枝和藤蔓构成，内衬树叶和草，一般位于树上，高度约为6.7米，常被藤蔓遮掩。每窝产两枚白色蛋，孵化期大约28天，主要由雌鸟独自承担。","identification":"雄性黄瘤凤冠雉以其黄色的瘤状突起和肉垂而独树一帜，而雌鸟则通过其黑色的喙和胸部及下腹部的淡色条纹与其它凤冠雉科物种区分开来。","protection":"IUCN：NT（近危）","distribution":"黄瘤凤冠雉主要分布在委内瑞拉北部，从马拉开波盆地和塔奇拉州东至苏利亚州和莫纳加斯州，以及邻近的哥伦比亚东北部，包括拉瓜希拉、北桑坦德、博亚卡和阿劳卡等地。在哥伦比亚，海拔分布于500至1500米之间；在委内瑞拉，则位于100至800米之间。","other":"尽管黄瘤凤冠雉在当地某些区域仍相对丰富，但由于森林向稻田的转化，其数量正在减少，尤其是在委内瑞拉的草原地区。"},{"name":"黑凤冠雉","english_name":"Black Curassow","scientific_name":"Crax alector","overview":"黑凤冠雉（英文名：Black Curassow，学名：Crax alector），是鸡形目凤冠雉科凤冠雉属的鸟类。广泛分布于南美洲北部的热带雨林区域，包括哥伦比亚、委内瑞拉、圭亚那、苏里南和巴西北部，同时被引入巴哈马、古巴、牙买加、海地、多米尼加共和国、波多黎各和小安的列斯群岛。其显著特征为全身黑色，雌雄羽毛相似，仅通过雌鸟头部白色条纹和雄鸟的黄色或橙红色鼻基加以区分。","appearance":"黑凤冠雉体型庞大，全长可达90厘米，雄鸟拥有带紫色光泽的黑色上体和不显眼的黑色羽冠，喙灰色，基部皮肤黄色或橙色，雌鸟与雄鸟相似但羽冠具白色条纹，幼鸟则呈现黑色并带有红褐色斑点。","call":"鸣叫声低沉，由两部分组成：“mm, m-...m,m,m,m,mmm”，随后可能伴随三声以上的翅膀拍打声，夜间常鸣唱。","habits":"栖息于低地森林和种植园的灌木丛中，偏好沿河地带和森林边缘的茂密植被。主要以果实为食，但也吃花、叶、真菌和无脊椎动物。通常在地面活动，有时跟随猴群觅食。","breeding":"繁殖季节在雨季，筑巢于离地几米高的树上，巢由树枝搭建。雌鸟单独孵化两枚白色蛋，孵化期约30天，雏鸟出生当天即可离开巢穴。","identification":"与其它Crax属物种相比，黑凤冠雉的冠羽较短且不密集，喙更细长，颜色随地域不同而异，雌雄外观极为相似。","protection":"IUCN：LC（无危）","distribution":"分布于亚马逊雨林北部，包括哥伦比亚、委内瑞拉、圭亚那、苏里南和巴西北部。","other":"面临栖息地丧失、狩猎和捕捉的威胁，虽然在某些保护区较为常见，但总体上其种群数量正在下降。"},{"name":"肉垂凤冠雉","english_name":"Wattled Curassow","scientific_name":"Crax globulosa","overview":"肉垂凤冠雉（英文名：Wattled Curassow，学名：Crax globulosa），是鸡形目凤冠雉科凤冠雉属的鸟类。以黑色羽毛、红色喙和明显的肉垂著称，分布于南美洲亚马逊盆地的偏远热带雨林中。雄鸟拥有白色的腹部区域，而雌鸟的腹部呈栗色。物种与水边环境紧密相关，尤其在季节性泛滥的森林和河岛中，树栖性较强。由于过度狩猎，其数量在很多地区已变得非常稀少。","appearance":"肉垂凤冠雉体长82至89厘米，体重约2500克。雄鸟具有黑色羽毛，腹部白色，头部有卷曲的羽毛，红色的喙饰和肉垂。雌鸟和幼鸟相似，但腹部呈红褐色，缺乏喙饰和肉垂。雏鸟覆盖着棕色的绒毛，腹部为白色。","call":"雄鸟的鸣唱是一种长而下降的哨音，常在夜间和清晨发出，类似于黄冠凤冠雉的叫声，伴有拍翅声。报警叫声为短促、向下弯曲的嗡嗡哨音，以及长而下降的颤音。","habits":"肉垂凤冠雉栖息于热带低地的湿润森林，最高可达300米。偏好靠近河流、湖泊边缘的沼泽地带，尤其是季节性泛滥的森林和河岛。在雨季有时会迁移到高地森林。以水果、种子为主食，偶尔摄取小型脊椎动物和无脊椎动物。群体活动，通常3至6只小群，偶尔形成15至20只的大群。","breeding":"关于野外繁殖的信息有限。巢由树枝、树叶和藤蔓构成，位于平均13.3米高处，靠近水源。每窝产两枚白色蛋，孵化后约两个月羽毛接近成年状态，但可能长达10个月才独立。在圈养条件下，一只雌鸟一年龄即可产卵，但卵较小且未能孵化。","identification":"雄鸟与红嘴凤冠雉区别明显，后者雄鸟仅有微小的喙冠，而肉垂凤冠雉的肉垂和喙冠更发达。雌性肉垂凤冠雉具有红色的蜡膜和红褐色腹部，与其它凤冠雉属成员区别明显。","protection":"IUCN：EN（濒危）","distribution":"分布于巴西西部、哥伦比亚东南部、厄瓜多尔东部、秘鲁东北部和玻利维亚北部的亚马逊盆地。具体分布受Caquetá-Japurá、Solimões、亚马逊和Madeira河流以及安第斯山脉300米等高线限制。","other":"历史上曾与蓝嘴凤冠雉杂交。"},{"name":"裸脸凤冠雉","english_name":"Bare-faced Curassow","scientific_name":"Crax fasciolata","overview":"裸脸凤冠雉（英文名：Bare-faced Curassow，学名：Crax fasciolata），是鸡形目凤冠雉科凤冠雉属的鸟类。雄鸟以黑色为主，带有卷曲的冠羽和白色的腹部，眼周有裸露的黑色皮肤。雌鸟上部黑白相间，腹部呈淡黄色至白色，喙黑，下喙基部带黄色。常见于南美洲的湿润森林和林缘地带，以果实、种子、花朵和小型无脊椎动物为食。","appearance":"雄性裸脸凤冠雉体长约77至85厘米，体重2700至2800克；雌鸟约75厘米，体重2200至2700克。雄鸟通体黑色，包括卷曲的长羽毛冠，腹部和肛门区白色，眼周有黑色裸露皮肤，喙基部有黄色肉垂，但不如黑凤冠雉发达。雌鸟背部具黑色与白色条纹，腹部和肛门区淡黄至白色，喙全黑，下喙基部带黄色。幼鸟似成年雄鸟，但眼下的裸露皮肤带黄色。","call":"最常听到的叫声为高音哨声“kseuw”。","habits":"栖息于湿润常绿林、半落叶林和画廊森林，有时在竹林中，海拔至少可达800米。非迁徙性，通常单独或成对活动。白天活动，早晨和傍晚更活跃，沿海滩漫步，主要以地面掉落的果实为食，也吃种子、花朵和无脊椎动物。","breeding":"繁殖期在夏季，巢为树上的枝叶平台，高4米，隐藏于藤蔓丛中。每次产两枚白色蛋，大小约为78.1至81毫米×53.8至58.4毫米。孵化期约30天，由雌鸟独自孵化，幼鸟孵化时重90克，28天后重400克，93天后重1260克。幼鸟与成鸟共同生活数月。","identification":"雄鸟与雌鸟在外表上有明显差异，雌鸟比雄鸟小，上部颜色更深，条纹更窄，下部颜色更浅，且具有黄色肉垂（不同于雌性裸脸凤冠雉）。","protection":"IUCN：VU（易危）","distribution":"分布于巴西东北部、巴拉圭北部、玻利维亚东部以及阿根廷极东北部的cerrado、pantanal和亚马逊盆地东南部。","other":"由于栖息地破坏和猎杀，部分地区的裸脸凤冠雉数量已显著下降。"},{"name":"红嘴凤冠雉","english_name":"Red-billed Curassow","scientific_name":"Crax blumenbachii","overview":"红嘴凤冠雉（英文名：Red-billed Curassow，学名：Crax blumenbachii），是鸡形目凤冠雉科凤冠雉属的鸟类。大型的凤冠雉科鸟类，为巴西东南部特有种。雄鸟以黑色为主，具卷曲羽冠和白色腹部，雌鸟翼部有黑栗条纹，腹部红褐色。红嘴凤冠雉分布于大西洋雨林地带，主要在巴伊亚南部至里约热内卢的高湿原始森林中。由于栖息地丧失和猎杀压力，该物种仅存于七片森林碎片中。","appearance":"成年红嘴凤冠雉总长80-93厘米，体重平均3.5千克。雄鸟头部、颈部、胸部、背部、翅膀和尾巴为黑色，带绿光泽，腹部及下体为白色；雌鸟腹部和下体为红褐色或赭色。两性均有黑色卷曲羽冠，雄鸟具红色肉垂和小肉瘤，雌鸟肉垂黑色，无肉瘤。","habits":"栖息于潮湿的原始森林，通常成对或小家庭群活动。以种子、果实、芽和小型无脊椎动物为食。雄鸟在特定季节发出响亮的‘轰隆’声。","breeding":"雌鸟产卵1至4枚，幼鸟年末即可离巢。具体繁殖细节有待进一步研究。","identification":"雄鸟的红色喙和肉垂明显，雌鸟上部黑色，羽冠黑白相间，翅膀有黑栗波状条纹。与肉垂凤冠雉的区别在于后者生活在亚马逊的水淹森林，且雌鸟也有红色肉垂。","protection":"IUCN：EN（濒危）","distribution":"分布于南美洲巴西东南部的大西洋雨林，包括埃斯皮里图圣多、巴伊亚和米纳斯吉拉斯州。","other":"成功实施了圈养繁殖计划，但野外种群仍受栖息地丧失和非法猎捕威胁。"},{"name":"白胸珠鸡","english_name":"White-breasted Guineafowl","scientific_name":"Agelastes meleagrides","overview":"白胸珠鸡（英文名：White-breasted Guineafowl，学名：Agelastes meleagrides），是鸡形目珠鸡科黑珠鸡属的鸟类。中等体型，长达45厘米，拥有黑色羽衣、裸露的红色头部、白色的胸部、绿色至褐色的喙以及灰褐色的脚。两性相似，雌鸟略小于雄鸟。分布于西非的科特迪瓦、加纳、几内亚、利比里亚和塞拉利昂的亚热带森林地带。","appearance":"白胸珠鸡体长约40至45厘米，体重约815克（圈养条件下）。头部和上颈部裸露，皮肤玫瑰红色至粉红色，颈下部有白色细丝状羽毛。颈下部、胸部和上背部纯白，其余部位黑色，次级飞羽和初级飞羽棕色，饰有白色或灰色斑纹。雄鸟有1至2个刺，雌鸟较雄鸟小且通常无刺。虹膜呈棕色，喙绿褐色，腿灰褐至灰黑色。幼鸟一般呈暗褐色，翅膀和身体上有红褐色羽毛，头部和颈部保留幼年绒毛，腹部纯白，无刺。","call":"深沉的'kok-kok'声，群鸟间用于联络。亦发出安静的啾啾声，雌鸟在群聚后发出下降的哨声。报道有响亮的旋律叫声，但具体描述不明。傍晚时，从栖木发出响亮的喇叭声，可能具有领地宣告的作用。","habits":"栖息于密集的原始雨林，偏好较为干燥的地区，也能在附近被选择性砍伐的森林中发现，尤其是较老的再生林，但似乎依赖原始森林的存在。在紧邻原始森林的可可种植园中也有记录。白天大部分时间用于觅食，主要以昆虫（如白蚁、蚂蚁、蟋蟀、千足虫、蠕虫、甲虫幼虫）、蜘蛛、小型软体动物以及落下的浆果和种子为食。缓慢行走于地面，频繁地用脚在土壤和枯叶堆中刮找食物。会加入黑猩猩群和其他陆生哺乳动物的觅食队伍。当一只鸟找到丰富的食物源时，常召唤其他群鸟（多达15至30只）共同觅食，但群内争斗频繁。","breeding":"繁殖期为10月至翌年5月，可能在雨季末的11月至1月达到高峰，但在某些地区（如利比里亚）全年都可能繁殖。绒毛雏鸟记录于11月至5月，亚成鸟于2月、5月和11月出现。巢筑于密林下层，具体描述未知。每窝产卵约12枚，蛋壳红褐色带白色孔点，尺寸约为45毫米×35毫米。雏鸟有灰褐色的绒毛，头部和颈部为深棕色。进一步的信息尚不可得。","identification":"白胸珠鸡与其他珠鸡通过其独特的白色颈部加以区分。雄鸟头色更深、更偏红色（而非粉色），这是基于行为观察得出的。亚种间的差异尚未详细描述。","protection":"IUCN：VU（易危）。非洲最受威胁的物种之一，总数量估计约85,000只，因栖息地破坏、森林碎片化和过度猎杀面临重大衰退。在塞拉利昂的戈拉森林，三个大型保护区（包括Tiwai岛野生动物保护区）中受到保护，但狩猎压力仍然存在。在利比里亚，已从大部分地区消失；科特迪瓦，仅限于Bossematie森林和Taï国家公园；加纳，近年来仅在几个保护区有零星记录。整个区域内，森林砍伐和狩猎尤其严重，该物种在加纳的未来岌岌可危。CITES III在加纳。","distribution":"分布于从塞拉利昂到加纳的非洲西部，优先选择覆盖良好的森林，尽管偏好较为干燥的气候，分布区因此较为广阔。"},{"name":"黑珠鸡","english_name":"Black Guineafowl","scientific_name":"Agelastes niger","overview":"黑珠鸡（英文名：Black Guineafowl，学名：Agelastes niger），是鸡形目珠鸡科黑珠鸡属的鸟类。中等体型的非洲珠鸡科鸟类，广泛分布于西非至中非的热带雨林地带，以其全黑色羽毛和裸露的橙粉色头部著称。","appearance":"成年黑珠鸡拥有裸露的粉红色头颈，头部有短绒毛状羽冠，喉部和下颈部散布着绒羽。全身羽毛呈黑色，腹部带有淡色斑点。雄鸟有1-3个腿上的刺，而雌鸟通常无刺或只有一个。幼鸟羽毛上部有浅黄色尖端，胸部有斑点，腹部白色。喙绿灰色，腿灰褐色。雄鸟平均比雌鸟大，长约42厘米，重约700克。","call":"发出单调高音的“kwee”声，以每秒2-3次的频率重复，遇险时叫声更为急促。","habits":"黑珠鸡主要栖息于低地热带雨林，偏好密集的灌木丛，偶尔出现在森林边缘或废弃的农田。它们是群居性鸟类，常以2-10只的小群体活动，以昆虫为主食，包括甲虫、蚂蚁、白蚁，也吃千足虫、小蛙、硬种子、绿叶和果实。在地上觅食，用脚爪刨土。","breeding":"可能实行一夫一妻制，繁殖时间不确定，但在刚果民主共和国东北部，主要在干燥季节12月至2月繁殖。巢穴未知，蛋壳颜色为淡红棕色，有时带黄或紫色调，尺寸约为42mm x 34mm。","identification":"与较大的长冠珠鸡相比，黑珠鸡没有头部长羽，羽毛无斑点，全身黑色，头部全红。雌雄相似，但雌鸟略小。","protection":"IUCN：LC（无危）","distribution":"分布于非洲，从尼日利亚东南部至刚果民主共和国中部，包括加蓬、安哥拉、中非共和国、刚果共和国等地。"},{"name":"珠鸡","english_name":"Helmeted Guineafowl","scientific_name":"Numida meleagris","overview":"珠鸡（英文名：Helmeted Guineafowl，学名：Numida meleagris），是鸡形目珠鸡科珠鸡属的鸟类。非洲南部至萨赫勒以南地区广泛分布的大型鸟类。其最显著的外部特征是头部上方有一个骨质头盔，裸露的头部皮肤颜色多样，包括白色、蓝色或红色。珠鸡分为多个亚种，其中灰顶珠鸡是最常见的类型，已培育出多种变种，如灰色、白色和淡紫色珠鸡。在中国，人们通常所指的珍珠鸡主要是灰色珠鸡类型。","appearance":"珠鸡体型较大，体长53至63厘米，体重在1145至1823克之间，性别差异表现为雄鸟平均略重于雌鸟。头部和颈部大部分无羽毛，裸露的皮肤呈蓝色至蓝白色，具有一特征性的角质骨质头盔。面部附着物颜色丰富，有黑色丝状羽毛。全身羽毛主要为黑灰色，点缀以白色斑点。雌雄相似，但雌鸟平均体型较小。幼鸟毛色暗淡，主要为深褐色，头盔、肉垂等较小，直到约100天后换羽成成年羽毛。不同的亚种在头颈附着物的密度、形状、颜色，头盔的大小和形状，以及胸部颜色上有所区别。","call":"发出粗糙的咯咯叫声，变化在强度和长度上，如鼻音般的‘kek-kek-kek-kek-kek-kek-kek...’，包括在栖息地的叫声。群体会用金属质感的‘chenk-chenk-chenk’保持联系，还会发出更为哀怨、传播更远的‘CHER-cheeng, CHER-cheeng...’叫声。雌鸟发出远传的‘ka-bak’声，前半部分鼻音清晰，后半部分更高音和沙哑；雄鸟则能回应以刺耳的摩擦音。","habits":"珠鸡适应各种开放环境，从林缘到灌木丛，再到农田和松树林，偏好有耕作区穿插的稀树草原，但会避开过度放牧的区域。它们依赖水源附近和合适的栖息地，如树木或灌木，以及饮食中的旧菜园、玉米田、遗落的谷物和休耕地。珠鸡群居，形成0.8至21.2平方公里范围的家园，根据栖息地和物种密度的不同而变化。它们是杂食性鸟类，以植物为主，特别是非农业种子，但也吃昆虫，尤其是蚱蜢和白蚁。它们在地上用脚抓食，也会从草穗上剥离种子。","breeding":"繁殖季节通常在雨季前后，从筑巢到孵化由雌鸟独自承担，雄鸟会在幼鸟出生后的前两周承担80%的抚育责任。巢是一个简单的地面凹坑，直径20至32厘米，深度5至8厘米，由雌鸟挑选并用草和羽毛铺垫。每窝通常有6至12枚蛋，孵化期约为24至30天。幼鸟孵化后几乎同步，能在14天后弱飞，4周后离巢，30周达到成年体重，雌鸟可在28至32周时开始繁殖。","identification":"珠鸡与冠珠鸡的主要区别在于颜色更深，具有头部的羽毛冠。不同亚种之间的辨识要点主要集中在头颈附着物的配置，包括头盔的尺寸、形状和颜色，以及面部肉垂的存在形式和大小。","protection":"IUCN：LC（无危）","distribution":"珠鸡广泛分布于非洲南部至萨赫勒以南的区域，包括东非、南非、西非和中非的部分地区。此外，通过引入，它们还存在于加勒比海群岛、北美、哥伦比亚、巴西、澳大利亚和欧洲的部分地区。","other":"珠鸡有时被用作控制蜱虫的生物防治手段，尤其是在城市郊区，因为使用杀虫剂不合适。"},{"name":"长冠珠鸡","english_name":"Plumed Guineafowl","scientific_name":"Guttera plumifera","overview":"长冠珠鸡（英文名：Plumed Guineafowl，学名：Guttera plumifera），是鸡形目珠鸡科冠珠鸡属的鸟类。具有独特的白色斑点装饰。生活在中非热带低地森林的高大、开阔的林下层，以其头顶显眼的黑色羽毛冠而得名。其脸部颜色暗淡且无羽毛，与较小的黑珠鸡相比，后者头部大部分裸露且呈鲜红色，缺乏长冠珠鸡的羽冠和醒目的白色斑点。","appearance":"长冠珠鸡体长约45至51厘米，体重约750至1000克。雄鸟和雌鸟的外观相似，但雌鸟平均体型较小。其头部和颈部有灰色裸露皮肤，包括喙基部的褶皱和小枕骨皮肤褶。最显著的特点是其长长的黑色羽冠，全身黑色羽毛上点缀着白色斑点，但缺乏网状纹理。翅膀主羽为栗色，最外侧次级飞羽边缘为白色。喙蓝灰色，虹膜棕色，腿蓝灰色。","call":"关于长冠珠鸡的鸣叫特征描述不多，主要包括远距离传播的尖锐的呱呱声，类似于好奇的鸭叫声，以及鼻音的‘kak’声，与冠珠鸡的叫声有所不同。在警报时，群体会发出异步合唱的‘ka-ka-ka-ka-ka’声。","habits":"长冠珠鸡主要栖息于原始森林，也会出现在非常成熟的次生林中，通常植被相对稀疏。它们不会进入森林内的耕作空地。它们以群居方式觅食，群体规模可达20至40只，主要在地面活动，通过脚爪挖掘土壤和枯叶寻找食物，食物包括种子、根茎、果实、叶子以及各种无脊椎动物，如蜗牛、蛞蝓、千足虫、蜘蛛和多种昆虫。","breeding":"长冠珠鸡的繁殖时间不固定，可能不是季节性的，但在较干燥的月份似乎会避免繁殖。在刚果民主共和国，繁殖期为3月和9月。它们可能是单配偶制，每窝产9至10枚蛋，蛋壳淡黄色，带有许多深色气孔。孵化期约为23天，雏鸟出生时主要覆盖着带暗色纵向条纹的绒毛。","identification":"与冠珠鸡相比，长冠珠鸡的羽冠更直、更高，两侧的肉垂更长，且其头部和颈部的裸露皮肤为灰蓝色，而schubotzi亚种的灰蓝色皮肤中夹杂着橙色斑块。此外，冠珠鸡的体型略大，头部和颈部裸露皮肤为红色，黑色颈圈明显，且白点为蓝白色。","protection":"IUCN：LC（无危）","distribution":"长冠珠鸡主要分布在非洲中西部的原始森林中。","other":"长冠珠鸡在全球范围内并不受到威胁，但因栖息地丧失和狩猎压力而数量可能正在下降。需要对其生态进行研究，以确定其需求，最终实现对关键栖息地的有效保护。"},{"name":"冠珠鸡","english_name":"Eastern Crested Guineafowl","scientific_name":"Guttera pucherani","overview":"冠珠鸡（英文名：Eastern Crested Guineafowl，学名：Guttera pucherani），是鸡形目珠鸡科冠珠鸡属的鸟类。具有黑色体羽，头小，全身布满蓝白色斑点，头部上方有一簇羽毛状的‘假发’，裸露的脸部皮肤呈红色，颈侧皮肤蓝色，喙象牙色，眼红。主要栖息于非洲森林边缘、次生林和森林-草原镶嵌地带，从北肯尼亚、索马里南部至坦桑尼亚中部，包括桑给巴尔和Tumbatu岛。","appearance":"体长约48-50厘米，头部小而具浓密黑色羽冠，头部和颈部有蓝灰色裸露皮肤，眼睛周围有大片红色裸皮，虹膜深红。雄雌相似，但雌鸟平均体型较小。幼鸟色泽较暗淡，黑白细条纹相间，裸露皮肤色彩较淡。成鸟羽毛黑色，点缀以蓝白色斑点。","call":"其典型叫声为一系列刺耳的节奏性‘咕噜’声，有时被解释为连续3-4个管状音符，间歇发出尖锐‘krek’声，最后以芦苇般的‘kraaaa’声结束。此外，还有较低沉的‘chuk’声，用于觅食时保持群体联系。","habits":"冠珠鸡为杂食性，主要在地面觅食，以植物种子、果实、昆虫、节肢动物等为食。它们通常在森林边缘、次生林、画廊森林以及森林-草原交错地带活动，有时进入原始森林。白天活动，夜晚休息。","breeding":"繁殖期在雨季，筑巢于地面密集植被下，靠近树根或灌木丛。巢为地面凹陷处，铺垫少量枯叶和草。每次产卵4-5枚，孵化期约23天，主要由雌鸟承担。雏鸟出生时带有纵向暗色条纹的浅黄色绒毛，一周左右体重可达82克，14-21天后即可飞翔。双亲共同抚养幼鸟。","identification":"与西冠珠鸡相比，东部冠珠鸡的眼睛周围有大胆的红色图案，颈部无黑色‘项圈’，虹膜红色而非暗色，叫声有所不同。与南冠珠鸡的区别在于面部和颈部皮肤颜色、无黑色-栗色‘项圈’，叫声也不同。","protection":"IUCN：LC（无危）","distribution":"分布于东非，自北肯尼亚和索马里南部至坦桑尼亚中部，包括桑给巴尔和Tumbatu岛。","other":"曾被认为是西冠珠鸡和南冠珠鸡的同种，但现在视为独立物种。"},{"name":"西冠珠鸡","english_name":"Western Crested Guineafowl","scientific_name":"Guttera verreauxi","overview":"西冠珠鸡（英文名：Western Crested Guineafowl，学名：Guttera verreauxi），是鸡形目珠鸡科冠珠鸡属的大型鸟类，主要分布在非洲几内亚比绍至喀麦隆西北部，肯尼亚西部，赞比亚和安哥拉等地。其显著特征是头部较小，身体庞大，全身覆盖着排列整齐的蓝白色斑点，头顶有蓬松的羽冠，面部皮肤蓝色，喉部红色，眼睛棕色。","appearance":"西冠珠鸡是一种体型较大的珠鸡，体长46-56厘米，头部裸露的皮肤呈蓝色，喉咙部分为红色，颈部下方有一圈黑色的宽“项圈”。羽毛基本为黑色，点缀着细小的蓝白色斑点，主要翼羽为棕色，次级飞羽最外侧边缘为白色。雌雄相似，但雌鸟平均比雄鸟稍小。幼鸟羽毛比成鸟暗淡，带有黑白相间的条纹。","call":"其典型的叫声先是一声裂响，随后是一连串快速而尖锐的‘krk pu-pu-pu-pu-pu’声，此外还有鼻音的吼叫和刺耳的咯咯声。","habits":"西冠珠鸡主要栖息于森林边缘、次生林和林带，也会出现在森林-草原镶嵌地带。它通常在地面觅食，偶尔也在树上进食。食物包括植物物质和各种无脊椎动物，如种子、果实、昆虫、蜘蛛等。这种鸟会跟随猴群，以猴子掉落的水果为食。","breeding":"西冠珠鸡是一夫一妻制，一年只繁殖一次。主要在雨季筑巢，巢建在地面，用枯叶和草简单铺垫，藏于树根或灌木下。每次产卵4-5枚，有时可达7-8枚，孵化期约23天。幼鸟孵化出来时覆盖着浅色绒毛，带有深色纵向条纹，由双亲共同照顾。","identification":"与冠珠鸡相比，西冠珠鸡的头部和颈部裸露皮肤为蓝色，喉部红色，下颈有黑色“项圈”，眼色为棕色。南冠珠鸡的头部和喉咙裸露皮肤颜色为黑灰色，没有红色，下颈有黑色或黑褐色的‘项圈’，虹膜红色。","protection":"IUCN：LC（无危）","distribution":"西冠珠鸡的分布范围广泛，从几内亚比绍向东延伸至喀麦隆中部和刚果盆地，乌干达到肯尼亚西部高地，以及东非大裂谷，另在安哥拉和赞比亚西北部也有分布。","other":"西冠珠鸡曾被认为是冠珠鸡的亚种之一，但在形态、叫声和有限的杂交证据下，现在被视为独立物种。"},{"name":"南冠珠鸡","english_name":"Southern Crested Guineafowl","scientific_name":"Guttera edouardi","overview":"南冠珠鸡（英文名：Southern Crested Guineafowl，学名：Guttera edouardi），是鸡形目珠鸡科冠珠鸡属的鸟类。体型较大的珍珠鸡，主要分布在非洲东南部，从坦桑尼亚到南非。其头部较小，身体覆盖着黑色羽毛，点缀以数百个蓝白色的斑点，头部上方有一簇羽毛状的‘假发’，裸露的面部呈象牙色，眼睛鲜红。面部皮肤的颜色因地理区域而异，通常是蓝灰色，带有红色和白色的斑块。生活在森林边缘、灌木丛和森林-草原镶嵌地带。","appearance":"南冠珠鸡拥有卷曲的黑色头部羽毛，头部裸露皮肤为黑灰色，颈部有一片棕色白肉褶，下颈处有一圈宽大的黑色和栗色（或纯黑色）‘项圈’。虹膜红色，腿脚暗蓝灰色。成年个体比幼鸟更鲜艳，幼鸟羽毛为黑白细条纹，颜色较暗淡。","call":"其最常见的叫声被描述为断续的‘chuk-chuk-chukchukerr’。共有八种叫声，主要用于聚集群组成员或驱赶入侵者。","habits":"南冠珠鸡主要栖息于森林边缘、次生林和画廊森林，也见于沿海森林。它们在地面觅食，偶尔也在树上。主要以植物物质和各种无脊椎动物为食，包括种子、果实、昆虫和其他小动物。","breeding":"繁殖季节可能在雨季高峰，即11月至次年2月。一夫一妻制，每次只育一窝。巢筑于地面，通常位于灌木下或树根旁，由干叶和草构成简单的垫层。每窝产4-5枚深粉红或污白色蛋，孵化期约为23天，仅由雌鸟负责孵化。幼鸟出生时主要呈浅黄色，带有深色条纹。","identification":"与西冠珠鸡的区别在于头部裸露皮肤的颜色、虹膜颜色和‘项圈’的存在与否。与冠珠鸡的区别在于面部和颈部裸露皮肤的颜色、虹膜颜色以及‘项圈’的有无。","protection":"IUCN：LC（无危）","distribution":"南冠珠鸡分布于非洲东部，从坦桑尼亚南部至南非，包括莫桑比克、赞比亚南部、马拉维和坦桑尼亚南部。","other":"南冠珠鸡过去曾被视为冠珠鸡的一个亚种，但现在被确认为独立物种。"},{"name":"鹫珠鸡","english_name":"Vulturine Guineafowl","scientific_name":"Acryllium vulturinum","overview":"鹫珠鸡（英文名：Vulturine Guineafowl，学名：Acryllium vulturinum），是鸡形目珠鸡科鹫珠鸡属的鸟类。体型最大，头颈部类似兀鹫，羽毛色彩丰富，包括钴蓝、淡紫、黑和白色。成群生活，分布于非洲东南部，从埃塞俄比亚至坦桑尼亚。","appearance":"体长60-72厘米，体重1100-1800克，雄鸟比雌鸟略大。拥有裸露的蓝脸和黑颈，长而细的脖子和腿，尾部尖端下垂。成年鸟的胸腹部为亮丽的钴蓝色，其余体羽为黑色并点缀着白色斑点。雌雄相似，雌鸟稍小，幼鸟主要为灰褐色，带有钝色蓝胸和短绒毛。","call":"发出响亮的‘chink-chink-chink-chink-chink’声，通常在归巢或警戒时发出。","habits":"栖息于干燥开阔的草原和灌木丛，倾向于保持在遮蔽处，夜间栖宿于树上。食物主要包括种子、小型无脊椎动物、浆果、昆虫、蜘蛛和蝎子。遇险时更倾向于奔跑而非飞行。","breeding":"繁殖季节可能在雨季开始或之后，集中于5月（埃塞俄比亚）、6月（肯尼亚）、6、8和12月（索马里）。一夫一妻制，巢建于地面，通常产4-8枚奶油色蛋，孵化期23-32天。幼鸟出生后几乎立即离巢，约2周后能飞行，1个月后与家族群合并。","identification":"与其他珠鸡相比，具有更长的脖子、腿和尾巴，头部和颈部裸露，胸腹部颜色独特。","protection":"IUCN：LC（无危）。总数量可能超过100万只，普遍常见且稳定，但在部分地区可能因过度狩猎而局部减少。","distribution":"非洲：从埃塞俄比亚和索马里至坦桑尼亚。"},{"name":"石鹑","english_name":"Stone Partridge","scientific_name":"Ptilopachus petrosus","appearance":"石鹑体型小至中等，长度约23至28厘米，体重187至198克。它们的尾巴翘起如同小型家禽，全身通常呈现较深的颜色，腹部为浅黄色，两胁有宽阔的栗色条纹。雌鸟的腹部为乳白色而非浅黄色。眼睛虹膜为棕色，眼周裸露皮肤为红色，喙为红褐色，尖端灰黄色，腿为深红色。幼鸟体羽具有横斑，次级飞羽和尾巴带有条纹。","call":"石鹑的叫声非常独特，是一系列响亮的‘wheet’音节，音调逐渐升高并变得更为强烈，通常由一对石鹑合唱。","habits":"石鹑生活在各种类型的灌木草原中，尤其偏好植被茂密、岩石遍布的山坡，海拔高度从600米到1500米。它们通常是成对或小群体活动，有时也会形成15至20只的大群。石鹑的食物包括草籽、草叶、果实、花蕾和部分昆虫。","breeding":"石鹑的繁殖季节可能受降雨影响，通常在雨季繁殖，但在湿润地区则在旱季。巢建在岩石、树木基部或草丛中，通常由草铺设。每窝产卵4至6枚，蛋壳颜色为淡石色至浅黄色，孵化后的小鸟上身覆盖黑色栗色绒毛，下身有深棕色黑点。","identification":"石鹑与凤头鹧鸪相似，但体型更小、颜色更深，没有明显的浅色眉纹。","protection":"IUCN：LC（无危）","distribution":"石鹑广泛分布于非洲西部，包括从肯尼亚和埃塞俄比亚到冈比亚的广大区域，大部分分布区域位于苏丹大草原。","other":"石鹑自2000年以来被引进到美国和欧洲，希望能在动物园和鸟类收藏中建立稳定种群。"},{"name":"纳氏石鹑","english_name":"Nahan's Partridge","scientific_name":"Ptilopachus nahani","overview":"纳氏石鹑（英文名：Nahan's Partridge，学名：Ptilopachus nahani），是鸡形目齿鹑科石鹑属的鸟类。传统上归类于雉科的鸟类。然而，现代分类学研究显示，与石鹑亲缘关系更近，可能与齿鹑科一样，是仅存于非洲的代表之一。分布于刚果民主共和国东北部和乌干达西部的热带雨林地带。","appearance":"纳氏石鹑体长约25厘米，属于小型陆栖鸟类。其显著特征包括红色的眼环、腿和喙基，上体呈褐色，而下体和头部则为黑白相间的条纹。","call":"该鸟的领地鸣叫为一系列悠扬的哨音，音量逐渐增强，音节变为双音节，结尾处音调陡升，持续时间约5至20秒，通常在早晨7:30到8:30之间听到。","habits":"栖息于密集的原始森林，偏好河流或沼泽地带，尤其喜欢有自然空隙和较干燥河岸的地方，海拔可达约1500米。以昆虫、小软体动物、嫩芽、种子和球茎为食，通过扒开枯叶寻找食物。通常结成六只左右的小群体，偶尔多达八只。","breeding":"繁殖期似乎全年都有，但主要集中在1月至3月和8月至11月。可能实行一夫一妻制。已知的巢穴位于树洞中，离地面1米高，或在树根间，由藤蔓或寄生植物遮掩，每窝产四枚淡粉色带淡棕色或紫色斑点的蛋。","identification":"与Latham的法兰科林相似，但可通过部分红色的喙、红色的裸露面部皮肤和红色而非黄色的腿加以区分。与鳞法兰科林也有几分相像，但体型更小，具有红色的裸露面部皮肤和明亮的白色下体标记。","protection":"IUCN：VU（易危）。总数量估计在50,000至99,999只之间，因栖息地丧失和狩猎而被认为正在减少。","distribution":"分布在刚果民主共和国东北部和乌干达西部的热带雨林中，包括Bugoma、Kibale和Mabira森林保护区，以及Semliki谷地的Virunga国家公园。","other":"纳氏石鹑在某些地区被视为不祥之兆，其在村庄附近出现预示着人类死亡的征兆。"},{"name":"须林鹑","english_name":"Bearded Wood Partridge","scientific_name":"Dendrortyx barbatus","overview":"须林鹑（英文名：Bearded Wood Partridge，学名：Dendrortyx barbatus），是鸡形目齿鹑科须林鹑属的鸟类。独特的森林鸟类，以蓝灰色的脸颊、颈部和上胸部，棕色冠羽和顶冠，以及主要为肉桂色的腹部为显著特征。分布于墨西哥东部的山地和高地，主要栖息于常绿湿润森林中，属于当地特有种。尽管近年来在新的地方发现了该物种，但由于栖息地碎片化威胁，仍被列为易危物种。","appearance":"须林鹑体长22至32厘米，拥有红色的短而粗壮的喙，眼周红色环纹，头部和小顶冠为黄褐色，脸颊、颈和上胸为蓝灰色，颈背、上背和胸侧带红色条纹。背部为黄褐色、灰褐色、黑色和淡灰色相间，胸部为红肉桂色，大腿和侧腹覆盖的羽毛为肉桂色，带有灰褐色斑点。翼羽为红棕色，尾羽外侧为红棕色。腿为红色，短而粗。两性羽毛相似，但雄鸟比雌鸟大。幼鸟与成鸟类似，但胸部颜色较暗淡，侧腹有棕色条纹。","call":"发出响亮的、欢快的哨声，通常在早晨和傍晚时分最为频繁，这是它们存在的重要线索。","habits":"须林鹑通常生活在海拔900至3100米的湿润山地森林和松-橡树森林中，偏好在森林地面活动，有时会在安静的小径或道路旁出现。它们以种子、果实、芽、块茎和昆虫为食，通常成对或小群体活动。","breeding":"关于繁殖行为的知识大多来自圈养观察。繁殖期在4月至6月之间，雄鸟会建造一个有隧道入口的穹顶状巢穴，每窝通常产卵五枚。","identification":"须林鹑在其分布范围内具有独特性，很难与其它物种混淆。与长尾林鹑相比，后者翼羽末端为灰棕色而非红棕色，面部图案也截然不同：前额、头部两侧、颈部和颈背为黑色，脸部有两条白色线条。此外，长尾林鹑倾向于在更高海拔出现。","protection":"IUCN：VU（易危）","distribution":"须林鹑分布于中美洲，主要集中在墨西哥中部的Sierra Madre Oriental山脉。"},{"name":"长尾林鹑","english_name":"Long-tailed Wood Partridge","scientific_name":"Dendrortyx macroura","overview":"长尾林鹑（英文名：Long-tailed Wood Partridge，学名：Dendrortyx macroura），是鸡形目齿鹑科须林鹑属的鸟类。鲜为人知的墨西哥特有种。体型较大，长度可达29至42厘米，体重介于350至465克之间。其显著特征为长尾，头黑带白纹，红喙红眼圈，灰褐体色。主要分布于墨西哥中部高海拔的常绿和松树森林中。","appearance":"长尾林鹑具有明显的长尾，胸腹有栗色中线，背部羽毛边缘为灰色，冠羽竖立，末端有赤褐色至帝王褐色斑点。头部黑色，面部有白色眉纹和颊纹，裸露部分呈鲜艳的天竺葵粉色。成年鸟和幼鸟的羽毛有所不同，幼鸟背部和下部有白色羽轴条纹。成年后（约半成熟时）获得类似成鸟的羽毛。雄雌外观相似，但雌鸟可能略小，尾稍短。","call":"发出响亮、悠扬的歌曲，通常在清晨和傍晚鸣唱，这是其存在的重要指示。","habits":"长尾林鹑栖息于墨西哥中部的高海拔森林，偏好有茂密灌木层的环境。它们以种子、小果实为主食，也会摄取小型节肢动物和叶片。它们白天在地面觅食，夜晚单独或成对栖息于树上或灌木丛中。","breeding":"繁殖期从四月至八月，期间进行一夫一妻制。它们在地面筑巢，每窝产4至6枚蛋。新生雏鸟早熟，孵化后不久就能离巢。","identification":"与其他须林鹑属物种的区别在于黑色耳羽、额部、喉部以及突出的白色眉纹和颊纹。与须林鹑相比，后者头部和颈部缺乏鲜明的黑白图案，而与黄顶林鹑的差异在于后者有奶油色到白色的眉纹、额部和喉部。","protection":"IUCN：LC（无危）","distribution":"长尾林鹑主要分布于墨西哥中部的高海拔森林，包括松树、橡树和常绿森林。","other":"尽管全球评估显示其不受威胁，但墨西哥法律对其进行保护，主要威胁来自森林砍伐导致的栖息地丧失。"},{"name":"黄顶林鹑","english_name":"Buffy-crowned Wood Partridge","scientific_name":"Dendrortyx leucophrys","overview":"黄顶林鹑（英文名：Buffy-crowned Wood Partridge，学名：Dendrortyx leucophrys），是鸡形目齿鹑科须林鹑属的鸟类。常栖息于高海拔的常绿森林和松树-常绿混合林中。","appearance":"成年黄顶林鹑体长28至35.5厘米，雄鸟体重约397克，雌鸟约340克。其头部特征明显，前额、眉纹、下巴和喉部均为白色；耳羽黑色。整体羽色为栗色和灰色相间，胸部和腹部为蓝灰色并带有栗色条纹。头顶、短冠和颈背为栗色。眼周有一圈醒目的红色裸皮，喙黑色，腿橙红色。雌鸟体型较小，尾巴较短。亚成鸟初级飞羽覆羽尖端呈淡黄色。hypospodius亚种体型较大，颜色更深更灰，尤其是下体，胸前和胸侧的条纹颜色更深（通常是黑色）且更窄，两侧和腹面的条纹较为一致，缺乏土黄色边缘。","call":"其鸣声主要为快速的一系列响亮粗哑的哨音“kee-orr-KWA”或“whew, Whit-cha, cha-waWHAT-cha”，通常由几声只有近距离才能听到的柔和音节开始。在群居时发出低沉的下降式咕噜声。最活跃的鸣叫时间是在黎明和清晨的头四小时，以及黄昏时分，尽管它可能在一天中的任何时候鸣叫。","habits":"偏好潮湿至半湿润的高山橡树林和松树林，以及云雾林，海拔高度在300至2900米之间。可在次生林（或部分砍伐的地区），包括沿着溪流狭窄地带的森林，以及偶尔在咖啡种植园中发现。在树木和高灌木上空筑巢过夜。","breeding":"繁殖季节记录在5月的危地马拉，2月至6月的萨尔瓦多。洪都拉斯和萨尔瓦多的幼鸟在4月至7月期间成长，而哥斯达黎加则在6月至9月。繁殖群在繁殖季节开始时可能解散。巢穴为穹顶状，由枯叶和树枝构建，长度约为23厘米，深度为19厘米，入口宽9厘米，高10厘米。在哥斯达黎加发现的八个地面巢穴中，七个位于干燥浓密的草丛内部，一个位于死树底部的洞穴中。一窝通常有6至7枚蛋，平均尺寸为42.4毫米×30.3毫米或42.6毫米×32.4毫米，呈浅粉色，散布着红色斑点，或奶油色带有棕色标记。刚孵化的雏鸟体重约为17.7克，有深棕色绒毛，喉咙、胸部和腹部有黄色区域。","identification":"黄顶林鹑与同属其他物种的区别在于其白色的前额和眉纹，以及眼周独特的红色裸皮。hypospodius亚种与指名亚种相比，体型更大，颜色更深，条纹更窄且颜色更深。","protection":"IUCN：LC（无危）","distribution":"黄顶林鹑分布于三个独立区域：指名亚种从墨西哥南部进入危地马拉西部，以及洪都拉斯、萨尔瓦多、尼加拉瓜西北部和危地马拉远东地区；hypospodius亚种则分布于哥斯达黎加中部。","other":"黄顶林鹑适应能力较强，能够在一定程度的栖息地改变中生存。"},{"name":"山翎鹑","english_name":"Mountain Quail","scientific_name":"Oreortyx pictus","appearance":"山翎鹑体型较大，雄鸟平均重245克，雌鸟平均重234克，全长约27厘米。最显著的特征是头顶上的一对长而直的黑色羽冠，由两根羽毛组成，位于灰色竖立的冠顶。喉咙处有一块栗色斑块，边缘环绕着狭窄的黑带和相邻的白色带。胸部呈灰色，腹部为白色。头部和上颈部为灰色，逐渐过渡到橄榄棕色的背部、翅膀和尾巴。两侧有栗色条纹，间杂着显眼的垂直白色条纹和水平的白色或淡褐色条纹。臀部为黑色，有时个别羽毛带有栗色边缘。","habits":"山翎鹑主要栖息在海拔2000至10000英尺的沙漠灌木丛、茂密的灌木丛、和混合或针叶林地带，如白杨、马萨尼亚塔、柳树或鼠尾草。它们通常在地面快速行走或奔跑，常靠近遮蔽处。它们主要在地面觅食，通过迅速踢动脚爪在落叶中寻找种子和昆虫。","breeding":"山翎鹑的繁殖行为是单偶制，很少群居。雌鸟通常会在植被隐蔽下的简单凹坑中产下9-10枚蛋，通常靠近水源。孵化期大约21至25天，主要是由雌鸟负责，但有初步研究显示雄鸟也可能独自孵卵，这可能意味着一对山翎鹑能在一季内抚养两窝小鸟。雏鸟早熟，孵化后数小时内就能跟随父母离开巢穴。","identification":"与珠颈斑鹑相比，山翎鹑体型稍大，具有更为鲜明的羽毛色彩和独特的头冠。雄鸟头冠较长，雌鸟较短，且雌鸟的背侧有更多棕色色调，下侧颜色更浅，侧翼的白色条纹更宽。","protection":"IUCN：LC（无危）","distribution":"山翎鹑分布于北美，从中加利福尼亚南部至墨西哥下加利福尼亚州，包括美国的华盛顿州、俄勒冈州、加利福尼亚州、内华达州、爱达荷州等地。"},{"name":"鳞斑鹑","english_name":"Scaled Quail","scientific_name":"Callipepla squamata","overview":"鳞斑鹑（英文名：Scaled Quail，学名：Callipepla squamata），是鸡形目齿鹑科翎鹑属的鸟类。在墨西哥和美国西南部沙漠草地常见。以独特的白色顶冠和鳞状羽饰而知名，全身呈蓝灰色，主要分布于美国西南部至墨西哥中部。是齿鹑科翎鹑属中的早期分支，大约在新世时期分化。","appearance":"鳞斑鹑体型圆胖，全长约30厘米，翅膀短而圆，有10根初级飞羽。性别差异不大，雄鸟和雌鸟外观相似，虽然繁殖季节雄鸟的头部和颈部颜色略偏蓝色。幼鸟缺乏成鸟明显的鳞片状外观，但在出生后约两个月开始换羽，直至第一年的大部分时间里，它们的羽毛仍带有斑驳的痕迹，整体显得更暗淡和棕色。","call":"鳞斑鹑会发出嘶哑的叫声，这在它们的栖息地中是标志性的声音。","habits":"这种鹌鹑喜欢群居，形成大型冬季群落，通常选择奔跑而非飞行来逃避天敌。它们在沙漠生境中的草地上或仙人掌和刺槐树下小群活动，以昆虫、种子和浆果为食。其饮食包括多种草本植物、灌木和野草的种子，夏季会增加绿色植物和昆虫的比例。","breeding":"繁殖期一般在春季，雌鸟会在草丛中筑巢，每次产下9至16枚斑点蛋。孵化由雌鸟承担，孵化期约为21到23天。双窝繁殖（在一个季节内连续产两窝蛋）很常见。雏鸟出生后很快就能跟随父母觅食，大约在11到15周后达到成年体型。","identification":"鳞斑鹑最显著的特点是其独特的白顶冠和鳞片状羽饰，与甘贝尔鹌鹑不同，鳞斑鹑的脸上没有黑色条纹。此外，四个亚种在羽毛色彩上有细微差别，北方两个亚种（hargravei和pallida）比墨西哥亚种（squamata）颜色更浅。","protection":"IUCN：LC（无危）","distribution":"鳞斑鹑分布于美国西南部，包括亚利桑那州南部、新墨西哥州北部、科罗拉多州东部和堪萨斯州西南部，向南穿过俄克拉荷马州西部和德克萨斯州西部及中部，进入墨西哥东北部至瓜纳华托、哈利斯科和塔毛利帕斯西部。在古巴、牙买加、海地、多米尼加共和国、波多黎各和夏威夷等地有人工引入，但在中央华盛顿和内华达东部已成功建立种群。","other":"鳞斑鹑的种群数量在美国呈下降趋势，可能受到过度放牧的影响，这严重减少了它们的觅食、筑巢和栖息地覆盖。"},{"name":"华丽翎鹑","english_name":"Elegant Quail","scientific_name":"Callipepla douglasii","overview":"华丽翎鹑（英文名：Elegant Quail，学名：Callipepla douglasii），是鸡形目齿鹑科翎鹑属的鸟类。小型的齿鹑科翎鹑属鸟类，仅分布于墨西哥西北部太平洋斜坡的热带刺灌林中，从索诺拉南部至纳亚里特。主要栖息于地面。","appearance":"华丽翎鹑长约25厘米，雄鸟具有独特的长而直的橙色羽冠，雌鸟的羽冠呈灰色。两性外观相似，以灰色为主，饰有黑色、棕色和白色的斑点与条纹，雄鸟还带有红棕色。喙黑色，虹膜棕色，腿色深灰至黑色。雄鸟翼侧的斑点较淡，可将其与类似种类区分开来。","call":"鸣叫包括帮助群鸟白天觅食时保持联系的“chip-chip”声，以及傍晚集合于栖息地时发出的“cu-cow”声，清晨再次觅食前也会重复此叫声。","habits":"它们主要栖息于墨西哥西海岸的山地森林，海拔可达1000米。偏好带刺灌木丛和落叶林，常在开阔地带和耕地上觅食。受到惊扰时，通常会静止不动或穿过灌木丛，只有在万不得已时才会飞起。","breeding":"繁殖季自4月底开始，5月进入高峰期。小群于4月中旬解散。巢建于地面，一窝产卵数通常为8至12枚（有时多达20枚，可能是两只雌鸟共同在一个巢中产卵的结果）。卵呈白色，带有淡褐色斑点，平均尺寸为33.9毫米×23.9毫米，孵化周期为22至23天。","identification":"雄鸟的金色羽冠及雌鸟的灰色羽冠，以及雄鸟翼侧的较淡斑点，是区分华丽翎鹑与类似种类的关键特征。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥西部，具体从索诺拉南部至纳亚里特，位于太平洋斜坡的山地森林中。"},{"name":"珠颈斑鹑","english_name":"California Quail","scientific_name":"Callipepla californica","overview":"珠颈斑鹑（英文名：California Quail，学名：Callipepla californica），是鸡形目齿鹑科翎鹑属的鸟类。作为加州的州鸟，这种小型陆栖鸟以其独特的前倾六羽曲冠和群居习性闻名。雄鸟拥有黑白色的面部花纹和灰蓝胸部，雌鸟则为较为朴素的灰棕色，腹部无栗色斑块。广泛分布于北美的西部地区，从加拿大西南部至墨西哥下加利福尼亚州。","appearance":"珠颈斑鹑体长约105-119毫米，翼展约38-43厘米，体态圆润丰满，羽毛呈现灰白和棕色相间。雄鸟的头部有一簇显眼的黑色曲冠，胸部、背部和翅膀为褐色，而雌鸟的头部和背部则为斑驳的褐色。它们的腹部具有黑白相间的鳞状图案，雄鸟腹部中央还有一片栗色斑块，雌鸟和幼鸟外观相似，但曲冠较短且颜色偏棕色。","call":"珠颈斑鹑发出多种声音，包括社交的“芝加哥”鸣声、联系的“噼啪”声以及警告的“噼啪”声。在繁殖季节，雄鸟会发出争斗的“尖叫”，有时会打断雌鸟的社交鸣叫。","habits":"珠颈斑鹑倾向于在地面觅食，以绿色植物、种子和昆虫为食，它们高度群居，尽管飞行能力不错，但在大多数情况下选择行走或奔跑。它们偏好栖息于草原、山麓、林地、峡谷和沙漠边缘，适应性强，几乎能在任何环境中生存。","breeding":"繁殖于西部北美的灌木丛和开阔林地，巢穴是一个浅浅的坑洞，铺有植被，位于地面上的灌木或其他遮蔽物下。雌鸟通常产卵约12枚。孵化后，幼鸟会与双亲一起活动，家庭群常会形成包含至少两个雌鸟、多个雄鸟和众多后代的多家庭‘联合群’。雄鸟不一定是所有幼鸟的生父。","identification":"珠颈斑鹑与近亲黑腹翎鹑的区别在于后者拥有更长的曲冠，更亮的头部色彩，且缺乏珠颈斑鹑腹部的鳞状外观。两物种约在1-2百万年前分离。","protection":"IUCN：LC（无危）","distribution":"原生于北美，从中部至南部的加拿大，贯穿美国西部直至墨西哥下加利福尼亚州。已引入新西兰、夏威夷、南美洲部分地区、南非和澳大利亚的诺福克岛及金岛。","other":"珠颈斑鹑是1931年被选为加州的州鸟。它们对人类的适应能力强，甚至能在城市公园和郊区花园中常见。"},{"name":"黑腹翎鹑","english_name":"Gambel's Quail","scientific_name":"Callipepla gambelii","overview":"黑腹翎鹑（英文名：Gambel's Quail，学名：Callipepla gambelii），是鸡形目齿鹑科翎鹑属的鸟类。是索若拉沙漠的代表性物种之一，与仙人掌和吉拉怪兽齐名。其独特的羽冠和群居特性使其在美国西南部易于识别。雄鸟具有醒目的黑色面部、白色眉纹和铜色头部，以及明显的黑色腹部补丁。雌鸟则拥有更朴素的灰褐色外观。本种分布于美国西南部和墨西哥西北部，包括亚利桑那州、加利福尼亚州、科罗拉多州等地。","appearance":"黑腹翎鹑身长约250毫米，翼展可达42厘米，体重介于160至200克之间。雄鸟头顶有弯曲的黑色羽冠，上体、颈部、前胸为青色，带有光泽；翅膀呈红褐色，饰有白色横斑。雌鸟色彩较淡，缺乏雄鸟的装饰性羽冠，整体呈现灰褐色调。脚趾粗壮，适合在地面快速移动。","call":"鸣唱声为响亮的哀号式叫声，伴有各种咕噜声和轻笑声，声音略显鼻音，音调较低。","habits":"黑腹翎鹑主要栖息于沙漠、温带森林边缘、草原及农田，偏好靠近密集灌木丛的环境。它们通常群居，以植物部分为主要食物来源，尤其是豆科植物，同时也食用昆虫。在面对威胁时，倾向于奔跑而非飞行，仅在必要时才会短距离飞行。","breeding":"黑腹翎鹑实行一夫一妻制，春季时，雌雄鸟配对并在较密的植被中筑巢。雌鸟产卵数量约10-12枚，孵化期为21-23天，主要由雌鸟承担孵化任务，雄鸟偶尔参与。雏鸟孵化后不久即可跟随双亲离开巢穴。","identification":"与珠颈斑鹑相比，黑腹翎鹑的腹部具有明显的黑色补丁，且雄鸟的羽冠更加鲜艳。此外，黑腹翎鹑的鸣叫声略显鼻音，音调更低。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于美国西南部，包括亚利桑那州、加利福尼亚州、科罗拉多州、新墨西哥州、内华达州、犹他州、得克萨斯州和索诺拉州；同时分布于新墨西哥州边境的奇瓦瓦州以及下加利福尼亚州的科罗拉多河区域。","other":"黑腹翎鹑曾在1912年由查尔斯·T·豪兰等人引入圣克莱门特岛，至今仍在那里生存。"},{"name":"斑鹑","english_name":"Banded Quail","scientific_name":"Philortyx fasciatus","overview":"斑鹑（英文名：Banded Quail，学名：Philortyx fasciatus），是鸡形目齿鹑科斑鹑属的鸟类。仅分布于墨西哥西南部内陆地区，主要栖息于干燥地区的灌木林和杂草丛生的田野。其最显著的特征是深色的头冠和黑白相间的腹部条纹。","appearance":"斑鹑体长18至21.5厘米，体重115至160克，雄鸟平均130克，雌鸟平均126克。全身灰褐色至灰色，头部灰褐色，具白色下颌和喉部。拥有直立的黑褐相间、尖端红褐色的头冠，喙黑色，腿棕色至肉色，眼深棕色。雌鸟的头冠较短。幼鸟喉部乳白色，背部和胸部有白色条纹，经过大约2至3个月后换羽成亚成鸟，此时面部、下颌和喉部为黑色，类似Colinus virginianus salvini，再过2至3个月换羽成成鸟。","call":"领域叫声为重复的清脆‘keeah！’，有时快速连续发出尖锐系列声。被惊扰时会发出尖叫的‘wheer whee-ar’或‘wheer-pee-pee-pee-peer’声，以及受惊时的低沉咆哮。","habits":"斑鹑通常以5至15只的小群生活，一年大部分时间形成群落，常在清晨和傍晚沿安静的道路觅食。受到惊吓时会突然飞起，同时发出尖锐的叫声。它们主要栖息于干燥的灌木林和杂草地，偶尔进入农田和牧场。是地栖性鸟类，主要以种子、块茎、芽和昆虫为食。","breeding":"繁殖记录显示，斑鹑在8月至9月间筑巢，繁殖系统推测为一夫一妻制。在圈养条件下，巢由草制成，顶部部分覆盖；平均产卵数5.5枚（3至7枚），卵间隔两天一枚；孵化期22.6天（21至23天），仅由雌鸟承担。卵白色，平均尺寸30.2毫米×23.7毫米。","identification":"斑鹑与其它种类的鹑类相比，其独特的头冠和腹部条纹是最明显的辨识特征。在分布区域内，没有其他鹑类与其相似。","protection":"IUCN：LC（无危）。总数量可能少于100,000只，但被认为稳定。分布有限，但在Jalisco和Michoacán最近扩展到几个新地点。面临的潜在威胁包括过度放牧和农业集约化。","distribution":"分布于墨西哥西部，从Jalisco和Colima向南至Morelos、Puebla西南部和Guerrero东南部，预测范围可能向东延伸至Oaxaca。主要栖息于墨西哥中部干草原和灌木丛，有时进入耕种地和牧场。","other":"斑鹑是一种非迁徙性鸟类，主要在其自然栖息地内活动。"},{"name":"山齿鹑","english_name":"Northern Bobwhite","scientific_name":"Colinus virginianus","appearance":"山齿鹑体型适中，长度约为24至28厘米，翼展33至38厘米。体重随地理位置而变，墨西哥的个体重量在129至159克之间，而北部地区的平均体重为170至173克，雄鸟最大可达255克。雄鸟具有白色喉咙和眉纹，周围环绕着黑色边框；雌鸟的喉咙和眉纹为黄褐色，无黑色边缘。它们的羽毛以赤褐色为主，翅膀上有灰色斑点，腹部有白色鳞状条纹，尾巴呈灰色。雌鸟总体上较暗淡，且没有雄鸟的鲜明对比。幼鸟的羽毛与雌鸟相似，但颜色更为暗淡，标记不那么明显。","call":"山齿鹑的叫声清晰，最著名的是雄鸟在春季和夏季发出的‘bob-WHITE’或‘bob-bob-WHITE’口哨声，音节缓慢，音调从低到高跨越一个八度。此外，还有轻柔的哨声和急促的警告口哨。","habits":"山齿鹑全年栖息在农田、草地、开阔林地、路边和树林边缘。它们广泛分布在美国中东部、东南部和墨西哥东部，从大湖区和明尼苏达州南部向东至纽约州和马萨诸塞州南部，向西延伸至内布拉斯加州南部、堪萨斯州、俄克拉荷马州、科罗拉多州前山丘陵地带海拔7,000英尺以下的地区，以及除最西部以外的整个德克萨斯州。山齿鹑主要以植物材料和小型无脊椎动物为食，包括种子、浆果、昆虫和其他小动物。","breeding":"山齿鹑在非繁殖季节通常形成由5至30个成员组成的群落。繁殖季节始于4月中旬，此时群体会解散，成对的鸟儿开始筑巢。雌鸟每天产一枚蛋，经过约23天的孵化期后，雏鸟出壳。鸟蛋呈白色，一端较尖。雄鸟和雌鸟都会参与孵化，但主要由雌鸟承担。若首次孵化失败，它们会尝试再次筑巢和孵化。雏鸟早熟，出生后24小时内就能离巢。繁殖季节持续至10月中旬，雌鸟能够在单个繁殖季内孵化三批蛋。","identification":"山齿鹑雄鸟头部有明显的黑白色斑纹，雌鸟则有黄褐色的喉咙和眉纹。与北美其他齿鹑相比，山齿鹑的特征较为独特，尤其是雄鸟的黑白面部图案。雌鸟在外观上差异较小，但在某些地区，如墨西哥南部的雄鸟可能呈现出更多的灰色，而胸膛则更加赤褐色。","protection":"IUCN：NT（近危）","distribution":"山齿鹑分布于北美中东部、东南部和墨西哥东部，从美国的大湖区和明尼苏达州南部向东至纽约州和马萨诸塞州南部，向西延伸至内布拉斯加州南部、堪萨斯州、俄克拉荷马州、科罗拉多州前山丘陵地带海拔7,000英尺以下的地区，以及除最西部以外的整个德克萨斯州。在佛罗里达州南端，已灭绝的Key West山齿鹑亚种曾在此生存。山齿鹑还出现在古巴，并被引入到多米尼加共和国、海地、巴哈马群岛、特克斯和凯科斯群岛、美国维尔京群岛、波多黎各、法国、中国、葡萄牙和意大利。在加拿大，特别是在安大略省的沃尔波尔岛，仍有少量自持种群存在。","other":"山齿鹑里氏亚种（ ridgwayi）被列入《华盛顿公约》附录一保护鸟类。"},{"name":"黑喉齿鹑","english_name":"Yucatan Bobwhite","scientific_name":"Colinus nigrogularis","overview":"黑喉齿鹑（英文名：Yucatan Bobwhite，学名：Colinus nigrogularis），是鸡形目齿鹑科齿鹑属的鸟类。以黑喉和白眼纹的鲜明对比而著称，常见于中美洲墨西哥东南部至洪都拉斯的灌木丛和海岸灌木区。","appearance":"黑喉齿鹑体长约18至21.5厘米，重约109至152克，雌雄外观相似。其特征性的脸部图案包括黑色前额、头部两侧和喉咙，小的栗色冠羽和头部顶部。羽毛混杂着赤褐色、白色和黑色。颈部背面和上背部呈肉桂色，饰有淡黄色和白色的斑点；背部呈栗色，边缘灰暗，臀部橄榄棕色和灰色，肩羽和翅膀覆羽呈肉桂色，带有灰色、栗色和黑色斑点。胸部和腹部白色，有黑色V字形条纹；两肋白色，边缘棕色和黑色。喙黑色，腿棕色或蓝灰色。雌鸟头部顶部淡黄色，饰有小的黑色斑点；头部两侧和颈部淡黄色，逐渐变为喉咙上的白色；背部和臀部斑驳的橄榄棕色，饰有栗色和黑色V字形条纹；胸部和腹部浅灰色，有小的黑色V字形条纹，腹部上逐渐变大。","call":"黑喉齿鹑的叫声与非常相似，但所有叫声通常音调更高，缺乏尖锐的尖叫。两性都会发出响亮的上扬哨声“bob-wheet！”的叫声，春季和夏季时会从篱笆柱或低树上反复发出，通常比更快，而且经常省略“bob”的音节。","habits":"黑喉齿鹑栖息于灌木丛、林地边缘、杂草丛生的田野、森林空地、松树林和农业用地，以及墨西哥的海滩灌木区。它们在旱季常与水源附近有关联，限制在低地，低于200米的墨西哥东南部。这种鸟群居，由12到20只鸟组成的群落被报道过。","breeding":"繁殖期从4月至8月或更晚；大多数关于处于繁殖状态的成鸟或巢穴的报告发生在6月至8月；11月发现刚孵化的雏鸟。可能是一夫一妻制。在地面的凹陷处筑巢，用草铺垫，通常隐藏在Agave丛下。蛋壳颜色从浅黄褐色到白色，有时有小的深色斑点；平均尺寸为30.5毫米×22.7毫米。","identification":"在大部分分布范围内，黑喉齿鹑是开放栖息地中唯一的鹌鹑种类；与热带森林中的歌鹑相比，它具有独特的面部图案和叫声。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥东南部至洪都拉斯，主要在低海拔的灌木丛和海岸灌木区。","other":"黑喉齿鹑的四个亚种已被认可，其中最淡的是persiccus，而指名亚种种可能是最深色的。"},{"name":"斑胸齿鹑","english_name":"Spot-bellied Bobwhite","scientific_name":"Colinus leucopogon","overview":"斑胸齿鹑（英文名：Spot-bellied Bobwhite，学名：Colinus leucopogon），是鸡形目齿鹑科齿鹑属的鸟类。分布于中美洲，从危地马拉延伸至哥斯达黎加。其有时被认为与冠齿鹑为同一物种，随着后者向北扩展至哥斯达黎加，两物种未来可能在分布上有所重叠。然而，斑胸齿鹑的哥斯达 Rican 亚种与冠齿鹑差异最大。","appearance":"斑胸齿鹑体长约22至24厘米，其六种亚种间的雄鸟羽毛颜色存在地理变异。所有亚种都有棕色背部，颈背带有黑色斑点。头部特征包括白色眉纹，眼周有深色线条，喉部为白色或棕色，有短小的冠羽。下腹部有斑点，其余下体部分依亚种不同而呈淡色、全斑点或带红褐色胸部。雄鸟平均重量约140克，雌鸟较暗淡，具淡黄色眉纹和斑驳喉部，平均重约115克。","call":"鸣声通常由雄鸟在春夏季发出，为上升的、粗糙的‘bob-Wight!’或‘bob-bob-White!’叫声。","habits":"斑胸齿鹑在非繁殖季节形成3至15只鸟的小群体，称为“coveys”。筑巢时，雌雄双方都会孵卵，但主要是由雌鸟承担。每窝约产10枚白色卵。雏鸟早熟，孵化几小时后即可离巢。这种羞怯的鸟类以种子和昆虫为食，尤其在繁殖季节更偏好昆虫。它在清晨和傍晚最为活跃。","breeding":"斑胸齿鹑的繁殖行为包括雌雄双方共同参与的筑巢和孵化过程，尽管多数情况下孵化主要由雌鸟负责。每窝产卵约10枚，雏鸟出生后不久便能离开巢穴。","identification":"斑胸齿鹑与冠齿鹑在形态上有显著差异，尤其是其哥斯达 Rican 亚种，可通过下腹部的斑点、头部特征和体色辨别。","protection":"IUCN状态未知。","distribution":"分布于中美洲，从危地马拉至哥斯达黎加的开阔草原、灌木丛和树木茂密的地带及其他开放林地。"},{"name":"冠齿鹑","english_name":"Crested Bobwhite","scientific_name":"Colinus cristatus","overview":"冠齿鹑（英文名：Crested Bobwhite，学名：Colinus cristatus），是鸡形目齿鹑科齿鹑属的鸟类。从哥斯达黎加延伸到南美的广大地区，同时在阿鲁巴岛和荷兰安的列斯群岛也有发现。其自然栖息地包括亚热带或热带的干燥灌木丛、季节性湿润或泛滥的低地草地以及重度退化的前森林地带。","appearance":"成年冠齿鹑体长约178至216毫米（约7.0至8.5英寸）。两性外观极为相似。额部和头顶的长羽呈淡黄色或白色，而冠羽可能偏暗。颈背及两侧黑白色相间的大理石花纹明显，喉咙部分白色或淡黄色，有时带有黑色斑点。上体部分杂有黑色、棕色和灰色斑点。下体部分颜色较浅，带有淡黄色、肉桂色和黑色标记。眼睛棕色，喙黑色，腿为蓝灰色。雌鸟比雄鸟略显棕色。","call":"雄性冠齿鹑在繁殖季节发出的叫声非常独特，是一种快速、沙哑的三音节‘quoit bob-white’或者二音节的‘oh, wheet’。","habits":"冠齿鹑常以小群体的形式在地面活动，偏好靠近茂密的遮蔽处。它们的食物主要包括嫩芽、嫩叶、叶片和小型无脊椎动物。","breeding":"繁殖信息未提供。","identification":"与其他齿鹑科物种相比，冠齿鹑可通过其独特的头部羽毛和叫声进行辨识。","protection":"IUCN：LC（无危）。冠齿鹑拥有广泛的分布范围，在许多地方数量丰富，其种群似乎正在增长。","distribution":"分布于中美洲至南美洲北部，包括哥斯达黎加至南美北部地区，以及阿鲁巴岛和荷兰安的列斯群岛。","other":"无"},{"name":"云斑林鹑","english_name":"Marbled Wood Quail","scientific_name":"Odontophorus gujanensis","overview":"云斑林鹑（英文名：Marbled Wood Quail，学名：Odontophorus gujanensis），是鸡形目齿鹑科林鹑属的鸟类。分布广泛，自中美洲的哥斯达黎加至南美洲北部，常见于热带和亚热带湿润低地森林。八种已知亚种差异不大，主要体现在头部颜色的微妙变化上。此鸟较为隐秘，常以响亮的叫声让人知晓其存在。","appearance":"云斑林鹑体长约23至29厘米，体形丰满，喙粗壮呈深色，腿部和脚趾蓝灰色。眼睛周围有橙红色裸露皮肤，虹膜棕色。头部前端和脸颊为红褐色，冠羽暗褐色并形成松散的短冠。背部和翅膀为棕色，带有黑色细纹，臀部和尾羽上覆羽模糊地斑点着较淡的颜色。下体为暗褐色，带有不明显的条纹。幼鸟外观与成鸟相似，但有红橙色的喙和非条纹状的红褐色冠羽。","call":"云斑林鹑的叫声响亮粗糙，通常在清晨或黄昏时分，由多只鸟同时发出低沉的滚动声，是森林中常见的声音。","habits":"云斑林鹑是地面栖息的鸟类，生活在低地雨林和云雾林的下层植被中，最高可达海拔1500米。它是一种难以观察到的鸟，常在地面活动，偶尔进入开阔地带但靠近倒木或灌丛以方便快速撤退。受惊扰时，它倾向于悄悄步行离开，必要时会突然起飞。它通常成小群活动，单列行进，以落叶层中的昆虫和落果为食。","breeding":"云斑林鹑似乎是一夫一妻制，会在树根或倒木底部的枯叶堆中建造巢穴，每次产卵约四个，白色，有时带棕色斑点，具体繁殖季节随地理位置而异。","identification":"云斑林鹑与黄眼斑林鹑的区别在于后者胸部有白色斑点，头顶红褐色与灰喉部形成对比。此外，林鹑的体型和颜色与一些小型穴䳍类似，但后者头部较小，颈部较长，看似无尾。","protection":"IUCN：LC（无危）","distribution":"云斑林鹑分布于中美洲至南美洲北部，从哥斯达黎加至玻利维亚东部。","other":"尽管云斑林鹑能够适应次生林环境，但亚马逊盆地的森林砍伐导致其栖息地减少，增加了猎杀风险，预计未来三代内的数量将下降25至30%。"},{"name":"斑翅林鹑","english_name":"Spot-winged Wood Quail","scientific_name":"Odontophorus capueira","overview":"斑翅林鹑（英文名：Spot-winged Wood Quail，学名：Odontophorus capueira），是鸡形目齿鹑科林鹑属的鸟类。常见于南美洲东部，包括巴西、阿根廷东北部和巴拉圭东部。拥有独特的外观特征，如红眼和栗色冠羽，通常在低地大西洋森林中成小群活动。斑翅林鹑在巴西被称为'uru'。","appearance":"斑翅林鹑体型丰满，陆栖，喙短而粗壮。具有红眼，栗色冠羽，橙色眉纹，灰色喉部和腹部，背部呈斑驳的棕色。雄鸟体重约457克，雌鸟约396克。头部两侧、脸颊区、下巴、喉部、胸部和腹部为均匀的灰色；整体颜色介于棕色到灰色之间。头顶和冠羽为栗色，额头和眉纹为棕红色。背部棕色，带有白色羽轴纹；肩羽栗色，带有白色羽轴纹；臀部tawny色带黑色斑点；飞羽黑色，带有白色斑点。喙黑色，腿灰黑色。雌鸟相似但略显纤细。幼鸟背部的羽轴纹更宽，臀部的黑色斑点更粗糙，胸部灰色，腹部红棕色。plumbeicollis亚种的下体较淡，带有米色色调；眉纹和上背的白色羽轴纹不太突出，喉部和前颈有黑褐色的虫蚀状条纹。","call":"斑翅林鹑的鸣唱是一连串快速且重复的“kloh-kloh-klohkloh”声，通常在黎明和黄昏时分，尤其是在月光皎洁的夜晚听到，但也可能在一天中的其他时间不规律地发出声音。此外，它们在警戒时会发出响亮的“wit, wit, wit”声，在树上的栖息处则发出颤抖而微弱的“bew, bew, bew”声。","habits":"斑翅林鹑生活在低地热带大西洋森林中，包括次生林，海拔至少可达1600米。它们在森林地面活动，形成由6-8只鸟组成的群落，有时可达10-15只，全年如此。它们以浆果为主食，尤其是Phytolacca decandra（马兜铃科）的浆果；还吃森林地面的Araucaria（南洋杉科）坚果，以及一些昆虫。","breeding":"斑翅林鹑的繁殖期为8月至11月，至少在圣保罗州的2月份也有记录。它们是单配偶制。在野外，它们在地面筑巢，有时利用犰狳洞穴。在圈养条件下，它们会建造直径40厘米、高50厘米的穹顶形巢，有一侧入口，通常产3-5枚蛋（如果需要替换，则产更少）。在野外，巢蛋孵化期为26-27天。据报道，巢中最多有12枚蛋，这可能表明不止一只雌鸟在同一巢中产卵。孵化由雌鸟单独完成，报道的孵化期为18-19天，雌鸟也是唯一照顾雏鸟的个体。","identification":"斑翅林鹑与其他鸟类的区别在于其明亮的红色裸眼环和眼睑，以及特有的灰色侧面、下巴、喉部、胸部和腹部。它们的头顶和冠羽是栗色，额头和眉纹是棕红色。背部棕色，带有明显的白色羽轴纹。在幼鸟中，背部的羽轴纹更宽，臀部的黑色斑点更粗糙，胸部为灰色，腹部为红棕色。","protection":"IUCN：LC（无危）。尽管斑翅林鹑的全球分布广泛，但在巴西的某些地区被认为受到威胁，特别是在里约热内卢的低地几乎灭绝。总体而言，它们的数量可能不到5万只，且正在减少。在巴西内陆的数量大幅减少，现在主要局限于受保护的大西洋沿岸森林。NE巴西的种群似乎是最危险的。在阿根廷和巴拉圭，近期记录很少。需要进行广泛的调查。已知有大约26只鸟被圈养。","distribution":"斑翅林鹑分布在南美洲东部，包括巴西东部至阿根廷东北部和巴拉圭东部，主要栖息于干枯的低地森林，包括次生林，海拔不超过1600米。","other":"关于斑翅林鹑的系统学历史和详细生态学研究信息有限。"},{"name":"黑耳林鹑","english_name":"Black-eared Wood Quail","scientific_name":"Odontophorus melanotis","overview":"黑耳林鹑（英文名：Black-eared Wood Quail，学名：Odontophorus melanotis），是鸡形目齿鹑科林鹑属的鸟类。体型类似雉鸡，以暗褐色或黑色为主色调，胸部呈赤褐色。分布于中美洲的热带及亚热带森林，从洪都拉斯至巴拿马，海拔450-1600米。数量稀少，且观察记录不多。","appearance":"成年黑耳林鹑体长22-28厘米，雄鸟体重约340克，雌鸟约329克。其特征为无斑点的栗色冠羽和顶羽，黑色的脸颊和喉部，眼周裸露的环带呈紫色。背部和臀部黑色或橄榄色，带有肉桂色的细纹，肩羽黑色或橄榄色，带有黑色斑点；腹部淡黄色。喙黑色，腿蓝黑色。雌鸟与雄鸟相似，但头部两侧颜色更深，更暗的栗色，眼环蓝黑色。幼鸟类似成鸟，但头顶颜色较暗淡，背部有白色或淡黄色的轴纹，腹部有黑色斑点和条纹，喙红棕色。","call":"黑耳林鹑会发出悠扬的‘kooLAWlik kooLAWlik kooLAWK kooLAWK’或‘LAWcooKLAWcoo’的叫声，有时由单个个体发出，也可形成二重唱，重复多达12次。在受到惊吓时，会发出流利的颤音，群落内的成员间则以柔和的咕咕声或尖叫声交流。","habits":"黑耳林鹑主要栖息在原始森林的地面或茂密的次生林中，偏好热带和亚热带森林环境。它们通常定居，不迁徙。以昆虫和落果为食，常单独、成对或以小群体（最多12只）活动，通过在枯叶堆中翻找食物。","breeding":"繁殖季节可能在巴拿马的旱季后期开始，可能是单配偶制。巢穴位于树根之间，用树叶和草铺垫。每窝产卵4枚，蛋壳颜色为奶油色或白色，带有棕色斑点，平均尺寸为37.6毫米×27.9毫米。关于繁殖的其他细节未知。","identification":"与棕额林鹑非常相似，但后者具有独特的白色颈带，而黑耳林鹑没有。黑耳林鹑的头部两侧颜色更深，胸羽颜色较暗。亚种vereuncus上体灰色较多，肩羽和翼覆羽上的黑色标记不明显，胫部暗色条纹较少。","protection":"IUCN：NT（近危）","distribution":"繁殖区域：中美洲，包括洪都拉斯、尼加拉瓜、哥斯达黎加和巴拿马的加勒比斜坡，以及哥伦比亚西北部可能也有分布。","other":"由于栖息地丧失和可能的狩猎压力，黑耳林鹑的数量正在下降，总数量可能少于50,000只。"},{"name":"棕额林鹑","english_name":"Rufous-fronted Wood Quail","scientific_name":"Odontophorus erythrops","overview":"棕额林鹑（英文名：Rufous-fronted Wood Quail，学名：Odontophorus erythrops），是鸡形目齿鹑科林鹑属的鸟类。分布于南美洲哥伦比亚西部和厄瓜多尔西部的鸟类。其显著特征是面部和下体呈明亮的棕红色，上体则为深褐色。","appearance":"该鸟长23至28厘米，雄鸟体重约340克，雌鸟约329克。雄鸟具有明显的赤褐色头冠、羽冠和脸部，眼周环绕着紫色裸露皮肤环（雌鸟为黑色）。背部和臀部可能是黑色或橄榄色，带有肉桂色斑纹；肩羽为黑色或橄榄色，带黑色斑点；胸部和腹部为深红棕色。喙为黑色，腿为蓝黑色。雌鸟头部两侧颜色更深，呈较暗淡的栗色，眼环为蓝黑色。幼鸟与雌鸟相似，但腹部有黑色斑点和条纹，背部有白色或淡黄色的羽轴纹。","call":"该鸟有两种鸣叫声，一是快速重复的清脆二重唱'chowita, chowita, chowita'，另一是共鸣强烈的'koo-klaw, koo-klaw, koo-klaw'，与栗林鹑的叫声类似。","habits":"生活在低地和山脚热带雨林，海拔高度在厄瓜多尔可达1600米，而在哥伦比亚通常仅到1100米。它们通常在森林地面活动，很少出现在开阔地带，以小群形式出现，喜食谷物。","breeding":"繁殖季节可能在1月至5月间，基于标本的生殖器官状态判断。在厄瓜多尔南部，1月初有观察到雌鸟在巢中的记录。推测为一夫一妻制，但具体繁殖细节尚不清楚。","identification":"与暗背林鹑非常相似，但可通过眼周裸露皮肤的颜色和部分个体的白喉条纹进行区分。亚种parambae的上体颜色比指名亚种更深，且有白喉条纹。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲的哥伦比亚西部和厄瓜多尔西部，包括太平洋斜坡的地区以及哥伦比亚的马格达莱纳河谷。","other":"曾被提议与几种其他木鹑合并为同一物种，目前认为棕额林鹑和栗林鹑构成超种。"},{"name":"黑额林鹑","english_name":"Black-fronted Wood Quail","scientific_name":"Odontophorus atrifrons","overview":"黑额林鹑（英文名：Black-fronted Wood Quail，学名：Odontophorus atrifrons），是鸡形目齿鹑科林鹑属的鸟类。主要分布在南美洲东北部的哥伦比亚和西北部的委内瑞拉，是当地特有种。","appearance":"黑额林鹑体长约24至30厘米，雄鸟体重约为311克，雌鸟约298克。其显著特征为黑色的额头、面颊和喉咙。雄鸟的冠羽为红褐色，背部呈灰色并带有黑色斑纹，向臀部逐渐变为棕色。翅膀上有肉桂色和黑色的斑点，闭合时可见白色小斑点。雌鸟相似，但下体颜色更偏红棕色。幼鸟的上喙呈棕红色，喉咙上的黑色羽毛尖端为黄橄榄色。","call":"黑额林鹑的叫声为典型的节奏感强的哨音系列，被形容为‘bob-a-white’，此外还有类似灰颈林秧鸡的咔哒声和群鸟重新聚集时的嘎嘎声。","habits":"黑额林鹑生活在海拔1200至3100米的热带和亚热带山地森林，最低可达700米。它们通常在森林地面活动，以小群形式觅食，数量可达十只。它们通过在落叶堆中刨食寻找浆果和昆虫。","breeding":"繁殖季节至少从五月持续到八月。已知巢穴位于地面的凹陷处，由干叶和小枝构成，巢内有三个白色蛋。","identification":"与棕额林鹑相比，后者有栗色下体；而领林鹑有大部分白色的面部和喉咙，胸部有斑点。不同亚种的区别在于黑色区域的大小和整体色彩：variegatus亚种的上体图案更强烈，冠部黑色区域更大，背部颜色更深；navai亚种身体呈暗褐色，缺乏红棕色调，冠部黑色区域更大，上翼覆羽和侧翼更棕色，腹下部为灰褐色。","protection":"IUCN：LC（无危）","distribution":"主要分布在哥伦比亚东北部的Sierra Nevada de Santa Marta山脉和委内瑞拉西北部的Serranía del Perijá山区。","other":"虽然在一些保护区如Sierra Nevada de Santa Marta国家公园内，但由于狩猎和森林砍伐的控制不力，保护效果有限。"},{"name":"栗林鹑","english_name":"Chestnut Wood Quail","scientific_name":"Odontophorus hyperythrus","overview":"栗林鹑（英文名：Chestnut Wood Quail，学名：Odontophorus hyperythrus），是鸡形目齿鹑科林鹑属的鸟类。生活在海拔1600至2800米的蒙特森林中，以种子、浆果和可能的昆虫为食。","appearance":"体型介于25至29厘米，体重雄鸟325至380克，雌鸟325至330克。整体色彩从栗色到深棕色，眼周和耳羽灰白色。头部呈栗色，前颈和胸部赤褐色；背部、臀部和翅膀主要为棕色；上翼覆羽有白色斑点；背部和臀部有细小的黑色波纹。喙黑色，虹膜深棕色，腿蓝灰色或暗灰色。雌鸟相似，但胸部和腹部大部为深灰色，冠部暗棕色，肩羽和翼覆羽缺乏淡黄色标记。幼鸟似成年雌鸟，但上翼覆羽和肩羽尖端泛白，年轻的雄鸟逐渐获得红色下体。","call":"发出类似同类的嬉戏口哨般的鸣唱，快速重复的二重奏，'orrit-kilyit...'；还有低沉的'peetit, peetit...'警报声。","habits":"通常居住在蒙特亚热带森林内部和边缘，包括密集的次生林和森林边界，主要在森林地面活动。偶尔在树上6至10米高处栖息。群居，通常由3至9个个体组成，全年维持2.6至9.0公顷的群体领地。通过在落叶层中刮擦寻找根、种子和从树上掉下的果实，包括Matissia bolivarii、Oreopanax floribundum、各种Miconia spp.、Xanthosoma sp.、Anthurium sp.、Chrysoclamis、Oreopanax、Saurauia和许多Chusquea的种子。","breeding":"繁殖季节似乎有两个高峰期，3月至5月和10月至12月，与一年中最潮湿的时期相吻合。巢穴为直径20厘米、高15厘米的穹顶球形，通过短隧道（入口直径10厘米）进入，由树叶和树枝构成，位于地面，其中一个位于倒下的树干旁边，另一个靠在堤岸上。产卵数为4至5枚，蛋壳白色无斑点，尺寸42.2至44.3毫米×30.4至41.4毫米，重量20.9至25克，仅由雌鸟单独孵化27至29天。刚孵化的小鸟上面主要是深色，有赤褐色的眉线和浅黄色的脸颊，以及橙红色的喙。幼鸟在家庭群体中生活数月。","identification":"与棕额林鹑没有已知的重叠；与云斑林鹑有部分重叠，但两种在海拔高度上分离。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚西部和中部安第斯山脉，局部出现在东部安第斯山脉。","other":"面临的主要威胁包括森林砍伐、狩猎和狗的捕食。在受保护地区如Las Orquideas、Los Nevados、Cueva de los Guácharos、Munchique和Farallones国家公园以及Otún Quimbaya野生动物和植物保护区中存在种群。"},{"name":"暗背林鹑","english_name":"Dark-backed Wood Quail","scientific_name":"Odontophorus melanonotus","overview":"暗背林鹑（英文名：Dark-backed Wood Quail，学名：Odontophorus melanonotus），是鸡形目齿鹑科林鹑属的鸟类。分布于南美洲哥伦比亚西南部至厄瓜多尔西北部的安第斯山脉地区。成鸟体长约23至28厘米，体重约322克，全身呈深褐色，喉部和胸部为红栗色，上体有细小的红栗色虫纹。该物种属于单型种。","appearance":"暗背林鹑体型类似大型葡萄柚，长23至28厘米，雄雌体重均约为322克。整体颜色为棕黑色，喉部和胸部为红栗色，逐渐变深向下。头部两侧、背部、臀部、翅膀和腹部为棕黑色，带有精细的红栗色虫纹。喙为黑色，腿为棕黑色。雌鸟与雄鸟外观相同。幼鸟色泽较淡，红栗色部分较暗淡，面部和胸部散布有红栗色羽毛，喙为红色，腿为绿灰色。","call":"暗背林鹑的广告鸣声通常以同步二重唱呈现，快速而欢快的“koreewow-koreewow-koreewow...”，音调略低于异域分布的棕胸林鹑。其叫声还包括柔和的哨声和圆润的滚动音符。","habits":"暗背林鹑栖息于海拔1100至2200米的低地亚热带森林，包括原始和次生林，通常在地面活动，但在树上筑巢。它们以地面昆虫和果实为食，常以十只左右的小群觅食。","breeding":"关于暗背林鹑的繁殖习性知之甚少，但有记录显示在6月至8月和12月发现刚孵化的雏鸟，依赖父母照顾的幼鸟在3月、5月、9月和1月被观察到。家庭群通常由2至5只幼鸟组成。","identification":"暗背林鹑在形态上最显著的特点是其红栗色的喉部和胸部，与同属的棕额林鹑相比，后者出现在较低海拔，头部图案差异明显。","protection":"IUCN：LC（无危）","distribution":"分布于南美哥伦比亚西南部的纳里诺省至厄瓜多尔西北部的埃斯梅拉达斯、卡尔奇、伊姆巴布拉、皮钦查和科托帕希省西部。"},{"name":"棕胸林鹑","english_name":"Rufous-breasted Wood Quail","scientific_name":"Odontophorus speciosus","overview":"棕胸林鹑（英文名：Rufous-breasted Wood Quail，学名：Odontophorus speciosus），是鸡形目齿鹑科林鹑属的鸟类。分布于南美的亚马逊雨林西部，主要在安第斯山脉东侧的云雾森林中，海拔介于800至2000米之间，以胸腹部的红褐色羽毛和头部的黑色与棕色相间的独特外观著称。","appearance":"体型丰满，类似小鸡，体长24-28厘米，体重约300克。拥有红褐色的胸部和腹部，头部顶部深棕色，侧面和喉部黑色，耳羽棕色，眼周裸露皮肤蓝黑色。背部和臀部棕色，饰有细密的黑色虫蚀状纹和白色羽轴，上翼覆羽斑点黑或白，羽轴白色。喙和腿均为蓝黑色。雌雄相似，但雌鸟上胸部红褐色边缘更淡，下胸部和腹部转为灰色。幼鸟头部侧面、下巴和喉部红褐色，边缘暗淡，头上的白条较窄，背部和臀部羽轴纹较少，肩羽尖端红褐色。","call":"远距离传播的鸣唱是一系列欢快的哨声，类似于‘keeroroko-keeroroko-keeroroko...’的重复二重奏，一只鸟发出‘DUEE-do’，另一只则发出‘CHEER-a-lo’。报警时会发出‘wekwekwek’的声音，还会发出低沉的哨声，如‘ro-coco’，仅在近距离时才可听到。","habits":"主要栖息于热带和亚热带湿润山地森林的地面，似乎不迁徙。其饮食习性与其他Odontophorus种类相似，推测主要以昆虫、坚果和植物为食，夏季尤其偏好高蛋白食物。","breeding":"具体繁殖信息有限，已知的是蛋壳为无斑点的白色，至少有一个窝含五个蛋。","identification":"与同属的暗背林鹑相比，其鸣唱音调更高，音节更多；与纹颊林鹑相比，鸣唱音节更多。不同亚种间，如soederstroemii与loricatus，头部颜色和头部侧面的颜色有所不同。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲的玻利维亚、厄瓜多尔和秘鲁，特别是在安第斯山脉东部的森林中，偶尔在秘鲁记录到较高海拔。","other":"在哥伦比亚南部最近被发现，数量可能超过50万只，但总体状况可能稳定。在秘鲁部分地区较为罕见，但在厄瓜多尔的Podocarpus国家公园相对常见。"},{"name":"黑顶林鹑","english_name":"Tacarcuna Wood Quail","scientific_name":"Odontophorus dialeucos","overview":"黑顶林鹑（英文名：Tacarcuna Wood Quail，学名：Odontophorus dialeucos），是鸡形目齿鹑科林鹑属的鸟类。罕见，分布于巴拿马东部和哥伦比亚西北部的边境地带，栖息于海拔约1000至1400米的成熟森林中。其显著特征为黑色头部，白眉纹和淡褐色颈背，胸部有白色横带。","appearance":"黑顶林鹑体长22至25厘米，雄鸟体重约为264克，雌鸟约为258克。头部顶部和喉咙为黑色，被白色眉纹、眼上方和下巴分隔开。颈部两侧和背面为肉桂色，背部和臀部橄榄棕色，带有细密的黑色网状斑点；胸部和腹部栗色，点缀着细小的白色斑点。喙为黑色，腿为棕黑色。雌鸟与雄鸟相似，但下体更呈黄褐色。幼鸟似雌鸟，但下颌的白色较少且较暗淡，喉部的黑色带更宽。","call":"关于黑顶林鹑的鸣叫特征信息缺失。","habits":"生活在小群体中，通常难以观察到。它们似乎不迁徙，以森林地面为栖息地。活动和觅食习性未知。","breeding":"关于黑顶林鹑的繁殖习性的信息极为有限，仅知幼鸟采集发生在6月初。","identification":"与同属的其他种类如Tarcarcuna wood quail、领林鹑、委内瑞拉林鹑、黑额林鹑和白喉林鹑相比，黑顶林鹑在外观上有其独特的特征，但具体的辨识要点需要进一步研究确认。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的巴拿马东部（Darién省）和南美洲的哥伦比亚西北部（Chocó省）。","other":"关于黑顶林鹑的分类学讨论指出，它可能与其他几种齿鹑属物种构成单一物种，但这一观点尚未被主流鸟类分类系统接受。"},{"name":"领林鹑","english_name":"Gorgeted Wood Quail","scientific_name":"Odontophorus strophium","overview":"领林鹑（英文名：Gorgeted Wood Quail，学名：Odontophorus strophium），是鸡形目齿鹑科林鹑属的鸟类。主要分布在哥伦比亚东部安第斯山脉北部的云雾森林中，以独特的黑白色喉部月牙图案著称。","appearance":"成年领林鹑具有明显的黑白色喉部纹饰，雄鸟下体为栗色，胸部点缀着白色斑点，雌鸟下体呈灰色。整体毛色为褐色，下胸部棕色，饰有白色斑点行，腹部红褐色；背部带有细白条纹，肩羽有黑色斑点。喙、腿黑色，虹膜深棕色。雌鸟与雄鸟相似，但下体暗灰，头部花纹更杂乱，喉部更白，黑色部分不那么浓重，胸部白色斑点行显著减少。幼鸟像雌鸟，但胸部和侧面更呈棕灰色，胸部白色斑点减少为条纹状，更带淡黄色，边缘黑色。","call":"领林鹑的鸣唱是一系列连续的口哨声，持续时间可达30秒，与同属其他物种类似，但由三个音符构成，音调下降的“ti-ti-oo”，前两个音符明显高于最后一个音符，音高在1.2至1.8 kHz之间，每秒重复约3个音节，有时会减缓至每秒2个音节。","habits":"生活在海拔1600至2050米的山地温带和亚热带森林中，尤其偏好被胡姆博尔特栎树主导的森林。在塞拉尼亚德洛斯亚里圭埃斯，它栖息于前山云雾森林，特征是非常陡峭的地形，平均树冠高度约12米，有高达15米的突出树木，且拥有较高水平的附生植物。主要在森林地面活动，也会利用次生林。通常以1至3只的小群体出现。","breeding":"繁殖季节似乎与每年3月至5月和9月至11月的降雨高峰相吻合，基于数个成鸟在繁殖状态下的标本收集、5月初见到的雏鸟以及12月采集到的幼鸟。关于繁殖行为的进一步信息尚未获得。","identification":"领林鹑是其分布范围内唯一具有黑白喉部环带的木鹑。雌雄之间主要通过下体颜色和喉部纹饰的差异进行辨识，而幼鸟与雌鸟相似，但具有更多差异性的特征。","protection":"IUCN：VU（易危）","distribution":"领林鹑主要分布在哥伦比亚东部安第斯山脉的西侧，具体包括桑坦德省（可能已灭绝）、昆迪纳马卡省和博亚卡省。其分布区极为有限，直到最近才发现于博亚卡省的两个新地点。","other":"领林鹑的总数量估计在1300至2900只之间，且仍在下降。历史上92%的分布区已被砍伐，主要威胁包括持续的森林破坏和狩猎。"},{"name":"委内瑞拉林鹑","english_name":"Venezuelan Wood Quail","scientific_name":"Odontophorus columbianus","overview":"委内瑞拉林鹑（英文名：Venezuelan Wood Quail，学名：Odontophorus columbianus），是鸡形目齿鹑科林鹑属的鸟类。以独特的外观和声音在云雾森林中被轻易辨认。","appearance":"成年委内瑞拉林鹑身长25至30厘米，雄鸟体重约343克，雌鸟约336克。其头部有短小的冠羽，喙粗壮。体羽主要呈红棕色，胸部、腹部和侧翼有大块白色斑点。喉部和下巴为白色，带有黑色条纹。雌鸟羽毛颜色较淡，白色斑点不明显，而幼鸟的白色斑点和条纹发育较差，喙为橙色。","call":"委内瑞拉林鹑的叫声独特，持续时间可达十秒，通常在黎明时分发出，声音类似快速重复的二重奏，被描述为“churdole-chur-it, churdole-chur-it...”。","habits":"委内瑞拉林鹑主要栖息在海拔800至2400米的蒙特亚热带云雾森林地面，偏好植被丰富、有棕榈树的成熟森林。它们通过翻动落叶层和挖掘土壤寻找种子、果实、昆虫和根茎作为食物。","breeding":"繁殖季节从三月开始，可能持续到七月底。已知的巢穴位于棕榈树基部，由植被覆盖，巢中发现六枚白色的蛋，尺寸约为40.5–43.5毫米×29.0–29.5毫米，孵化期大约为30天。","identification":"与之相近的云斑林鹑相比，委内瑞拉林鹑具有白色喉部，而前者眼周有裸露的橙色皮肤，且喉部无白色。","protection":"IUCN：NT（近危）","distribution":"委内瑞拉林鹑主要分布在委内瑞拉中北部，具体包括从卡拉沃沃东至米兰达西北部，以及塔奇拉西部的两个孤立群体。","other":"委内瑞拉林鹑面临的主要威胁包括森林砍伐、狩猎和城市化。虽然在一些保护区如圣埃斯特万国家公园、埃尔塔马、马卡罗、埃尔阿维拉和瓜托波国家公园以及皮科科达齐自然纪念碑中仍有分布，但总体数量估计在1500至7000只之间，且正在减少。"},{"name":"白喉林鹑","english_name":"Black-breasted Wood Quail","scientific_name":"Odontophorus leucolaemus","overview":"白喉林鹑（英文名：Black-breasted Wood Quail，学名：Odontophorus leucolaemus），是鸡形目齿鹑科林鹑属的鸟类。小型陆生鸟类，体长22至25.5厘米，平均体重雌鸟286克，雄鸟300克。分布于中美洲的哥斯达黎加和巴拿马，主要栖息于热带和亚热带湿润山地森林。其特征为深棕色体羽，黑色胸腹部，喉部有白色斑块。","appearance":"白喉林鹑体型丰满，喙结实，头部、冠羽、耳羽黑色，喉部有大白色斑点，颈与胸部黑色，带有暗淡的白色羽尖。全身以深棕色为主，腹部棕色，带有细密的黑色虫蚀状纹。虹膜深棕色，喙黑色，腿灰色，两性相似。幼鸟胸羽呈深栗色，喉部有灰暗斑点，上身有红褐色条纹，喙可能为棕色或红色。在哥斯达黎加的多塔山脉，存在一个体型较小，几乎全黑的种群。","call":"早晨和傍晚最为活跃，会发出长达60秒的‘kee-a WOWa kee-a WOW-a’（类似‘where-ARE-you where-ARE-you’）的叫声，最远可传播500米。此外，还有低沉、嘶哑、咯咯的叫声，遇警时发出颤音，争斗时发出‘CUH-k’rrr’的叫声，以及保持群体联系的各种上升音调的啾啾声。","habits":"白喉林鹑生活在海拔700至1850米的热带和亚热带森林中，包括次生林和森林边缘，主要在森林内部。它们通常在森林地面活动，偏好茂密的植被环境，如灌木丛和藤蔓之间。白天成对或小群活动，每群约2至15只，平均占地3.3公顷，无论是在破碎还是连续的森林中。","breeding":"繁殖季节大约在六月开始，可能是单配偶制。在重度遮荫的次生林沿溪流边筑巢，巢穴位于落叶层中的凹陷处，入口朝下，尺寸约为24毫米×13厘米。一窝产5枚蛋，蛋壳白色，后染成棕色，大小为44.5毫米×28.7毫米。孵化期16至17天。成年鸟群守卫巢址，但不参与孵化。幼鸟在其出生领地逗留至性成熟。","identification":"与其他林鹑的区别在于黑色胸部和脸部，以及喉部的可变白色标记。哥斯达黎加多塔山脉的种群因全黑外观而独特。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加东部、中部高地到巴拿马西部。大多数记录来自加勒比海斜坡。","other":"面临的主要威胁可能包括森林砍伐和狩猎。"},{"name":"纹颊林鹑","english_name":"Stripe-faced Wood Quail","scientific_name":"Odontophorus balliviani","overview":"纹颊林鹑（英文名：Stripe-faced Wood Quail，学名：Odontophorus balliviani），是鸡形目齿鹑科林鹑属的鸟类。胸前有白色斑点，黑色眼罩和红色头冠，以及独特的红眼环。通常在云雾森林和小树森林中活动。","appearance":"纹颊林鹑体长约26至28厘米，雄鸟体重约311克，雌鸟约324克。头部为棕色，带有裸露的红色眼圈和下方的黑色条纹。冠羽和头顶为栗色，边缘呈淡黄色。背部和臀部为棕色，带有黑色的虫蚀状花纹。喉咙为淡黄色，饰有白色条纹，胸部和腹部为棕色，点缀以白色钻石形斑点。雌鸟外观相似，但上体颜色更浅，下体更多呈现赤褐色。","call":"其鸣唱为快速重复的“whydlyi-i, whydlyi-i....”，由一对中的两个个体合唱，同时还有较粗犷、更急促的报警叫声以及可能是接触信号的弹跳式啾啾声。","habits":"该物种生活在海拔1000至3300米的山地亚热带森林中，常见有树蕨、竹子和寄生植物，偶尔下降至800米。它们偏好浓密的森林、矮化云雾林、年轻的次生林、开阔地带和沼泽草地，尤其是沟壑环境。","breeding":"关于纹颊林鹑的繁殖生态知之甚少。在玻利维亚，五月时有规律地听到其歌声。卵的尺寸约为38毫米×26.8毫米。","identification":"纹颊林鹑与其他鸟类的区别在于其独特的黑眼罩和红色头冠，以及胸部和腹部的白色钻石形斑点。","protection":"IUCN：LC（无危）。尽管总体数量可能不足50,000只，且可能正在减少，但全球并不认为受到威胁。其分布范围有限，面临森林砍伐、城市化和农业扩张的潜在威胁。","distribution":"繁殖区域主要集中在南美洲安第斯山脉的东坡，包括秘鲁东南部（库斯科和普诺省）和玻利维亚西北部（拉巴斯和科恰班巴省）。"},{"name":"黄眼斑林鹑","english_name":"Starred Wood Quail","scientific_name":"Odontophorus stellatus","overview":"黄眼斑林鹑（英文名：Starred Wood Quail，学名：Odontophorus stellatus），是鸡形目齿鹑科林鹑属的鸟类。其特征为拥有一个明显的红褐色至棕黑色的冠羽，头部和颈部为灰褐色，最显著的是黄色的眼环，有时上眉纹带有白色斑点。","appearance":"成年雄性黄眼斑林鹑体长约24-28厘米，重约358克；雌鸟稍小，约28厘米，重约315克。雄鸟的大型冠羽呈红栗色，雌鸟的为较暗的棕色或棕黑色。整体颜色为棕色至红褐色，背部棕色至红褐色，臀部渐变为浅黄色，饰有细密的黑色波状条纹；肩羽有黑色斑点和白色羽轴；上翼覆羽尖端为白色。胸部为红栗色，但中间部分颜色较淡；胸部两侧有稀疏的白色钻石状斑点，如同泪滴。喙和腿为黑色。雌鸟与雄鸟相似，但冠羽颜色更深。幼鸟与成鸟类似，但喙为橙红色至黄色，年轻的雄鸟有红褐色的冠羽。","call":"黄眼斑林鹑的鸣叫声为缓慢而略带滚动的'korkorralo'系列连续低沉的鸣唱，通常在清晨、傍晚或雨后反复发出，其叫声在第二音节末尾带有颤音。此外，还有快速、略带口吃的冒泡式颤音作为警报声，以及幼鸟发出的尖锐、快节奏和高音调的笛声。","habits":"生活在低地热带森林，包括硬木林、过渡林和泛洪平原森林，一般在海拔400米以下，局部可达1050米。它们通常是定居的，以小型群体（5-8只）的形式在森林地面活动，通过扒开枯叶寻找昆虫和浆果。黄昏时分，它们会穿越开阔地带，保持紧密队形接近浓密的掩护。","breeding":"关于繁殖的信息非常有限，已知它们会在地面建造典型的Odontophorus巢，形状为穹顶状结构，带有小入口孔，蛋为白色。在秘鲁东南部，幼鸟曾在11月和2月被发现，刚出生的雏鸟羽毛主要为深色，头部两侧有宽阔的淡黄色条纹，面部颜色相似；喙为橙红色。","identification":"在大部分分布范围内，黄眼斑林鹑是唯一的Odontophorus种类，仅与云斑林鹑和棕胸林鹑有边缘重叠。前者具有更广泛的红褐色眼周皮肤，整体颜色为暗褐色，外观少有冠羽，而后者可能只在较高海拔出现，有黑色的脸部和喉咙，冠羽较短。","protection":"IUCN：LC（无危）","distribution":"分布于亚马逊河流域的东部厄瓜多尔、东部秘鲁、巴西西部以及玻利维亚北部和东北部。"},{"name":"点斑林鹑","english_name":"Spotted Wood Quail","scientific_name":"Odontophorus guttatus","overview":"点斑林鹑（英文名：Spotted Wood Quail，学名：Odontophorus guttatus），是鸡形目齿鹑科林鹑属的鸟类。偏好湿润热带森林内部环境。","appearance":"体长23至28厘米，平均体重雄鸟约314克，雌鸟约294克。两性相似，具竖立的橙色或红褐色冠羽，黑色喉咙带白色条纹，胸部和腹部为棕色，饰以白色圆点或泪滴状斑点。背部和臀部呈深棕色，带有白色羽轴和黑色、黄褐色斑点。喙和腿呈暗绿色或黑色。幼鸟具有锈红色冠羽，喉咙呈灰白色斑驳，侧腹和胸部有黑色条纹。","call":"早晨和傍晚时分，会发出一系列快速而清晰的哨声，如‘whipa, whipee-o’，通常在群中二重奏。此外，还有快速颤音在警报时，以及群成员间联系的下降式啾啾声和尖叫声。","habits":"在热带和亚热带山地森林的500至3000米高度活动，偶尔降至100米，如在哥斯达黎加。偏好森林底层的浓密下层植被和竹林丛。可能在墨西哥进行局部迁徙，但在哥斯达黎加可能会进行海拔迁移。以小球茎、根茎、大坚果肉和昆虫为食。","breeding":"可能在5月至6月于墨西哥尤卡坦州筑巢，哥斯达黎加和巴拿马发现有幼鸟。巢建于地面，蛋为奶油白色，有时带有棕色斑点。繁殖期间，雄鸟会在求偶展示中竖起其扇形的冠羽。","identification":"是中美地区唯一有明显白点的Odontophorus属物种，与体型更小、更易见的歌鹑形成对比。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥南部至尤卡坦半岛，以及伯利兹、危地马拉、洪都拉斯西部和中部至尼加拉瓜相邻地区；在哥斯达黎加和巴拿马西部也有零星分布。","other":"尽管处于孤立的小群体中，但点斑林鹑似乎比同属的其他物种更能抵御栖息地破坏和碎片化的影响。"},{"name":"歌鹑","english_name":"Singing Quail","scientific_name":"Dactylortyx thoracicus","overview":"歌鹑（英文名：Singing Quail，学名：Dactylortyx thoracicus），是鸡形目齿鹑科歌鹑属的鸟类。是歌鹑属的唯一成员，拥有11个亚种。分布于中美洲，包括墨西哥中部至洪都拉斯，以及中美地峡的北端。其体长20至23厘米，雄鸟体重180至266克，雌鸟115至206克。","appearance":"雄鸟具有深棕色头部，灰身配以橙色面颊，眼后有黑色条纹，背部与翅膀呈斑驳的灰色和棕色，腹部灰褐色带白色条纹。雌鸟颜色相反，灰脸白喉，胸部和侧面淡棕色。幼鸟类似雌鸟，但腹部有黑色斑点。亚种间存在颜色和体型差异，山区个体较大，低地个体较小且颜色较浅。","call":"发出响亮、远传、节奏感强的鸣唱，开始是一系列犹豫、哀怨的哨音，随后频率和音调上升，形成快速连贯的旋律，中间音最高，类似'pitch-will-weeler, tser-tee-lur'，有时会由一群鸟异步合唱。","habits":"居住于森林地面，偏好有稀疏灌木层的森林，包括次生林、老树边缘、砍伐区域和咖啡种植园。以小球茎、种子（如马利筋）、昆虫（如蜈蚣、蟋蟀）为食，偶食咖啡豆。通常成群3至5只觅食，最多可达12只。","breeding":"繁殖季节从2月持续到10月，巢中发现5枚蛋，平均尺寸29至31×23.5至25毫米，乳白色带有黄色斑点。幼雏在7月至8月被观察到。","identification":"与Odontophorus属物种和Rhyncortyx cinctus有明显的区别，可通过颜色、体型和栖息环境识别。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，包括墨西哥中部至洪都拉斯，以及中美地峡的北端，具体见墨西哥、伯利兹、萨尔瓦多、危地马拉、洪都拉斯。","other":"虽然面临森林砍伐、可能的狩猎和森林放牧威胁，但歌鹑似乎比中南美洲的其他鹌鹑更能够抵御栖息地破坏和碎片化。"},{"name":"彩鹑","english_name":"Montezuma Quail","scientific_name":"Cyrtonyx montezumae","overview":"彩鹑（英文名：Montezuma Quail，学名：Cyrtonyx montezumae），是鸡形目齿鹑科彩鹑属的鸟类。分布于美国西南部至墨西哥的隐秘而罕见，别称包括哈勒昆鹑、愚鹑、疯狂鹑、马塞纳鹑、斑鹑、黑鹑和梅恩斯鹑。雄鸟具有鲜明的黑白脸部图案，雌鸟则以棕色为主，头部圆润，羽冠下垂。其分布区域主要集中在山地草木混合的环境中。","appearance":"彩鹑体型中等，陆栖，体长约20.5至23厘米，雄鸟平均重约195克，雌鸟约176克。体形丰满，蹲伏状，颈短，尾部极短且柔软，几乎与尾覆羽齐平。雄鸟脸部有引人注目的黑白相间图案，两颊黑色，喉部白色，下颌至颈带有一横贯的白色颈环；侧腹至尾下覆羽深栗色，逐渐变为黑色。雌鸟面部图案较淡，整体呈棕色，下体颜色类似冬季橡树叶子的颜色，带有白色条纹和细小的黑色斑点。两性均有蓝灰色的脚，爪较长。","call":"雄鸟的叫声是一连串六至九个音符，音调下降，远传且颤音，类似于嘶鸣。配对时的鸣唱声音独特，有一种神秘、忧郁的低沉哨声，开始高音，然后逐渐降低，类似昆虫的嗡嗡声。通常从地面发出，不同于其他种类的鹑鸟。","habits":"彩鹑生活在山地的开阔林地，尤其是橡树林区，有时也会出现在松林、杜松林、溪流走廊、沙漠高地以及偶尔的高山松林。它们主要在地面觅食，通过挖掘土壤寻找种子、草根、橡子、昆虫、球茎、根和块茎。彩鹑全年以成对形式活动，秋季和冬季会与幼鸟组成小群体，很少见到大规模的群体。","breeding":"彩鹑的繁殖期始于夏季雨季，即7月至8月。雄鸟在2月或3月开始鸣唱，巢穴是一个草制的穹顶结构，只有一个入口，比大多数鹑鸟家族的巢更为复杂。每窝产卵约11枚，蛋壳颜色为白色。孵化期约为25天，由双亲共同承担。幼鸟出生后，雄鸟会协助抚养。","identification":"彩鹑与其他鹑鸟如山齿鹑的区别在于其独特的脸谱和体色。雄鸟的脸部图案、深栗色的胸部和白色的侧斑点是明显的识别特征。雌鸟则以其淡棕色的整体外观和细腻的黑色斑点区别于其他鹑鸟。与眼斑彩鹑相比，彩鹑在墨西哥南部的亚种具有更深的灰底色和更大的肉桂色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于北美和中美洲，具体包括美国西南部（亚利桑那州、新墨西哥州、得克萨斯州西部）和墨西哥中部至南部。","other":"彩鹑被分为四个亚种，其中两个在美国南部，与墨西哥的montezumae亚种相似；而另两个在墨西哥巴尔萨河以南，即sallei和rowleyi亚种，它们的雄鸟具有暗灰色侧腹和大的肉桂色斑点，部分鸟类学家认为这两个亚种应被视为独立物种，称为Salle’s Quail。"},{"name":"眼斑彩鹑","english_name":"Ocellated Quail","scientific_name":"Cyrtonyx ocellatus","appearance":"眼斑彩鹑体长约20.5至23厘米，雄鸟体重约218克，雌鸟约182克。雄鸟头部具有醒目的黑白拼接图案，冠部和颈背呈黄褐色至橄榄褐色，胸部中央为淡肉桂色，两侧有明显的灰底带肉桂色斑点。雌鸟颜色较为暗淡，以棕色为主，头部有类似雄鸟的图案，但以棕色和棕白色代替了黑色和白色。两者均有一簇蓬松的顶冠。","call":"眼斑彩鹑的鸣叫声尚未详细描述，但据说与蒙特祖玛彩鹑的鸣叫类似，雄鸟会发出单一的下降式嗡嗡哨音，而雌鸟则会发出一系列下降的短音。","habits":"眼斑彩鹑完全陆栖，栖息于灌木丛和开阔的松树与橡树林，海拔高度一般在750至3050米之间。它们通过脚挖掘寻找根茎和块茎作为食物，繁殖季节还会捕食多种昆虫。","breeding":"关于眼斑彩鹑的繁殖生态知之甚少。在危地马拉，已知其繁殖期大约在4月至8月之间，但巢穴和蛋的详细描述尚未报道。","identification":"雄性眼斑彩鹑与蒙特祖玛彩鹑的区别在于前者胸侧的白点较少，胸部中央更偏橙色，后侧斑点较深，背部有肉桂色条纹。雌性眼斑彩鹑与蒙特祖玛雌鸟相似，但色彩更为暗淡。","protection":"IUCN：VU（易危）","distribution":"眼斑彩鹑分布于中美洲，具体包括墨西哥南部至尼加拉瓜，主要栖息于墨西哥西南部至尼加拉瓜的松栎林和灌木丛中。","other":"眼斑彩鹑数量估计不足10,000只，近年来因农业用地需求增加、危地马拉的矿业开采和狩猎压力加大，其种群正经历快速减少。"},{"name":"茶脸鹑","english_name":"Tawny-faced Quail","scientific_name":"Rhynchortyx cinctus","overview":"茶脸鹑（英文名：Tawny-faced Quail，学名：Rhynchortyx cinctus），是鸡形目齿鹑科茶脸鹑属的鸟类。分布于中美洲洪都拉斯至南美洲厄瓜多尔的低地热带森林，海拔可达约1,450米。其最显著的特征为雄鸟拥有橙色脸部和灰色胸部，而雌鸟则有淡色眼纹和鳞状腹部，体型比木鹑小。","appearance":"茶脸鹑体长17至20厘米，体重约150至165克。头部前额、侧面及颊部呈赤褐色；眼睛有黑色条纹延伸至颈侧。全身灰褐相间，雄鸟具有亮橙色脸部和灰色胸部，背部和臀部由灰至棕，具黑色条纹；雌鸟总体较暗，头部和颈部为深棕色，背部和上胸为棕色，臀部有斑点。雏鸟颜色更深，上部主为巧克力棕色，有黑色眼纹。","call":"其叫声带有空洞、类似锡纳穆或鸽子的音质，通常开始一系列单调的哨声，随后是一系列高低音的哨声，持续约1秒，‘cooo’或‘toot’。黄昏时尤其爱鸣叫，夜间也会在近地面的栖息处唱歌。","habits":"茶脸鹑生活在低地热带森林，以啄食种子、蠕虫和昆虫为主。它们会在地面活动，但也选择在树木或灌木丛中较低的位置休息。","breeding":"繁殖季节至少在巴拿马的三月至四月，具体繁殖行为细节尚不完全清楚。雌鸟产白色蛋，尺寸约为29.6-30毫米×23.5-23.8毫米。刚孵化的雏鸟上部主要为巧克力棕色，眼纹、喉部、颊部及冠侧为淡肉桂色，下部为淡褐色。","identification":"与木鹑相比体型更小，雄鸟具有独特的橙色脸部和灰色胸部，而雌鸟则有淡色眼纹和鳞状腹部，易于区分。","protection":"IUCN：NT（近危）","distribution":"分布于中美洲的洪都拉斯至南美洲的厄瓜多尔，包括哥伦比亚、哥斯达黎加、厄瓜多尔、尼加拉瓜和巴拿马。","other":"茶脸鹑共有三个亚种，分别为指名亚种R. c. cinctus、R. c. pudibundus和R. c. australis，它们在毛色色调上有细微差异。"},{"name":"火鸡","english_name":"Wild Turkey","scientific_name":"Meleagris gallopavo","overview":"火鸡（英文名：Wild Turkey，学名：Meleagris gallopavo），是鸡形目雉科火鸡属的鸟类。是现存的两种火鸡之一，也是Galliformes目中最重的成员。家养火鸡的祖先，家养火鸡最初源自墨西哥南部的一种野火鸡亚种。火鸡广泛分布于北美洲，从加拿大南部至美国48个州和夏威夷，再到墨西哥北部的Sierra Madre Occidental山脉。","appearance":"成年雄性火鸡体重在5到11公斤之间，体长100-125厘米。成年雌性火鸡通常较小，体重在2.5至5.4公斤之间，体长76至95厘米。雄性火鸡具有较大的羽毛区，呈现出红、紫、绿、铜、青铜和金色的虹彩光泽。雌性火鸡的羽毛则较暗淡，多为棕色和灰色调。雄性火鸡拥有一个长而暗色的扇形尾巴和闪亮的青铜色翅膀。雄性火鸡平均重量约为7.6公斤，雌鸟平均重量为4.26公斤。","call":"火鸡的鸣叫声多样，包括集合叫声、咕噜声、简单的叫声、呼噜声、咔哒声、兴奋的叫声、飞行降落时的咔嚓声、树上的叫声、kee kee跑声和扑腾声。早春时节，一年以上的雄性火鸡会发出咕噜声，宣布其存在给雌鸟和竞争的雄鸟。","habits":"火鸡偏好硬木和混合针叶林-硬木森林，带有散落的开阔地带，如牧场、田地、果园和季节性沼泽。它们适应各种密集的本土植物社区，条件是覆盖和开阔地带广泛可用。火鸡主要在清晨和傍晚觅食，它们是杂食性的，主要吃橡子、坚果、种子、浆果、芽、叶子、蕨类植物、根和昆虫。偶尔也会食用两栖动物和小型爬行动物。","breeding":"雄性火鸡是多配偶制，与尽可能多的雌鸟交配。雄性火鸡通过膨胀羽毛、展开尾巴并拖曳翅膀的方式向雌鸟展示，这种行为被称为展翅炫耀。春季，雄性火鸡聚集在空旷地带进行求偶展示。雌性火鸡会在筑巢季节寻找巢址，巢位于地面，被树木植被包围。雌鸟产下10-14枚卵，每天产一枚，孵化期至少28天。幼鸟在出生后大约12-24小时内就能离开巢穴。","identification":"雄性火鸡与雌性火鸡在外观上有显著差异，雄鸟更大，羽毛有金属光泽，雌鸟羽毛较为暗淡。雄性火鸡有长而黑暗的扇形尾巴和闪亮的青铜色翅膀，雌性火鸡没有这样的特征。雄性火鸡头部和颈部的皮肤颜色可以随着情绪的变化而改变，从红色变为白色。","protection":"IUCN：LC（无危）","distribution":"火鸡分布于北美的大部分地区，从加拿大南部至美国48个州和夏威夷，再到墨西哥北部的Sierra Madre Occidental山脉。在繁殖区域内，它们常见于东部和四个西部和墨西哥的亚种。","other":"火鸡有六种公认的亚种，两种在东部，四种在西部和墨西哥。火鸡通过陷阱转移的方式得以在其原生范围内重新建立，超过20万只火鸡已被引入美国本土48个州、夏威夷、加拿大南部和墨西哥北部。"},{"name":"眼斑火鸡","english_name":"Ocellated Turkey","scientific_name":"Meleagris ocellata","overview":"眼斑火鸡（英文名：Ocellated Turkey，学名：Meleagris ocellata），是鸡形目雉科火鸡属的鸟类。又名: 七面鸟或吐绶鸡，羽毛色彩斑斓，呈现绿色、蓝色、金色、黑色和青铜色。主要分布在墨西哥东南部的尤卡坦半岛、危地马拉的佩滕地区和伯利兹北部。在当地有多种称呼，如pavo、pavo ocelado、pavo del monte、pavo real和玛雅语中的ucutz il chican。","appearance":"眼斑火鸡是一种色彩绚丽的鸡形目鸟类，拥有蓝绿色和青铜色的虹彩羽毛，头部裸露呈粉蓝色，点缀着橙红色肉质突起。雄鸟具有独特的冠状突起，繁殖季节时会膨胀变大。腿部深红色，雄鸟还长有长达5厘米的锐利距刺。翅膀覆羽青铜色，尾羽末端带有独特的眼状图案，由蓝黑包围的金色尖端构成。雌雄差异不如北美野生火鸡明显，但雌鸟的羽毛色泽较为暗淡。","call":"雄性眼斑火鸡的鸣叫开始于一系列低频的'咚咚'声，类似于小型汽油引擎启动的声音，随着节奏加快，发出典型的鸣叫声。母鸟的鸣叫与北美亲戚类似。","habits":"它们通常生活在地面，但在夜间会到树上休息以躲避夜行性捕食者。食性广泛，包括昆虫、草籽、坚果和树叶。繁殖季节前，成年雄鸟会组成不超过三只的小群，而由幼鸟和雌鸟组成的群体可能多达八只以上。雄鸟在繁殖季会展开华丽的求偶舞蹈，通过脚拍打地面、摇晃尾羽和振动翅膀吸引雌鸟。","breeding":"繁殖季始于二月初，三月达到高峰，四月末结束。雄鸟通过复杂的求偶展示吸引雌鸟，包括拍打地面、摇摆尾羽和拖拽翅膀。孵化期为28天，雌鸟每次产卵8至15枚。雏鸟出生后很快就能跟随母亲，直到它们进入年轻成年期。","identification":"与北美野生火鸡相比，眼斑火鸡的羽毛更为明亮，更偏向蓝绿色，具有蓝色垂肉，且没有胡须。雄鸟尾羽上的大次端蓝色斑点（'ocelli'）是其特有的特征。","protection":"IUCN：NT（近危）","distribution":"眼斑火鸡主要分布在中美洲的墨西哥东南部（包括尤卡坦半岛）、伯利兹和危地马拉的北部和西部地区。","other":"眼斑火鸡曾被墨西哥当局视为濒危物种，近年来由于土地利用变化和过度猎杀，种群数量有所下降。"},{"name":"披肩榛鸡","english_name":"Ruffed Grouse","scientific_name":"Bonasa umbellus","overview":"披肩榛鸡（英文名：Ruffed Grouse，学名：Bonasa umbellus），是鸡形目雉科榛鸡属的鸟类。具有独特的羽色变化，从冷灰色到红棕色，以适应不同环境。在北至加拿大和阿拉斯加，南至乔治亚州的森林地带均有分布，特别是在杨树和白桦树茂密的早期演替森林中最为常见。","appearance":"披肩榛鸡体型中等，体重约450-750克，体长40-50厘米，翼展可达50-64厘米。拥有两种主要的羽色形态：灰相和红相。头部、颈部和背部通常呈灰棕色，胸部有明显的条纹，腹部白色较多。尾巴为同样的棕灰色，具规律的条纹和靠近末端的宽黑带。雄鸟和雌鸟都有颈部两侧的羽毛形成的披肩，头部有小而尖的顶冠。雌鸟尾巴的黑色次端带可能断开，雄鸟的则通常完整。雄鸟在展示时会竖起颈部的羽毛形成披肩。","call":"雄鸟在春季会通过快速拍打翅膀产生特有的低音鼓声，用于吸引雌鸟和警告其他雄鸟。","habits":"栖息于混合林区，尤其偏好有杨树的森林。它们主要在地面或树上觅食，以树叶、芽、果实、种子和昆虫为食。冬季，它们会在雪下挖掘洞穴以保暖。","breeding":"繁殖季节，雄鸟会通过“鼓点”展示来吸引雌鸟。它们在地面上筑巢，雌鸟独自孵化，每窝产卵数约为10个左右。孵化期约为23天。","identification":"与枞树镰翅鸡相比，披肩榛鸡的下部有更丰富的白色，尾巴上有明显的黑色次端带。雄鸟在展示时会展开颈部的披肩。","protection":"IUCN：LC（无危）","distribution":"分布于北美，包括美国北部、加拿大和阿拉斯加。","other":"披肩榛鸡是宾夕法尼亚州的州鸟。"},{"name":"花尾榛鸡","english_name":"Hazel Grouse","scientific_name":"Tetrastes bonasia","overview":"花尾榛鸡（英文名：Hazel Grouse，学名：Tetrastes bonasia），是鸡形目雉科花尾榛鸡属的鸟类。是最小的松鸡科成员之一，体型类似鸽子。分布广泛，从东欧至西伯利亚东部乃至日本北海道，栖息于茂密湿润的混合针叶林，偏好云杉环境。雄鸟喉部和尾端黑色，雌鸟喉部斑驳棕白色，羽冠较短。分布于欧亚大陆北部，是中国东北地区的特有种类。","appearance":"小型榛鸡，体长35-40厘米，体重305-430克（雄鸟）和307-422克（雌鸟）。雄鸟头部有小型竖立的羽冠，喉部和尾端黑色，下体暗棕色夹杂白色斑点。雌鸟羽冠较短，喉部为斑驳的白色。下体具暗灰色和赭色斑纹，尾部相对较长且圆，边缘白色，带有黑色次端带，中央尾羽全褐色。幼鸟与成鸟相似，但初级飞羽外侧有更多横斑。","call":"雄鸟发出高音调的‘ti-ti-ti-ti-ti’叫声，雌鸟则发出清脆的‘tettettettettet’声。飞行时翅膀的振动也会产生特有的声音。","habits":"栖息于混合针叶林，偏好云杉林，活动范围从低山丘陵到1800米的山地。冬季多在落叶桦树林和河流两岸的乔木林活动，夏季则在更开放的年轻林区。以猫柳、桦树、白桦等植物的猫耳和嫩枝为食，春季逐渐转为树叶和地面植被。幼鸟出生后十天内主要食用昆虫。形成混合性别群体，尤其是在食物稀缺的冬季。","breeding":"繁殖期为4月下旬至5月初，雌鸟单独筑巢，产卵7-14枚，孵化期21-25天。雏鸟孵化几天后即可跟随母鸟觅食，约3个月后达到成鸟阶段。","identification":"与镰翅鸡区分，后者无羽冠，下颌无白色边框，肩部无白色条纹，下体无白色底纹，且尾部特征不同。","protection":"IUCN：LC（无危）。在中国和部分中欧、北欧国家的红色名录中。近年来在西欧和中欧部分地区数量显著下降。","distribution":"分布于欧亚大陆的西北部、中北部和东北部，包括中国东北、俄罗斯、日本北海道等地。","other":"花尾榛鸡在东北地区被视为美味佳肴，自清朝起就被列为岁贡鸟。由于森林砍伐和过度狩猎，其数量大幅减少，已成为中国国家二级保护动物。"},{"name":"斑尾榛鸡","english_name":"Chinese Grouse","scientific_name":"Tetrastes sewerzowi","overview":"斑尾榛鸡（英文名：Chinese Grouse，学名：Tetrastes sewerzowi），是鸡形目雉科花尾榛鸡属的鸟类。又称: 羊角鸡，为中国特有种，仅分布于中国中部的甘肃、青海、四川等地。山地森林中的土著，是其分布范围内唯一的榛鸡种类。体型健壮，具顶冠，全身呈棕色，腹部花纹密集，雄鸟喉部有黑边白线，雌鸟喉部棕色。分布于高山森林地带。","appearance":"斑尾榛鸡为小型榛鸡，体长33-40厘米，雄鸟体重279-390克，雌鸟体重270-407克。雄鸟冬季体重最高，而雌鸟则相反。雄鸟上体宽幅黑纹，上胸栗色，尾羽具独特条纹。雌鸟色彩较为暗淡，喉部黑色被白色边缘羽毛遮掩，下体更显土黄色，黑纹不那么强烈。虹膜深褐色，喙黑色，脚灰黑色。幼鸟羽衣详情未知。次级种群secunda比指名亚种更偏赤褐色。","call":"雄鸟在春季和秋季进行领地展示，通过拍打翅膀发出“噗噗”的声音，有时伴随从地面跳至1米高的动作，翅膀的声音产生低频的震撼效果。雄鸟间的争斗会发出嘶哑的‘恩恩恩恩…’声，分为颤音和尖叫两部分，有时结束时会有咯咯声。雌鸟在带领幼鸟时会发出‘泽泽泽-哒哒’的警告声。","habits":"栖息于海拔2400至4300米的高山针叶林和桦树林，春季食用柳树和桦树的花蕾和叶片，夏季偏好虎耳草的花序和果实，秋季则偏好山楂果实。冬季以沙棘果和柳树枝芽为主食。春季主要栖息于东北朝向的山坡，有高大的乔木和丰富的灌木。全年基本定居，雄鸟领地面积约为2.1公顷。","breeding":"繁殖期在5月末至6月中旬，一夫一妻制。雄鸟在冬季建立领地，3月形成配对，5月开始交配。巢建在树根下、树桩或岩石旁，由草构成，有时衬以松针和苔藓。每窝产卵5-8枚，平均6.19枚，孵化期25天，由雌鸟单独孵卵。幼鸟孵化后由雌鸟独自照顾，约2-3个月后独立。","identification":"与花尾榛鸡非常相似，但斑尾榛鸡的跗蹠羽毛较少，上体黑纹更宽，上胸更显栗色，尾羽条纹不同。雌鸟喉部黑色部分被白色边缘羽毛遮掩，下体颜色更显土黄色，黑纹不那么强烈。","protection":"IUCN：NT（近危）","distribution":"分布于中国中部，从甘肃中部到青海南部，西藏东部，云南西北部和四川北部。在甘肃连花山自然保护区密度可达15个领地/平方公里。","other":"斑尾榛鸡在中国法律中列为濒危物种，其栖息地遭受森林砍伐和破碎化威胁，导致种群数量下降。目前，中国正在采取措施减少森林砍伐，以保护该物种。"},{"name":"镰翅鸡","english_name":"Siberian Grouse","scientific_name":"Falcipennis falcipennis","overview":"镰翅鸡（英文名：Siberian Grouse，学名：Falcipennis falcipennis），是鸡形目雉科镰翅鸡属的鸟类。中型、体态丰满的森林栖息鸟类。其独特的外观特征包括雄鸟的黑色喉部，周围环绕着白色的边缘，以及眼上方醒目的红色裸皮。雌鸟则为棕色，头部更为圆润。分布于远东俄罗斯的湿润、阴凉的针叶林中，以云杉、冷杉、落叶松为主，偶尔在中国东北黑龙江下游及小兴安岭东北侧有记录。","appearance":"镰翅鸡体型中等偏大，长约38至43厘米，雄鸟体重介于580至735克之间，雌鸟体重在650至740克左右。雄鸟通体暗褐色，腹部点缀白色斑点，颈部有黑色项圈，边缘以白色勾勒，眼上方有一片鲜红色皮肤。雌鸟色调较淡，为斑驳的棕色，缺乏雄鸟面部的鲜明标记。幼鸟与成年雄鸟相似，但背部有褐色斑点，羽轴呈淡赭色条纹；雌鸟幼鸟则类似成年雌鸟，但色彩更鲜艳，条纹更细碎。","call":"雄鸟的求偶展示类似于松鸡，先是扇动尾巴，伸直身体，发出拉长的呼噜声，随后跳入空中，同时发出咔哒声。雌鸟在求偶场地上会发出低沉的警报声，并可能进行鼓翼飞行。","habits":"镰翅鸡栖息于阴湿的针叶林，如云杉、冷杉、落叶松和红松林中，偏好有浓密灌木层和浆果丰富的环境。它们是留鸟，不做迁徙，但在季节变换时会进行有限的垂直移动。夏季和秋季，饮食转向浆果和叶子，冬季则主要以针叶树的嫩枝为食。它们通常单独或小群体活动，群体可达十只左右。","breeding":"繁殖期自4月下旬至7月，雄鸟通过展示和鸣叫吸引雌鸟。雌鸟在灌木丛中筑巢，产卵6至12枚，卵呈锈褐色，带有深色锈斑。孵化期约23至24天，由雌鸟独自承担。雏鸟孵化后不久即可跟随母鸟活动。","identification":"与枞树镰翅鸡的区别在于，镰翅鸡的下体有黑白条纹，外侧初级飞羽窄而尖，且分布范围完全不重叠。雌鸟相比雄鸟颜色更浅，头部有更明显的棕褐色调。","protection":"IUCN：NT（近危）","distribution":"主要分布于远东俄罗斯，包括滨海边疆区、哈巴罗夫斯克边疆区、阿穆尔州和萨哈林岛。历史上在中国东北有少量记录，但目前在中国已难觅踪迹。","other":"近年来，由于森林砍伐、过度狩猎和森林火灾的影响，镰翅鸡的数量在持续减少。"},{"name":"枞树镰翅鸡","english_name":"Spruce Grouse","scientific_name":"Canachites canadensis","overview":"枞树镰翅鸡（英文名：Spruce Grouse，学名：Canachites canadensis），是鸡形目雉科 Canachites 属的鸟类。中型的雉科鸟类，与北美的针叶林或泰加林紧密相关。该物种仅由属内的单一成员组成，是北美最树栖的镰翅鸡之一，适应在树上活动。在面对威胁时，依赖于其伪装和不动的能力，即使人类接近至数英尺之内才飞走。","appearance":"成年枞树镰翅鸡体长38-43厘米，翼展54.5-57.5厘米，雄鸟体重550-650克，雌鸟450-550克。雄鸟上身主要呈灰色，下身黑色，侧边有白色斑点，眼上有红色裸皮组成的\"眉梳\"。雌鸟为红褐色或灰色斑驳，下身有深色和白色的条纹。幼鸟外观似雌鸟。雄鸟\"富兰克林\"亚种的胸部较暗，没有白色的条纹。","call":"枞树镰翅鸡相对沉默，但有用于警告、领地防卫、维持雏鸟群聚或吸引配偶的几种叫声。雄鸟\"富兰克林\"亚种以翅膀拍击显示领地，发出两声间隔约0.5秒的响亮拍击声。","habits":"栖息于针叶林，偏好年轻林区，夏季靠近浆果和其他灌木丰富的下层植被，冬季则偏好密集的林地。它们主要在地面行走或沿树枝移动，而非飞行。在秋季会长出\"雪鞋\"，帮助在雪地上行走和抓握树枝。","breeding":"雄鸟建立领地吸引雌鸟，雌鸟单独负责筑巢和孵卵。巢位于低矮的松枝或倒下的树木附近，由草、树叶和羽毛构成。每年5月初至7月初为繁殖季节，每次产卵4-7枚，孵化期约为24天。雏鸟出生后不久即可离开巢穴，随雌鸟一起，直到3-5周大。","identification":"与杨梅镰翅鸡相比，枞树镰翅鸡较小，雌鸟有明显的水平条纹，雄鸟没有白边颈部裸皮。\"富兰克林\"亚种的雄鸟缺乏\"加拿大\"亚种的赤褐色尾尖，而\"富兰克林\"亚种的上尾覆羽有白色尖端。","protection":"IUCN：LC（无危）","distribution":"分布于加拿大全境、美国阿拉斯加州、新英格兰北部、纽约州阿迪朗达克山脉、密歇根州北部、明尼苏达州东北部、威斯康星州北部，以及蒙大拿州、爱达荷州、缅因州、俄勒冈州和华盛顿州的山区针叶林。","other":"在一些地区，如纽约州和佛蒙特州，被列为濒危物种，而在威斯康星州则被视为极度濒危。"},{"name":"西方松鸡","english_name":"Western Capercaillie","scientific_name":"Tetrao urogallus","overview":"西方松鸡（英文名：Western Capercaillie，学名：Tetrao urogallus），是鸡形目雉科松鸡属的鸟类。雄鸟大小为雌鸟的近两倍，显示了极端的雌雄异型性。西方松鸡广泛分布在欧洲和帕莱阿尔泰地区的成熟针叶林中，以它独特的求偶展示而闻名。该物种全球数量被列为\"无危\"等级，尽管中欧地区的种群正在减少且碎片化。","appearance":"雄性西方松鸡体型庞大，长度通常在74至85厘米之间，翼展可达90至125厘米，平均体重约4.1千克。雌鸟明显较小，长度约为54至64厘米，体重在1.5至2.5千克之间。雄鸟体羽呈深灰到深棕色，胸部羽毛为暗金属绿色，腹部和尾下覆羽的颜色因亚种而异，从黑色到白色。雌鸟上体羽毛为棕色，带有黑色和银色条纹，下体颜色较浅，呈黄褐色。两性均具有白色的翼斑，脚部羽毛茂密，尤其在冬季，用于保暖。","call":"雄性西方松鸡发出复杂的鸣叫声，包括低强度的\"敲击声\"阶段，随后是快速点击音的\"鼓点\"阶段，最后是类似猪的尖叫，整个表演持续约5.5秒，频率可达每分钟7-8次。","habits":"西方松鸡主要栖息于成熟的针叶林，偏好阴凉潮湿的环境，如沼泽和泥炭地附近的林地。它们以松树针叶为主食，特别是在冬季，同时也会食用各种植物的针叶、叶子、果实、昆虫、草类等。春季，雄鸟会在黎明时分在开阔地带进行求偶展示。夏季，松鸡倾向于在密集的森林中活动，以躲避炎热天气。","breeding":"繁殖季节从三月持续至六月。雄鸟在清晨开始在树枝上展示求偶行为，雌鸟在四月至六月间产卵，每窝产卵量平均为8枚，但可多达12枚，孵化期约为26至28天。雏鸟出生后不久就能跟随母亲觅食，主要以昆虫为食。","identification":"西方松鸡与黑琴鸡相比，雌性西方松鸡胸部有明显的锈色斑块，尾巴更长、更圆，且比黑琴鸡的雌鸟大。雄性西方松鸡的黑色头部和颈部与黑琴鸡也有显著差异。","protection":"IUCN：LC（无危）","distribution":"西方松鸡广泛分布于欧洲北部和中部的针叶林中，包括挪威、瑞典、芬兰、俄罗斯和罗马尼亚等地。在英国、德国的部分地区和西班牙西北部的坎塔布连山脉，种群数量已大幅下降或面临威胁。","other":"西方松鸡在苏格兰曾一度灭绝，但在1836年至1837年间成功进行了重新引入。"},{"name":"黑嘴松鸡","english_name":"Black-billed Capercaillie","scientific_name":"Tetrao urogalloides","overview":"黑嘴松鸡（英文名：Black-billed Capercaillie，学名：Tetrao urogalloides），是鸡形目雉科松鸡属的鸟类。大型雉科鸟类，主要栖息于东北泰加林的落叶松、冷杉、云杉、樟子松和红松等针叶林的林中空地、林缘和河谷地带，尤其是林下植被丰富的区域。该物种在东亚北部广泛分布。","appearance":"雄性黑嘴松鸡体长89–97厘米，体重3350–4580克，具有光泽的黑色头部和胸部，白色斑点装饰的棕色翅膀，以及眼上方醒目的红色条纹。雌鸟较小，体长69–75厘米，体重1700–2200克，头部和颈部呈棕色，身体有黑色条纹。雄鸟的脖子向上伸展，黑色尾巴宽大上翘，雌鸟羽毛较灰，胸前条纹更重，翼覆羽和次级飞羽上的白色标记较大。","call":"雄性黑嘴松鸡的求偶叫声为一系列节奏感强的咔嗒声，持续5–7秒（偶尔可达12秒），声音响亮，可传至0.5公里远，通常以“tack-tack-tack...”结尾，转为“tr-r-rack”。在激昂情境下，叫声变得不那么有节奏。","habits":"黑嘴松鸡主要栖息于泰加森林，偏好松树为主的环境，从平原到山区均有分布，适应较为开放的环境。它们在春季进行求偶展示，雄鸟通过扇尾、展胸、低头和张口来保卫领地。食物以松树芽、针叶、果实为主，春夏季节会食用浆果和叶子。","breeding":"繁殖期从3月至4月，雌鸟筑巢产卵，巢穴通常位于松树下，由松针、树皮、小树枝和羽毛构成。5至6月进入繁殖高峰期，孵化期约为20至25天。雏鸟出生后不久即可跟随母鸟觅食，约一个月后能飞到大树上栖息。","identification":"与西部的西方松鸡相比，黑嘴松鸡体型略小，喙部黑色，尾部更长且呈扁平状，头部和颈部颜色更深，翼部和尾部有显著的白色标记。","protection":"IUCN：LC（无危）。在中国，黑嘴松鸡的数量急剧下降，部分地区已濒临灭绝，主要原因是栖息地破坏和过度狩猎。大兴安岭的森林火灾严重威胁其生存。","distribution":"黑嘴松鸡分布于欧亚东北部，主要在中国东北的大兴安岭、小兴安岭和阿尔山等地。在俄罗斯的西伯利亚也有广泛分布。","other":"黑嘴松鸡在特定地区与西方松鸡存在杂交现象，显示出其对环境的适应性和灵活性。"},{"name":"黑琴鸡","english_name":"Black Grouse","scientific_name":"Lyrurus tetrix","overview":"黑琴鸡（英文名：Black Grouse，学名：Lyrurus tetrix），是鸡形目雉科琴鸡属的鸟类。别名: 黑野鸡，中等体型，身长约为55厘米。雄鸟通体黑色，带蓝绿色金属光泽，尾部呈叉状，外侧尾羽长且向外卷曲，形成独特的琴状。雌鸟则为黄褐色，饰有黑褐色斑点，尾羽亦呈叉状。广泛分布于欧亚大陆北部的森林和开放地带。","appearance":"雄性黑琴鸡约60厘米长，体重1100-1250克，最高可达2100克，外表漆黑，带有蓝色或绿色反光，与白色的腕部斑块、明显的翼条和下尾覆羽形成鲜明对比。尾部独特地呈现为琴状，外侧尾羽长且向外弯曲。头部和颈部在夏末至秋季时有棕色斑点或条纹，喉咙部分有少量白色。雌鸟主要为棕色，饰有黑色重条纹，比更暗，翼上有细长的白色翼条，尾部较短，闭合时略呈叉状。幼鸟与成鸟相似，但颜色较浅，尾羽曲线不那么明显。雄鸟达到完全成熟需三年，雌鸟则在两年。","call":"春季黎明时，雄鸟在公共的求偶场发出低沉的咕噜声，声音先以气泡般的颤音开始，逐渐增大，通常随后是两次双声的咕咕声，如“bububububrrru！..curr-curr..curr-curr”，连续重复，可达3.5公里之遥。雄鸟在不同情境下也会发出拉长的嘶嘶声，如‘khahweeee’或类似的声音。雌鸟则会发出短促、共鸣的‘kwuk..kwuk..kwuk…’声来安抚雏鸟，或在警告时发出低沉的‘krruagg’声。","habits":"黑琴鸡栖息在针叶林、针阔叶混交林或森林草原，海拔高度通常在600-900米，有时高达1500米。偏好落叶松林、樟子松林以及与白桦林、山杨林等组成的混交林。春季活动范围扩大，多在地面觅食。夏季在巢区附近的地面活动，有时也会上树，但活动范围较小。秋季离开繁殖区，结成不同数量的群体四处游荡。冬季，即使在零下40℃的严寒中，它们依然活跃在河畔和山谷间，利用黑色羽毛的吸热能力抵御寒冷。它们活动能力强，擅长地面奔跑和飞翔，但不能持久远飞。它们的警觉性低于松鸡，有时人类可以靠近。雄鸟在求偶时能发出一系列类似吹泡泡和拉风箱的美妙歌声。","breeding":"黑琴鸡的繁殖期在每年4月上旬至中旬，雄鸟眼上方的眉纹变为鲜艳的血红色，标志着发情期的开始。它们选择开阔地带作为求偶场，巢筑于林缘树下或灌木丛中，通常在地面凹处，内衬枯枝、树叶和羽毛。每窝产卵8-10枚，最多可达14枚，卵为淡赭色或褐色，具深褐色斑点。从筑巢到育雏，均由雌鸟独立完成。孵化期为24-29天。雏鸟出生后，如同黄褐色的绒毛球，半个月内仅能短距离飞翔，约一个月后能飞到大树上栖息。","identification":"黑琴鸡与柳雷鸟相比，后者体型较小，锈色更重，在飞行中展示的是实心的深色尾巴。与西方松鸡雌鸟相比，黑琴鸡雌鸟颜色更深，翼条更细，尾部更短。不同亚种在大小、雄鸟的光泽色彩和雌鸟的整体着色上存在差异。","protection":"IUCN：LC（无危）","distribution":"广泛分布在欧亚大陆北部，包括北欧、俄罗斯、中欧部分地区、东欧、亚洲中部和东北部，如中国、韩国等地。在中国，主要分布在北部地区。","other":"黑琴鸡的尾巴自维多利亚时代晚期以来，一直是苏格兰高地服饰帽子上的流行装饰品。"},{"name":"高加索黑琴鸡","english_name":"Caucasian Grouse","scientific_name":"Lyrurus mlokosiewiczi","appearance":"雄性高加索黑琴鸡体型较大，长度约50-55厘米，雌鸟略小，长约37-42厘米。雄鸟全身羽毛漆黑，肩部有一小块白色斑点，尾巴深曲向下，拥有醒目的红色‘眉毛’。雌鸟则为灰褐色，身上带有密集的黑色细条纹，尾巴接近方形末端。雌雄幼鸟外观相似，但上体更偏赤褐色，幼鸟有淡白色的翼带。成年雄鸟的黑色羽毛会在秋季首次出现，春季时基本达到成鸟特征，除了头部、颈部和翼盖羽毛仍保留一些棕褐色。","call":"雌鸟会发出兴奋的咯咯声。雄鸟在展示时，翅膀拍打产生的声音清晰可闻，尤其是在空中跳跃时露出白色的下翼面，同时在领地飞行中产生低频声音，金属音与高频翅膀拍打交替出现，跳跃频率在雌鸟到达时增加。","habits":"高加索黑琴鸡生活在高山森林与亚高山草甸之间的过渡地带，常在云杉、桦树林边和杜鹃花灌木丛中发现。夏季，它们主要出现在亚高山草甸，冬季则集中在森林较高处，海拔范围在1700-3300米之间，冬季会下降至700-1000米。食物包括桦树芽、金雀花果、杜鹃叶、冷杉针叶和越橘叶，昆虫和蜘蛛幼鸟时期为主要食物。","breeding":"繁殖期一般在五月，巢穴建在灌木丛中或岩石下，由草、叶子和羽毛铺垫。每窝通常产5-6枚淡奶油色带有棕色或红棕色斑点的蛋，孵化期约为20-25天。雏鸟在出生后10-14天能飞行，大约两个月后达到成鸟大小。性别比例在孵化时为1:1，雏鸟死亡率首月可能高达50%。","identification":"与黑琴鸡相比，高加索黑琴鸡的羽毛更显绿色黑色，翼带和下尾覆羽缺乏白色，尾部的‘琴键’较短，部分向下弯曲。雌鸟尾部几乎呈方形末端，上体条纹更窄，上体暗色标记更细且更规则。","protection":"IUCN：NT（近危）","distribution":"分布于俄罗斯远西南部山区向东至阿塞拜疆东北部，向南至土耳其东北部，亚美尼亚和伊朗远西北部。","other":"高加索黑琴鸡是世界上研究最少的琴鸡之一，近年来数量有所减少。"},{"name":"艾草松鸡","english_name":"Sage Grouse","scientific_name":"Centrocercus urophasianus","overview":"艾草松鸡（英文名：Sage Grouse，学名：Centrocercus urophasianus），是鸡形目雉科艾草松鸡属的鸟类。北美最大的松鸡，广泛分布于北美的西部和中部地区，包括加拿大和美国的多个省份与州。其显著特征包括长而尖的尾部，以及雄鸟成鸟展示时的大型白色胸部和黑色喉咙，腹部黑色，以及两个黄色可充气的颈部囊。","appearance":"艾草松鸡成鸟体型庞大，雄鸟体重可达3.2千克，尾部细长且尖锐，腿部羽毛延伸至脚趾。雄鸟头部上方有黄色斑点，背部呈灰色，胸部白色，喉咙深棕色，腹部黑色；颈部有两个黄色的可充气囊，求偶时会膨胀以吸引雌鸟。雌鸟背部和喉咙为杂色的棕灰色，腹部颜色较深。雏鸟背部颜色与雌鸟相似，腹部为白色。","call":"雄性艾草松鸡在求偶展示中发出低沉的咕噜声或爆裂声，通过胸部的空气囊制造出特有的声音。","habits":"艾草松鸡常居于三齿蒿生境，冬季可能移至海拔较低的地带。它们在地面觅食，主要以三齿蒿、昆虫和其他植物为食。它们无法消化较硬的种子，与同类中的其他物种有所不同。","breeding":"艾草松鸡在春季进行复杂的求偶仪式，雄鸟在求偶场上展示，雌鸟观察并选择最具吸引力的雄鸟交配。巢建于三齿蒿下或草堆上，雏鸟出生后即可行走，两周内能短距离飞行，五周后能远距离飞行。","identification":"艾草松鸡与Gunnison Sage-Grouse（Gunnison艾草松鸡）相比，体型更大，无栖息地重叠，且尾部更深色，头饰羽毛更细长。与蓝镰翅鸡和乌镰翅鸡相比，艾草松鸡尾部更尖，体型略大。","protection":"IUCN：NT（近危）艾草松鸡的数目由于栖地丧失而减少，尤其是在加拿大和美国的部分地区已经出现区域性灭绝。尽管整体上未被列入濒危，但各区域的种群可能面临严重威胁。","distribution":"艾草松鸡分布在北美，从加拿大中南部至美国中西部，包括美国的多个州和加拿大的艾伯塔省和沙士吉万省。","other":"艾草松鸡是Pomona-Pitzer Sagehens运动队的吉祥物，该队代表Pomona College和Pitzer College。"},{"name":"小艾草松鸡","english_name":"Gunnison Grouse","scientific_name":"Centrocercus minimus","overview":"小艾草松鸡（英文名：Gunnison Grouse，学名：Centrocercus minimus），是鸡形目雉科艾草松鸡属的鸟类。北美特有的雉科大型鸟类。其体型丰满，头部较小，尾巴较长，雄鸟羽毛以灰色为主调，带有精细的图案，腹部黑色，尾羽尖长。雄鸟具有白色胸部和黑色喉咙，展示时会展开尾羽，鼓起胸前的黄色气囊，发出液体般的爆裂声。与更广泛的艾草松鸡相比，体型小约三分之一，头后部的羽毛更为浓密。","appearance":"雄性小艾草松鸡体重1.7至2.4千克，雌鸟0.9至1.3千克。上体呈灰褐色，密集地带有灰白标记；尾羽长而尖，有白色条纹；初级飞羽棕色，翼下覆羽白色；腹部黑褐色，带有大的白色斑点；大腿淡黄色。头部有黄绿色肉质冠，颈部后方有长而细的丝状羽。雌鸟体型较小，颜色较为暗淡，缺乏雄鸟的可膨胀裸皮。","call":"雄鸟在求偶展示时会发出独特的'爆裂'声，通过快速摇动头部和翅膀，同时膨胀颈部的特殊口袋产生。","habits":"小艾草松鸡主要栖息于广阔的艾草灌丛地带，偏好潮湿的河岸区域。它们倾向于步行而非飞行，仅在受惊或威胁时才会飞翔。春季，雄鸟会在被称为'lek'的特定领地上进行炫耀表演，吸引雌鸟。","breeding":"繁殖季节从2月至4月，雄鸟在lek上展示，吸引雌鸟交配。雌鸟单独筑巢，每窝产卵6至8枚，孵化期25至27天。雏鸟孵化后即能自行觅食。","identification":"与艾草松鸡相比，小艾草松鸡体型更小，尾羽上的白色条纹更为明显，雄鸟颈部丝状羽更长更厚，展示时的叫声也不同。","protection":"IUCN：EN（濒危）","distribution":"小艾草松鸡的分布局限于北美的科罗拉多州西南部和犹他州东南部，曾经在亚利桑那州、新墨西哥州和俄克拉荷马州也有分布，但现在已在那里绝迹。","other":"小艾草松鸡的数量在不断下降，估计全球数量不足4,000只。自2014年12月22日起，被列为美国《濒危物种法》下的受威胁物种。"},{"name":"蓝镰翅鸡","english_name":"Dusky Grouse","scientific_name":"Dendragapus obscurus","overview":"蓝镰翅鸡（英文名：Dusky Grouse，学名：Dendragapus obscurus），是鸡形目雉科蓝镰翅鸡属的鸟类。原产于北美西部的山地地区，分布自加拿大育空地区南部至美国科罗拉多州中部。曾被认为是乌镰翅鸡的内陆亚种，但DNA证据支持将其与乌镰翅鸡区分为两个独立物种。蓝镰翅鸡的繁殖生境通常位于大陆性高山森林边缘，冬季则移居到针叶林中以针叶为主要食物。","appearance":"蓝镰翅鸡是一种大型的、类似鸡的鸟类，拥有暗色的羽毛和相对长的尾巴，尾巴末端呈灰色。雄鸟比雌鸟大，展示时会展露带有紫色皮肤的颈部和红色的眼上肉垂，眼上肉垂颜色会从黄色变为红色。雌鸟颜色更偏棕色，上体有条纹。幼鸟外观类似于成年鸟，但具有更细的淡色翼部条纹和更加斑驳的尾羽上侧。","call":"雄鸟在展示时会发出深沉的呼呼声。","habits":"蓝镰翅鸡主要栖息在混合森林和针叶林边缘，偏好有灌木和草丛的环境。它们大部分时间在地面活动，觅食植物和昆虫，冬季则更多地在树上寻找叶子、针叶和芽。雄鸟在早春通过短距离飞行和地面炫耀行为吸引雌鸟。","breeding":"雄鸟通过深沉的呼呼声在领地上歌唱，以吸引雌鸟。交配后，雌鸟离开雄鸟的领地独立筑巢。","identification":"蓝镰翅鸡比披肩榛鸡和枞树镰翅鸡体型更大，颜色更深、更灰。与乌镰翅鸡相比，蓝镰翅鸡的色彩较淡，雄鸟颈部裸露皮肤呈紫红色，而乌镰翅鸡的皮肤呈黄色。蓝镰翅鸡的尾巴更加方形，通常有20根尾羽，而乌镰翅鸡通常有18根。","protection":"IUCN：LC（无危）","distribution":"繁殖区域从加拿大南部的育空地区延伸至美国中部的科罗拉多州，非繁殖季节则可能移居至密集的针叶林地带。","other":"蓝镰翅鸡的四个亚种在尾羽、肩羽和翼覆羽的标记上有细微差异，南方亚种（obscurus和oreinus）尾羽末端有灰色带，而北方亚种（richardsonii和pallidus）则几乎无此特征。"},{"name":"乌镰翅鸡","english_name":"Sooty Grouse","scientific_name":"Dendragapus fuliginosus","overview":"乌镰翅鸡（英文名：Sooty Grouse，学名：Dendragapus fuliginosus），是鸡形目雉科蓝镰翅鸡属的鸟类。大型、深色、类似鸡的鸟类，广泛分布于北美太平洋沿岸山脉，从南阿拉斯加和加拿大不列颠哥伦比亚省向南延伸至加利福尼亚州和内华达西部的山地森林地带。曾被认为是蓝镰翅鸡的沿海亚种，但基于近期DNA证据，现已与蓝镰翅鸡分离为独立物种。乌镰翅鸡的显著特征包括其较长的尾巴和暗灰色的外观。","appearance":"乌镰翅鸡体型较大，长度约44-57厘米，拥有相对较长的尾巴。雄鸟比雌鸟大，毛色以暗灰色、棕灰色和黑色为主，胸部有时可见稀疏的白色斑点。尾羽呈黑色，尖端有一条明显的窄至宽的灰色带。雄鸟颈部有特化的黄色裸皮区，周围环绕着明亮的白色羽毛，展示时尤为显眼。雌鸟颜色更偏棕色，羽毛图案更加复杂。幼鸟与成鸟相似，但保留了部分幼年特征，如较窄和更圆的尾羽，尤其是在雄鸟中更为明显。","call":"雄性乌镰翅鸡在展示时会发出深沉的鸣叫声，音调略高于灰蓝镰翅鸡。","habits":"乌镰翅鸡栖息于多种林地环境，从沿海雨林到亚高山和高山森林均有分布，冬季几乎全部栖息于针叶林中，以针叶为食。它们在春季从树上的栖木上展示，进行短暂的飞行并在地面进行炫耀表演。","breeding":"雄鸟通过深沉的呼叫声吸引雌鸟，雌鸟在交配后离开雄鸟的领地，在地面的浅坑中筑巢，通常被灌木或倒木遮蔽，产卵量约为5至10枚。雏鸟出生后的前10天几乎完全依赖昆虫为食。","identification":"乌镰翅鸡与蓝镰翅鸡相比，整体颜色更深，尤其是雄鸟，颈部裸皮区呈黄色，而蓝镰翅鸡的为紫红色至红色。乌镰翅鸡的尾羽较为圆润，通常由18根尾羽组成，而蓝镰翅鸡通常有20根尾羽。此外，乌镰翅鸡的叫声更高亢响亮。","protection":"IUCN：LC（无危）","distribution":"乌镰翅鸡主要分布于北美的山地森林区域，从阿拉斯加东南部到加利福尼亚南部，包括不列颠哥伦比亚、华盛顿州、俄勒冈州和内华达州西部。","other":"乌镰翅鸡分为四个亚种，差异主要体现在尾羽形状和羽毛图案上。"},{"name":"尖尾松鸡","english_name":"Sharp-tailed Grouse","scientific_name":"Tympanuchus phasianellus","overview":"尖尾松鸡（英文名：Sharp-tailed Grouse，学名：Tympanuchus phasianellus），是鸡形目雉科草原松鸡属的鸟类。广泛分布于北美的中北部和西北部地区，包括阿拉斯加、加拿大北部和西部，以及美国的部分西部和中西部州。是加拿大萨斯喀彻温省的省鸟。","appearance":"尖尾松鸡体型圆胖，类似鸡类，体长41-47厘米，体重596-1031克，随季节和性别变化。头部、颈部、背部和翅膀上有深棕色、黑色和淡褐色条纹；胸部羽毛呈白色，边缘带浅褐色；上腹部羽毛白色，有小橄榄棕色V形标记；尾羽白色，具黑斑。雌雄两性相似，但雄鸟更大，具有粉紫色至淡紫色的颈部气囊，仅在展示时显露膨胀。","call":"雄性尖尾松鸡在求偶展示时会发出独特的‘咕咕’声，用于吸引和竞争雌鸟。","habits":"尖尾松鸡夏季在地面觅食，冬季则在树上觅食。它们以种子、芽、浆果、草本植物和叶片为主食，夏季也会摄食昆虫，尤其是蚱蜢。这些鸟儿会在特定的开阔区域聚集，称为‘lek’，雄鸟在此进行快速踏步展示，发出叫声，并可能互相争斗。","breeding":"尖尾松鸡是群居鸟种，雄鸟在春季聚集在lek上，从三月到七月，高峰出现在四月底至五月初。雄鸟通过快速踩踏地面、摇动尾巴并发出响声，同时展示紫色颈囊来吸引雌鸟。雌鸟选择最强势的一两个雄鸟交配，之后独自筑巢育雏。","identification":"尖尾松鸡的下腹部有均匀的V形标记，这与下腹部有重横条纹的较小和草原松鸡形成鲜明对比。雄鸟的紫色颈囊是另一种区分特征，而草原鸡的雄鸟具有黄色或橙色的气囊。","protection":"IUCN：LC（无危）","distribution":"尖尾松鸡分布于北美中北部和西北部，包括阿拉斯加、加拿大北部和西部，以及美国的部分西部和中西部州。","other":"尖尾松鸡历史上曾广泛分布于北美，但随着生境变化，许多南部和东部地区的数量已大幅减少。然而，与农业土地相关的人口在美国种植了草和草本植物，根据政府赞助的保护储备计划（CRP），提供了数千公顷的筑巢和育雏生境，导致1980年代末和1990年代初人口增加。"},{"name":"小草原松鸡","english_name":"Lesser Prairie Chicken","scientific_name":"Tympanuchus pallidicinctus","overview":"小草原松鸡（英文名：Lesser Prairie Chicken，学名：Tympanuchus pallidicinctus），是鸡形目雉科草原松鸡属的鸟类。亦称小草原榛鸡，其体型介于草原松鸡与尖尾松鸡之间，色泽偏淡，主要栖息于北美中部沙丘及草原地带，而非高草草原。该物种非迁徙性，具有领地意识。","appearance":"小草原松鸡是一种中等至大型鸡形目鸟类，体长约为38至41厘米，体重22.1至28.7盎司。羽毛呈条纹状，白色与棕色相间，整体外观上比近亲草原松鸡更小且颜色更浅。成年个体的上半身被交替的深棕色和淡褐色条纹覆盖，下巴和喉咙部分几乎无标记，尾巴短而圆，呈暗褐色。雄鸟展示时，头部两侧的羽毛竖起，露出类似耳状的羽毛，颈部皮肤变红。","call":"雄性小草原松鸡在展示期间会发出特有的咯咯声和轰鸣声，这是通过颈部的可膨胀气囊产生的。","habits":"小草原松鸡主要居住在以橡木和沙艾草为主的短草草原，偏好沙质地带。它们的生活习性包括在春季聚集在传统的展示场（称为lek或求偶场）进行求偶展示。它们以昆虫、种子和谷物为食，偶尔会攀爬植被寻找果实、猫爪草和芽叶。它们主要生活在地面，但能够飞行较长距离，以连接休息和觅食区域。","breeding":"小草原松鸡在春季进行繁殖，雄鸟会在lek上进行展示以吸引雌鸟。雌鸟独自筑巢，产卵，孵化和抚养幼鸟。具体的繁殖细节，如巢的构造、交配、产卵数量和孵化时间，需参照更详细的资料。","identification":"小草原松鸡与草原松鸡外观相似，但前者体型较小，色彩较浅。两者在地理分布上没有重叠。与尖尾松鸡相比，小草原松鸡缺乏颈部延长的羽毛，尾部形状不同，下体颜色更浅，带有V形标记而非条纹。","protection":"IUCN：VU（易危）","distribution":"小草原松鸡的分布集中在北美中部，主要在西部堪萨斯州，以及俄克拉荷马州西部、德克萨斯州泛手区、新墨西哥州东部和科罗拉多州东南部的沙丘和草原。","other":"自20世纪初以来，由于牧场过度放牧、干旱和农田扩张，小草原松鸡的种群数量和分布范围已显著减少。"},{"name":"草原松鸡","english_name":"Greater Prairie Chicken","scientific_name":"Tympanuchus cupido","overview":"草原松鸡（英文名：Greater Prairie Chicken，学名：Tympanuchus cupido），是鸡形目雉科草原松鸡属的鸟类。又名: 奥氏角雉，是北美原生的大型鸟类，曾广泛分布于橡树林间的大草原。由于栖息地丧失，其数量锐减，现存小群落正接受保护以维持生存。物种内分为两个现生亚种和已灭绝的Heath Hen，后者原居于美国东北部。","appearance":"成年个体体型中等至大，类似鸡类，体态丰满，翅膀圆润，尾巴短而圆。雄鸟具有橙色眼上方的梳状羽毛和可竖起的深色头羽，颈部有一圆形裸露斑块，展示时可膨胀，颜色为橙色。雌鸟头羽较短，无黄色梳状羽毛和橙色颈部斑块。成年个体长度约43厘米，体重介于700至1200克之间，翼展可达69.5至72.5厘米。","call":"雄鸟在求偶展示中会发出著名的轰鸣声，通过颈部膨胀的气囊发声。","habits":"偏好未受干扰的草原环境，适应农业与草原混合地带。主要以种子和果实为食，夏季增加绿色植物和昆虫摄入，如蚱蜢、蟋蟀和甲虫。栖息于高草草原，可容忍农田与草原交错地带。","breeding":"春季雄鸟聚集于展示区，通过舞蹈吸引雌鸟。雌鸟在远离展示区的地方筑巢，每窝产卵5至17枚，孵化期23至24天。雏鸟由雌鸟独自抚养，约1至4周离巢，10至12周完全独立，1岁时达到性成熟。","identification":"比小草原松鸡略大且更暗，比尖尾松鸡体型更大，侧腹条纹更重。雄鸟的颈部气囊颜色为黄橙色，区别于小草原松鸡和尖尾松鸡。","protection":"IUCN：NT（近危）","distribution":"分布于北美，从加拿大中南部至美国德克萨斯州，主要栖息于高草和混生草原，偶尔出现在农田和灌木丛中。","other":"草原松鸡阿特沃特亚种（T. c. attwateri），又称奥氏角雉，是华盛顿公约附录一保护物种。"},{"name":"白尾雷鸟","english_name":"White-tailed Ptarmigan","scientific_name":"Lagopus leucura","overview":"白尾雷鸟（英文名：White-tailed Ptarmigan，学名：Lagopus leucura），是鸡形目雉科雷鸟属的鸟类。常年居住在北美高山环境，从树线到高山地带，是北美的特有种。以适应极端环境的生理和行为特征著称，能在寒冷、开阔的高山环境中生存，以低矮灌木和草本植物的芽、叶和花为食。","appearance":"白尾雷鸟体型丰满，长度约30-31厘米，体重330-480克，雄鸟略大。羽毛随季节变化，夏季呈现灰褐色斑点，冬季全白，翼腹尾终年白色。雌雄类似，雄鸟有红色眼线，脚趾覆盖白羽。","call":"一般保持沉默，偶尔发出低沉的咕哝声和轻柔的咯咯声。","habits":"栖息于高山岩石区和苔藓地面，偏好步行而非飞行，主要以植物为食。冬季形成小群，夏季单独或成对出现。","breeding":"春季雄鸟展示羽毛吸引雌鸟，雌鸟筑巢于地面，产卵2-8枚，孵化期约23天。幼鸟孵化后很快离开巢穴。","identification":"与其它雷鸟区别在于体型较小，尾羽全年白色。雄鸟眼上方有红色眼线。","protection":"IUCN：LC（无危）","distribution":"分布于北美西部山脉，从阿拉斯加至新墨西哥北部，跨越4370公里，纬度从67°N至35°N。","other":"白尾雷鸟是唯一全年居住在高山或亚高山环境的北美鸟类。"},{"name":"岩雷鸟","english_name":"Rock Ptarmigan","scientific_name":"Lagopus muta","overview":"岩雷鸟（英文名：Rock Ptarmigan，学名：Lagopus muta），是鸡形目雉科雷鸟属的鸟类。中等体型，以其矮胖墩实的外观著称。其羽色随季节变化，冬季全身呈现纯白，夏季则为冷灰至棕色，带有深色条纹。雄性岩雷鸟具有独特的红色肉冠，特别是在繁殖季节颜色更为鲜艳。雌性岩雷鸟则更善于伪装，夏季羽毛上带有复杂的黑白标记，使它们在巢中几乎难以被发现。岩雷鸟分布于北极苔原冻土带和高山的树线以上，是中国国家二级保护动物，仅在新疆西北部的阿尔泰山地区有所记录。","appearance":"岩雷鸟体型中等，长度约34-36厘米，体重介于440-640克之间，比柳雷鸟小约十个百分点。羽毛颜色随季节变换，冬季全身纯白，夏季则变为灰褐色或棕黑色，带有黑色边缘的尾羽和白色的翼部。雄性岩雷鸟在繁殖季节头部上方有显著的红色肉冠，雌鸟的肉冠较小且颜色较淡。幼鸟呈黄橄榄色和黑色斑驳的组合，身体羽毛柔软蓬松。","call":"雄性岩雷鸟发出一系列喉音和咔哒声，尤其是在繁殖季节用于领土声明。空中求偶仪式包括快速飞行和向上滑翔，伴随着特殊的叫声。","habits":"岩雷鸟生活在北极附近的冻原地带和高山地带，夏季栖息于矮桦灌丛、高山草原，冬季向气候较暖的地区迁移。它们以植物的嫩枝、叶、根为食，秋季和冬季会组成高达数百只的群体。繁殖期实行一夫一妻制。","breeding":"岩雷鸟的繁殖期为6月至8月，雄鸟通过鸣叫和展示吸引雌鸟。雌鸟在雄鸟领地内筑巢，每窝产卵6-13枚，卵色为赭色，带有栗色斑点。孵化期约为24-26天，雏鸟孵化后跟随亲鸟转移至较高且湿润的山坡。","identification":"岩雷鸟与柳雷鸟相似，但夏季羽毛更灰暗，冬季眼先黑色而非白色。雄性岩雷鸟的肉冠在繁殖季节膨胀并变红，而柳雷鸟缺乏这一特征。岩雷鸟的栖息地更高，更接近树线。","protection":"IUCN：LC（无危）\n岩雷鸟在中国属于国家二级保护动物。","distribution":"岩雷鸟广泛分布于北美和欧亚地区的北部，包括北极圈内的冻原地带。在中国，岩雷鸟仅见于新疆西北部的阿尔泰山地区。","other":"岩雷鸟的多个亚种在世界范围内得到识别，其中两个亚种evermanni和welchi因其独特的羽毛和体型差异，曾被描述为独立物种。"},{"name":"柳雷鸟","english_name":"Willow Ptarmigan","scientific_name":"Lagopus lagopus","overview":"柳雷鸟（英文名：Willow Ptarmigan，学名：Lagopus lagopus），是鸡形目雉科雷鸟属的鸟类。环北极地区体型最大、数量最多的雷鸟，圆胖如鸡，羽色随季节在纯白与棕红间剧变，冬季尾羽外侧黑色。繁殖于北美、欧亚大陆的苔原、亚高山灌丛及林缘，冬季局部迁徙至低海拔柳丛或森林空地。全球现存15个亚种，是已知唯一雄性长期参与育雏的松鸡。","appearance":"体长35–43.5厘米，翅长17.5–21.8厘米，体重430–810克，雄鸟大于雌鸟。冬季全身雪白，仅尾羽外侧黑色；春季雄鸟头颈转为红棕，背棕褐；夏季雌鸟淡黄褐具黑白细纹。喙短而厚，眼上方具红色肉垂，雄者更鲜艳。跗跖及趾全年被羽，冬季羽量增多以保温并防沉雪。幼鸟保留最外侧两枚初级飞羽至翌夏，羽色较深，可据此区分年龄。","call":"雄鸟发出带鼻音的“咯咯”笑声及多种咯咯声；繁殖期以空中“飞行歌”示域，先为断续鼻音，继之连续咯咯串响。雌雄均具短促“kok”警戒、拖长“krrow”争斗、低吼“ko-ko-ko”飞行意向等叫声，雌鸟另有轻柔“purr”告警及“moan”唤雏。","habits":"栖息于低湿苔原、林缘、灌丛、沼泽及柳丛，海拔自海平面至亚高山带。冬季迁往低纬度或低海拔的柳丛、河谷及森林空地，集群20–200只，偶见千只大群。昼行性，晨昏觅食，主食柳、桦芽、嫩枝、叶、浆果及昆虫，冬季以柳芽为主。遇敌静伏或短距飞逃，常借雪穴保温避寒。","breeding":"一夫一妻为主，5–9%雄鸟一雄多雌。雄鸟3月中下旬占区，4月初雌鸟至并形成配偶，配偶期可持续至雏鸟独立。雌鸟独筑巢，巢为地面浅坑，内衬草叶羽毛，直径15–20厘米，深8–16厘米。每窝4–14枚卵，卵乳白具褐斑，卵重约22克，占雌鸟体重5%。孵化21–23天，雌鸟独孵，雄鸟警戒并可协助育雏。雏鸟早成，出壳后3–10小时离巢，10–12日龄可飞，70–110日龄达成体大小，9–10月离亲。","identification":"与白尾雷鸟区别：尾羽外侧黑色，体型较大，喙更粗厚；与岩雷鸟区别：冬季无黑色过眼纹，雄鸟夏羽红棕而非灰棕，喙高大于9.5毫米，体型平均大10%。雌鸟较难区分，但柳雷鸟体色更棕、喙略厚。","protection":"IUCN: LC（无危）。分布极广且数量丰富，局部因狩猎、栖息地退化及气候变化略有缩减。","distribution":"繁殖区：北美自阿拉斯加北部、班克斯岛、巴芬岛南至纽芬兰、不列颠哥伦比亚及魁北克、拉布拉多；落基山及亚高山带南达约50°N。欧亚自斯堪的纳维亚、俄罗斯北部、西伯利亚至堪察加、萨哈林岛及蒙古北部。非繁殖区：北美冬季南迁至加拿大南部各省及美国北部各州；欧亚北部种群短距离南移。","other":"苏格兰雷鸟已分拆独立成种。历史上曾尝试向德国、比利时及俄罗斯多地引入，多未成功。"},{"name":"雪鹑","english_name":"Snow Partridge","scientific_name":"Lerwa lerwa","overview":"雪鹑（英文名：Snow Partridge，学名：Lerwa lerwa），是鸡形目雉科雪鹑属的鸟类。本属唯一物种，体型不大，成年个体长30-40厘米。通体呈现灰色，头颈间缀以黑白细条纹，腹部和两翼可见棕色条纹，拥有鲜红的喙和脚。广泛分布于喜马拉雅山脉至中国中部的高海拔地区，常见于海拔3000-5000米的高山草甸和碎石地带。以植物为主食，偶尔摄入昆虫。","appearance":"雪鹑外观灰白相间，上体斑驳，下体密集锈色条纹，头部和颈部有精致的黑白色条纹，腹部及两翼饰有棕色条纹。成年个体长度约30-40厘米，体重介于454-709克之间。雄鸟具有钝刺，雌鸟则无，雌雄羽色相似，但雌鸟体型稍小，喙色可能偏粉或灰粉色。幼鸟标记不如成鸟明显，下体呈淡褐色，头部和颈部斑点较小，上胸有细密的红褐色条纹。中国种群（major）体型略大，上体色调更偏赤褐色，下体颜色稍浅。","call":"雪鹑的鸣叫在繁殖季节尤其明显，雄鸟的叫声响亮且音调上升，具有一种滑腻、吱吱声，类似于湿鞋在瓷砖上的声音；雌鸟的叫声较为柔和，音调下降。","habits":"雪鹑通常以6-8只的小群体出现，但在非繁殖季节可能聚集至30只左右。它们偏好栖息于高山草地和开阔的山坡，夏季多见于雪线以上的地带，冬季可能降至2100-2700米。食物以苔藓、地衣为主，也食用浆果和植物嫩芽。遭遇危险时，会迅速振翅飞起并分散逃离。","breeding":"繁殖期从5月至7月，雪鹑实行一夫一妻制，领地面积约5公顷。巢穴通常位于岩石旁或高山灌木丛中，建于陡峭斜坡或山脊附近。每窝产卵数量在2到5枚之间，有时可达7枚，蛋壳淡黄色，表面有红褐色斑点。孵化由雌鸟独自承担，雏鸟在100天左右达到成鸟体重，但次年才会更换最外侧的初级飞羽。","identification":"雪鹑与喜马拉雅雪鸡相比，生活在更少裸露的岩石地带，且更为大胆。雄鸟有刺，雌鸟无刺，雄鸟喙色更为鲜艳。中国种群的体型和色彩略有差异。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉，自巴基斯坦北部至中国中部，包括尼泊尔、印度北部等地。在中国，主要见于西藏、四川、甘肃、云南等地的高海拔区域。","other":"雪鹑已知存在于七个保护区中，包括印度的大喜马拉雅国家公园和南达德维国家公园，尼泊尔的谢-福克斯当多国家公园，中国西藏的扎玉自然保护区，以及四川的卧龙国家级自然保护区、凤通寨和小寨沟自然保护区。"},{"name":"红喉雉鹑","english_name":"Verreaux's Monal-Partridge","scientific_name":"Tetraophasis obscurus","overview":"红喉雉鹑（英文名：Chestnut-throated Monal-Partridge，学名：Tetraophasis obscurus），是鸡形目雉科雉鹑属的鸟类。大型陆栖鸟，主要分布在中国西部的青藏高原东部，包括青海东部、甘肃中部和四川北部与西部。体长约48厘米，以暗褐色为主调，具独特亮红色眼周皮肤和醒目的栗色喉咙，翅膀和侧翼有白色边缘，胸部细密黑色斑点。本种纪念法国自然学家Jules Verreaux。","appearance":"红喉雉鹑整体呈棕色，头部略尖，喉部为深栗色，眼睛周围有鲜艳的红色裸皮。羽毛图案复杂，胸腹部有精致的黑色斑点，翅膀和侧翼边缘白色。雄鸟具有单个的刺，雌鸟则可能缺少环绕栗色喉部的淡色环。幼鸟特征未充分描述，但已知有小型淡褐色喉斑，无环状标记。","call":"其鸣声类似黄喉雉鹑，是一种嘈杂的组合，包括粗糙、喉音、气泡和摩擦音符。当受惊时会发出响亮的叫声。","habits":"栖息于海拔2800至4500米的高山森林、杜鹃灌丛、高山草甸和裸露的草地，偏好岩石和溪流附近的环境。常在3至5只的小群体中活动，以树叶、花朵、种子和根茎为食。在一些地区，特别是在受保护的西藏寺庙附近，它们可能变得非常温顺，甚至会以群体形式出现。","breeding":"繁殖信息稀少，但已知在地面和树上筑巢，为非合作繁殖者。平均产卵数为4.2枚，孵化期大约27至28天，仅由雌鸟独自孵化。雏鸟出生后不久即可跟随亲鸟外出觅食。","identification":"与Szechenyi's Partridge相比，红喉雉鹑的下巴、喉咙和前颈主要为深栗色，臀部和上尾覆羽更偏棕色。两物种不重叠分布。","protection":"IUCN：LC（无危）。在中国受法律保护，被列入红色名录。尽管种群数量估计在25,000至40,000之间，但由于栖息地偏远，实际数量可能更多。面临栖息地退化威胁。","distribution":"红喉雉鹑仅分布于中国西部，包括青藏高原东部的青海、甘肃和四川的部分地区。","other":"红喉雉鹑在某些保护区如Lianhuashan和Wanglang国家自然保护区可见。"},{"name":"黄喉雉鹑","english_name":"Szechenyi's Monal-Partridge","scientific_name":"Tetraophasis szechenyii","overview":"黄喉雉鹑（英文名：Buff-throated Monal-Partridge，学名：Tetraophasis szechenyii），是鸡形目雉科雉鹑属的鸟类。大型陆栖鸟类，广泛分布在喜马拉雅山脉的高海拔地区，包括西藏东南部、青海南部、四川西部和云南西北部。其显著特征包括橙色眼圈、金色喉部以及灰色胸腹部。该物种参与了合作繁殖行为。","appearance":"黄喉雉鹑体型中等，长度介于29至50厘米之间，体重在660至1790克之间。全身呈哑光棕色，头部具有醒目的橙色眼圈，胸部和前颈为浅驼色，背部有白色横纹，侧面有锈色条纹。尾巴较长，由18根白尖羽毛组成，可在受惊时部分竖立展开。雄鸟比雌鸟稍大，眼圈更大，雌鸟较小且缺乏雄鸟的脚刺。","call":"发出响亮、重复的、双音或三音的咯咯声，其间穿插单调的磨擦声。","habits":"栖息于海拔3300至4800米的针叶林、杜鹃灌木丛、高山草甸和岩石沟壑，偏好在森林地带活动，但也出现在树线以上的岩石高原。夜间常栖息在同一棵树上。主要食物包括植物根、小球茎、苔藓、小果子和绿叶。在西藏东部的寺院附近，人们会提供大米和玉米作为补充食物。","breeding":"繁殖季节通常从3月下半月至5月底，筑巢于土壤凹坑中，铺垫树叶、枝条和树皮，或置于2至12米高的树木（冷杉、橡树、落叶松）中。巢杯状，由苔藓、地衣和羽毛构成，有时掺杂人造织物碎片。合作繁殖，每组家庭中可能有一至三个非繁殖个体作为助手，协助照料幼鸟，尤其是警戒和领土防御。雌鸟单独负责孵化2至5枚粉色带深红色斑点的蛋，孵化期为24至29天。","identification":"与同属的红喉雉鹑的区别在于，黄喉雉鹑的喉部和前颈颜色较淡，臀部和尾上覆羽更灰，与背部颜色形成对比。雌鸟与雄鸟相似，但体型略小且缺乏脚刺。","protection":"IUCN：LC（无危）；国家重点保护野生动物名录新增，保护级别：I级（2021.02.05）","distribution":"分布于喜马拉雅山脉的高海拔地区，具体包括西藏东南部、青海南部、四川西部和云南西北部，以及印度东北部的边缘地带。","other":"在四川，由于佛教寺院提供的补充喂食和保护，黄喉雉鹑较为常见。然而，随着中国影响力在四川西部地区的增强，人们的态度正在发生变化，这可能对该物种产生影响。"},{"name":"高加索雪鸡","english_name":"Caucasian Snowcock","scientific_name":"Tetraogallus caucasicus","overview":"高加索雪鸡（英文名：Caucasian Snowcock，学名：Tetraogallus caucasicus），是鸡形目雉科雪鸡属的鸟类。大型而健壮的鸟类，体长52至56厘米，重约1730至1930克，主要分布于高加索山脉，包括俄罗斯西南部、格鲁吉亚北部和阿塞拜疆北部的高山地带。","appearance":"高加索雪鸡全身羽毛以灰调为主，伴有褐色、白色和黑色的复杂图案。其胸部颜色较深，体侧显微红色，喉部为白色，脖子两边有明显的白色斑纹，颈背呈现铁锈色。雌雄羽色相似，但雌鸟颜色较为暗淡，缺乏雄鸟的短刺。幼鸟比成鸟小且颜色更暗淡，胸带部位的栗色不如成年雄鸟明显。","call":"高加索雪鸡发出类似白腰杓鹬的凄凉哨音，其歌声为拉长的调式哨声“wu-oo-wee-lee-uh”，音调逐渐升高，通常在结尾时声音会突然下降，此外还有警惕时的上升音调“ooee…ooee…”以及受到惊吓时响亮的‘cok-cok-cok’声。","habits":"栖息于海拔2500米至雪线之间的高山岩石地带，避开大范围的积雪覆盖区。在温暖季节，它们会向更高海拔移动，追踪常年积雪线。以素食为主，春季和夏季约40%的食物为草类，其余时间则以植物的各个部分为食，如叶、果实、茎和块茎等。","breeding":"繁殖期从4月底持续到7月，雌鸟在开阔地带或岩石遮蔽下筑巢，产下5至8枚浅绿色或淡蓝色带有棕色斑点的蛋，由雌鸟单独孵化约28天。雏鸟出生后呈淡褐色，密集地布满棕黑色标记，下部为淡奶油色。性成熟大约在一年左右。","identification":"与其他雪鸡种类的区别在于，高加索雪鸡具有深灰色下体和强烈的胸带条纹，颈背呈锈色，但这些差异仅在成年雄鸟中明显。雌鸟较雄鸟颜色更暗淡，侧翼条纹较窄，上体斑点更大且更苍白。","protection":"IUCN：LC（无危）。尽管分布范围有限，但目前数量稳定，估计有数十万只。面临的主要威胁是过度放牧导致的栖息地退化。在至少三个保护区中得到保护，包括俄罗斯的Tebezdinsky保护区、阿塞拜疆的Zakataly保护区和格鲁吉亚的Lagodechy保护区。","distribution":"主要分布在高加索山脉的高海拔地区，具体包括俄罗斯西南部、格鲁吉亚北部和阿塞拜疆北部。","other":"已禁止狩猎，数量被认为稳定，估计有41万只，尽管分布范围小，但目前全球不受威胁。"},{"name":"里海雪鸡","english_name":"Caspian Snowcock","scientific_name":"Tetraogallus caspius","overview":"里海雪鸡（英文名：Caspian Snowcock，学名：Tetraogallus caspius），是鸡形目雉科雪鸡属的鸟类。大型而健壮的高山鸟类。灰褐色为主色调，背部和翅膀带有白锈色条纹，脸部有白棕相间的条纹。分布于土耳其东部至伊朗的高山区，栖息于岩石山地，海拔从森林上限至雪线，有时因大雪而降至较低海拔。","appearance":"体长55-61厘米，翼展95-105厘米，雄鸟体重2500-2684克，雌鸟1800-2344克。整体灰棕色，背部和翅膀有白锈色条纹，脸部白棕条纹明显。雌鸟较雄鸟小而暗淡，上体斑点较小，无锈色标记，颈部两侧更灰，眉纹短，胸部斑点少且羽毛窄条纹状，侧翼条纹弱化。雄鸟有单个短刺，幼鸟羽色模式不明显，类似小型雌鸟。成年雄鸟与雌鸟的区别在于胸部条纹不明显，上体斑点较大且更鲜艳。","call":"领域叫声为重复的、远传的、拉长调的口哨声，'wu-oo-wee-lee-uh'，音质悠扬而哀婉，与白腰杓鹬相似但更为柔和。每一声比前一声音调更高，通常以呼吸式的尖锐下降结束。警戒时发出强烈的'cok-cok-cok'声。","habits":"主要生活在海拔2400米以上至雪线的山区，偶尔降至1800米，偏好岩石峭壁地带，夏季晚期甚至会进入树丛。素食性，饮食与高加索雪鸡相似，但具体细节未知。早晨从高崖的栖息地飞往喜好的斜坡觅食，白天逐渐向上移动，中午休息。通常成对或小群活动，最多八只，秋季时可能形成多达60只的大群体。","breeding":"繁殖期在4月底至5月，交配从4月开始，被认为是单配偶制。在开阔地或岩石遮蔽下筑巢，巢呈深圆凹形，以草或松针及羽毛简单铺垫。产5-9枚浅灰色带绿色光泽的蛋，散有红棕色斑点，由雌鸟独自孵化28-29天，幼鸟出生同步，孵化后具有肉桂粉和深灰色绒毛，白色腹部，由雌鸟独自抚育。15-20天即可飞行。性成熟在一年龄。","identification":"与高加索雪鸡相比，整体更灰，胸部斑点稀疏而非条纹状。雌鸟体型更小，上体斑点较小，缺乏锈色标记，颈部侧面更灰，眉纹短，胸部斑点少且羽毛窄条纹状，侧翼条纹弱化。三个亚种主要在羽色饱和度和淡黄色调程度上有差异。","protection":"IUCN：LC（无危）。在1978年被列为苏联红色名录，CITES I级保护。总成熟个体数量估计为6700-33,000只。面临过度放牧和非法狩猎威胁，特别是在亚美尼亚、阿塞拜疆和土库曼斯坦。部分保护区内的物种受到保护。","distribution":"分布于土耳其山区中部、东部，格鲁吉亚南部和阿塞拜疆至伊朗东北部、中南部，主要在高山区。","other":"在土耳其、亚美尼亚、阿塞拜疆和伊朗的高山地区有分布，适应裸露石质地面和一些高山灌木环境。"},{"name":"暗腹雪鸡","english_name":"Himalayan Snowcock","scientific_name":"Tetraogallus himalayensis","overview":"暗腹雪鸡（英文名：Himalayan Snowcock，学名：Tetraogallus himalayensis），是鸡形目雉科雪鸡属的鸟类。体型较大，通体呈土棕或红棕色。典型的高山耐寒鸟类，栖息于海拔2500至5500米的高山裸岩地区、高山草甸及稀疏灌丛附近。在中国，主要分布在西藏、新疆、青海、甘肃等地，是国家二级重点保护动物，同时被列为《中国濒危动物红皮书》的稀有种。","appearance":"暗腹雪鸡体长55-74厘米，体重1.4-3.1千克，主要颜色为灰色、白色、栗色和黑色。喉部白色，与暗灰色下体通过细碎的栗色项圈分隔，胸前有两条深棕色线条。头部前额呈淡黄色，眼周灰度更深。虹膜棕色，喙呈角质棕色，眼睑边缘蓝灰色，眼眶皮肤淡黄色，腿橙红色。幼鸟较成鸟淡，标记不那么明显，但保留了白色眉纹、栗色冠羽和耳羽、颈后栗色带以及下体变化的V字形淡色栗色尖端。成鸟的性别在外表上相似，但雌鸟较小，缺乏雄鸟的大腿刺。","call":"暗腹雪鸡的叫声包括雄鸟招呼雌鸟的“ge，ge，ge ……”，惊散后互相招呼的“ger - u，ger - u，ger - u …”，受惊时的“gua ……gua ……gua …………”，呼唤幼雏的“gululu …gululu …”，以及发现敌害时的“jiu …,jiu …- ,jiu…-”。","habits":"暗腹雪鸡是留鸟，但有垂直迁徙习性，夏季栖息于高山地带，冬季下迁至山势较低的灌丛或草坡。它们主要在海拔2500至5500米的高山和裸岩地区活动，以植物性食物为主，春季以羊茅草、委陵菜和野葱为食，夏秋季以棘豆和羊茅草为主食，冬季主要食用羊茅草。它们通常在开阔地带觅食，日活动光照总时数在10-14小时，觅食时间约8小时左右。","breeding":"暗腹雪鸡的繁殖期为夏季，通常在4月至6月。雌鸟会在领域内筑巢，巢相当简陋，呈碟状，垫以少许枯枝、草茎和自身腹羽。每巢产卵大概4至8枚，卵淡赭石色，具有棕褐色或褐色斑点。雌鸟独自承担孵化责任，孵化期约27至28天。雏鸟出壳后有较强的活动能力，能够迅速跟随亲鸟觅食。","identification":"暗腹雪鸡与藏雪鸡有相似之处，但在色彩和大小上有细微差异，暗腹雪鸡略大，胸脯颜色更淡，有更水平的黑色条纹。它是唯一一种颈部有细薄棕色项圈的雪鸡。","protection":"IUCN：LC（无危）；中国国家重点保护野生动物名录：二级","distribution":"暗腹雪鸡主要分布在喜马拉雅山脉和邻近的帕米尔山脉，包括西藏、新疆、青海、甘肃等地区。在美国，它们在内华达州的Ruby Mountains也有引入的种群。","other":"暗腹雪鸡的孵化期是最危险和困难的时期，地面巢易受天敌侵袭，如大嘴乌鸦、金雕、大鵟、香鼬和狐等。"},{"name":"藏雪鸡","english_name":"Tibetan Snowcock","scientific_name":"Tetraogallus tibetanus","overview":"藏雪鸡（英文名：Tibetan Snowcock，学名：Tetraogallus tibetanus），是鸡形目雉科雪鸡属的鸟类。又名: 淡腹雪鸡，亦被称为淡腹雪鸡或'贝母鸡'，常见于西藏地区的高山雪线附近，是中国国家二级保护动物。","appearance":"成年藏雪鸡体长50-56厘米，重约1500-1750克（雄鸟）和1170-1600克（雌鸟）。头部呈灰色，具白色眉纹和橙色眼后斑，背部棕色，带有黑白条纹，腹部雪白，有细黑条纹。雄鸟有短的脚刺，雌鸟较小，头颈图案较模糊，无脚刺。幼鸟似雌鸟，但上部有浅色条纹，下部几乎无黑纹，具不规则的苍白斑点。","call":"藏雪鸡发出响亮、粗哑的叫声，可远距离传播，包括一系列穿透力强的哨音，以及类似'chuck-aa-chuck-aa-chuck-chuck-chee-da-da-da'的咕噜声。","habits":"栖息于海拔3700米以上的开阔山坡，夏季可达5800米，冬季降至2500-4000米。以草本植物为食，如星花、岩白菜、黄芪、银莲花和报春花。冬季会形成50只左右的群体，与蓝马鸡和蓝羊共食。","breeding":"藏雪鸡可能实行一夫一妻制，繁殖期从4月开始，持续至7月初，筑巢于岩石下或灌木丛中，巢内铺有少量草料。产卵数4-7枚，颜色从淡黄色到橄榄褐色不等，孵化期19-27天，由雌鸟承担。","identification":"与其他雪鸡相比，藏雪鸡具有显著的白色腹部和粗黑侧条纹，头部特征明显，有白色耳羽和暗色脸颊，雌雄差异在于体型和脚刺的存在。","protection":"IUCN：LC（无危）。CITES I级保护。在中国，藏雪鸡被列为国家二级保护动物。","distribution":"分布于喜马拉雅山脉和西藏高原，包括塔吉克斯坦的帕米尔高原，冬季可能下移到较低海拔。","other":"藏雪鸡的主要天敌包括猞猁、狐狸、雕和秃鹫，同时面临人类狩猎的威胁。"},{"name":"阿尔泰雪鸡","english_name":"Altai Snowcock","scientific_name":"Tetraogallus altaicus","overview":"阿尔泰雪鸡（英文名：Altai Snowcock，学名：Tetraogallus altaicus），是鸡形目雉科雪鸡属的鸟类。体型健硕的灰褐色雪鸡，分布于西蒙古、西南西伯利亚及相邻的中国新疆、哈萨克斯坦和俄罗斯地区。栖息于海拔较高的山地，自低矮的山麓至孤立的雪山之巅。在大部分分布范围内是唯一的雪鸡种类，仅在中国西北部与喜马拉雅雪鸡有轻微重叠。阿尔泰雪鸡的头部和颈部呈浅棕色，腹部洁白，背部为暗棕色与白色相间，这些特征即便在远处或恶劣天气条件下也极为醒目。","appearance":"体长约57至58厘米，雄鸟平均体重约3千克，雌鸟约为2.54千克。与藏雪鸡相比，其白色下体无黑色条纹，胸部有黑色斑点而非白色斑块。与暗腹雪鸡的区别在于，前者具有白色（而非暗灰色）的侧腹，与黑色的下腹部形成鲜明对比，且白色主要限于初级飞羽（后者二级飞羽广泛白色）。雌鸟比雄鸟略小，通常无距，仅在最年长的个体中可能有短距。虹膜棕色，眼圈皮肤橙黄色，喙角质色，基部较深，跗跖粉红至橙红色。雏鸟与成鸟相似，但初级飞羽尖端磨损。","call":"叫声特征描述较少，已知声音比高加索雪鸡更嘶哑粗糙，但比喜马拉雅雪鸡更为悦耳。","habits":"栖息于山地草原、高山草甸和冻土带，海拔范围从400米（如图瓦西部）至雪线附近，一般在2000至3600米之间，偏好陡峭斜坡和崎岖地形，包括峡谷和悬崖，也会进入森林觅食。冬季会从夏季的2500至3000米高度降至约2000米，遇到大雪时会移至积雪较少的区域，但不一定降低海拔。食物包括块茎、球根、种子、嫩枝（如桦树）、浆果（如小檗），多达40种植物，还包括昆虫和小型哺乳动物。经常与西伯利亚羱羊共同觅食，尤其是在冬季，甚至会在人类聚居区边缘与家鸡一同觅食。","breeding":"一夫一妻制，雄鸟在雌鸟产完最后一枚卵后聚集。繁殖期约从中三月中旬开始，具体日期取决于天气、栖息地和鸟龄，通常四月更为常见。巢建于碎石中，由雌鸟选择，内部简单铺设植物材料和羽毛。一窝产卵数从4至15枚不等，推测后者可能为两只雌鸟共同产于一巢。孵化期28天，仅由雌鸟承担。雏鸟次年即可繁殖。","identification":"与藏雪鸡和暗腹雪鸡通过下体颜色、飞羽特征和体色对比进行区分。","protection":"IUCN：LC（无危）。在蒙古一侧有一定数量，但在狭窄的分布区内，属于较为珍稀的雪鸡种类。中国目前仅发现约50只。","distribution":"分布于远东北哈萨克斯坦、西伯利亚南部、中国新疆北部以及西、中蒙古。在中国新疆与蒙古和俄罗斯交界地区有记录。"},{"name":"欧石鸡","english_name":"Rock Partridge","scientific_name":"Alectoris graeca","overview":"欧石鸡（英文名：Rock Partridge，学名：Alectoris graeca），是鸡形目雉科石鸡属的鸟类。欧洲特有，与东部的赤胸山鹧鸪亲缘关系密切，外观非常相似。其分布于南欧，偏好干燥、开放的山地环境，常在海拔高达3000米的地方发现，但在某些地区也能在较低的开阔平原上找到栖息地，那里草木稀疏，灌木丛低矮。在早上的时候，这种鸟的领地意识强烈，会发出一系列不规则的鸣叫声。","appearance":"成年欧石鸡的体型介于32至37厘米之间，体重范围为雄鸟550至850克，雌鸟410至720克，翼展可达46至53厘米。喉部白色，与类似外观的赤胸山鹧鸪奶油色的喉部形成对比；与其它相似物种的分布范围几乎没有重叠。雄鸟比雌鸟稍大，雌鸟的头部图案较为暗淡，且没有跗跖上的肉瘤。幼鸟体型较小，颜色较暗淡，图案较少；大约在4个月大时，它们开始变得与成鸟相似，但会保留最外侧的两根初级飞羽长达一年。","call":"欧石鸡在清晨最为活跃，会发出一连串急促的“chi-TiTiTi-CHIK”声，被认为是更高音、更快节奏和更尖锐的叫声，与同类相比更加清脆。当受到惊吓时，会发出尖锐的哨声“peeyou”，随后是一连串的“wittoo-wittoo-wittoo”声，这与石鸡的叫声相似。","habits":"欧石鸡主要栖息在石灰岩山区，喜欢有短草、稀疏灌木覆盖和一些树木的地方。在亚高山地带，通常出现在海拔900米以上，常见于1200至1500米之间，偏爱向阳的斜坡。它们很少在密闭森林中被发现，但存在于松树、落叶松和杜松等开放林地。它们在草地、牧场和低矮灌木丛中广泛分布，在岩石地面如碎石坡、悬崖和峭壁上也能找到它们的身影。冬季，它们会进行高度迁移，最初向更高的地方移动，然后随着冬季的进展而下降。","breeding":"繁殖期从阿尔卑斯山脉的5月中旬到6月，希腊从4月底到6月。成对配偶关系长期稳定，偶尔会出现连续的多配偶制和伴侣交换。雄鸟选择筑巢地点，雌鸟挖掘巢穴。正常情况下，每窝产8至14枚（6至21枚）蛋，颜色为奶油黄色到淡黄色，上面散布着红褐色斑点。孵化期由雌鸟独自承担，持续24至26天。雏鸟出生后，主要或完全由雌鸟喂养，而雄鸟则守护幼鸟。","identification":"与赤胸山鹧鸪的区别在于背部更灰，前颈白色而非黄色。喉咙周围的黑色项圈是该物种的显著特征，使其与红腿石鸡区分开来。","protection":"IUCN：NT（近危）","distribution":"欧石鸡主要分布在南欧，从法国东南部、瑞士和奥地利西南部穿过意大利和西西里岛，到达巴尔干半岛和希腊，东至保加利亚东部。在阿尔卑斯山脉，它可以在高达2400米的地方被发现，有时甚至达到2700米。","other":"在过去的几十年中，欧石鸡的数量在大部分分布范围内呈下降趋势。"},{"name":"石鸡","english_name":"Chukar Partridge","scientific_name":"Alectoris chukar","overview":"石鸡（英文名：Chukar Partridge，学名：Alectoris chukar），是鸡形目雉科石鸡属的鸟类。中型雉类，体长34-38厘米，体重538-765克。其最显著的外部特征是嘴、脚呈珊瑚红色，虹膜为栗褐色，头侧环绕着完整的黑色环带，与白色的喉部形成鲜明对比。原生于亚洲，包括中国、印度等地，现已广泛引入北美、新西兰和夏威夷等地。","appearance":"石鸡具有中等体型，总长度约34-38厘米，重量在550-675克之间。雌雄相似，但雌鸟略小，头部图案稍显暗淡，无雄鸟的跗跖结节。通体灰褐色至橄榄色，腹部呈暖橙色。面部有醒目的黑色条纹，穿过前额、眼睛，延伸至颈部，形成独特的围脖。喙鲜红色（幼鸟较淡），腿部玫瑰红色，两侧有明显的黑色和栗色横纹，尾部外侧羽毛为栗色。幼鸟比雌鸟更小，初期头部和侧面的图案不明显，但很快就能看到黑色围脖和侧面的横纹，约4个月时接近成鸟形态，但保留最外侧的初级飞羽直至第二年。","call":"石鸡的鸣叫声为一系列粗糙沙哑的音符：“ chuKAR，chuKAR，chuKAR”，重音在第二个音节，声音像是在呼唤自己的名字。","habits":"石鸡偏好于西部美国大盆地的陡峭岩石地形，那里混合了灌木、草本和多年生植物。它们在农业边缘的岩石峡谷或山区生存，但在没有农业的西方过度放牧的开阔草原上繁盛。主要食物是草本植物的叶子和种子，尤其是入侵的野燕麦。石鸡是留鸟，白天活动，喜集群，常在山坡附近的农田觅食，遇险时快速奔跑或飞翔，清晨和黄昏时雄鸟会站在高处鸣叫。","breeding":"繁殖期从4月末持续至6月中旬。4月中下旬开始发情，雄鸟清晨鸣叫，偶有争偶斗争。巢建在石堆、山坡灌丛或草丛中，极其简陋，仅以地面凹坑为基础，内垫枯草。每窝产卵7-17枚，偶有多至20枚，卵呈棕白色或皮黄色，带有暗红色斑点。孵化期约23-25天，雏鸟早熟，孵出后不久即可随亲鸟活动。","identification":"石鸡与欧石鸡非常相似，主要区别在于头部黑色图案的范围（欧石鸡的额部和眼周黑色，石鸡的相应部位为白色），胸部黑色围脖形状（石鸡的呈V字形，欧石鸡的更圆润），以及侧面羽毛上的黑色条纹（石鸡的条纹较少，间距更大）。石鸡的上体颜色一般更偏棕色，少有蓝灰色。","protection":"IUCN：LC（无危）","distribution":"石鸡的原生分布区域包括亚洲南部，如中国、印度等国，以及中东部分地区。已成功引入并广泛分布在北美的西部地区、新西兰和夏威夷，此外，在加拿大、智利、阿根廷等地也建立了野生种群。","other":"石鸡在北美被广泛引入，成为狩猎爱好者的目标物种，尤其在内华达州和俄勒冈州，它是捕猎量最大的山地鸡形目鸟类。"},{"name":"大石鸡","english_name":"Przevalski's Partridge","scientific_name":"Alectoris magna","overview":"大石鸡（英文名：Przevalski's Partridge，学名：Alectoris magna），是鸡形目雉科石鸡属的鸟类。以黄色调和较大的体型区别于石鸡。分布于青海东北部至甘肃祁连山脉的特定区域，栖息于1800至3500米海拔的山地与丘陵地带。","appearance":"大石鸡具有独特的颈部锈色颈环，雄鸟拥有单一的胫骨刺，雌鸟略小于雄鸟。成年大石鸡的上体主要为沙灰色，带有少量棕色，尾羽为赤褐色，两侧有黑色、奶油色和狭窄的栗色条带。幼鸟的羽毛较均匀，白色斑点丰富，约两个月后变得更为成鸟化。","call":"鸣唱始于一系列加速的鼻音咯咯声，突然转换为双重音节“kuk...kuk...kok..kow..kow..kow-ow..kow-ow..kow-ow…”。集结叫声在早晨觅食前重复“ga, ga, ga, gela, gela, gela...”。受到惊吓的鸟会发出兴奋的、传播远的“fei-ji..fei-ji..fei-ji…”。","habits":"大石鸡偏好居住在有草和小灌木覆盖的多岩石的山坡和山谷，海拔从1300米到4000米。冬季可能出现在农场和村庄周围。它们实行海拔迁移，特别是在寒冷的冬季天气。成鸟以种子、根茎、球茎、幼苗和嫩芽为食，也吃一些无脊椎动物，如蜘蛛、蚱蜢和甲虫。幼鸟主要食用昆虫和绿叶。","breeding":"繁殖期从5月初持续到7月，配对发生在3月末至4月中旬，此时群体解散（通常多达30只）。雄鸟在繁殖期间表现出明显的不安，全天奔走鸣叫，为巢区和雌鸟而争斗。巢建在有遮蔽的阳光充足的地方，通常由草、叶子和羽毛简单构成。每窝产7至20枚淡黄色带有红棕色斑点的蛋，平均12.3枚，仅由雌鸟孵化22至24天。双亲共同抚养幼鸟，家庭保持在一起直到下一个繁殖季节。","identification":"大石鸡与石鸡相似，但可通过其浅色的眼前纹和颈部的不同图案识别：深色的颈带广泛呈现温暖的棕褐色，形成极其细薄且几乎断开的领环，而石鸡有黑色的厚实连续的领环。此外，大石鸡的眼睛为黄灰色，而非棕色。","protection":"IUCN：LC（无危）。大石鸡在中国西北部某些地区的数量尚可，但由于过度猎捕和栖息地恶化，数量迅速下降。已列入中国国家重点保护野生动物名录，保护级别为二级（自2021年2月5日起）。","distribution":"分布于中国北部的青藏高原东北部，包括青海和甘肃东南部（青藏高原东北部和甘肃西部中央区域）。","other":"大石鸡有记录的两个亚种，其中之一为lanzhouensis，特征在于上体缺乏沙色调，两侧的黑色条带更宽，内项链比外项链更宽（与指名亚种相反），且喙更高更厚。"},{"name":"黑脸石鸡","english_name":"Philby's Partridge","scientific_name":"Alectoris philbyi","overview":"黑脸石鸡（英文名：Philby's Partridge，学名：Alectoris philbyi），是鸡形目雉科石鸡属的鸟类。沙特阿拉伯西南部和也门北部特有种。其最显著的特征是黑色的脸颊和喉咙，以及灰蓝头部与白色细线相隔的独特外观。生活在阿拉伯山脉的干燥岩石地带，通常在海拔1280至3600米之间。","appearance":"黑脸石鸡拥有灰色和浅棕色为主的羽毛，侧面带有栗色和白色的条纹，脸部具有醒目的黑色面罩。飞行时，翼尖较暗，尾部两侧呈栗色。雄鸟比雌鸟稍大，雌鸟头部图案较淡，无跗跖结节，虹膜为栗褐色，喙鲜红，面部皮肤和腿为玫瑰红色。幼鸟总体上呈暗棕色，起初缺乏面部图案，背部有细密的条纹，腿部颜色较淡。","call":"其典型的叫声是一系列强调的“chuk-chek-chuk”声，尤其是在清晨和傍晚发出。当受到惊吓时会发出‘chork chork chork’的爆炸声或更嘈杂的‘chuk-a-chuk-oo’声。","habits":"栖息于阿拉伯山脉的干燥岩石地带，偏好有灌木覆盖的斜坡。它们主要在早晨和傍晚活动，以种子、植物物质和小型无脊椎动物为食，通常形成少于15只的小群，偶尔可达20只。","breeding":"繁殖季节从3月持续到8月，期间领地叫声达到顶峰。筑巢于杜松树丛下或岩石旁，蛋的颜色为白色到淡黄褐色，带有紫色或淡棕色斑点，大小约为40.1-45.5毫米×31.7-35毫米。孵化期大约为25天。雏鸟有奶油色的颈背，脸颊、下巴、喉咙、胸部和下部有淡黄色绒毛，背部颜色较深，有三条奶油色纵向条纹，喙呈粉红色，腿和脚橙粉色，虹膜棕色。","identification":"与阿拉伯石鸡相似，但通过黑色面罩和飞行时尾巴的栗色部分可以区分。雌雄个体间主要通过大小和头部图案的鲜明程度辨别。","protection":"IUCN：LC（无危）。在沙特阿拉伯局部常见，也门稀有，总估计有约25,000对。物种目前稳定，但对其栖息地的破坏可能影响某些地区的种群。","distribution":"分布于沙特阿拉伯西南部山区和也门西北部，主要在阿拉伯山脉的中高海拔地区。","other":"尽管不是饮食中的常见食材，但在美国1980年代被引入，现在在鸟类养殖中较为普遍。"},{"name":"北非石鸡","english_name":"Barbary Partridge","scientific_name":"Alectoris barbara","overview":"北非石鸡（英文名：Barbary Partridge，学名：Alectoris barbara），是鸡形目雉科石鸡属的鸟类。以美丽的外观著称，拥有淡色的脸庞和星点状的披肩，雄雌相似。该物种主要分布在北非地区，包括非洲北部，是直布罗陀的国鸟，出现在当地1便士硬币上。","appearance":"北非石鸡是一种圆胖的鸟类，背部呈灰褐色，胸部灰色，腹部浅黄色。脸部为淡灰色，带有宽阔的红褐色颈带，两胁有红色条纹，白色底色上布满赤褐色条纹，腿部红色。雄鸟和雌鸟外观几乎相同，仅雌鸟体型略小，缺乏雄鸟的钝刺。虹膜呈栗棕色，喙鲜红色，面部皮肤和腿为玫瑰红色。幼鸟颜色更均匀且偏黄，缺乏成鸟的头部特征图案和侧翼的条纹，喙和腿呈黄色，但在秋季前逐渐接近成年个体的特征。四个亚种在侧翼的斑纹和整体羽色上有差异。","call":"其广告鸣叫声为一系列短促的‘kchek’音符，当受到惊吓时会发出响亮的高音尖叫‘kree-ah’或‘chuckachew-chew-chew-chew’，强度可变。","habits":"北非石鸡偏好岩石地带、干旱的山坡以及阿尔卑斯森林的干燥区域，最高可达海拔3300米。它们也出现在开阔的松林、阿甘树（Argania spinosa）林地和柑橘种植园中，以及沙漠草原和种植地。在摩洛哥，它们的数量在树林、空地和作物混合的环境中最高。它们通常是定居者，但在冬季大雪时会从阿特拉斯山脉的高处下降。","breeding":"繁殖期从2月到6月中旬，筑巢于地面的凹坑中，通常覆盖在长草或巨石下，每窝产卵6至27枚，平均孵化率为94%，孵化期为24至25天。雏鸟出生时同步孵化，约10至12天后能进行弱飞，50至60天达到成鸟大小。","identification":"与同属其他物种的区别在于其栗色加褐色的冠和宽阔的颈带。与红腿石鸡相比，北非石鸡头部和颈部的图案不同。","protection":"IUCN：LC（无危）","distribution":"主要分布在北非，包括直布罗陀和加那利群岛（亚种A. b. koenigi）。它也被引入到葡萄牙大陆和撒丁岛。","other":"北非石鸡是北非最重要的狩猎对象之一，农业实践的强化也是导致某些地方数量减少的一个重要原因。"},{"name":"红腿石鸡","english_name":"Red-legged Partridge","scientific_name":"Alectoris rufa","overview":"红腿石鸡（英文名：Red-legged Partridge，学名：Alectoris rufa），是鸡形目雉科石鸡属的鸟类。体型圆润，主要分布在欧洲西南部。其背部呈淡棕色，腹部为白色，脸部白色并带有独特的黑色喉部条纹，两侧肋部有明显的横纹，腿部红色。在受惊扰时更倾向于奔跑而非飞行。","appearance":"成年红腿石鸡的上身沙褐色，腹部粉红色，胸部浅灰色，具有显著的黑色喉纹，侧面有鲜明的红黑相间的侧纹，喉咙乳白色，腿部和喙均为红色。头部顶部和上颈部为温暖的粉棕色，前额和侧面边缘为淡蓝灰色，有一条细窄的米色眉线从鼻孔上方延伸至下颈部两侧。虹膜为中等棕色，腿为粉红色。","call":"其叫声为三音节的'ka-chu-chu'。","habits":"这种鸟主要栖息在干燥的低地环境，如农田和开阔的岩石地带。它是一种留鸟，非繁殖季节形成群体。以种子为主食，幼鸟尤其依赖昆虫作为蛋白质来源。当受到干扰时，偏好奔跑而非飞行，必要时可短距离飞行。","breeding":"红腿石鸡在干燥的低地筑巢，通常在地面，形成稳定的配偶关系，有时会出现一雄多雌的情况。每窝平均产11.2到12.7枚白色或淡黄色斑点的蛋，孵化期大约23到25天。雏鸟出生时覆盖着丰富的棕色和奶油色绒毛，约10天后即可初步飞行，达到成鸟大小需50到60天。","identification":"与相似物种如欧石鸡和珠鸡相比，红腿石鸡的黑色条纹颈饰是其独特标志，上体颜色更偏向土褐色。雌雄幼鸟在大小和颜色上有细微差异，幼鸟的颜色更为暗淡。","protection":"IUCN：NT（近危）","distribution":"自然分布于西南欧（法国、伊比利亚半岛和意大利西北部），已自然化于英格兰和威尔士的平原地区，最北可至苏格兰的萨瑟兰。","other":"红腿石鸡在英国被引入作为狩猎鸟类，同时在新西兰也有养殖和少量野外存活的记录。"},{"name":"阿拉伯石鸡","english_name":"Arabian Partridge","scientific_name":"Alectoris melanocephala","overview":"阿拉伯石鸡（英文名：Arabian Partridge，学名：Alectoris melanocephala），是鸡形目雉科石鸡属的鸟类。广泛分布于南部阿拉伯半岛，包括沙特阿拉伯南部、也门和阿曼西部。体长可达41厘米，雄鸟平均体重724克，雌鸟约522克，拥有独特的黑冠白眉纹和蓝灰色的身体，腿和喙呈粉红色。","appearance":"阿拉伯石鸡体型较大，雄鸟平均重724克，雌鸟约522克，体长约为41厘米。头部的黑色冠和颈部形成鲜明对比，有宽大的白色眉纹和白色的喉部，黑色线条从喙角延伸至眼下方，形成“V”型图案。颈侧为淡棕色，身体、翅膀和尾巴呈现蓝灰色，两侧有深色条纹。腿和喙为粉红色，雄鸟有腿上的小突起。雌鸟略小于雄鸟，缺乏钝刺。虹膜为栗褐色，嘴鲜红色，面部皮肤、腿和脚为玫瑰红色。幼鸟呈灰褐色，有姜红色的冠，颈部、肩部和胸部有浅色斑点，缺乏面部图案和侧面的条纹；裸露部位可能主要是黑色。冬季的鸟与成鸟相似，但有较短的冠，黑色的喙，外观可能较暗淡。","call":"阿拉伯石鸡的叫声通常是一系列‘cuck, cuck, cuck, owk-owk-owk’的叫声，开始缓慢均匀，随后音速和音量逐渐增加。在配偶或群体间接触时发出更柔和的‘cook, cook, cookcookcookcook’声。当受到惊吓时，会发出‘kerkow-kerkow-kerkow’的声音。","habits":"栖息于草坡和多石地带，植被覆盖良好，海拔从近海平面至约1400米。它们是地面生活的鸟类，以种子、草本植物（如地中海草和银丝草）、谷物种子和昆虫为食。通常在早晨和傍晚觅食，通常以15只左右的小群出现，偶尔会聚集多达27只。","breeding":"繁殖季节从3月持续到5月，鸟巢是一个轻微凹陷的地面，通常位于海拔600米以上的地方，巢中有5至8枚白色带明显孔隙的蛋，尺寸大约为50.3毫米×37.3毫米。孵化期约为24至25天。雌雄双方可能分别孵化不同的窝，孵化后雏鸟群可能会合并。","identification":"与黑脸石鸡的区别在于更大的体型、灰色的尾羽（飞行中可见）、更宽的白色眉纹和黑色的冠。雌鸟比雄鸟稍小，缺乏钝刺。","protection":"IUCN：LC（无危）。阿拉伯石鸡的全球数量估计为40万对，总体上数量稳定。在沙特阿拉伯局部常见，在也门分布广泛但稀少，在阿曼南部较为常见。虽然没有记录到直接威胁，但其生境可能受到过度放牧、农业用地转换和周期性干旱的影响。狩猎和收集鸟蛋的情况存在，但目前认为不会产生重大负面影响。","distribution":"阿拉伯石鸡原产于阿拉伯半岛南部，具体包括沙特阿拉伯南部、也门和阿曼西部。它还被引入到阿联酋。两个亚种A. m. guichardi和A. m. melanocephala分别分布在东部哈德拉毛特和东部也门以及其余范围内。2022年，在沙特阿拉伯的Harrat Uwayrid生物圈保护区发现了该物种，位置比已知的所有其他种群向北移动了约100公里。"},{"name":"漠鹑","english_name":"See-see Partridge","scientific_name":"Ammoperdix griseogularis","overview":"漠鹑（英文名：See-see Partridge，学名：Ammoperdix griseogularis），是鸡形目雉科沙鹑属的鸟类。别称源自其独特的叫声。主要分布于东南土耳其至叙利亚北部，经伊拉克、伊朗、巴基斯坦至阿富汗的干燥和半干旱地区。体长约22-25厘米，具有独特的黑白眉纹、白色耳斑和橙色喙。","appearance":"漠鹑体长22-25厘米，体重雄鸟187-238克，雌鸟182-205克，翼展约40-42厘米。雄鸟具橙色喙，而非淡黄色，有黑色眉纹、白色颊斑和条纹侧腹。雌鸟较暗淡，颈部有白色斑点而非粉色条纹。幼鸟类似成年雄鸟，但面部图案不明显，缺乏侧腹标记。","call":"雄鸟发出远距离重复的'wheet-div'或'hoe-it'声，首音带有鞭打般的质感，类似斑胸田鸡的叫声。在受惊或飞行时，会发出快速的'bwuit-bwuit-bwuit'声。被惊扰时，翅膀发出的尖锐声音是其得名的来源。","habits":"栖息于干燥石质山坡或轻度植被覆盖的荒地，海拔通常低于2000米，偏好平坦地形，常靠近水源。以植物嫩芽、叶子、种子和浆果为主食，也会食用昆虫。通常在白天活动，偏好奔跑而非飞行，仅在必要时短距离飞行。","breeding":"繁殖期为4月中旬至7月，一般为一夫一妻制。筑巢于地面，由草或岩石遮蔽，每次产6-9枚蛋，颜色为奶油色或乳白色，由雌鸟单独孵化至少21天。雏鸟孵化后由雌鸟或双亲共同抚养。","identification":"雄鸟与沙鹑的区别在于灰喉、淡色颈斑和黑白边缘的眼纹。雌鸟与沙鹑雌鸟相比，颈部有白色斑点而非粉色条纹。","protection":"IUCN：LC（无危）。分布广泛，部分地区数量合理，但在叙利亚较为罕见。","distribution":"分布于东南土耳其、叙利亚北部、沙特阿拉伯局部、亚美尼亚南部、乌兹别克斯坦、土库曼斯坦东南部、塔吉克斯坦南部，穿过伊朗和阿富汗（除东北部）至喜马拉雅山南麓的巴基斯坦。","other":"近年来在亚美尼亚南部首次被发现，其在土耳其的分布范围可能自1950年以来有所扩大。"},{"name":"沙鹑","english_name":"Sand Partridge","scientific_name":"Ammoperdix heyi","overview":"沙鹑（英文名：Sand Partridge，学名：Ammoperdix heyi），是鸡形目雉科沙鹑属的鸟类。主要分布于欧亚大陆及非洲北部的阿拉伯半岛、埃及和苏丹北部。与东南土耳其至巴基斯坦的漠鹑关系密切，外观相似。","appearance":"沙鹑是一种圆胖型鸟类，身长22至25厘米，体重约180至200克，翼展可达39至41厘米。雄鸟头部呈灰色，具白色眉纹和颊斑，侧颈平滑无白色斑点，颈部两侧的粉红色条纹是其显著特征之一。雌鸟颜色较淡，沙色和灰色交织，标记较少，颈部侧面有粉红色条纹而非白色斑点。幼鸟与雌鸟外观相似。","call":"雄性沙鹑的鸣唱声为上升的、犬吠般的\"kew-kew-kew\"或\"watcha-watcha-watcha\"，此外还会发出远传的、响亮的笛音\"quip\"或\"qu-ip\"，以及受到惊吓或被激怒时的急促\"wuit-wuit-wuit\"。","habits":"沙鹑栖息于沙漠和半沙漠地带，偏好岩石嶙峋的斜坡、散落着植被的地带，以及海拔高达2000米的山脊。它们经常访问水源饮水，尤其在早晨。以种子、浆果和昆虫（如蝗虫）为食，夏季主要摄取种子。","breeding":"繁殖季节从二月持续到八月，在以色列，可能在雨水充足的冬季之后双窝繁殖。在约旦和西奈半岛，三月至四月产卵。在阿拉伯半岛，产卵主要在四月，但也有记录显示直到八月和十一月仍在繁殖。雌鸟独自孵化5至14枚（通常8至12枚）淡奶油色带灰或粉色色调的蛋，孵化期约为21至24天。雏鸟9至20天离巢，约30天达到成年体型。","identification":"沙鹑与漠鹑的区别在于头部图案，雄性沙鹑的侧颈无白色斑点，而漠鹑则有。雌性沙鹑由于头纹较弱，辨识较为困难。","protection":"IUCN：LC（无危）","distribution":"沙鹑广泛分布于阿拉伯半岛、埃及东部、苏丹北部、以色列、约旦、沙特阿拉伯、阿曼、也门、阿联酋等地。在阿拉伯半岛估计有约90万对沙鹑。","other":"沙鹑已被引入沙特阿拉伯和阿联酋的两个离岸岛屿。"},{"name":"黑鹧鸪","english_name":"Black Francolin","scientific_name":"Francolinus francolinus","overview":"黑鹧鸪（英文名：Black Francolin，学名：Francolinus francolinus），是鸡形目雉科鹧鸪属的鸟类。以其独特的羽色和响亮的叫声闻名。被指定为印度哈里亚纳邦的州鸟，当地称为kaala teetar。分布于欧亚大陆南部，自土耳其东部至印度东北部和孟加拉国。雄鸟的羽毛色彩斑斓，由黑色、棕色、栗色和白色构成，雌鸟则以棕色为主，带有淡色的颈背斑块。","appearance":"雄性黑鹧鸪长约33至36厘米，重约453克。其特征为黑色的头部和胸部，脸颊上有明显的白色斑点，颈部有栗色的领圈，背部和翅膀呈金色和棕色的鳞状图案。雌鸟体型略小，主色调为棕色，头顶和喉咙为黑色，胸前和侧腹有黑色的条纹。两性的腿和脖子颜色从红棕色到红色不等。","call":"黑鹧鸪的叫声独特，被描述为响亮的‘klik cheek-cheek-cheerakik’，通常在早晨和傍晚听到，尤其是在繁殖季节几乎全天候都能听见。雄鸟常站在土丘、岩石或低矮的树枝上鸣叫，随后会引来周围其他鸟儿的回应。","habits":"黑鹧鸪主要栖息在有足够高作物遮蔽的灌木丛生地带，偏好靠近水源的厚密植被区。它们不是森林鸟，但会在草原边缘或与草地相连的灌木丛中活动。这种鸟通常在受到惊扰时才会飞行，飞行短暂而直接。","breeding":"黑鹧鸪在3月至5月期间于高草丛中筑巢，雄鸟会通过发出独特的叫声吸引配偶。繁殖期间，雌雄双方共同照顾孵化后的幼鸟，幼鸟会与父母一起度过第一个冬天。巢穴通常位于灌木下的浅坑内，铺设着各种杂草。","identification":"与灰鹧鸪相比，黑鹧鸪具有灰色和棕黄色的身体，喉咙部分为黑色而非缓冲色，缺少红褐色的领圈。雄性黑鹧鸪的白颊斑和黑色羽毛下的白色斑点是辨识关键。","protection":"IUCN：LC（无危）","distribution":"黑鹧鸪分布于欧亚大陆南部，从土耳其东南部向东延伸至巴基斯坦和印度东部，直至孟加拉国。在历史上，其分布范围更为广泛，但由于过度猎杀，分布和数量已显著减少。","other":"黑鹧鸪曾被引入美国路易斯安那州、佛罗里达州南部、关岛和夏威夷群岛等地。"},{"name":"花彩鹧鸪","english_name":"Painted Francolin","scientific_name":"Francolinus pictus","overview":"花彩鹧鸪（英文名：Painted Francolin，学名：Francolinus pictus），是鸡形目雉科鹧鸪属的鸟类。广泛分布在印度次大陆，包括印度中央和南部以及斯里兰卡低地。其最显著的特征是白色斑点遍布全身，特别是在腹部和背部。雄鸟的背部有醒目的白点黑底花纹。","appearance":"体型约31-32厘米，体重242-340克。雄鸟背部有明显的黑白相间的斑点，面部和喉部呈鲜艳的红褐色，腿部和脚橙黄色至红色。雌鸟较淡，下巴无斑点，下体有较柔和的条纹，色彩较暗淡。幼鸟类似雌鸟，但侧翼和下胸的斑纹更为明显。三个亚种：指名亚种 pictus、pallidus 和 watsoni，它们的区别在于下体的深浅程度。","call":"在晚夏和雨季期间，通过重复的、尖锐高音的“click—khrak-khrukuk—khrakakak”叫声被常见检测到。叫声与黑鹧鸪相似，但节奏略有不同，音调更低沉，更具喉音。","habits":"栖息于半干旱的草地、灌木丛或耕作地带，偏好有零星树木和茂密低矮植被的环境。在繁殖季节后，通常隐藏于密集的覆盖物中。以草籽、稻谷、昆虫和Cyperus rotundus的块根为食。飞行时，尾巴有时会翘起。","breeding":"筑巢时间可能与印度的雨季同步，一般在6月至10月间，但在斯里兰卡则为3月至6月。一夫一妻制，巢穴建在地面凹处，通常位于密集的遮蔽下。产卵4-6枚橄榄棕色的蛋，仅由雌鸟孵化。","identification":"与黑鹧鸪区别明显，花彩鹧鸪缺乏红褐色颈背环，脸部和喉咙颜色更亮，无眼后黑线，下体斑点更重。watsoni亚种的两性差异较小，黑色标记更为强烈。","protection":"IUCN：LC（无危）。然而，watsoni亚种被认为是脆弱的，由于过度狩猎和栖息地破坏，其分布和数量需进一步调查。印度亚种仍然广泛分布，但过去80年中，由于草原损失，其数量显著下降。","distribution":"分布于印度的拉贾斯坦邦、北方邦至印度半岛南部，避开马拉巴尔海岸和哥印拜陀南部地区，以及斯里兰卡东部至尼格拉和比比勒的低地。","other":"在文化上，该鸟出现在斯里兰卡的一枚4.50卢比邮票上。"},{"name":"中华鹧鸪","english_name":"Chinese Francolin","scientific_name":"Francolinus pintadeanus","overview":"中华鹧鸪（英文名：Chinese Francolin，学名：Francolinus pintadeanus），是鸡形目雉科鹧鸪属的鸟类。又称: 中国鹧鸪、越雉、怀南，典型的鹧鸪。主要栖息于干燥、多灌木的环境，尤其是丘陵和山区。雄鸟面部特征明显，拥有白色脸颊和红褐色的冠部、肩部及腹部，全身覆盖精致的黑白相间的鳞状羽毛。雌鸟总体上呈棕色，花纹细腻，不如雄鸟鲜艳。其分布广泛，横跨东南亚多个国家。","appearance":"中华鹧鸪体型适中，长度约30-34厘米，重量在280-400克之间。雄鸟具有一条细黑的颊纹，肩羽无淡色末端带，最显著的是拥有白色喉咙和头部侧面，胸部及中央下体密集白色斑点。雌鸟头部图案较为暗淡，大部分下体呈淡黄色并带有深色条纹，背部棕色，尾上覆羽也是棕色。喙黑色，虹膜棕色，腿在繁殖季节为红色，非繁殖季节及雌鸟为黄棕色。幼鸟外观类似成年雌鸟，但色泽较暗淡，有条纹，后颈和上体有条纹而非斑点，眼纹和颊纹不明显。","call":"在繁殖季节，中华鹧鸪非常喧闹。雄鸟会在显眼的位置发出广告性的叫声，一系列5-6个响亮、刺耳、金属质感的音符，声音类似于“kak-kak-kuich, ka-ka”或“wi-ta-tak-takaa”。首音高而短，第三音上扬，第五音下滑，最后两个音节快速连发，整个叫声后有长时间的停顿。","habits":"中华鹧鸪偏好干燥开阔的森林和灌木丛、草地以及耕作区边缘。它们在低海拔的橡树林和喜马拉雅山麓、滚动地形上的龙脑香林的草地上活动。在泰国，它们的记录高度达到1500米。它们通常在清晨和傍晚最为活跃，尽管小群体通常在隐蔽处觅食，但也愿意进入农田。它们以种子、嫩芽和昆虫为食。","breeding":"繁殖期在亚洲南部为3月至9月，在缅甸南部为3月至4月，但在9月至10月也有巢穴的报告。巢建在地面竹林中或草丛和次生植被中，用草和树叶衬里。产卵数为4-5枚，蛋壳颜色为奶油色或橄榄奶油色。孵化由雌鸟独自承担，孵化期约为21天。","identification":"雄性中华鹧鸪通过其独特的黑白斑点、白喉和头部侧面以及肩部的红褐色与其它斑点鹧鸪区分开来。雌鸟通过锈色眉纹、颈部无红褐色、脸颊较淡与雌鸟区分。","protection":"IUCN：LC（无危）。在中国被认为相当常见。主要威胁来自栖息地的农业开发和过度放牧，但这些在泰国并不被视为严重威胁。毛里求斯的引入种群可能在20世纪初已灭绝，菲律宾吕宋岛的引入种群似乎也被根除。","distribution":"中华鹧鸪分布在柬埔寨、中国、印度、老挝、缅甸、菲律宾、泰国和越南。在毛里求斯、菲律宾、马达加斯加、美国、智利和阿根廷有引入种群。中国大陆主要分布在东南部。","other":"中华鹧鸪的雄鸟性格好斗，为了保护巢区而表现出强烈的领地意识。"},{"name":"灰鹧鸪","english_name":"Grey Francolin","scientific_name":"Ortygornis pondicerianus","overview":"灰鹧鸪（英文名：Grey Francolin，学名：Ortygornis pondicerianus），是鸡形目雉科 Ortygornis 属的鸟类。亦被称为灰鹧鸪。原生于南亚，包括伊朗东南部至印度和斯里兰卡。在开放的草地和干燥地带生活，如干草丛、灌木丛和农田。群居生活，叫声响亮，常被描述为“kateetar-kateetar”。在印度次大陆，当地人称之为teetar，这一名字源自其特有的鸣叫。","appearance":"灰鹧鸪是一种中等体型的鸟，雄鸟平均长度为29-34厘米，雌鸟为26-30厘米。雄鸟的体重在260-340克之间，而雌鸟在200-310克。全身布满条纹，脸部呈淡色，喉咙边缘有一圈细黑线。雄鸟可能有单个或两个腿上的刺，雌鸟通常没有刺。喙暗色，虹膜棕色，腿橙色。幼鸟外观与成鸟相似，但头部和喉咙的标记不那么明显。","call":"灰鹧鸪的叫声响亮且重复，被描述为“kateetar-kateetar”。在繁殖季节，雄鸟的叫声吸引挑战者，有时会形成对唱。","habits":"偏好低矮草地覆盖的开阔地带，海拔高度一般不超过500米（印度）和1200米（巴基斯坦）。它们以种子、谷物和昆虫（如白蚁和甲虫）为食，偶尔捕食蛇类等较大猎物。夜宿于低矮的灌木丛中。","breeding":"繁殖季节主要在4月至9月，筑巢于地面隐蔽处，有时也会在墙壁或岩石的缝隙中。每窝产卵6到8枚，较大的窝卵数可能反映了种内寄生现象。","identification":"与花彩鹧鸪容易混淆，但后者斑点更明显，底色较暗。与沼泽鹧鸪相比，后者侧翼有条纹而非斑纹，栖息于湿润的草地和芦苇区。","protection":"IUCN：LC（无危）","distribution":"分布于伊朗东南部至印度次大陆和斯里兰卡。在印度次大陆，分布于喜马拉雅山脚以南，西至印度河流域，东至孟加拉国。在斯里兰卡北部也有分布。引入种群见于美国夏威夷群岛和内华达州。","other":"在印度次大陆北部，灰鹧鸪已被驯养用于斗鸟活动。"}];
